const ASUBHA_DATA = [
            { text: `Hãy dừng lại, tư tưởng dục vọng!<br>Hãy dừng lại, tư tưởng sân hận!<br>Hãy dừng lại, tư tưởng não hại!<br>Ðến đây thôi, tư tưởng dục vọng!<br>Ðến đây thôi, tư tưởng sân hận!<br>Ðến đây thôi, tư tưởng não hại!`, ref: "Trường Bộ 17 – Kinh Ðại Thiện Kiến Vương", url: "https://loicuaducphat.org/dn/dn17.html#content" },

{ text: `“Chư Thiện hữu, ở đây có người thân cận dục lạc, thân cận bất thiện pháp. Sau một thời gian, vị nào được nghe Thánh pháp, như lý tác ý, chứng đắc Chánh pháp và tùy pháp. Và khi nghe được Thánh pháp, như lý tác ý, chứng đắc Chánh pháp và tùy pháp vị này sống không thân cận dục lạc, không thân cận bất thiện pháp. Nhờ sống không thân cận dục lạc, không thân cận bất thiện pháp, an lạc khởi lên, và hơn cả an lạc, hoan hỷ khởi lên. Chư Thiện hữu, như từ thoải mái, hỷ duyệt sanh, cũng vậy, Chư thiện hữu nhờ sống không thân cận dục lạc, không thân cận bất thiện pháp, an lạc khởi lên, và hơn cả an lạc, hoan hỷ khởi lên. Chư Thiện hữu, đó là con đường tắt thứ nhất hướng đến an lạc đã được Thế Tôn, bậc Trí Giả, bậc Kiến Giả, bậc Ứng Cúng, Chánh Ðẳng Giác chứng ngộ.`, ref: "Trường Bộ 18 – Kinh Xa-ni-sa", url: "https://loicuaducphat.org/dn/dn18.html#content" },

{ text: `"Này Ðại vương, khi mắt thấy sắc, Tỷ-kheo không nắm giữ tướng chung, không nắm giữ tướng riêng. Những nguyên nhân gì, khiến nhãn căn không được chế ngự, khiến tham ái, ưu bi, các ác, bất thiện pháp khởi lên, Tỷ-kheo tự chế ngự nguyên nhân ấy, hộ trì nhãn căn, thực hành sự hộ trì nhãn căn. "`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Những nguyên nhân gì khiến ý căn không được chế ngự, khiến tham ái, ưu bi, các ác, bất thiện pháp khởi lên, Tỷ-kheo chế ngự nguyên nhân ấy, hộ trì ý căn, thực hành sự hộ trì ý căn. Vị ấy, nhờ sự hộ trì cao quý các căn ấy, nên hưởng lạc thọ nội tâm, không vẩn đục. "`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Tỷ-kheo ly dục, ly ác pháp, chứng và trú thiền thứ nhất, một trạng thái hỷ lạc do ly dục sanh, với tầm, với tứ. Tỷ-kheo thấm nhuần, tẩm ướt, làm cho sung mãn, tràn đầy thân mình với hỷ lạc do ly dục sanh, không một chỗ nào trên toàn thân không được hỷ lạc do ly dục sanh ấy thấm nhuần. "`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Khi mắt thấy sắc, Tỷ-kheo không nắm giữ tướng chung, không nắm giữ tướng riêng. Những nguyên nhân gì, khiến nhãn căn không được chế ngự, khiến tham ái, ưu bi, các ác, bất thiện pháp khởi lên, Tỷ-kheo tự chế ngự nguyên nhân ấy, hộ trì nhãn căn... Vị ấy nhờ sự hộ trì cao quý các căn ấy, nên hưởng lạc thọ nội tâm, không vẩn đục."`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `Thế Tôn liền thứ lớp giảng pháp cho Bà-la-môn Pokkharasàdi, thuyết về bố thí, thuyết về trì giới, thuyết về các cõi trời, trình bày sự nguy hiểm, sự hạ liệt, sự nhiễm ô của dục lạc và sự lợi ích của xuất ly. Khi Thế Tôn biết tâm của Bà-la-môn Pokkharasàdi đã sẵn sàng, đã nhu thuận, không còn chướng ngại, được phấn khởi, được tín thành, liền thuyết pháp mà chư Phật đã chứng ngộ, tức là khổ, tập, diệt, đạo. Cũng như tấm vải thuần bạch, được gột rửa các vết đen, sẽ rất dễ thấm màu nhuộm, cũng vậy, chính chỗ ngồi này, pháp nhãn xa trần ly cấu khởi lên trong tâm Bà-la-môn Pokkharasàdi: "Phàm pháp gì được tập khởi lên đều bị tiêu diệt".`, ref: "Trường Bộ 3 – Kinh Ambattha ", url: "https://loicuaducphat.org/dn/dn3.html#content" },

{ text: `Này Poṭṭhapāda, Khi nhiễm pháp được diệt trừ, tịnh pháp được tăng trưởng, ngay hiện tại tự mình giác ngộ, với thắng trí, chứng đạt và an trú trí tuệ sung mãn, quảng đại, thời hân hoan sanh, hoan hỷ, khinh an, chánh niệm, tỉnh giác và lạc trú sanh.`, ref: "Trường Bộ 9 – Kinh Poṭṭhapāda", url: "https://loicuaducphat.org/dn/dn9.html#content" },


{ text: `Này các Tỷ-kheo, Thế Tôn Vipassì, bậc A-la-hán, Chánh Ðẳng Giác suy nghĩ: “Pháp này do Ta chứng được, thật là sâu kín, khó thấy, khó chứng, tịch tịnh, cao thượng, siêu lý luận, vi diệu, chỉ người trí mới hiểu thấu. Còn quần chúng này thì ưa ái dục, khoái ái dục, ham thích ái dục. Ðối với quần chúng ưa ái dục, khoái ái dục, ham thích ái dục, thật khó mà thấy được định lý “Y tánh duyên khởi pháp” (idapaccayatā paṭicca samuppāda); thật khó mà thấy được định lý tất cả hành là tịch tịnh, tất cả sanh y được trừ bỏ, ái được đoạn tận, ly dục, ái diệt, Niết-bàn.`, ref: "Trường Bộ 14 – Kinh Ðại bổn", url: "https://loicuaducphat.org/dn/dn14.html#content" },

{ text: `Này các Tỷ-kheo, Thế Tôn Vipassì, bậc A-la-hán, Chánh Ðẳng Giác nhìn đời với Phật nhãn, thấy có hạng chúng sanh nhiễm ít bụi đời, nhiễm nhiều bụi đời, có hạng lợi căn độn căn, có hạng tánh thuận tánh nghịch, có hạng dễ dạy khó dạy, và một số ít thấy sự nguy hiểm phải tái sanh thế giới khác và sự nguy hiểm của những hành động lỗi lầm. Như trong hồ sen xanh, sen hồng hay sen trắng, có một số hoa sen xanh, sen hồng hay sen trắng sanh ra dưới nước, lớn lên dưới nước, không vượt lên khỏi mặt nước, được nuôi dưỡng dưới nước; có một số hoa sen xanh, sen hồng hay sen trắng sanh ra dưới nước lớn lên dưới nước, sống vươn lên tới mặt nước, có một số hoa sen xanh, sen hồng hay sen trắng sanh ra dưới nước lớn lên dưới nước vươn lên khỏi mặt nước, không bị nước làm đẫm ướt.`, ref: "Trường Bộ 14 – Kinh Ðại bổn", url: "https://loicuaducphat.org/dn/dn14.html#content" },

{ text: `Này các Tỷ-kheo, khi nào chúng Tỷ-kheo không bị chi phối bởi tham ái, tham ái này tác thành một đời sống khác, thời này các Tỷ-kheo, chúng Tỷ-kheo sẽ được cường thịnh, không bị suy giảm.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này Ānanda, ở đời, vị Tỷ-kheo, đối với thân quán thân, tinh tấn, tỉnh giác, chánh niệm, nhiếp phục mọi tham ái, ưu bi trên đời; đối với các cảm thọ … đối với tâm … đối với các pháp, quán pháp, tinh tấn, tỉnh giác, chánh niệm, nhiếp phục mọi tham ái, ưu bi trên đời. Này Ānanda, như vậy vị Tỷ-kheo tự mình là ngọn đèn cho chính mình, tự mình nương tựa chính mình, không nương tựa một gì khác, dùng Chánh pháp làm ngọn đèn, dùng Chánh pháp làm chỗ nương tựa, không nương tựa một gì khác.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này các Tỷ-kheo, chính vì không giác ngộ, không chứng đạt bốn Pháp mà Ta và các Ngươi lâu đời phải trôi lăn trong biển sanh tử. Thế nào là bốn? Này các Tỷ-kheo, chính vì không giác ngộ, không chứng đạt Thánh Giới mà Ta và các Ngươi lâu đời phải trôi lăn trong biển sanh tử. Này các Tỷ-kheo, chính vì không giác ngộ, không chứng đạt Thánh Ðịnh mà Ta và các Ngươi lâu đời phải trôi lăn trong biển sanh tử. Này các Tỷ-kheo, chính vì không giác ngộ, không chứng đạt Thánh Tuệ mà Ta và các Ngươi lâu đời phải trôi lăn trong biển sanh tử. Này các Tỷ-kheo, chính vì không giác ngộ, không chứng đạt Thánh giải thoát mà Ta và các Ngươi lâu đời phải trôi lăn trong biển sanh tử.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Các hành là vô thường,<br>Có sanh phải có diệt<br>Ðã sanh, chúng phải diệt,<br>Nhiếp chúng là an lạc.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Như vậy, vị ấy sống quán thân trên nội thân; hay sống quán thân trên ngoại thân; hay sống quán thân trên cả nội thân, ngoại thân. Hay vị ấy sống quán tánh sanh khởi trên thân; hay sống quán tánh diệt tận trên thân; hay sống quán tánh sanh diệt trên thân. “Có thân đây”, vị ấy an trú chánh niệm như vậy với hy vọng hướng đến chánh trí, chánh niệm. Và vị ấy sống không nương tựa, không chấp trước một vật gì trên đời. Này các Tỷ kheo, như vậy Tỷ kheo sống quán thân trên thân.`, ref: "Trường Bộ 22 – Kinh Ðại Niệm xứ", url: "https://loicuaducphat.org/dn/dn22.html#content" },

{ text: `Này các Tỷ kheo, ở đây Tỷ kheo, nội tâm có tham dục, tuệ tri: “Nội tâm tôi có tham dục”; hay nội tâm không có tham dục, tuệ tri rằng: “Nội tâm tôi không có tham dục”. Và với tham dục chưa sanh nay sanh khởi, vị ấy tuệ tri như vậy. Và với tham dục đã sanh nay được đoạn diệt, vị ấy tuệ tri như vậy. Và với tham dục đã được đoạn diệt, tương lai không sanh khởi nữa, vị ấy tuệ tri như vậy.`, ref: "Trường Bộ 22 – Kinh Ðại Niệm xứ", url: "https://loicuaducphat.org/dn/dn22.html#content" },

{ text: `Này các Tỷ kheo, sự tham ái này khi sanh khởi thì sanh khởi ở đâu, khi an trú thì an trú ở đâu? Ở đời, sắc gì thân ái, sắc gì khả ái? Ở đời con mắt là sắc thân ái, là sắc khả ái. Sự tham ái này khi sanh khởi thì sanh khởi ở đấy, khi an trú thì an trú ở đấy. Ở đời cái tai … ở đời mũi … ở đời lưỡi … ở đời thân … ở đời ý là sắc thân ái, là sắc khả ái. Sự tham ái này khi sanh khởi thì sanh khởi ở đấy, khi an trú thì an trú ở đấy.`, ref: "Trường Bộ 22 – Kinh Ðại Niệm xứ", url: "https://loicuaducphat.org/dn/dn22.html#content" },

{ text: `Này các Tỷ kheo, thế nào là Chánh tư duy? Tư duy về ly dục, tư duy về vô sân, tư duy về bất hại. Này các tỷ kheo, như vậy gọi là Chánh tư duy.`, ref: "Trường Bộ 22 – Kinh Ðại Niệm xứ", url: "https://loicuaducphat.org/dn/dn22.html#content" },

{ text: `Này các Tỷ kheo, và thế nào là Chánh tinh tấn? Này các Tỷ kheo, ở đây Tỷ kheo, đối với các ác, bất thiện pháp chưa sanh, khởi lên ý muốn không cho sanh khởi; vị này nỗ lực, tinh tấn, quyết tâm, trì chí. Ðối với các ác, bất thiện pháp đã sanh, khởi lên ý muốn trừ diệt, vị này nỗ lực, tinh tấn, quyết tâm, trì chí. Ðối với các thiện pháp chưa sanh, khởi lên ý muốn khiến cho sanh khởi; vị này nỗ lực, tinh tấn, quyết tâm, trì chí. Ðối với các thiện pháp đã sanh, khởi lên ý muốn khiến cho an trú, không cho băng hoại, khiến cho tăng trưởng, phát triển, viên mãn. Vị này nỗ lực, tinh tấn, quyết tâm, trì chí. Này các Tỷ kheo, như vậy gọi là Chánh tinh tấn.`, ref: "Trường Bộ 22 – Kinh Ðại Niệm xứ", url: "https://loicuaducphat.org/dn/dn22.html#content" },

{ text: `Này các Tỷ kheo, thế nào là Chánh niệm? Này các Tỷ kheo, ở đây vị Tỷ kheo sống quán thân trên thân, nhiệt tâm, tỉnh giác, chánh niệm, để chế ngự tham ưu ở đời; trên các cảm thọ … trên các tâm … quán pháp trên các pháp, tinh cần tỉnh giác, chánh niệm để chế ngự tham ưu ở đời. Này các Tỷ kheo, như vậy gọi là Chánh niệm.`, ref: "Trường Bộ 22 – Kinh Ðại Niệm xứ", url: "https://loicuaducphat.org/dn/dn22.html#content" },

{ text: `Và này Nigrodha, có những pháp bất thiện không được từ bỏ, làm cho cấu uế, đưa đến tái sanh, đem lại đau khổ, đưa lại quả khổ, đem lại già, bệnh, chết trong tương lai. Những pháp ấy, Ta thuyết giảng để diệt trừ chúng. Nếu các Ngươi thực hành đúng theo lời giảng dạy, thời các pháp cấu uế của ngươi được trừ diệt, các pháp thanh tịnh được tăng trưởng, và các ngươi sẽ tự chứng biết, chứng ngộ, đạt đến an trú ngay trong hiện tại, trí tuệ cụ túc, viên mãn.`, ref: "Trường Bộ 25 – Kinh Ưu-đàm-bà-la Sư tử hống", url: "https://loicuaducphat.org/dn/dn25.html#content" },

{ text: `Này các Tỷ kheo, thế nào là một Tỷ kheo sống tự mình là ngọn đèn cho chính mình, tự mình nương tựa mình, không nương tựa một ai khác, lấy Chánh pháp làm ngọn đèn, nương tựa Chánh pháp, không nương tựa một gì khác? Này các Tỷ kheo, ở đây vị Tỷ kheo sống quán thân trên tự thân, nhiệt tâm, tinh cần, chánh niệm, tỉnh giác, để diệt trừ tham ưu ở đời, trên các cảm thọ … trên các tâm … quán pháp trên các pháp, nhiệt tâm, tinh cần, chánh niệm, tỉnh giác, để có thể diệt trừ tham ưu ở đời. Như vậy này các Tỷ kheo, vị Tỷ kheo sống tự mình là ngọn đèn cho chính mình, tự mình nương tựa mình, không nương tựa một ai khác, lấy Chánh pháp làm ngọn đèn, nương tựa Chánh pháp, không nương tựa một gì khác.`, ref: "Trường Bộ 26 – Kinh Chuyển luân Thánh vương Sư tử hống", url: "https://loicuaducphat.org/dn/dn26.html#content" },


{ text: `Này các Tỷ kheo, hãy đi lại trong giới hạn được phép của mình, trong giới hạn Tổ phụ các Ngươi truyền lại. Này các Tỷ kheo, nếu các Ngươi đi lại trong giới hạn được phép của mình, trong giới hạn Tổ phụ các Ngươi truyền lại thời tuổi thọ sẽ được tăng thịnh, sắc đẹp sẽ được tăng thịnh, an lạc sẽ được tăng thịnh, tài sản sẽ được tăng thịnh, thế lực sẽ được tăng thịnh.`, ref: "Trường Bộ 26 – Kinh Chuyển luân Thánh vương Sư tử hống", url: "https://loicuaducphat.org/dn/dn26.html#content" },

{ text: `Này Cunda Ta không thuyết giảng chỉ để ngăn chặn các lậu hoặc ngay trong hiện tại. Này Cunda, Ta không thuyết pháp, chỉ để diệt trừ các lậu hoặc trong tương lai mà thôi. Này Cunda, Ta thuyết pháp vừa để ngăn chặn các lậu hoặc ngay trong hiện tại mà cũng để diệt trừ các lậu hoặc trong tương lai nữa.`, ref: "Trường Bộ 29 – Kinh Thanh Tịnh", url: "https://loicuaducphat.org/dn/dn29.html#content" },


{ text: `Lại nữa này Cunda, ở đây có người say đắm, đam mê sống vây quanh với năm món dục lạc, đó là hỷ lạc thứ tư. Này Cunda, bốn loại hỷ lạc này là thấp kém, hạ liệt, thuộc phàm phu, không xứng Thánh hạnh, không có lợi ích, không hướng đến yểm ly, vô tham, tịch diệt, an tịnh, thắng trí, giác ngộ và Niết-bàn. Này Cunda, sự kiện này có thể xảy ra. Các du sĩ ngoại đạo có thể nói: “Các vị Sa-môn Thích tử đang sống đam mê bốn loại hỷ lạc này”. Họ cần phải được trả lời: “Nói như vậy là không phải; các ông nói như vậy là không đúng đắn. Nói như vậy là các ông xuyên tạc, không đúng sự thật, không thực có”.`, ref: "Trường Bộ 29 – Kinh Thanh Tịnh", url: "https://loicuaducphat.org/dn/dn29.html#content" },

{ text: `Bốn chánh cần: Ở đây, này các Hiền giả vị Tỷ-kheo, với mục đích khiến cho các ác, bất thiện pháp từ trước chưa sanh không cho sanh khởi, khởi lên ý muốn, cố gắng, tinh tấn, sách tâm, trì tâm. Với mục đích khiến cho các ác bất thiện pháp đã sanh ra được trừ diệt, khởi lên ý muốn, cố gắng, tinh tấn, sách tâm, trì tâm. Với mục đích khiến cho các thiện pháp từ trước chưa sanh nay cho sanh khởi, khởi lên ý muốn, cố gắng, tinh tấn, sách tâm, trì tâm. Với mục đích khiến cho các thiện pháp đã được sanh có thể duy trì, không có mù mờ, được tăng cường, được quảng đại, được tu tập, được viên mãn, khởi lên ý muốn, cố gắng, tinh tấn, sách tâm, trì tâm.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `Này các Hiền giả, thế nào là đoạn trừ tinh cần? Này các Hiền giả, ở đây, vị Tỷ-kheo không chấp nhận dục tầm đã khởi lên, từ bỏ, đoạn trừ, tiêu diệt, không cho hiện hữu; không chấp nhận sân tầm đã khởi lên … không chấp nhận hại tầm đã khởi lên, từ bỏ, đoạn trừ, tiêu diệt, không cho hiện hữu. Này các Hiền giả, như vậy gọi là đoạn trừ tinh cần.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `“Này các Tỷ-kheo, thế nào là các lậu hoặc phải do phòng hộ được đoạn trừ? Ở đây, có Tỷ-kheo như lý giác sát, sống phòng hộ với sự phòng hộ mắt. Này các Tỷ-kheo, nếu Tỷ-kheo ấy sống không phòng hộ với sự phòng hộ mắt, các lậu hoặc tàn hại và nhiệt não ấy có thể khởi lên. Nếu sống phòng hộ mắt, các lậu hoặc tàn hại và nhiệt não ấy không còn nữa. Này các Tỷ-kheo, các pháp ấy được gọi là các lậu hoặc phải do phòng hộ được đoạn trừ.`, ref: "Trung Bộ 2 – Kinh Tất Cả Lậu Hoặc", url: "https://loicuaducphat.org/mn/mn2.html#content" },

{ text: `Này các Tỷ-kheo, ở đây, Tỷ-kheo như lý giác sát không có chấp nhận dục niệm đã khởi lên, từ bỏ, trừ diệt, diệt tận, không cho tồn tại (dục niệm ấy); không có chấp nhận sân niệm đã khởi lên, từ bỏ, trừ diệt, diệt tận, không cho tồn tại (sân niệm ấy); không có chấp nhận hại niệm đã khởi lên, từ bỏ, trừ diệt, diệt tận, không cho tồn tại (hại niệm ấy); không chấp nhận các ác bất thiện pháp luôn luôn khởi lên, từ bỏ, trừ diệt, diệt tận, không cho tồn tại (các ác bất thiện pháp ấy)`, ref: "Trung Bộ 2 – Kinh Tất Cả Lậu Hoặc", url: "https://loicuaducphat.org/mn/mn2.html#content" },

{ text: `“Này các Tỷ-kheo, đối với Tỷ-kheo những lậu hoặc nào phải do tri kiến được đoạn trừ đã được tri kiến đoạn trừ, những lậu hoặc nào phải do phòng hộ được đoạn trừ đã được phòng hộ đoạn trừ... Tỷ-kheo ấy được gọi là đã sống phòng hộ với sự phòng hộ tất cả lậu hoặc, đã đoạn diệt khát ái, đã thoát ly kiết sử, đã chánh quán kiêu mạn, đã diệt tận khổ đau.”`, ref: "Trung Bộ 2 – Kinh Tất Cả Lậu Hoặc", url: "https://loicuaducphat.org/mn/mn2.html#content" },

{ text: `Ở đây, này chư Hiền, tham là ác pháp, và sân cũng là ác pháp, có một con đường Trung đạo diệt trừ tham và diệt trừ sân, khiến (tịnh) nhãn sanh, khiến (chân) trí sanh, hướng đến tịch tịnh, thắng trí, giác ngộ, Niết-bàn. Và này chư Hiền con đường Trung đạo ấy là gì- (con đường) khiến (tịnh) nhãn sanh, khiến (chân) trí sanh, hướng đến tịch tịnh, thắng trí, giác ngộ, Niết-bàn? Ðó là con đường Thánh tám ngành, tức là: Chánh tri kiến, Chánh tư duy, Chánh ngữ, Chánh nghiệp, Chánh mạng, Chánh tinh tấn, Chánh niệm, Chánh định. Này chư Hiền, đó là con đường Trung đạo, khiến (tịnh) nhãn sanh, khiến (chân) trí sanh, hướng đến tịch tịnh, thắng trí, giác ngộ, Niết-bàn.`, ref: "Trung Bộ 3 – Kinh Thừa Tự Pháp", url: "https://loicuaducphat.org/mn/mn3.html#content" },

{ text: `Ở đây, này Hiền giả, hạng người có cấu uế, và như thật tuệ tri: “Nội thân ta có cấu uế”. Với người này, có thể chờ đợi như sau: “Người này sẽ khởi lên ước muốn, sẽ cố gắng, sẽ tinh tấn để diệt trừ cấu uế ấy. Người này sẽ từ trần, trong khi không còn tham, không còn sân, không còn si, trong khi không còn cấu uế, trong khi tâm không còn ô nhiễm”. Này Hiền giả, giống như cái bát bằng đồng, mang từ chợ về hay mang từ nhà thợ rèn về, phủ đầy bụi bặm, và người chủ cái bát ấy dùng đến, lau chùi và không quăng cái bát ấy vào chỗ đầy bụi bặm. Này Hiền giả, như vậy cái bát ấy, sau một thời gian được thanh tịnh hơn, được sạch sẽ hơn.`, ref: "Trung Bộ 5 – Kinh Không Uế Nhiễm", url: "https://loicuaducphat.org/mn/mn5.html#content" },


{ text: `Này Hiền giả, như vậy hạng người có cấu uế và như thật tuệ tri: “Nội thân ta có cấu uế”. Với hạng người này, có thể chờ đợi như sau: “Người này sẽ khởi lên ước muốn, sẽ cố gắng, sẽ tinh tấn, để diệt trừ cấu uế ấy. Người này sẽ từ trần, trong khi không còn tham, không còn sân, không còn si, trong khi không còn cấu uế, trong khi tâm không còn ô nhiễm”.`, ref: "Trung Bộ 5 – Kinh Không Uế Nhiễm", url: "https://loicuaducphat.org/mn/mn5.html#content" },

{ text: `- Này Hiền giả, như vậy hạng người không có cấu uế, và như thật tuệ tri: “Nội thân ta không có cấu uế”. Với người này có thể chờ đợi như sau: “Người này sẽ không tư niệm tịnh tướng. Do không tư niệm tịnh tướng, tham sẽ không làm ô nhiễm tâm người này. Người này sẽ từ trần, không có tham, không có sân, không có si, không còn cấu uế, tâm không còn ô nhiễm”.`, ref: "Trung Bộ 5 – Kinh Không Uế Nhiễm", url: "https://loicuaducphat.org/mn/mn5.html#content" },

{ text: `Ở đây, này Hiền giả, hạng người không có cấu uế nhưng không như thật tuệ tri: “Nội thân ta không có cấu uế”. Với người này, có thể chờ đợi như sau: “Người này sẽ tư niệm tịnh tướng. Do tư niệm tịnh tướng, tham sẽ làm ô nhiễm tâm của người này. Người này sẽ từ trần, trong khi còn có tham, còn có sân, còn có si, trong khi còn cấu uế, trong khi tâm còn ô nhiễm”. Này Hiền giả, giống như một cái bát bằng đồng, mang từ chợ về hay mang từ nhà thợ rèn về, thanh tịnh và sạch sẽ. Và người chủ cái bát ấy không dùng đến, không lau chùi và quăng cái bát ấy vào chỗ đầy bụi bặm. Này Hiền giả, như vậy cái bát ấy, sau một thời gian, càng ô nhiễm hơn, càng bụi bặm hơn.`, ref: "Trung Bộ 5 – Kinh Không Uế Nhiễm", url: "https://loicuaducphat.org/mn/mn5.html#content" },

{ text: `- Này Hiền giả, như vậy hạng người không có cấu uế nhưng không như thật tuệ tri: “Nội thân ta không có cấu uế”. Với người này có thể chờ đợi sau: “Người này sẽ tư niệm tịnh tướng. Do tư niệm tịnh tướng, tham sẽ làm ô nhiễm tâm của người này. Người này sẽ từ trần trong khi còn có tham, còn có sân, còn có si, trong khi còn cấu uế, trong khi tâm còn ô nhiễm”.`, ref: "Trung Bộ 5 – Kinh Không Uế Nhiễm", url: "https://loicuaducphat.org/mn/mn5.html#content" },

{ text: `- Này Hiền giả, cấu uế gọi là cấu uế, danh từ gì là đồng nghĩa cái gọi là cấu uế?<br>- Này Hiền giả, các ác bất thiện pháp, cảnh giới của dục là đồng nghĩa cái gọi là cấu uế.`, ref: "Trung Bộ 5 – Kinh Không Uế Nhiễm", url: "https://loicuaducphat.org/mn/mn5.html#content" },

{ text: `Này các Tỷ-kheo, như một tấm vải cấu uế, nhiễm bụi, một người thợ nhuộm nhúng tấm vải ấy vào thuốc nhuộm này hay thuốc nhuộm khác- hoặc xanh, hoặc vàng, hoặc đỏ, hoặc tía- vải ấy sẽ được màu nhuộm không tốt đẹp, sẽ được màu nhuộm không sạch sẽ. Vì sao vậy? Này các Tỷ-kheo, vì tấm vải không được trong sạch. Cũng vậy, này các Tỷ-kheo, cõi ác chờ đợi một tâm cấu uế. Này các Tỷ-kheo, như một tấm vải thanh tịnh, trong sạch, một người thợ nhuộm nhúng tấm vải ấy vào thuốc nhuộm này hay thuốc nhuộm khác- hoặc xanh, hoặc vàng, hoặc đỏ, hoặc tía, vải ấy sẽ được màu nhuộm tốt đẹp, sẽ được màu nhuộm sạch sẽ. Vì sao vậy? Này các Tỷ-kheo, vì tấm vải được trong sạch. Cũng vậy, này các Tỷ-kheo, cõi thiện chờ đợi một tâm không cấu uế.`, ref: "Trung Bộ 7 – Kinh Ví Dụ Tấm Vải", url: "https://loicuaducphat.org/mn/mn7.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là những cấu uế của tâm? Tham dục, tà tham là cấu uế của tâm, sân là cấu uế của tâm, phẫn là cấu uế của tâm, hận là cấu uế của tâm, hư ngụy, não hại, tật đố, xan tham, man trá, khi cuống, ngoan cố, cấp tháo, quá mạn, kiêu, phóng dật là cấu uế của tâm.`, ref: "Trung Bộ 7 – Kinh Ví Dụ Tấm Vải", url: "https://loicuaducphat.org/mn/mn7.html#content" },

{ text: `Này các Tỷ-kheo, Tỷ-kheo nào nghĩ rằng: “Tham dục, tà tham là cấu uế của tâm” và sau khi biết vậy, vị ấy đoạn trừ tham dục, tà tham cấu uế của tâm; nghĩ rằng: “Sân là cấu uế của tâm”, và sau khi biết vậy, vị ấy đoạn trừ sân, cấu uế của tâm; phẫn … hận … hư ngụy … não hại, tật đố, xan tham, man trá, khi cuống … ngoan cố … cấp tháo … mạn … quá mạn … kiêu; nghĩ rằng: “Phóng dật là cấu uế của tâm” thì sau khi biết vậy, vị ấy đoạn trừ phóng dật, cấu uế của tâm.`, ref: "Trung Bộ 7 – Kinh Ví Dụ Tấm Vải", url: "https://loicuaducphat.org/mn/mn7.html#content" },

{ text: `Này các Tỷ-kheo, như một tấm vải cấu uế, nhiễm bụi, nếu bỏ trong nước sạch, trở thành thanh tịnh sạch sẽ, như bỏ vào lò lửa trở thành thanh tịnh sạch sẽ. Cũng vậy, này các Tỷ-kheo, một Tỷ-kheo, giới như vậy, pháp như vậy, tuệ như vậy- nếu có ăn đồ khất thực với gạo thơm, hạt đen được vất đi, với các món canh, với các món ăn khác, cũng không vì vậy trở thành một chướng ngại cho vị ấy.`, ref: "Trung Bộ 7 – Kinh Ví Dụ Tấm Vải", url: "https://loicuaducphat.org/mn/mn7.html#content" },

{ text: `Này Cunda, ví như các bất thiện pháp, tất cả đều hướng hạ, còn các thiện pháp, tất cả đều hướng thượng. Cũng vậy, này Cunda: Con người không làm hại, hướng thượng đối với người làm hại, con người từ bỏ sát sanh, hướng thượng đối với người sát sanh. Con người từ bỏ lấy của không cho, hướng thượng đối với người lấy của không cho. Con người không nhiễm thế tục, không cố chấp tư kiến, tánh dễ hành xả, hướng thượng đối với người nhiễm thế tục, cố chấp tư kiến, tánh khó hành xả.`, ref: "Trung Bộ 8 – Kinh Ðoạn Giảm", url: "https://loicuaducphat.org/mn/mn8.html#content" },

{ text: `Chư Hiền, thế nào là Khổ? Sanh là khổ, già là khổ, bệnh là khổ, chết là khổ, sầu bi khổ ưu não là khổ, cầu không được là khổ, tóm lại năm thủ uẩn là khổ. Chư Hiền, như vậy gọi là Khổ. Chư Hiền, thế nào là Tập khởi của khổ? Chính là ái đưa đến tái sanh, cùng khởi hỷ dục và tham hướng đến tái sanh, cùng khởi hỷ dục và tham, tìm cầu hỷ lạc chỗ này chỗ kia, tức là dục ái, hữu ái, phi hữu ái. Chư Hiền, như vậy gọi là Tập khởi của khổ.`, ref: "Trung Bộ 9 – Kinh Chánh Tri Kiến", url: "https://loicuaducphat.org/mn/mn9.html#content" },

{ text: `Chư Hiền, thế nào là Ðoạn diệt của khổ? Ðó là sự đoạn diệt, ly tham, không có dư tàn, sự quăng bỏ, sự từ bỏ, sự giải thoát, sự vô chấp khát ái ấy. Chư Hiền, thế nào là Con Ðường đưa đến đoạn diệt của khổ? Chính là Thánh Ðạo Tám Ngành đưa đến khổ diệt, tức là: Chánh Tri kiến, Chánh Tư duy, Chánh Ngữ, Chánh Nghiệp, Chánh Mạng, Chánh Tinh tấn, Chánh Niệm, Chánh Ðịnh.`, ref: "Trung Bộ 9 – Kinh Chánh Tri Kiến", url: "https://loicuaducphat.org/mn/mn9.html#content" },

{ text: `Này các Tỷ-kheo, không cần gì nửa tháng, một vị nào tu tập Bốn Niệm xứ này trong bảy ngày, vị ấy có thể chứng một trong hai quả sau đây: Một là chứng Chánh trí ngay trong hiện tại, hai là nếu còn hữu dư y, thì chứng quả Bất hoàn. Này các Tỷ-kheo, đây là con đường độc nhất đưa đến thanh tịnh cho chúng sanh, vượt khỏi sầu não, diệt trừ khổ ưu, thành tựu Chánh trí, chứng ngộ Niết-bàn. Ðó là Bốn Niệm xứ.`, ref: "Trung Bộ 10 – Kinh Niệm Xứ", url: "https://loicuaducphat.org/mn/mn10.html#content" },

{ text: `Lại nữa, này các Tỷ-kheo, do dục làm nhân, do dục làm duyên, do dục làm nguyên nhân, do chính dục làm nhân, vua tranh đoạt với vua, Sát-đế-lị tranh đoạt với Sát-đế-lị, Bà-la-môn tranh đoạt với Bà-la-môn, gia chủ tranh đoạt với gia chủ, mẹ tranh đoạt với con, con tranh đoạt với mẹ, cha tranh đoạt với con, con tranh đoạt với cha, anh em tranh đoạt với anh em, anh tranh đoạt với chị, chị tranh đoạt với anh, bạn bè tranh đoạt với bạn bè. Khi họ đã dấn mình vào tranh chấp, tranh luận, tranh đoạt; họ công phá nhau bằng tay; họ công phá nhau bằng đá; họ công phá nhau bằng gậy; họ công phá nhau bằng kiếm. Ở đây họ đi đến tử vong, đi đến sự đau khổ gần như tử vong. Này các Tỷ-kheo, như vậy là sự nguy hiểm các dục, thiết thực hiện tại, thuộc khổ uẩn, lấy dục làm nhân, lấy dục làm duyên, là nguồn gốc của dục, là nguyên nhân của dục.`, ref: "Trung Bộ 13 – Ðại Kinh Khổ Uẩn", url: "https://loicuaducphat.org/mn/mn13.html#content" },

{ text: `Lại nữa, này các Tỷ-kheo, do dục làm nhân, do dục làm duyên, do dục làm nguyên nhân, do chính dục làm nhân, họ cầm mâu và thuẫn, họ đeo cung và tên, họ công phá thành quách mới trét vôi hồ và tên được nhắm bắn nhau, đao được quăng ném nhau, kiếm được vung chém nhau. Ở đây, họ bắn đâm nhau bằng tên, họ quăng đâm nhau bằng đao, họ đổ nước phân sôi, họ đè bẹp nhau bằng đá, họ chặt đầu nhau bằng kiếm. Ở đây họ đi đến tử vong, đi đến sự đau khổ gần như tử vong. Này các Tỷ-kheo, như vậy là sự nguy hiểm các dục, thiết thực hiện tại, thuộc khổ uẩn, lấy dục làm nhân, lấy dục làm duyên, là nguồn gốc của dục, là nguyên nhân của dục.`, ref: "Trung Bộ 13 – Ðại Kinh Khổ Uẩn", url: "https://loicuaducphat.org/mn/mn13.html#content" },

{ text: `Lại nữa, này các Tỷ-kheo, do dục làm nhân, do dục làm duyên, do dục làm nguyên nhân, do chính dục làm nhân, họ sống làm các ác hạnh về thân, làm các ác hạnh về lời nói, làm các ác hạnh về ý. Do họ sống làm các ác hạnh về thân, làm các ác hạnh về lời nói, làm các ác hạnh về ý, khi thân hoại mạng chung, họ sanh vào cõi dữ, ác thú, đọa xứ, địa ngục. Này các Tỷ-kheo, như vậy là sự nguy hiểm các dục, đưa đến đau khổ tương lai, là khổ uẩn, do dục làm nhân, do dục làm duyên, do dục làm nhân duyên, do chính dục làm nhân.`, ref: "Trung Bộ 13 – Ðại Kinh Khổ Uẩn", url: "https://loicuaducphat.org/mn/mn13.html#content" },

{ text: `- Này các Tỷ-kheo, như vậy là sự nguy hiểm các sắc pháp. Lại nữa, này các Tỷ-kheo, người ta thấy cô gái ấy, thi thể bị quăng vào nghĩa địa, một ngày hay hai ngày hay ba ngày, thi thể ấy trương phồng lên, xanh đen lại, nát thối ra. Này các Tỷ-kheo, các Người nghĩ thế nào? Có phải sự mỹ diệu sắc đẹp xưa kia của cô gái đã biến mất và sự nguy hiểm đã hiện ra?<br>- Bạch Thế Tôn, sự thật là vậy.<br>- Này các Tỷ-kheo, như vậy là sự nguy hiểm các sắc pháp.`, ref: "Trung Bộ 13 – Ðại Kinh Khổ Uẩn", url: "https://loicuaducphat.org/mn/mn13.html#content" },

{ text: `- Này các Tỷ-kheo, như vậy là sự nguy hiểm các sắc pháp. Lại nữa, này các Tỷ-kheo, người ta thấy cô gái ấy, thi thể bị quăng vào nghĩa địa, chỉ có toàn xương trắng màu vỏ ốc … chỉ còn một đống xương lâu hơn một năm … chỉ còn các xương thối trở thành bột. Này các Tỷ-kheo, các Người nghĩ thế nào? Có phải sự mỹ diệu về sắc đẹp xưa kia của cô gái nay đã biến mất, và sự nguy hiểm hiện ra?<br>- Bạch Thế Tôn, sự thật là vậy.<br>- Này các Tỷ-kheo, như vậy là sự nguy hiểm các sắc pháp.`, ref: "Trung Bộ 13 – Ðại Kinh Khổ Uẩn", url: "https://loicuaducphat.org/mn/mn13.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là sự nguy hiểm các cảm thọ? Này các Tỷ-kheo, các cảm thọ là vô thường, khổ, biến hoại, như vậy là sự nguy hiểm các cảm thọ. Và này các Tỷ-kheo, thế nào là sự xuất ly các cảm thọ? Này các Tỷ-kheo, sự điều phục dục tham đối với các cảm thọ, sự đoạn trừ dục tham, như vậy gọi là sự xuất ly các cảm thọ.`, ref: "Trung Bộ 13 – Ðại Kinh Khổ Uẩn", url: "https://loicuaducphat.org/mn/mn13.html#content" },

{ text: `Này Mahānāma, thuở xưa, khi Ta còn là Bồ-tát, chưa chứng được Bồ-đề, chưa thành Chánh Ðẳng Chánh Giác, Ta khéo thấy với như thật chánh trí tuệ: “Các dục vui ít, khổ nhiều, não nhiều, sự nguy hiểm ở đây lại nhiều hơn”, dầu Ta có thấy với như thật chánh trí tuệ như vậy, nhưng Ta chưa chứng được hỷ lạc do ly dục, ly ác bất thiện pháp sanh hay một pháp nào khác cao thượng hơn. Và như vậy Ta biết rằng, Ta chưa khỏi bị các dục chi phối. Và này Mahānāma, khi nào Ta khéo thấy với như thật chánh trí tuệ: “Các dục, vui ít, khổ nhiều, não nhiều, sự nguy hiểm ở đây lại nhiều hơn”, và Ta chứng được hỷ lạc do ly dục, ly ác bất thiện pháp sanh hay một pháp nào khác cao thượng hơn, như vậy Ta khỏi bị các dục chi phối.`, ref: "Trung Bộ 14 – Tiểu Kinh Khổ Uẩn", url: "https://loicuaducphat.org/mn/mn14.html#content" },

{ text: `Và này Mahānāma, thế nào là vị ngọt các dục? Này Mahānāma, có năm pháp tăng trưởng các dục này: Các sắc pháp do mắt nhận thức, khả ái, khả lạc, khả ý, khả hỷ, tương ưng với dục, hấp dẫn; các tiếng do tai nhận thức…; các hương do mũi nhận thức…; các vị do lưỡi nhận thức…; các xúc do thân nhận thức, khả ái, khả lạc, khả ý, khả hỷ, tương ưng với dục, hấp dẫn. Này Mahānāma, có năm pháp tăng trưởng các dục như vậy. Này Mahānāma, y cứ vào năm pháp tăng trưởng các dục này, có lạc và hỷ khởi lên, như vậy là vị ngọt các dục.`, ref: "Trung Bộ 14 – Tiểu Kinh Khổ Uẩn", url: "https://loicuaducphat.org/mn/mn14.html#content" },

{ text: `Chư Hiền, nếu trong khi quán sát, Tỷ-kheo thấy rõ rằng tất cả các ác, bất thiện pháp chưa được đoạn trừ trong nội tâm, thì chư Hiền, Tỷ-kheo ấy cần phải tinh tấn đoạn trừ các ác, bất thiện pháp ấy. Chư Hiền, nếu Tỷ-kheo trong khi quán sát thấy rõ rằng tất cả các ác, bất thiện pháp đã được đoạn trừ trong nội tâm, thì chư Hiền, Tỷ-kheo ấy phải sống với tâm niệm hoan hỷ, ngày đêm tu học thiện pháp.`, ref: "Trung Bộ 15 – Kinh Tư Lượng", url: "https://loicuaducphat.org/mn/mn15.html#content" },

{ text: `Thế nào là năm tâm triền phược chưa được đoạn tận? Chư Tỷ-kheo, ở đây, Tỷ-kheo, đối với những dục, không phải không tham ái, không phải không dục cầu, không phải không ái luyến, không phải không khao khát, không phải không nhiệt tình, không phải không khát ái. Chư Tỷ-kheo, vị Tỷ-kheo nào đối với những dục, không phải không tham ái … không phải không khát ái, tâm của vị ấy không hướng về nỗ lực, chuyên cần, kiên trì, tinh tấn. Nếu tâm của ai không hướng về nỗ lực, chuyên cần, kiên trì, tinh tấn, như vậy là tâm triền phược thứ nhất chưa được đoạn tận.`, ref: "Trung Bộ 16 – Kinh Tâm Hoang Vu", url: "https://loicuaducphat.org/mn/mn16.html#content" },

{ text: `Chư Tỷ-kheo, rồi Ta sống không phóng dật, nhiệt tâm, tinh cần. Khi dục tầm khởi lên, Ta tuệ tri: “Dục tầm này khởi lên nơi Ta, và dục tầm này đưa đến tự hại, đưa đến hại người, đưa đến hại cả hai, diệt trí tuệ, dự phần vào phiền não, không đưa đến Niết-bàn”. Chư Tỷ-kheo, khi Ta suy tư: “Dục tầm này đưa đến tự hại”, dục tầm được biến mất, Chư Tỷ-kheo, khi Ta suy tư: “Dục tầm đưa đến hại người”, dục tầm được biến mất. Chư Tỷ-kheo, khi Ta suy tư: “Dục tầm đưa đến hại cả hai”, dục tầm được biến mất. Chư Tỷ-kheo, khi Ta suy tư: “Dục tầm diệt trí tuệ, dự phần vào phiền não, không đưa đến Niết-bàn”, dục tầm được biến mất. Chư Tỷ-kheo, như vậy Ta tiếp tục trừ bỏ, xả ly và đoạn tận dục tầm.`, ref: "Trung Bộ 19 – Kinh Song Tầm", url: "https://loicuaducphat.org/mn/mn19.html#content" },


{ text: `Chư Tỷ-kheo, Tỷ-kheo suy tư, quán sát nhiều vấn đề gì, thời tâm sanh khuynh hướng đối với vấn đề ấy. Chư Tỷ-kheo, nếu Tỷ-kheo suy tư, quán sát nhiều về dục tầm, vị ấy từ bỏ ly dục tầm. Khi tâm đã nặng về dục tầm, thời tâm vị ấy có khuynh hướng về dục tầm. Chư Tỷ-kheo, nếu Tỷ-kheo suy tư quán sát nhiều về sân tầm … (như trên) … về hại tầm, vị ấy từ bỏ vô hại tầm. Khi tâm đã đặt nặng về hại tầm thời tâm vị ấy có khuynh hướng về hại tầm.`, ref: "Trung Bộ 19 – Kinh Song Tầm", url: "https://loicuaducphat.org/mn/mn19.html#content" },

{ text: `Chư Tỷ-kheo, ví như vào cuối tháng mùa mưa, về mùa thu, khi lúa đã trổ hạt, một người mục đồng chăn giữ bò, cầm roi đánh các con bò bên này, đánh bên kia, chế ngự chúng, ngăn chặn chúng. Vì sao vậy? Chư Tỷ-kheo, vì người mục đồng thấy do nhân duyên này, đưa đến sự chết, sự tù tội, sự đánh đập hay sự trách móc. Chư Tỷ-kheo, cũng vậy, Ta đã thấy sự nguy hại, sự hạ liệt, sự uế nhiễm của các pháp bất thiện, và thấy sự viễn ly, sự lợi ích, sự thanh tịnh của các thiện pháp.`, ref: "Trung Bộ 19 – Kinh Song Tầm", url: "https://loicuaducphat.org/mn/mn19.html#content" },

{ text: `Chư Tỷ-kheo, trong khi Ta sống không phóng dật, nhiệt tâm, tinh cần như vậy, khi ly dục tầm khởi lên, Ta tuệ tri như vầy: “Ly dục tầm này khởi lên nơi Ta và ly dục tầm này không đưa đến tự hại, không đưa đến hại người, không đưa đến hại cả hai, tăng trưởng trí tuệ, không dự phần vào phiền não, đưa đến Niết-bàn”. Chư Tỷ-kheo, nếu ban đêm Ta suy tư, quán sát (về ly dục tầm) không phải từ nhân duyên ấy Ta thấy sợ hãi. Chư Tỷ-kheo, nếu ban ngày Ta suy tư, quán sát (về ly dục tầm), không phải từ nhân duyên ấy Ta thấy sợ hãi. Chư Tỷ-kheo, nếu ban đêm, ban ngày, Ta suy tư, quán sát (về ly dục tầm), không phải từ nhân duyên ấy Ta thấy sợ hãi. Và Ta suy tư, quán sát quá lâu, thân Ta có thể mệt mỏi; khi thân mệt mỏi thì tâm bị dao động; khi tâm bị dao động thì tâm rất khó được định tĩnh. Chư Tỷ-kheo, rồi tự nội thân Ta trấn an tâm, trấn tịnh tâm, khiến được nhất tâm, khiến thành định tĩnh. Vì sao vậy? Vì để tâm Ta khỏi dao động.`, ref: "Trung Bộ 19 – Kinh Song Tầm", url: "https://loicuaducphat.org/mn/mn19.html#content" },

{ text: `Chư Tỷ-kheo, giống như trong khu rừng rậm rạp có một hồ nước lớn thâm sâu, và một đoàn nai lớn sống gần một bên. Có một người đến, không muốn chúng được lợi ích, không muốn chúng được hạnh phúc, không muốn chúng được an ổn khỏi các ách nạn. Nếu có con đường nào được yên ổn, được an toàn, đưa đến hoan hỷ, người ấy sẽ chặn đóng con đường này lại, sẽ mở con đường nguy hiểm, sẽ đặt con mồi đực, sẽ đặt con mồi cái. Chư Tỷ-kheo, như vậy, sau một thời gian đoàn nai lớn ấy gặp ách nạn và hao mòn dần. Chư Tỷ-kheo, có một người đến, muốn đoàn nai ấy được lợi ích, muốn chúng được hạnh phúc, muốn chúng được an ổn khỏi các ách nạn. Nếu có con đường nào được yên ổn, được an toàn, người ấy sẽ mở con đường này, sẽ đóng con đường nguy hiểm lại, sẽ đem con mồi đực đi, sẽ hủy bỏ con mồi cái. Chư Tỷ-kheo, như vậy đoàn nai lớn ấy sau một thời gian sẽ được tăng trưởng, hưng thịnh, thành mãn.`, ref: "Trung Bộ 19 – Kinh Song Tầm", url: "https://loicuaducphat.org/mn/mn19.html#content" },

{ text: `Chư Tỷ-kheo, hồ nước lớn, thâm sâu chỉ cho các dục. Chư Tỷ-kheo, đoàn nai lớn chỉ cho các loài hữu tình. Chư Tỷ-kheo, con người không muốn chúng được lợi ích, không muốn chúng được hạnh phúc, không muốn chúng được an ổn khỏi các ách nạn chỉ cho ác ma. Chư Tỷ-kheo, con đường nguy hiểm chỉ cho con đường tà đạo có tám ngành, tức là tà tri kiến, tà tư duy, tà ngữ, tà nghiệp, tà mạng, tà tinh tấn, tà niệm, tà định. Chư Tỷ-kheo, con mồi đực chỉ cho hỷ và tham. Chư Tỷ-kheo, con mồi cái chỉ cho vô minh. Chư Tỷ-kheo, còn người muốn chúng được lợi ích, muốn chúng được hạnh phúc, muốn chúng được an ổn khỏi các ách nạn chỉ cho Như Lai, bậc A-la-hán, Chánh Ðẳng Giác. Con đường yên ổn, an toàn, đưa đến hoan hỷ chỉ cho con đường Thánh đạo Tám ngành, tức là Chánh tri kiến, Chánh tư duy, Chánh ngữ, Chánh nghiệp, Chánh mạng, Chánh tinh tấn, Chánh niệm, Chánh định.`, ref: "Trung Bộ 19 – Kinh Song Tầm", url: "https://loicuaducphat.org/mn/mn19.html#content" },

{ text: `Chư Tỷ-kheo, như vậy Ta mở con đường yên ổn, an toàn, đưa đến hoan hỷ, Ta đóng con đường nguy hiểm, Ta mang đi con mồi đực, Ta hủy bỏ con mồi cái. Chư Tỷ-kheo, những gì vị Ðạo Sư cần phải làm cho các đệ tử vì lòng thương tưởng họ, những điều ấy Ta đã làm, vì lòng thương tưởng các Người. Chư Tỷ-kheo, đây là các gốc cây, đây là các chỗ trống. Hãy Thiền định, chớ có phóng dật, chớ có hối tiếc về sau. Ðó là lời giáo huấn của Ta.`, ref: "Trung Bộ 19 – Kinh Song Tầm", url: "https://loicuaducphat.org/mn/mn19.html#content" },

{ text: `Chư Tỷ-kheo, ví như một người thợ mộc thiện xảo hay đệ tử một người thợ mộc, dùng một cái nêm nhỏ đánh bật ra, đánh tung ra, đánh văng ra một cái nêm khác; chư Tỷ-kheo, cũng vậy, khi một Tỷ-kheo y cứ một tướng nào, tác ý một tướng nào, các ác bất thiện tầm liên hệ đến dục, liên hệ đến sân, liên hệ đến si sanh khởi, thời này chư Tỷ-kheo, Tỷ-kheo ấy cần phải tác ý một tướng khác liên hệ đến thiện, không phải tướng kia. Nhờ tác ý một tướng khác liên hệ đến thiện, khác với tướng kia, các ác bất thiện tầm liên hệ đến dục, liên hệ đến sân, liên hệ đến si được trừ diệt, đi đến diệt vong. Chính nhờ diệt trừ chúng, nội tâm được an trú, an tịnh, nhất tâm, định tĩnh.`, ref: "Trung Bộ 20 – Kinh An Trú Tầm", url: "https://loicuaducphat.org/mn/mn20.html#content" },

{ text: `Chư Tỷ-kheo, nếu Tỷ-kheo ấy khi tác ý một tướng khác với tướng kia, liên hệ đến thiện, các ác bất thiện tầm liên hệ đến dục, liên hệ đến sân, liên hệ đến si vẫn khởi lên, thời này chư Tỷ-kheo, Tỷ-kheo ấy cần phải quán sát các nguy hiểm của những tầm ấy: “Ðây là những tầm bất thiện, đây là những tầm có tội, đây là những tầm có khổ báo”. Nhờ quán sát các nguy hiểm của những tầm ấy, các bất thiện tầm liên hệ đến dục, liên hệ đến sân, liên hệ đến si được trừ diệt, đi đến diệt vong. Chính nhờ diệt trừ chúng, nội tâm được an trú, an tịnh, nhất tâm, định tĩnh.`, ref: "Trung Bộ 20 – Kinh An Trú Tầm", url: "https://loicuaducphat.org/mn/mn20.html#content" },

{ text: `Chư Tỷ-kheo, ví như một người đàn bà hay người đàn ông trẻ tuổi, trong tuổi thanh xuân, tánh ưa trang sức nếu một xác rắn, hay xác chó, hay xác người được quàng vào cổ, người ấy phải lo âu, xấu hổ, ghê tởm. Chư Tỷ-kheo, cũng vậy, nếu Tỷ-kheo ấy quán sát các nguy hiểm của những tầm ấy: “Ðây là những tầm bất thiện, đây là những tầm có tội, đây là những tầm có khổ báo”. Nhờ quán sát các nguy hiểm của những tầm ấy, các bất thiện tầm liên hệ đến dục, liên hệ đến sân, liên hệ đến si được trừ diệt, đi đến diệt vong. Chính nhờ diệt trừ chúng, nội tâm được an trú, an tịnh, nhất tâm, định tĩnh.`, ref: "Trung Bộ 20 – Kinh An Trú Tầm", url: "https://loicuaducphat.org/mn/mn20.html#content" },

{ text: `Chư Tỷ-kheo, nếu Tỷ-kheo ấy trong khi quán sát các nguy hiểm của những tầm ấy, các ác bất thiện tầm liên hệ đến dục, liên hệ đến sân, liên hệ đến si vẫn khởi lên, thời này chư Tỷ-kheo, Tỷ-kheo ấy cần phải không ức niệm, không tác ý những tầm ấy. Nhờ không ức niệm, không tác ý các tầm ấy, các ác bất thiện tầm liên hệ đến dục, liên hệ đến sân, liên hệ đến si được trừ diệt, đi đến diệt vong. Chính nhờ diệt trừ chúng, nội tâm được an trú, an tịnh, nhất tâm, định tĩnh. Chư Tỷ-kheo, ví như một người có mắt, không muốn thấy các sắc pháp nằm trong tầm mắt của mình, người ấy nhắm mắt lại hay ngó qua một bên. Chư Tỷ-kheo, cũng vậy, nếu Tỷ-kheo ấy, trong khi không ức niệm, không tác ý … được an trú, an tịnh, nhất tâm, định tĩnh.`, ref: "Trung Bộ 20 – Kinh An Trú Tầm", url: "https://loicuaducphat.org/mn/mn20.html#content" },

{ text: `Chư Tỷ-kheo, nếu Tỷ-kheo, trong khi y cứ tướng nào, tác ý tướng nào, các ác bất thiện tầm liên hệ đến dục, liên hệ đến sân, liên hệ đến si sanh khởi. Tỷ-kheo ấy tác ý một tướng khác, liên hệ đến thiện, khác với tướng kia, các ác, bất thiện tầm liên hệ đến dục, liên hệ đến sân, liên hệ đến si được diệt trừ, đi đến diệt vong. Chính nhờ diệt trừ chúng, nội tâm được an trú, an tịnh, nhất tâm, định tĩnh.`, ref: "Trung Bộ 20 – Kinh An Trú Tầm", url: "https://loicuaducphat.org/mn/mn20.html#content" },

{ text: `Do vậy, này các Tỷ-kheo, hãy từ bỏ bất thiện, hãy nỗ lực đối với các thiện pháp, như vậy các Ngươi mới thành tựu sự trưởng thành, hưng thịnh, lớn mạnh trong Pháp và Luật này. Chư Tỷ-kheo, cũng như gần một thôn làng hay thị trấn nhỏ, có ngôi rừng cây tala lớn, ngôi rừng bị các cây leo y lan bao phủ. Có một người đến khu rừng này, muốn lợi ích cho ngôi rừng, muốn hạnh phúc, muốn an ổn khỏi các ách phược cho ngôi rừng. Người ấy chặt đứt các nhành cây cong thiếu hẳn sinh lực, vất chúng ra khỏi ngôi rừng, dọn dẹp trong rừng sạch sẽ. Người ấy săn sóc kỹ lưỡng các nhánh cây tala thẳng thắn, khéo mọc. Chư Tỷ-kheo, sau một thời gian, ngôi rừng như vậy được trưởng thành, hưng thịnh, lớn mạnh. Cũng vậy, này các Tỷ-kheo, các Ngươi hãy từ bỏ bất thiện, hãy nỗ lực đối với các thiện pháp, như vậy các Ngươi mới thành tựu sự trưởng thành, hưng thịnh, lớn mạnh trong Pháp và Luật này.`, ref: "Trung Bộ 21 – Kinh Ví Dụ Cái Cưa", url: "https://loicuaducphat.org/mn/mn21.html#content" },

{ text: `Thật sự, này các Tỷ-kheo, sự kiện này không xảy ra, người ta có thể thọ dụng các dục ngoài các dục, ngoài các dục tưởng, ngoài các dục tầm.`, ref: "Trung Bộ 22 – Kinh Ví Dụ Con Rắn", url: "https://loicuaducphat.org/mn/mn22.html#content" },
{ text: `Này các Tỷ-kheo, có hai loại tầm cầu này: Thánh cầu và phi Thánh cầu. Chư Tỷ-kheo, và thế nào là phi Thánh cầu? Ở đây, này các Tỷ-kheo, có người tự mình bị sanh lại tầm cầu cái bị sanh, tự mình bị già lại tìm cầu cái bị già, tự mình bị bệnh … tự mình bị chết … tự mình bị sầu … tự mình bị ô nhiễm lại tầm cầu cái bị ô nhiễm. Này các Tỷ-kheo, cái gì theo các Người gọi là bị sanh? Này các Tỷ-kheo, vợ con là bị sanh; đầy tớ nam, đầy tớ nữ là bị sanh; dê và cừu là bị sanh; gà và heo là bị sanh; voi, bò, ngựa đực, ngựa cái là bị sanh; vàng và bạc là bị sanh. Này các Tỷ-kheo, những chấp thủ ấy bị sanh, và người ấy lại nắm giữ, tham đắm, mê say chúng, tự mình bị sanh lại tầm cầu cái bị sanh.`, ref: "Trung Bộ 26 – Kinh Thánh Cầu", url: "https://loicuaducphat.org/mn/mn26.html#content" },
{ text: `Và này các Tỷ-kheo, thế nào là Thánh cầu? Ở đây, này các Tỷ-kheo, có người tự mình bị sanh, sau khi biết rõ sự nguy hại của bị sanh, tìm cầu cái vô sanh, vô thượng an ổn khỏi các khổ ách, Niết-bàn; tự mình bị già, sau khi biết rõ sự nguy hại của bị già, tìm cầu cái không già, vô thượng an ổn khỏi các khổ ách, Niết-bàn; tự mình bị bệnh … cái không bệnh … tự mình bị chết … cái bất tử … tự mình bị sầu … cái không sầu … tự mình bị ô nhiễm, sau khi biết rõ sự nguy hại của ô nhiễm, tìm cầu cái không ô nhiễm, vô thượng an ổn khỏi các khổ ách, Niết-bàn. Này các Tỷ-kheo, như vậy, gọi là Thánh cầu.`, ref: "Trung Bộ 26 – Kinh Thánh Cầu", url: "https://loicuaducphat.org/mn/mn26.html#content" },

{ text: `Này các Tỷ-kheo, Ta cũng vậy, trước khi Giác Ngộ, khi chưa chứng Chánh Ðẳng Giác, khi còn là Bồ-tát, tự mình bị sanh lại tìm cầu cái bị sanh, tự mình bị già, lại tìm cầu cái bị già, tự mình bị bệnh … tự mình bị chết … tự mình bị sầu” … tự mình bị ô nhiễm lại tìm cầu cái bị ô nhiễm. Này các Tỷ-kheo, rồi Ta suy nghĩ như sau: “Tại sao Ta, tự mình bị sanh lại tìm cầu cái bị sanh, tự mình bị già … (như trên) … tự mình bi ô nhiễm lại tìm cầu cái bị ô nhiễm? Vậy Ta, tự mình bị sanh, sau khi biết rõ sự nguy hại của bị sanh, hãy tìm cầu cái không sanh, vô thượng an ổn khỏi các khổ ách, Niết-bàn; tự mình bị già … cái không già … tự mình bị bệnh … cái không bệnh … tự mình bị chết … cái bất tử … tự mình bị sầu … cái không sầu … tự mình bi ô nhiễm, sau khi biết rõ sự nguy hại của cái bị nhiễm, hãy tìm cầu cái không ô nhiễm, vô thượng an ổn khỏi các khổ ách, Niết-bàn.`, ref: "Trung Bộ 26 – Kinh Thánh Cầu", url: "https://loicuaducphat.org/mn/mn26.html#content" },

{ text: `Này các Tỷ-kheo, rồi Ta suy nghĩ như sau: “Pháp này do Ta chứng được, thật là sâu kín, khó thấy, khó chứng, tịch tịnh, cao thượng, siêu lý luận, vi diệu, chỉ người trí mới hiểu thấu. Còn quần chúng này thì ưa ái dục, khoái ái dục, ham thích ái dục. Ðối với quần chúng ưa ái dục, khoái ái dục, ham thích ái dục, thật khó mà thấy được định lý Idapaccàyata Paticcasamuppada (Y Tánh Duyên Khởi Pháp); sự kiện này thật khó thấy; tức là sự tịnh chỉ tất cả hành, sự trừ bỏ tất cả sanh y, ái diệt, ly tham, đoạn diệt, Niết-bàn.`, ref: "Trung Bộ 26 – Kinh Thánh Cầu", url: "https://loicuaducphat.org/mn/mn26.html#content" },

{ text: `Này các Tỷ-kheo, sau khi biết được lời Phạm thiên yêu cầu, vì lòng từ bi đối với chúng sanh, với Phật nhãn, Ta nhìn quanh thế giới. Này các Tỷ-kheo, với Phật nhãn, Ta thấy có hạng chúng sanh ít nhiễm bụi đời, nhiều nhiễm bụi đời, có hạng lợi căn, độn căn, có hạng thiện tánh, ác tánh, có hạng dễ dạy, khó dạy, và một số ít thấy sự nguy hiểm phải tái sanh thế giới khác và sự nguy hiểm làm những hành động lỗi lầm. Như trong hồ sen xanh, hồ sen hồng hay hồ sen trắng có một số hoa sen xanh, sen hồng, hay sen trắng sanh ra dưới nước, lớn lên dưới nước, không vượt lên khỏi mặt nước, được nuôi dưỡng dưới nước. Có một hoa sen xanh, sen hồng hay sen trắng sanh ra dưới nước, lớn lên dưới nước, sống vươn lên tới mặt nước. Có một số hoa sen xanh, sen hồng hay sen trắng sanh ra dưới nước, lớn lên dưới nước, vươn lên khỏi mặt nước, không bị nước đẫm ướt.`, ref: "Trung Bộ 26 – Kinh Thánh Cầu", url: "https://loicuaducphat.org/mn/mn26.html#content" },

{ text: `Này các Tỷ-kheo, có năm dục trưởng dưỡng. Thế nào là năm? Các sắc do mắt nhận thức, sắc này khả ái, khả hỷ, khả lạc, khả ý, kích thích lòng dục, hấp dẫn. Các tiếng do tai nhận thức … (như trên) … các hương do mũi nhận thức … các vị do lưỡi nhận thức … các xúc do thân cảm xúc là khả ái, khả hỷ, khả lạc, khả ý, kích thích lòng dục, hấp dẫn. Này các Tỷ-kheo, như vậy, là năm dục trưởng dưỡng.`, ref: "Trung Bộ 26 – Kinh Thánh Cầu", url: "https://loicuaducphat.org/mn/mn26.html#content" },

{ text: `Này các Tỷ-kheo, những Sa-môn hay Bà-la-môn nào bị trói buộc, bị tham đắm, bị mê say bởi năm dục trưởng dưỡng này, không thấy sự nguy hại của chúng, không biết rõ sự xuất ly khỏi chúng, mà thọ dụng chúng, những vị ấy cần phải được hiểu là: “Các Người đã rơi vào bất hạnh, đã rơi vào tai họa, đã bị Ác ma sử dụng như ý muốn”. Này các Tỷ-kheo, như một con nai sống trong rừng bị sập bẫy nằm xuống, con nai ấy cần phải được hiểu là: “Nó đã rơi vào bất hạnh, đã rơi vào tai họa, đã bị thợ săn sử dụng như ý muốn. Khi người thợ săn đến, con nai không thể bỏ đi như ý muốn. Này các Tỷ-kheo, cũng vậy, những vị Sa-môn hay Bà-la-môn nào bị trói buộc … (như trên) … đã bị Ác ma sử dụng như ý muốn.`, ref: "Trung Bộ 26 – Kinh Thánh Cầu", url: "https://loicuaducphat.org/mn/mn26.html#content" },

{ text: `Này các Tỷ-kheo, những Sa-môn hay Bà-la-môn nào không bị trói buộc, không bị tham đắm, không bị mê say bởi năm dục trưởng dưỡng này, thấy sự nguy hại của chúng, biết rõ sự xuất ly khỏi chúng, và thọ dụng chúng, những vị ấy cần phải được hiểu là: “Các Người không rơi vào bất hạnh, không rơi vào tai họa, không bị Ác ma sử dụng như ý muốn”. Này các Tỷ-kheo, như một con nai sống trong rừng, không bị sập bẫy phải nằm xuống, con nai ấy cần phải được hiểu là: “Nó không rơi vào bất hạnh, nó không rơi vào tai họa, nó không bị người thợ săn sử dụng như ý muốn”. Khi người thợ săn đến, con nai có thể bỏ đi như ý muốn. Này các Tỷ-kheo, cũng vậy, những Sa-môn hay Bà-la-môn nào không bị trói buộc … không bị Ác ma sử dụng như ý muốn.`, ref: "Trung Bộ 26 – Kinh Thánh Cầu", url: "https://loicuaducphat.org/mn/mn26.html#content" },

{ text: `Chư Tỷ-kheo, ví như con nai sống trong rừng, đi qua đi lại trong rừng, an tâm nó đi, an tâm nó đứng, an tâm nó ngồi, an tâm nó nằm. Tại sao vậy? Này các Tỷ-kheo, vì nó vượt khỏi tầm tay của người thợ săn. Cũng vậy, này các Tỷ-kheo, một Tỷ-kheo ly dục, ly ác bất thiện pháp chứng và trú Thiền thứ nhất, một trạng thái hỷ lạc, do ly dục sanh, có tầm có tứ. Này các Tỷ-kheo, Tỷ-kheo ấy được gọi là: một vị đã làm Ác Ma mù mắt, đã diệt trừ mọi vết tích, đã vượt khỏi tầm mắt Ác ma.`, ref: "Trung Bộ 26 – Kinh Thánh Cầu", url: "https://loicuaducphat.org/mn/mn26.html#content" },

{ text: `Sau khi thấy bằng trí tuệ, các lậu hoặc được đoạn trừ. Này các Tỷ-kheo, Tỷ-kheo ấy được gọi là một vị đã làm Ác ma mù mắt, đã diệt trừ mọi vết tích, đã vượt khỏi tầm mắt Ác ma. Vị ấy đã vượt khỏi mọi triền phược ở đời. An tâm vị ấy đi, an tâm vị ấy đứng, an tâm vị ấy ngồi, an tâm vị ấy nằm. Vì sao vậy? Này các Tỷ-kheo, vì vị ấy vượt khỏi tầm tay của Ác ma.`, ref: "Trung Bộ 26 – Kinh Thánh Cầu", url: "https://loicuaducphat.org/mn/mn26.html#content" },

{ text: `Này các Tỷ-kheo, thế nào là các công việc đáng phải làm hơn nữa? “Chúng ta phải hộ trì các căn. Khi mắt thấy sắc, không nắm giữ tướng chung, không nắm giữ tướng riêng. Những nguyên nhân gì khiến con mắt không được chế ngự, khiến tham ái, ưu bi, các ác, bất thiện pháp khởi lên, chúng ta sẽ tự chế ngự nguyên nhân ấy, hộ trì con mắt, thực hành sự hộ trì con mắt. Khi tai nghe tiếng … mũi ngửi hương … lưỡi nếm vị … thân cảm xúc … ý nhận thức các pháp, không nắm giữ tướng chung, không nắm giữ tướng riêng. Những nguyên nhân gì khiến ý căn không được chế ngự, khiến tham ái, ưu, bi, các ác, bất thiện pháp khởi lên, chúng ta sẽ tự chế ngự nguyên nhân ấy, hộ trì ý căn, thực hành sự hộ trì ý căn”.`, ref: "Trung Bộ 39 – Ðại Kinh Xóm Ngựa", url: "https://loicuaducphat.org/mn/mn39.html#content" },

{ text: `Này các Tỷ-kheo, như thế nào, Tỷ-kheo là Sa-môn? Vị này đã làm cho dừng lại các ác, các pháp bất thiện, những pháp này ô nhiễm, đưa đến tái sanh, đáng sợ hãi, đem lại khổ quả, đưa đến sanh, già, chết trong tương lai. Như vậy, này các Tỷ-kheo, Tỷ-kheo là Sa-môn.`, ref: "Trung Bộ 39 – Ðại Kinh Xóm Ngựa", url: "https://loicuaducphat.org/mn/mn39.html#content" },

{ text: `Và này các Tỷ-kheo, như thế nào là Tỷ-kheo đã tắm sạch sẽ? Vị này đã tắm gội sạch sẽ các ác, các pháp bất thiện, những pháp này ô nhiễm, đưa đến tái sanh, đáng sợ hãi, đem lại khổ quả, đưa đến sanh già, chết trong tương lai. Như vậy, này các Tỷ-kheo, Tỷ-kheo đã tắm sạch sẽ.`, ref: "Trung Bộ 39 – Ðại Kinh Xóm Ngựa", url: "https://loicuaducphat.org/mn/mn39.html#content" },

{ text: `Và này các Tỷ-kheo, như thế nào là Tỷ-kheo đã biết và hiểu rõ? Vị này đã biết và hiểu rõ các ác, các pháp bất thiện, những pháp này ô nhiễm, đưa đến tái sanh, đáng sợ hãi, đem lại khổ quả, đưa đến sanh già, chết trong tương lai. Như vậy, này các Tỷ-kheo, Tỷ-kheo đã biết và hiểu rõ.`, ref: "Trung Bộ 39 – Ðại Kinh Xóm Ngựa", url: "https://loicuaducphat.org/mn/mn39.html#content" },

{ text: `Và này các Tỷ-kheo, như thế nào là Tỷ-kheo có học? Vị này đã tiêu diệt các ác, các pháp bất thiện, những pháp này ô nhiễm, đưa đến tái sanh, đáng sợ hãi, đem lại khổ quả, đưa đến sanh già, chết trong tương lai. Như vậy, này các Tỷ-kheo, Tỷ-kheo có học.`, ref: "Trung Bộ 39 – Ðại Kinh Xóm Ngựa", url: "https://loicuaducphat.org/mn/mn39.html#content" },

{ text: `Và này các Tỷ-kheo, như thế nào là Tỷ-kheo được gọi là bậc Thánh? Vị này đã làm cho xa lìa các ác pháp bất thiện, những pháp này ô nhiễm, đưa đến tái sanh, đáng sợ hãi, đem lại khổ quả, đưa đến sanh già, chết trong tương lai. Như vậy, này các Tỷ-kheo, Tỷ-kheo được gọi là bậc Thánh.`, ref: "Trung Bộ 39 – Ðại Kinh Xóm Ngựa", url: "https://loicuaducphat.org/mn/mn39.html#content" },

{ text: `Và này các Tỷ-kheo, như thế nào là Tỷ-kheo được gọi là bậc A-la-hán? Vị này đã làm cho xa lìa các ác, các pháp bất thiện, những pháp này ô nhiễm, đưa đến tái sanh, đáng sợ hãi, đem lại khổ quả, đưa đến sanh già, chết trong tương lai. Như vậy, này các Tỷ-kheo, Tỷ-kheo là bậc A-la-hán.`, ref: "Trung Bộ 39 – Ðại Kinh Xóm Ngựa", url: "https://loicuaducphat.org/mn/mn39.html#content" },

{ text: `Và này Mahānāma, thế nào là vị Thánh đệ tử hộ trì các căn? Ở đây, này Mahānāma, vị Thánh đệ tử, khi mắt thấy sắc, không nắm giữ tướng chung, không nắm giữ tướng riêng. Những nguyên nhân gì vì nhãn căn không được chế ngự, khiến tham ưu, các ác, bất thiện pháp khởi lên, vị ấy tự chế ngự nguyên nhân ấy, hộ trì nhãn căn, thực hành sự hộ trì nhãn căn. Khi tai nghe tiếng … mũi ngửi hương … lưỡi nếm vị … thân cảm xúc … ý nhận thức các pháp, vị ấy không nắm giữ tướng chung, không nắm giữ tướng riêng. Những nguyên nhân gì vì ý căn không được chế ngự, khiến tham ưu, các ác, bất thiện pháp khởi lên, vị ấy chế ngự nguyên nhân ấy, hộ trì ý căn, thực hành sự hộ trì ý căn. Này Mahānāma, như vậy là vị Thánh đệ tử hộ trì các căn.`, ref: "Trung Bộ 53 – Kinh Hữu học", url: "https://loicuaducphat.org/mn/mn53.html#content" },

{ text: `Ở đây, này Mahānāma, vị Thánh đệ tử có lòng tàm, tự xấu hổ vì thân ác hạnh, khẩu ác hạnh, ý ác hạnh, tự xấu hổ vì thành tựu ác, bất thiện pháp. Vị này có lòng quý, tự sợ hãi vì thân ác hạnh, khẩu ác hạnh, ý ác hạnh, tự sợ hãi vì thành tựu ác, bất thiện pháp.`, ref: "Trung Bộ 53 – Kinh Hữu học", url: "https://loicuaducphat.org/mn/mn53.html#content" },

{ text: `Ở đây, này Mahānāma, vị Thánh đệ tử sống tinh cần tinh tấn, trừ bỏ các pháp bất thiện, thành tựu các thiện pháp, nỗ lực, kiên trì, không từ bỏ gánh nặng đối với các thiện pháp. Vị ấy có niệm, thành tựu niệm tuệ tối thắng, nhớ lại, nhớ lại nhiều lần những gì đã làm từ lâu, đã nói từ lâu. Vị ấy có trí tuệ, thành tựu trí tuệ về sanh diệt, thành tựu Thánh thể nhập đưa đến chơn chánh đoạn tận khổ đau. Này Mahānāma, như vậy vị Thánh đệ tử thành tựu diệu pháp.`, ref: "Trung Bộ 53 – Kinh Hữu học", url: "https://loicuaducphat.org/mn/mn53.html#content" },

{ text: `Này Rāhula, khi Ông muốn làm một thân nghiệp gì, hãy phản tỉnh thân nghiệp ấy như sau: “Thân nghiệp này của ta có thể đưa đến tự hại, có thể đưa đến hại người, có thể đưa đến hại cả hai; thời thân nghiệp này là bất thiện, đưa đến đau khổ, đem đến quả báo đau khổ”. Này Rāhula, nếu trong khi phản tỉnh, Ông biết: “Thân nghiệp này, ta muốn làm. Thân nghiệp này của ta có thể đưa đến tự hại, có thể đưa đến hại người, có thể đưa đến hại cả hai; thời thân nghiệp này là bất thiện, đưa đến đau khổ, đem đến quả báo đau khổ”. Một thân nghiệp như vậy, này Rāhula, Ông nhất định chớ có làm. Này Rāhula, nếu sau khi phản tỉnh, ông biết: “Thân nghiệp này ta muốn làm. Thân nghiệp này của ta không có thể đưa đến tự hại, không có thể đưa đến hại người, không có thể đưa đến hại cả hai; thời thân nghiệp này là thiện, đưa đến an lạc, đem đến quả báo an lạc”. Một thân nghiệp như vậy, này Rāhula, Ông nên làm.`, ref: "Trung Bộ 61 – Kinh Giáo Giới Rahula", url: "https://loicuaducphat.org/mn/mn61.html#content" },

{ text: `Này Rāhula, hãy tu tập sự tu tập về bất tịnh. Này Rāhula, do tu tập sự tu tập về bất tịnh, cái gì thuộc tham ái được trừ diệt. Này Rāhula, hãy tu tập sự tu tập về vô thường. Này Rāhula, do tu tập sự tu tập về vô thường, cái gì thuộc ngã mạn được trừ diệt.`, ref: "Trung Bộ 62 – Đại Kinh Giáo Giới Rahula", url: "https://loicuaducphat.org/mn/mn62.html#content" },
{ text: `Và này Ānanda, thế nào là con đường, thế nào là lộ trình đưa đến sự đoạn trừ năm hạ phần kiết sử? Ở đây, này Ānanda, Tỷ-kheo do viễn ly các sanh y (Upadhiviveka), do đoạn trừ các bất thiện pháp, do làm cho an tịnh thân thô ác hành một cách toàn diện, ly dục, ly bất thiện pháp, chứng và trú Thiền thứ nhất, một trạng thái hỷ lạc do ly dục sanh, có tầm, có tứ.`, ref: "Trung Bộ 64 – Ðại Kinh Màlunkyà", url: "https://loicuaducphat.org/mn/mn64.html#content" },

{ text: `Vị ấy chánh quán mọi sắc pháp, thọ pháp, tưởng pháp, hành pháp, thức pháp là vô thường, khổ, như bệnh, như cục bướu, như mũi tên, như điều bất hạnh, như bệnh chướng, như kẻ địch, như phá hoại, là không, là vô ngã. Vị này giải thoát tâm khỏi các pháp ấy. Sau khi giải thoát tâm khỏi các pháp ấy, vị ấy tập trung tâm vào bất tử giới (Amatadhatu) và nghĩ rằng: “Ðây là tịch tịnh, đây là vi diệu, tức là sự an chỉ tất cả hành, sự xả ly tất cả sanh y, sự ái diệt, vô tham, đoạn diệt, Niết-bàn”. Nếu an trú vững chắc ở đây, vị này đạt đến sự đoạn tận các lậu hoặc. Nếu vị ấy không đạt đến sự đoạn tận các lậu hoặc, thời do sự tham pháp, hỷ pháp của mình, thời do sự đoạn tận năm hạ phần kiết sử, vị ấy được hóa sanh, nhập Niết-bàn ở đấy, không phải trở lui đời này nữa.`, ref: "Trung Bộ 64 – Ðại Kinh Màlunkyà", url: "https://loicuaducphat.org/mn/mn64.html#content" },

{ text: `Rồi Tôn giả Udāyi, trong khi độc cư Thiền tịnh, sự suy tư sau đây đã khởi lên trong tâm trí Tôn giả: “Thế Tôn thật sự là vị đã đoạn trừ nhiều khổ pháp cho chúng ta. Thế Tôn thật sự là vị đã mang lại nhiều lạc pháp cho chúng ta. Thế Tôn thật sự là vị đã đoạn trừ nhiều bất thiện pháp cho chúng ta. Thế Tôn thật sự là vị đã mang lại nhiều thiện pháp cho chúng ta”.`, ref: "Trung Bộ 66 – Kinh Ví Dụ Con Chim Cáy", url: "https://loicuaducphat.org/mn/mn66.html#content" },

{ text: `Này Udāyi, ở đây có một số người ngu si; khi Ta nói: “Hãy từ bỏ việc này”, liền nói như sau: “Có sá gì sự việc tiểu tiết, nhỏ mọn này. Sa-môn này đặt quá nặng về cấm đoán đoạn giảm”. Họ không chịu từ bỏ và gây lên bất mãn chống Ta và chống những Tỷ-kheo muốn thực hành học giới. Sự việc ấy, này Udāyi, đối với họ, trở thành một trói buộc mạnh mẽ, một trói buộc vững chắc, một trói buộc kiên cường, một trói buộc không mục nát, một khúc gỗ to lớn.`, ref: "Trung Bộ 66 – Kinh Ví Dụ Con Chim Cáy", url: "https://loicuaducphat.org/mn/mn66.html#content" },

{ text: `Ở đây, này Udāyi, có người sống, hướng đến sự đoạn trừ sanh y, sự từ bỏ sanh y. Nhưng trong khi vị này sống hướng đến sự đoạn trừ sanh y, sự từ bỏ sanh y, các tư niệm điên đảo, các tư niệm, tư duy liên hệ đến sanh y, tùy lúc tùy thời hiện hành khởi lên. Này Udāyi, niệm khởi lên chậm chạp và vị này đoạn trừ niệm ấy một cách mau chóng, từ bỏ, chấm dứt, tiêu diệt (niệm ấy). Này Udāyi, ví như một người nhỏ hai hay ba giọt nước vào một ấm nước đun sôi cả ngày. Này Udāyi giọt nước rơi một cách chậm chạp như bị tiêu diệt, tiêu mất một cách mau chóng. Này Udāyi, Ta nói: “Người này cũng bị trói buộc, không phải không bị trói buộc”. Vì sao vậy? Này Udāyi, sự sai biệt về căn tánh trong người này đã được Ta biết rõ.`, ref: "Trung Bộ 66 – Kinh Ví Dụ Con Chim Cáy", url: "https://loicuaducphat.org/mn/mn66.html#content" },

{ text: `Nhưng ở đây, này Udāyi, có người nghĩ rằng: “Sanh y là nguồn gốc của đau khổ”, sau khi biết như vậy, vị ấy thành vô sanh y, giải thoát với sự đoạn diệt sanh y. Này Udāyi, Ta nói: “Người này không bị trói buộc, không phải bị trói buộc”. Vì sao vậy? Này Udāyi, sự sai biệt về căn tánh trong người này đã được Ta biết rõ.`, ref: "Trung Bộ 66 – Kinh Ví Dụ Con Chim Cáy", url: "https://loicuaducphat.org/mn/mn66.html#content" },

{ text: `Này Udāyi, có năm dục trưởng dưỡng này. Thế nào là năm? Sắc do mắt nhận thức, khả ái, khả hỷ, khả lạc, khả ý, kích thích lòng dục, hấp dẫn. Tiếng do tai nhận thức, … hương do mũi nhận thức, … vị do lưỡi nhận thức, … xúc do thân cảm xúc, khả ái, khả hỷ, khả lạc, khả ý, kích thích lòng dục, hấp dẫn. Những pháp này, này Udāyi, là năm dục trưởng dưỡng. Này Udāyi, phàm có lạc gì, hỷ gì khởi lên, do duyên năm dục trưởng dưỡng này, lạc hỷ ấy được gọi là dục lạc, ô uế lạc, phàm phu lạc, phi Thánh lạc, không nên thực hiện, không nên tu tập, không nên làm cho sung mãn. Ta nói rằng lạc ấy đáng phải sợ hãi.`, ref: "Trung Bộ 66 – Kinh Ví Dụ Con Chim Cáy", url: "https://loicuaducphat.org/mn/mn66.html#content" },

{ text: `Và xuất gia như vậy, này các Anuruddha, người Thiện gia nam tử cần phải làm gì? Này các Anuruddha, ly dục, ly bất thiện pháp. Nếu không chứng được hỷ lạc hay một trạng thái khác an tịnh hơn, thời dục tham xâm chiếm tâm và an trú, sân xâm chiếm tâm và an trú, hôn trầm thụy miên … trạo cử, hối quá … nghi hoặc … bất lạc … giải đãi xâm chiếm tâm và an trú. Này các Anuruddha, khi chưa ly dục, chưa ly bất thiện pháp, vị ấy không chứng được hỷ lạc hay một trạng thái khác an tịnh hơn. Này các Anuruddha, ly dục, ly bất thiện pháp, vị ấy chứng được hỷ lạc hay một trạng thái khác an tịnh hơn, thời dục tham không xâm chiếm tâm và an trú, sân không xâm chiếm tâm và an trú, hôn trầm thụy miên … trạo cử hối quá … nghi hoặc … bất lạc … giải đãi không xâm chiếm tâm và an trú. Này các Anuruddha, ly dục, ly bất thiện pháp, vị ấy chứng được hỷ lạc hay một trạng thái khác an tịnh hơn.`, ref: "Trung Bộ 68 – Kinh Nalakapāna", url: "https://loicuaducphat.org/mn/mn68.html#content" },

{ text: `Nhưng này Aggivessana, thân này có sắc, do bốn đại thành, do cha mẹ sanh, nhờ cơm cháo nuôi dưỡng, vô thường, biến hoại, phân toái, đoạn tuyệt, hoại diệt, cần phải được quán sát là vô thường, khổ, như bệnh, như cục bướu, như mũi tên, như điều bất hạnh, như bệnh chướng, như kẻ địch, như phá hoại, là không, là vô ngã. Khi vị ấy quán sát thân này là vô thường, khổ, như bệnh, như cục bướu, như mũi tên, như điều bất hạnh, như bệnh chướng, như kẻ địch, như phá hoại, là không, là vô ngã, thời thân, thân dục, thân ái, thân phục tòng được đoạn diệt.`, ref: "Trung Bộ 74 – Kinh Trường Trảo", url: "https://loicuaducphat.org/mn/mn74.html#content" },

{ text: `Này Aggivessana, lạc thọ là vô thường, hữu vi, do duyên sanh, bị đoạn diệt, bị hủy hoại, bị suy tàn, bị tiêu diệt. Này Aggivessana, khổ thọ là vô thường, hữu vi, do duyên sanh, bị đoạn diệt, bị hủy hại, bị suy tàn, bị tiêu diệt. Này Aggivessana, bất khổ bất lạc thọ là vô thường, hữu vi, do duyên sanh, bị đoạn diệt, bị hủy hoại, bị suy tàn, bị tiêu diệt.`, ref: "Trung Bộ 74 – Kinh Trường Trảo", url: "https://loicuaducphat.org/mn/mn74.html#content" },
{ text: `Ông nghĩ thế nào, ? Ở đây, này Magandiya, có người trước kia đam mê các sắc pháp do mắt nhận thức, các sắc pháp này là khả ái, khả hỷ, khả lạc, khả ý, liên hệ đến dục, hấp dẫn. Người ấy sau một thời gian, sau khi như chơn biết được sự tập khởi, sự đoạn diệt, vị ngọt, sự nguy hiểm và sự xuất ly của các sắc pháp, sau khi đoạn tận sắc ái, sau khi trừ diệt nhiệt não đối với sắc pháp, người này trú với khát ái được đoạn trừ, với nội tâm an tịnh.`, ref: "Trung Bộ 75 – Kinh Māgandiya", url: "https://loicuaducphat.org/mn/mn75.html#content" },

{ text: `Rồi Ta sau một thời gian, sau khi như chơn biết được sự tập khởi, sự đoạn diệt, vị ngọt, sự nguy hiểm và sự xuất ly của các dục vọng, sau khi đoạn tận dục ái, sau khi trừ diệt nhiệt não của các dục, Ta trú với khát ái được đoạn trừ, với nội tâm an tịnh. Rồi Ta thấy các chúng sanh khác, chưa xả ly tham ái đối với các dục đang bị các dục ái nhai nghiến, đang bị dục nhiệt não thiêu đốt, đang chạy theo các dục. Ta không ước vọng được như họ; ở đây, Ta không ham thích. Vì sao vậy? Vì rằng, này Magandiya, có hỷ lạc này, ly dục, ly bất thiện pháp, sau khi chứng đạt Thiên lạc, được an trú, hoan hỷ trong hỷ lạc ấy. Ta không ao ước cái gì thấp kém; ở đây, Ta không ham thích.`, ref: "Trung Bộ 75 – Kinh Māgandiya", url: "https://loicuaducphat.org/mn/mn75.html#content" },

{ text: `Cũng vậy, này Magandiya, sự xúc chạm với các dục trong thời quá khứ cũng là đau khổ, rất là nồng cháy, rất là nhiệt não, và sự xúc chạm với các dục trong thời vị lai cũng là đau khổ, rất là nồng cháy, rất là nhiệt não, và sự xúc chạm với các dục trong thời hiện lại cũng là đau khổ, rất là nồng cháy, rất là nhiệt não. Và này Magandiya, những chúng sanh này chưa đoạn trừ tham ái đối với các dục, đang bị các dục ái nhai nghiến, đang bị dục nhiệt não thiêu đốt, với các căn bị hư hoại, do sự xúc chạm đau khổ với các dục, lại có phản tưởng là được lạc thọ.`, ref: "Trung Bộ 75 – Kinh Māgandiya", url: "https://loicuaducphat.org/mn/mn75.html#content" },

{ text: `Ví như, này Magandiya, một người bị bệnh cùi thân (đầy) lở lói, thân bị hư thối nứt chảy, bị các loài trùng đục khoét, đang cào rách miệng các vết thương với móng tay, hơ đốt thân mình trên hố than hừng. Này Magandiya, người bị bệnh cùi với thân (đầy) lở lói, thân bị hư thối nứt chảy, bị các loài trùng đục khoét, càng cào rách miệng các vết thương với các móng tay, càng hơ đốt thân mình trên hố than hừng chừng nào thời miệng các vết thương ấy lại càng thêm bất tịnh, càng thêm hôi thối và càng thêm thối nát, và người ấy chỉ có cảm giác dễ chịu, thỏa thích do nhân duyên gãi ngứa miệng các vết thương; cũng vậy, này Magandiya, các chúng sanh, chưa đoạn trừ tham ái đối với các dục, đang bị các dục ái nhai nghiến, đang bị dục nhiệt não thiêu đốt, chạy theo các dục. Này Magandiya các chúng sanh, chưa đoạn trừ tham ái đối với các dục, đang bị các dục ái nhai nghiến, đang bị dục nhiệt não thiêu đốt, càng chạy theo dục chừng nào, thời dục ái các chúng sanh ấy càng tăng trưởng, càng bị dục nhiệt não thiêu đốt, và họ chỉ có cảm giác dễ chịu, thỏa thích do duyên năm dục trưởng dưỡng.`, ref: "Trung Bộ 75 – Kinh Māgandiya", url: "https://loicuaducphat.org/mn/mn75.html#content" },

{ text: `Này Magandiya, Ông nghĩ thế nào? Ông có thấy hay nghe một vị vua hay vị đại thần của vua hưởng thụ một cách đầy đủ, một cách sung mãn năm dục trưởng dưỡng, dục ái chưa được đoạn tận, dục nhiệt não chưa được trừ diệt, đã trú, đang trú hay sẽ trú với khát ái được đoạn trừ, với nội tâm an tịnh không?<br>- Thưa không, Tôn giả Gotama.`, ref: "Trung Bộ 75 – Kinh Māgandiya", url: "https://loicuaducphat.org/mn/mn75.html#content" },

{ text: `- Lành thay, này Magandiya! Này Magandiya, Ta cũng không thấy, cũng không nghe một vị vua hay vị đại thần của vua hưởng thụ một cách đầy đủ, một cách sung mãn năm dục trưởng dưỡng, dục ái chưa được đoạn tận, dục nhiệt não chưa được trừ diệt, đã trú, đang trú hay sẽ trú với khát ái được đoạn trừ, với nội tâm an tịnh. Nhưng này Magandiya, những vị Sa-môn hay Bà-la-môn nào đã sống, đang sống hay sẽ sống với khát ái được đoạn trừ, với nội tâm an tịnh, tất cả những vị này, sau khi như chơn biết sự tập khởi, sự đoạn diệt, vị ngọt, sự nguy hiểm và sự xuất ly của các dục ấy, với dục ái được đoạn tận, với dục nhiệt não được trừ diệt, đã trú, đang trú hay sẽ trú với khát ái được đoạn trừ, với nội tâm được an tịnh.`, ref: "Trung Bộ 75 – Kinh Māgandiya", url: "https://loicuaducphat.org/mn/mn75.html#content" },

{ text: `Cũng vậy, này Magandiya, nếu Ta thuyết pháp cho Ông: “Ðây là không bệnh, đây là Niết-bàn”, Ông có thể biết không bệnh, Ông có thể thấy Niết-bàn. Và với mắt được khởi lên cho Ông, lòng tham dục đối với năm thủ uẩn được đoạn trừ; và Ông có thể nghĩ như sau: “Thật sự trong một thời gian dài, ta bị tâm này lường gạt, lừa dối, phỉnh gạt, chấp thủ sắc, ta đã chấp thủ, chấp thủ thọ, ta đã chấp thủ, chấp thủ tưởng, ta đã chấp thủ, chấp thủ các hành, ta đã chấp thủ, chấp thủ thức, ta đã chấp thủ. Do duyên chấp thủ ấy nơi ta, nên có hữu; do duyên hữu, có sanh; do duyên sanh, có già chết, sầu, bi, khổ, ưu, não khởi lên. Như vậy là sự tập khởi của toàn bộ Khổ uẩn”.`, ref: "Trung Bộ 75 – Kinh Māgandiya", url: "https://loicuaducphat.org/mn/mn75.html#content" },

{ text: `Vậy này Magandiya, hãy thân cận các vị chân nhân. Này Magandiya, do Ông thân cận các vị chân nhân, thời này Magandiya, Ông sẽ được nghe diệu pháp. Này Magandiya, do Ông được nghe diệu pháp, thời này Magandiya, Ông sẽ sống đúng với Chánh pháp và tùy pháp. Này Magandiya, do Ông sống đúng với Chánh pháp và tùy pháp, thời này Magandiya, Ông sẽ tự mình biết, tự mình thấy: “Ðây là những bệnh chướng, những cục bướu, những mũi tên. Ở đây, những bệnh chướng, những cục bướu, những mũi tên được trừ diệt, không có dư tàn. Do chấp thủ được diệt ở ta, nên hữu diệt; do hữu diệt, sanh diệt; do sanh diệt, già, chết, sầu, bi, khổ, ưu, não được diệt trừ. Như vậy là sự đoạn diệt của toàn bộ khổ uẩn này”.`, ref: "Trung Bộ 75 – Kinh Māgandiya", url: "https://loicuaducphat.org/mn/mn75.html#content" },

{ text: `Này Sunakkhatta, Ta nói ví dụ này với mục đích làm sáng tỏ ý nghĩa. Nghĩa ở đây như sau: Vết thương, này Sunakkhatta, là đồng nghĩa với sáu xúc xứ (phassayatana); thuốc độc, này Sunakkhatta, là đồng nghĩa với vô minh; mũi tên, này Sunakkhatta, là đồng nghĩa với ái; vật dụng dò tìm, này Sunakkhatta, là đồng nghĩa với niệm; con dao, này Sunakkhatta, là đồng nghĩa với Thánh trí tuệ. Vị y sĩ giải phẫu, này Sunakkhatta, là đồng nghĩa với Như Lai, bậc A-la-hán, Chánh Ðẳng Giác. Thật vậy, này Sunakkhatta, Tỷ-kheo tự mình phòng hộ đối với sáu xúc xứ, nghĩ rằng: “Sanh y (Upadhi) là căn bản của khổ”, sau khi biết như vậy, vị ấy trở thành vô sanh y, giải thoát nhờ đoạn diệt sanh y. Vị ấy còn chú thân của mình trên sanh y hay để tâm đến sanh y, sự tình như vậy không xảy ra.`, ref: "Trung Bộ 105 – Kinh Thiện Tinh", url: "https://loicuaducphat.org/mn/mn105.html#content" },

{ text: `Ví như, này Sunakkhatta, một chén uống nước bằng đồng, đẹp đẽ và hương thơm, và chén ấy lại tẩm thuốc độc. Rồi một người đến, muốn sống, muốn không chết, muốn lạc, yếm ly khổ. Này Sunakkhatta, Ông nghĩ thế nào? Người ấy có uống chén bằng đồng này không, nếu người ấy biết: “Sau khi tôi uống từ đây, tôi sẽ đi đến chết hoặc đi đến gần như chết?” - Thưa không, bạch Thế Tôn. - Cũng vậy, này Sunakkhatta, Tỷ-kheo ấy chắc chắn phòng hộ đối với sáu xúc xứ. “Sanh y là căn bản của đau khổ”, sau khi biết vậy, vị ấy trở thành vô sanh y, giải thoát nhờ đoạn diệt sanh y. Còn chú thân của vị ấy trên sanh y, để tâm đến sanh y, sự tình như vậy không xảy ra.`, ref: "Trung Bộ 105 – Kinh Thiện Tinh", url: "https://loicuaducphat.org/mn/mn105.html#content" },

{ text: `Ví như, này Sunakkhatta, một con rắn độc hết sức độc hại, và có một người đến, muốn sống, muốn không chết, muốn lạc, yếm ly khổ. Này Sunakkhatta, Ông nghĩ thế nào? Người ấy có đưa tay hay gót chân cho con rắn độc hại này không, nếu người ấy biết: “Nếu ta bị con rắn này cắn, ta sẽ đi đến chết hay khổ gần như chết?” - Thưa không, bạch Thế Tôn. - Cũng vậy, này Sunakkhatta, Tỷ-kheo ấy chắc chắn phòng hộ sáu xúc xứ. “Sanh y là căn bản đau khổ”, sau khi biết vậy, vị ấy trở thành vô sanh y, giải thoát nhờ đoạn diệt sanh y. Còn chú thân của vị ấy trên sanh y, hay để tâm đến sanh y, sự tình như vậy không xảy ra.`, ref: "Trung Bộ 105 – Kinh Thiện Tinh", url: "https://loicuaducphat.org/mn/mn105.html#content" },

{ text: `Này chư Hiền, thế nào là truy tìm quá khứ? Mắt của tôi trong thời quá khứ là như vậy, các sắc pháp là như vậy, và thức ở đây bị dục và ái trói chặt. Vì thức bị dục và ái trói chặt, vị ấy hân hoan trong ấy. Vì hân hoan trong ấy, vị ấy truy tìm quá khứ. Tai của tôi trong quá khứ là như vậy, các tiếng là như vậy … Mũi của tôi trong quá khứ là như vậy, các hương là như vậy … Lưỡi của tôi trong quá khứ là như vậy, các vị là như vậy … Ý của tôi trong quá khứ là như vậy, các pháp là như vậy, và thức ở đây, bị dục và ái trói chặt. Vì rằng thức bị dục và ái trói chặt, vị ấy hân hoan trong ấy. Vì hân hoan trong ấy, vị ấy truy tìm quá khứ. Như vậy, này chư Hiền, là truy tìm quá khứ.`, ref: "Trung Bộ 133 – Kinh Ðại Ca-chiên-diên Nhất Dạ Hiền Giả", url: "https://loicuaducphat.org/mn/mn133.html#content" },

{ text: `‘Này các Tỷ-kheo, vị Tỷ-kheo cần phải quán sát một cách như thế nào để thức của vị ấy đối với ngoại trần không tán loạn, không tản rộng, tâm không trú trước nội trần, không bị chấp thủ quấy rối. Này các Tỷ-kheo, nếu thức đối với ngoại trần không tán loạn, không tản rộng, tâm không trú trước nội trần, không bị chấp thủ quấy rối, sẽ không có tập khởi, sanh khởi của khổ về sanh, già, chết trong tương lai’. Chư Hiền, sao gọi là thức đối với ngoại trần, bị tán loạn, bị tản rộng? Ở đây, này chư Hiền, khi vị Tỷ-kheo thấy sắc với con mắt, thức truy cầu sắc tướng, bị trói buộc bởi vị của sắc tướng, bị cột chặt bởi vị của sắc tướng, bị triền phược bởi kiết sử vị của sắc tướng, như vậy gọi là thức đối với ngoại trần bị tán loạn, bị tản rộng. Khi vị Tỷ-kheo nghe tiếng với tai… ngửi hương với mũi… nếm vị với lưỡi… cảm xúc với thân… nhận thức pháp với ý, thức truy cầu pháp tướng, bị trói buộc bởi vị của pháp tướng, bị cột chặt bởi vị của pháp tướng, bị triền phược bởi kiết sử vị của pháp tướng; như vậy gọi là thức đối với ngoại trần bị tán loạn, bị tản rộng. Như vậy, này chư Hiền, gọi là thức bị tán loạn, bị tản rộng.`, ref: "Trung Bộ 138 – Kinh Tổng Thuyết Và Biệt Thuyết", url: "https://loicuaducphat.org/mn/mn138.html#content" },

{ text: `Này các Tỷ-kheo, có năm dục trưởng dưỡng này. Thế nào là năm? Các sắc pháp do mắt nhận thức, khả ái, khả lạc, khả ý, khả hỷ, liên hệ đến dục, hấp dẫn; các tiếng do tai nhận thức,… ; các hương do mũi nhận thức,… ; các vị do lưỡi nhận thức… ; các xúc do thân cảm giác, khả ái, khả lạc, khả ý, khả hỷ, liên hệ đến dục, hấp dẫn. Này các Tỷ-kheo, như vậy là năm dục trưởng dưỡng. Này các Tỷ-kheo, do duyên năm dục trưởng dưỡng này khởi lên lạc và hỷ, như vậy gọi là dục lạc, uế lạc, phàm phu lạc, phi Thánh lạc. ‘Ta nói loại lạc này không nên thực hành, không nên tu tập, không nên làm cho sung mãn, nên sợ hãi’.`, ref: "Trung Bộ 139 – Kinh Tránh Phân Biệt", url: "https://loicuaducphat.org/mn/mn139.html#content" },

{ text: `“Này các Tỷ-kheo, không biết, không thấy như chơn mắt; không biết, không thấy như chơn các sắc; không biết, không thấy như chơn nhãn thức; không biết, không thấy như chơn nhãn xúc; do duyên nhãn xúc này khởi lên lạc thọ, khổ thọ hay bất khổ bất lạc thọ; không biết, không thấy như chơn cảm thọ ấy, vị ấy ái trước đối với mắt, ái trước đối với các sắc, ái trước đối với nhãn thức, ái trước đối với nhãn xúc. Do duyên nhãn xúc này khởi lên lạc thọ, khổ thọ hay bất khổ bất lạc thọ, vị ấy ái trước đối với cảm thọ ấy. Khi vị ấy trú, quán sát vị ngọt, bị ái trước, hệ lụy và tham đắm, nên năm thủ uẩn đi đến tích trữ trong tương lai. Và ái của vị ấy đưa đến tái sanh, câu hữu với hỷ và tham, tìm sự hoan lạc chỗ này, chỗ kia; ái ấy được tăng trưởng; những thân ưu não tăng trưởng; những tâm ưu não tăng trưởng; những thân nhiệt não tăng trưởng; những tâm khổ não tăng trưởng. những thân khổ não tăng trưởng; những tâm khổ não tăng trưởng; Vị ấy cảm thọ thân khổ và tâm khổ.`, ref: "Trung Bộ 149 – Đại Kinh Sáu Xứ", url: "https://loicuaducphat.org/mn/mn149.html#content" },

{ text: `Này các Gia chủ, nhưng nếu du sĩ ngoại đạo ấy hỏi các Ông như sau: ‘Do căn cứ gì về các Tôn giả ấy, do truyền thống gì, các vị nói về các Tôn giả ấy như sau? Chắc chắn các Tôn giả ấy là ly tham, hay đang đi trên con đường điều phục tham, hay ly sân, hay đang đi trên con đường điều phục sân, hay ly si, hay đang đi trên con đường điều phục si?’ Khi được hỏi vậy, này các Gia chủ, các Ông hãy trả lời các du sĩ ngoại đạo ấy như sau: ‘Các Tôn giả ấy sống tại các trú xứ xa vắng trong các khu rừng nhàn tịnh. Nhưng tại các chỗ như vậy, không có các sắc do mắt nhận thức để họ có thể thấy, và sau khi thấy, có lòng thích thú; nhưng tại các chỗ như vậy, không có các tiếng do tai nhận thức để họ có thể nghe, và sau khi nghe, có lòng thích thú; nhưng tại các chỗ như vậy, không có hương do mũi nhận thức, để họ có thể ngửi và sau khi ngửi, có lòng thích thú; nhưng tại các chỗ ấy như vậy, không có các vị do lưỡi nhận thức, để họ có thể nếm, và sau khi nếm, có lòng thích thú; nhưng tại các chỗ như vậy, không có các xúc do thân nhận thức, để họ có thể cảm giác, và sau khi cảm giác, có lòng thích thú. Chư Hiền giả, do căn cứ này, do những truyền thống này, mà chúng tôi nói về các Tôn giả ấy như sau: Thật vậy, chư Tôn giả ấy ly tham hay đang đi trên con đường nhiếp phục tham, hay ly sân, hay đang đi trên con đường nhiếp phục sân, hay ly si, hay đang đi trên con đường nhiếp phục si’.`, ref: "Trung Bộ 150 – Kinh Nói Cho Dân Chúng Nagaravinda", url: "https://loicuaducphat.org/mn/mn150.html#content" },

{ text: `“Này Tỷ-kheo, gò mối là đồng nghĩa với cái thân do bốn đại thành, do cha mẹ sanh, nhờ cơm cháo nuôi dưỡng, vô thường, biến hoại, phấn toái, đoạn tuyệt, hoại diệt. Này Tỷ-kheo, cái gì thuộc về công việc ban ngày, ban đêm suy tầm, suy nghĩ, như vậy là ban đêm phun khói. Này Tỷ-kheo, cái gì sau khi suy tầm, suy tư ban đêm, ban ngày đem ra thực hành, về thân, về lời nói, về ý, như vậy là ban ngày chói sáng. Này Tỷ-kheo, Bà-la-môn là đồng nghĩa với Như Lai, bậc A-la-hán, Chánh Ðẳng Giác. Này Tỷ-kheo, người có trí là đồng nghĩa với Tỷ-kheo hữu học. Này Tỷ-kheo, cái gươm là đồng nghĩa với trí tuệ của bậc Thánh. Này Tỷ-kheo, đào lên là đồng nghĩa với tinh tấn, tinh cần. Này Tỷ-kheo, cái then cửa là đồng nghĩa với vô minh; đem then cửa lên là từ bỏ vô minh này; kẻ có trí, cầm gươm đào lên là ý nghĩa này.`, ref: "Trung Bộ 23 – Kinh Gò Mối", url: "https://loicuaducphat.org/mn/mn23.html#content" },


{ text: `Này Tỷ-kheo, con dao phay là đồng nghĩa với năm dục trưởng dưỡng, tức là lấy con dao phay lên là từ bỏ năm dục trưởng dưỡng này, kẻ có trí, cầm gươm đào lên là ý nghĩa này. Này Tỷ-kheo, miếng thịt là đồng nghĩa với hỷ tham; lấy miếng thịt lên là từ bỏ hỷ tham này; kẻ có trí, cầm gươm đào lên là ý nghĩa này. Này Tỷ-kheo, con rắn hổ là đồng nghĩa với vị Tỷ-kheo đã diệt trừ các lậu hoặc; hãy để con rắn hổ yên, chớ đụng chạm con rắn hổ, hãy đảnh lễ con rắn hổ, là ý nghĩa này.`, ref: "Trung Bộ 23 – Kinh Gò Mối", url: "https://loicuaducphat.org/mn/mn23.html#content" },

{ text: `Chư Tỷ-kheo, đồ mồi đồng nghĩa với năm dục trưởng dưỡng. Chư Tỷ-kheo, người thợ săn bẫy mồi đồng nghĩa với Ác ma. Chư Tỷ-kheo, các quyến thuộc của người thợ săn bẫy mồi đồng nghĩa với quyến thuộc của Ác ma. Chư Tỷ-kheo, các đàn nai đồng nghĩa với các Sa-môn, Bà-la-môn. Ở đây, này các Tỷ-kheo, hạng Sa-môn, Bà-la-môn đầu tiên xâm nhập, tham đắm ăn các đồ mồi do Ác ma gieo ra và các vật dụng thế gian. Ở đây, họ xâm nhập, tham đắm ăn các món ăn, nên trở thành mê loạn; vì mê loạn, họ trở thành phóng dật; vì phóng dật, họ trở thành những người bị làm theo ý Ác ma muốn giữa các đồ mồi này và giữa các vật dụng thế gian. Như vậy, này các Tỷ-kheo, hạng Sa-môn, Bà-la-môn đầu tiên này không thoát được như ý lực của Ác ma.`, ref: "Trung Bộ 25 – Kinh Bẫy Mồi", url: "https://loicuaducphat.org/mn/mn25.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, hạng Sa-môn, Bà-la-môn thứ hai suy nghĩ như sau: “Hạng Sa-môn, Bà-la-môn đầu tiên này đã xâm nhập, tham đắm ăn các đồ mồi do Ác ma gieo ra, và các vật dụng thế gian. Ở đây, họ xâm nhập, tham đắm ăn các món ăn, nên trở thành mê loạn; vì mê loạn, họ trở thành phóng dật; vì phóng dật, họ trở thành những người bị làm theo ý Ác ma muốn giữa các đồ mồi ấy và giữa các vật dụng thế gian. Như vậy, hạng Sa-môn, Bà-la-môn đầu tiên này đã không thoát khỏi như ý lực của Ác ma. Vậy, chúng ta hãy hoàn toàn từ bỏ các đồ mồi và các vật dụng thế gian, từ bỏ các vật dụng đáng sợ hãi, đi sâu vào rừng và an trú”. Họ hoàn toàn từ bỏ các đồ mồi, các vật dụng thế gian, từ bỏ các vật dụng đáng sợ hãi, đi sâu vào rừng và an trú. Ở đây, họ trở thành những người ăn cỏ lúa, ăn lúa tắc, những người ăn gạo lức, những người ăn hột cải Nivara, những người ăn da vụn, những người ăn trấu, những người ăn nước bột gạo, những người ăn hột vừng, những người ăn cỏ, những người ăn phân bò, những người ăn trái cây, những người ăn rễ cây trong rừng, những người ăn trái cây rụng để sống. Cuối tháng mùa hạ, cỏ nước trở thành khan hiếm, thân hình của hạng Sa-môn, Bà-la-môn ấy trở thành hết sức gầy yếu. Vì thân hình hạng Sa-môn, Bà-la-môn ấy trở thành hết sức gầy yếu, nên sức lực tinh tấn của họ bị kiệt quệ. Vì sức lực tinh tấn bị kiệt quệ, nên tâm giải thoát bị kiệt quệ. Vì tâm giải thoát bị kiệt quệ, họ trở lui lại các đồ mồi do Ác ma gieo ra và các vật dụng thế gian. Ở đây, họ xâm nhập, tham đắm ăn các món ăn. Do ở đây xâm nhập, tham đắm ăn các món ăn, chúng trở thành mê loạn. Do mê loạn, họ trở thành phóng dật. Do phóng dật, họ trở thành những người bị làm theo ý Ác ma muốn giữa các đồ mồi này và giữa các vật dụng thế gian. Như vậy, này các Tỷ-kheo, hạng Sa-môn, Bà-la-môn thứ hai này đã không thoát khỏi như ý lực của Ác ma.`, ref: "Trung Bộ 25 – Kinh Bẫy Mồi", url: "https://loicuaducphat.org/mn/mn25.html#content" },

{ text: `Này các Tỷ-kheo, ở đây hạng Sa-môn, Bà-la-môn thứ ba suy nghĩ như sau: “Hạng Sa-môn, Bà-la-môn đầu tiên này xâm nhập, tham đắm ăn các đồ mồi được Ác ma gieo ra và các vật dụng thế gian… (như trên)… Như vậy hạng Sa-môn, Bà-la-môn đầu tiên này đã không thoát khỏi như ý lực của Ác ma. Vậy chúng ta hãy làm một chỗ ẩn nấp gần các đồ mồi do Ác ma gieo ra và các vật dụng thế gian. Ở đây, sau khi làm một chỗ ẩn nấp xong, không xâm nhập, không tham đắm, chúng ta sẽ ăn các đồ mồi do Ác ma gieo ra và các vật dụng thế gian. Do không xâm nhập, không tham đắm ăn các món ăn, chúng ta sẽ không trở thành mê loạn. Do không mê loạn, chúng ta sẽ không trở thành phóng dật. Do không phóng dật, chúng ta sẽ không trở thành những người bị làm theo Ác ma muốn, giữa các đồ mồi và các vật dụng thế gian.” Hạng Sa-môn, Bà-la-môn này làm chỗ ẩn nấp gần các đồ mồi do Ác ma gieo ra và giữa các vật dụng thế gian. Sau khi làm chỗ ẩn nấp ở đây xong, họ không xâm nhập, không tham đắm ăn các đồ mồi do Ác ma gieo ra và các vật dụng thế gian. Không xâm nhập, không tham đắm, họ không ăn các đồ mồi nên không trở thành mê loạn. Do không mê loạn, họ không trở thành phóng dật. Do không phóng dật, họ không trở thành những người bị làm theo Ác ma muốn giữa các đồ mồi và các vật dụng thế gian. Nhưng rồi họ có những tà kiến như sau: “Thế giới là thường còn; thế giới là không thường còn; thế giới là hữu biên; thế giới là vô biên; ...”. Như vậy, này các Tỷ-kheo, các Sa-môn, Bà-la-môn thứ ba này đã không thoát khỏi như ý lực của Ác ma.`, ref: "Trung Bộ 25 – Kinh Bẫy Mồi", url: "https://loicuaducphat.org/mn/mn25.html#content" },

{ text: `Này các Tỷ-kheo, sao gọi là Ác ma và Ác ma quyến thuộc không thể đến được? Ở đây, này các Tỷ-kheo, Tỷ-kheo ly dục, ly ác bất thiện pháp chứng và trú Thiền thứ nhất, một trạng thái hỷ lạc do ly dục sanh, có tầm có tứ. Này các Tỷ-kheo, như vậy gọi là Tỷ-kheo làm Ác ma mù mắt, đoạn tuyệt mắt của Ác ma, không còn dấu tích, khiến Ác ma không thấy đường đi lối về. Lại nữa, này các Tỷ-kheo, Tỷ-kheo diệt tầm và tứ, chứng và trú Thiền thứ hai, một trạng thái hỷ lạc do định sanh, không tầm không tứ, nội tĩnh nhất tâm. Như vậy gọi là vị Tỷ-kheo làm Ác ma mù mắt, đoạn tuyệt mắt của Ác ma, không còn dấu tích, khiến Ác ma không thấy đường đi lối về.`, ref: "Trung Bộ 25 – Kinh Bẫy Mồi", url: "https://loicuaducphat.org/mn/mn25.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là Tỷ-kheo không băng bó vết thương? Ở đây, này các Tỷ-kheo, Tỷ-kheo, khi mắt thấy sắc, nắm giữ tướng chung, nắm giữ tướng riêng. Những nguyên nhân gì làm con mắt không được chế ngự, khiến tham ái, ưu bi, các ác, bất thiện pháp khởi lên; Tỷ-kheo không tự chế ngự nguyên nhân ấy, không hộ trì con mắt, không thực hành sự hộ trì con mắt. Khi tai nghe tiếng… mũi ngửi hương… lưỡi nếm vị… thân cảm xúc… ý nhận thức các pháp, vị ấy nắm giữ tướng chung, nắm giữ tướng riêng. Những nguyên nhân gì khiến ý căn không được chế ngự, khiến tham ái, ưu bi, các ác, bất thiện pháp khởi lên; Tỷ-kheo không chế ngự nguyên nhân ấy, không hộ trì ý căn, không thực hành sự hộ trì ý căn. Như vậy, này các Tỷ-kheo, là Tỷ-kheo không băng bó vết thương.`, ref: "Trung Bộ 33 – Đại Kinh Người Chăn Bò", url: "https://loicuaducphat.org/mn/mn33.html#content" },

{ text: `Chư Tỷ-kheo, thế nào là Tỷ-kheo không biết rõ các sắc? Ở đây, này các Tỷ-kheo, Tỷ-kheo đối với sắc pháp không như thật biết tất cả loại sắc thuộc bốn đại và sắc do bốn đại hợp thành. Như vậy, này các Tỷ-kheo, Tỷ-kheo không biết rõ các sắc. Chư Tỷ-kheo, thế nào là Tỷ-kheo không khéo (phân biệt) các tướng? Ở đây, này các Tỷ-kheo, Tỷ-kheo không như thật biết kẻ ngu và nghiệp tướng của người đó, kẻ trí và nghiệp tướng của người đó. Như vậy, này các Tỷ-kheo, Tỷ-kheo không khéo (phân biệt) các tướng. Chư Tỷ-kheo, thế nào là Tỷ-kheo không trừ bỏ trứng con bò chét? Ở đây, này các Tỷ-kheo, Tỷ-kheo thọ dụng dục tầm khởi lên, không từ bỏ, không tránh né, không chấm dứt, không làm cho không tồn tại,. Tỷ kheo thọ dụng sân tầm khởi lên … thọ dụng hại tầm khởi lên … thọ dụng các ác, bất thiện pháp khởi lên, không từ bỏ, không tránh né, không chấm dứt, không làm cho không tồn tại. Như vậy, này các Tỷ-kheo, là Tỷ-kheo không trừ bỏ trứng con bò chét.`, ref: "Trung Bộ 33 – Đại Kinh Người Chăn Bò", url: "https://loicuaducphat.org/mn/mn33.html#content" },

{ text: `“Này Aggivessana, thế nào là thân không tu tập và thế nào là tâm không tu tập? Ở đây, này Aggivessana, kẻ vô văn phàm phu khởi lên lạc thọ. Người này được cảm giác lạc thọ, liền tham đắm lạc thọ và rơi vào sự tham đắm lạc thọ. Nếu lạc thọ ấy bị diệt mất, do lạc thọ đoạn diệt, khởi lên khổ thọ. Người ấy, do cảm giác khổ thọ, nên sầu muộn, than van, khóc lóc, đập ngực, đưa đến bất tỉnh. Này Aggivessana, lạc thọ ấy khởi lên cho người kia, chi phối tâm và an trú, do thân không tu tập. Khổ thọ ấy khởi lên chi phối tâm và an trú, do tâm không tu tập. Này Aggivessana, không luận người nào mà cả hai phương tiện đều có lạc thọ khởi lên, chi phối tâm và an trú, do thân không tu tập; khổ thọ khởi lên, chi phối tâm và an trú, do tâm không tu tập. Như vậy, này Aggivessana, người ấy là người có thân không tu tập và tâm không tu tập.`, ref: "Trung Bộ 36 – Đại Kinh Saccaka", url: "https://loicuaducphat.org/mn/mn36.html#content" },

{ text: `Và này Aggivessana, thế nào là thân tu tập và tâm tu tập? Ở đây, này Aggivessana, lạc thọ khởi lên cho vị Thánh đệ tử nghe nhiều. Vị này được cảm giác lạc thọ, nhưng không tham đắm lạc thọ, không rơi vào sự tham đắm lạc thọ. Nếu lạc thọ ấy bị diệt mất, do lạc thọ đoạn diệt, khởi lên khổ thọ, vị ấy cảm giác khổ thọ nhưng không sầu muộn, than van, khóc lóc, đập ngực, đưa đến bất tỉnh. Này Aggivessana, lạc thọ ấy khởi lên cho vị kia, không chi phối tâm và không an trú, do thân có tu tập; khổ thọ ấy khởi lên cho vị kia, không chi phối tâm và không an trú, do tâm có tu tập. Này Aggivessana, không luận người nào mà cả hai phương tiện đều có lạc thọ khởi lên, không chi phối tâm và không an trú, do thân có tu tập; khổ thọ khởi lên, không chi phối tâm và không an trú, do tâm có tu tập, như vậy này Aggivessana, người ấy là người có thân tu tập, có tâm tu tập.`, ref: "Trung Bộ 36 – Đại Kinh Saccaka", url: "https://loicuaducphat.org/mn/mn36.html#content" },

{ text: `Này các Tỷ-kheo, đứa trẻ sau khi lớn lên, sau khi các căn do mắt nhận thức, được thuần thục, thọ hưởng đầy đủ năm món dục lạc; các sắc do mắt nhận thức, sắc này khả ái, khả hỷ, khả lạc, khả ý, kích thích lòng dục, hấp dẫn; các tiếng do tai nhận thức… Các hương do mũi nhận thức… Các vị do lưỡi nhận thức… Các xúc do thân cảm xúc; các xúc này khả ái, khả hỷ, khả lạc, khả ý, kích thích lòng dục. Khi thấy sắc bằng mắt, người đó tham ái đối với sắc đẹp, người đó ghét bỏ đối với sắc xấu, người đó sống niệm không an trú trên thân, với một tâm nhỏ mọn. Người đó không như thật tuệ tri tâm giải thoát, tuệ giải thoát, chính nhờ chúng mà các ác bất thiện pháp của người đó được trừ diệt, không có dư tàn. Như vậy, đối diện với thân, sơ (thuận, nghịch) có cảm thọ nào khởi lên: lạc thọ, khổ thọ, hay bất khổ bất lạc thọ, người đó tùy hỷ, hoan nghênh, tham trước thọ ấy. Vì tùy hỷ, hoan nghênh, tham trước cảm thọ ấy, nên dục sanh hỷ, có tâm dục hỷ đối với những cảm thọ ấy nên dục hỷ sanh. Có tâm dục hỷ đối với những cảm thọ ấy, tức là chấp thủ. Do duyên thủ nên hữu sanh; do duyên hữu nên sanh sinh khởi; do duyên sanh nên già, chết, sầu, bi, khổ, ưu, não, sanh. Như vậy là sự tập khởi của toàn bộ khổ uẩn này.`, ref: "Trung Bộ 38 – Đại Kinh Đoạn Tận Ái", url: "https://loicuaducphat.org/mn/mn38.html#content" },

{ text: `Này các Tỷ-kheo, thế nào là Tỷ-kheo thực hành các pháp môn xứng đáng bậc Sa-môn? Này các Tỷ-kheo, đối với Tỷ-kheo có tâm tham dục và lòng tham dục được đoạn diệt, có tâm sân hận và lòng sân hận được đoạn diệt, có tâm phẫn nộ và lòng phẫn nộ được đoạn diệt, có tâm hiềm hận và lòng hiềm hận được đoạn diệt, có tâm giả dối và lòng giả dối được đoạn diệt, có tâm não hại và lòng não hại được đoạn diệt, có tâm tật đố và lòng tật đố được đoạn diệt, có tâm xan lẩn và lòng xan lẩn được đoạn diệt, có tâm man trá và lòng man trá được đoạn diệt, có tâm xảo trá và lòng xảo trá được đoạn diệt, có tâm ái dục và lòng ái dục được đoạn diệt, có tà kiến và tà kiến được đoạn diệt… Này các Tỷ-kheo, Ta nói rằng, nếu vị ấy thực hành các pháp môn xứng đáng bậc Sa-môn, thì có thể đoạn diệt được những cấu uế cho Sa-môn, những tỳ vết cho Sa-môn, những lỗi lầm cho Sa-môn, đọa sanh vào đọa xứ, sự thọ lãnh các ác thú. Vị ấy thấy tự ngã được gột sạch tất cả những ác, bất thiện pháp và vị ấy thấy tự ngã được giải thoát. Do thấy tự ngã được gột sạch tất cả những ác, bất thiện pháp ấy, do thấy tự ngã được giải thoát nên hân hoan sanh; do tâm hân hoan nên hỷ sanh; do hỷ nên thân được khinh an; do thân khinh an nên lạc thọ sanh; do lạc thọ nên tâm được định tĩnh. Ta nói rằng chính nhờ nội tâm định tĩnh, vị ấy thực hành các pháp môn xứng đáng bậc Sa-môn.`, ref: "Trung Bộ 40 – Tiểu Kinh Xóm Ngựa", url: "https://loicuaducphat.org/mn/mn40.html#content" },

{ text: `“Này Hiền giả, như thế nào sự tái sanh trong tương lai được xảy ra?” “Này Hiền giả, bị vô minh ngăn che, bị tham ái trói buộc, các loài hữu tình thích thú chỗ này chỗ kia, như vậy, sự tái sinh trong tương lai được xảy ra.” “Này Hiền giả, như thế nào sự tái sanh trong tương lai không xảy ra?” “Này Hiền giả, vô minh được xả ly, minh khởi, tham ái được đoạn diệt, như vậy sự tái sanh trong tương lai không xảy ra.”`, ref: "Trung Bộ 43 – Đại Kinh Phương Quảng", url: "https://loicuaducphat.org/mn/mn43.html#content" },

{ text: `“Này Hiền giả, thế nào là Thiền thứ nhất?” “Ở đây, này Hiền giả, vị Tỷ-kheo ly dục, ly ác bất thiện pháp, chứng và trú Thiền thứ nhất, một trạng thái hỷ lạc do ly dục sanh, có tầm, có tứ. Như vậy, này Hiền giả, gọi là Thiền thứ nhất.” “Này Hiền giả, Thiền thứ nhất có bao nhiêu chi phần?” “Này Hiền giả, Thiền thứ nhất có năm chi phần. Ở đây, này Hiền giả, Tỷ-kheo thành tựu Thiền thứ nhất, có tầm, tứ, hỷ, lạc và nhất tâm. Này Hiền giả, Thiền thứ nhất có năm chi phần như vậy.” “Này Hiền giả, Thiền thứ nhất từ bỏ bao nhiêu chi phần và thành tựu bao nhiêu chi phần?” “Này Hiền giả, Thiền thứ nhất từ bỏ năm chi phần và thành tựu năm chi phần. Ở đây, này Hiền giả, vị Tỷ-kheo thành tựu Thiền thứ nhất từ bỏ tham dục, từ bỏ sân, từ bỏ hôn trầm thụy miên, từ bỏ trạo hối, từ bỏ nghi, thành tựu tầm, tứ, hỷ, lạc và nhất tâm. Này Hiền giả, như vậy Thiền thứ nhất từ bỏ năm chi phần, và thành tựu năm chi phần.”`, ref: "Trung Bộ 43 – Đại Kinh Phương Quảng", url: "https://loicuaducphat.org/mn/mn43.html#content" },

{ text: `Này các Tỷ-kheo, thế nào là loại pháp hành hiện tại lạc, tương lai quả báo khổ? Này các Tỷ-kheo, có một số Sa-môn thuyết như sau, có sở kiến như sau: “Không có lỗi trong các dục”. Những vị này đắm mình trong các dục, Sau khi đắm mình trong các dục, khi thân hoại mạng chung, các vị ấy phải sanh vào cõi dữ, ác thú, đọa xứ, địa ngục. Ở đây, họ cảm thọ những cảm giác đau khổ, thống khổ, khốc liệt. Họ nói như sau: “Các Tôn giả Sa-môn, Bà-la-môn này thấy sự sợ hãi tương lai của các dục, nói đến sự đoạn trừ các dục, nêu lên sự hiểu biết về các dục. Nhưng chúng ta, do các dục này làm nhân, do các dục này làm duyên, phải cảm thọ những cảm giác đau khổ, thống khổ, khốc liệt”. Này các Tỷ-kheo, như vậy gọi là pháp hành hiện tại lạc, tương lai quả báo khổ.`, ref: "Trung Bộ 45 – Tiểu Kinh Pháp Hành", url: "https://loicuaducphat.org/mn/mn45.html#content" },

{ text: `Này các Tỷ-kheo, thế nào là pháp hành hiện tại khổ, tương lai quả báo lạc? Ở đây, này các Tỷ-kheo, có người tự tánh sanh ra quá nặng về tham ái, luôn luôn cảm thọ những cảm giác khổ ưu do tham ái sanh; có người tự tánh sanh ra quá nặng về sân hận, luôn luôn cảm thọ những cảm giác khổ ưu do sân hận sanh; có người tự tánh sanh ra quá nặng về si mê, luôn luôn cảm thọ những cảm giác khổ ưu do si mê sanh. Với khổ và với ưu, với mặt đầy nước mắt và khóc than, vị ấy sống theo phạm hạnh, hoàn toàn đầy đủ trong sạch. Vị ấy sau khi thân hoại mạng chung, được sanh thiện thú, Thiên giới, cõi đời này. Như vậy, này các Tỷ-kheo, được gọi là pháp hành hiện tại khổ, tương lai quả báo lạc.`, ref: "Trung Bộ 45 – Tiểu Kinh Pháp Hành", url: "https://loicuaducphat.org/mn/mn45.html#content" },

{ text: `Này các Tỷ-kheo, ví như trái bí đắng có tẩm thuốc độc. Rồi một người đến muốn sống, muốn không chết, ưa lạc, hiềm ghét khổ, và có người nói với người ấy như sau: “Này bạn, trái bí đắng này có tẩm thuốc độc, nếu bạn muốn, hãy ăn. Trong khi ăn, bạn không được thích thú về sắc, về hương, về vị. Sau khi ăn, bạn có thể đi đến chết hay đau khổ gần như chết”. Người ấy có thể ăn không có suy nghĩ, không có từ bỏ. Trong khi ăn, người ấy không được thích thú về sắc, về hương, về vị. Sau khi ăn, người ấy bị chết, hay bị đau khổ gần như chết. Này các Tỷ-kheo, Ta nói pháp hành này giống như ví dụ ấy, tức là pháp hành hiện tại khổ và tương lai quả báo cũng khổ.`, ref: "Trung Bộ 46 – Đại Kinh Pháp Hành", url: "https://loicuaducphat.org/mn/mn46.html#content" },

{ text: `Này các Tỷ-kheo, ví như một bình đồng đựng nước uống, có sắc, có hương, có vị, và nước uống ấy có tẩm thuốc độc. Rồi một người đến, muốn sống, muốn không chết, muốn ưa lạc, hiềm ghét khổ. Và có người nói với người ấy như sau: “Này bạn, bình đồng đựng nước uống này, có sắc, có hương, có vị, và nước uống ấy có tẩm thuốc độc. Nếu bạn muốn, hãy uống. Trong khi uống, bạn sẽ được thích thú về sắc, về hương, về vị. Sau khi uống, bạn có thể đi đến chết hay đau khổ gần như chết”. Người kia có thể uống, không suy nghĩ, không từ bỏ. Trong khi uống, người ấy được thích thú về sắc, về hương, về vị. Sau khi uống, người ấy có thể đi đến chết hay đau khổ gần như chết. Này các Tỷ-kheo, Ta nói pháp hành này giống như ví dụ ấy, tức là pháp hành hiện tại lạc, tương lai quả báo khổ.`, ref: "Trung Bộ 46 – Đại Kinh Pháp Hành", url: "https://loicuaducphat.org/mn/mn46.html#content" },

{ text: `Này các Tỷ-kheo, ví như nước tiểu được trộn nhiều loại thuốc. Rồi có người đi đến, bị bệnh hoàng đản, và có người nói với người đó như sau: “Này bạn, nước tiểu này được trộn với nhiều loại thuốc. Nếu bạn muốn, hãy uống. Trong khi uống, bạn không được thích thú về sắc, về hương, về vị. Nhưng sau khi uống, bạn sẽ được an lạc”. Người ấy có thể uống, sau khi suy nghĩ, không có từ bỏ. Trong khi uống, người ấy không được thích thú về sắc, về hương, về vị. Nhưng sau khi uống, người ấy được an lạc. Này các Tỷ-kheo, Ta nói pháp hành này giống như ví dụ ấy, tức là pháp hành hiện tại khổ, tương lai quả báo lạc.`, ref: "Trung Bộ 46 – Đại Kinh Pháp Hành", url: "https://loicuaducphat.org/mn/mn46.html#content" },

{ text: `“Này Gia chủ, ví như có con chó đói lả, suy nhược, đi đến một lò thịt giết bò. Ở đây, có người giết bò thiện xảo hay người đệ tử quăng cho nó một khúc xương, khéo lóc, tận lóc, không có thịt, chỉ có dính máu. Này Gia chủ, Ông nghĩ thế nào? Con chó ấy, khi gặm khúc xương ấy, khéo lóc, tận lóc, không có thịt, chỉ có dính máu có thể đoạn trừ được đói lả suy nhược của nó không?” “Bạch Thế Tôn, không. Vì sao vậy? Với khúc xương khéo lóc, tận lóc, không có thịt, chỉ có dính máu ấy, bạch Thế Tôn, con chó kia chỉ có mệt nhọc khốn khổ mà thôi.” “Cũng vậy, này Gia chủ, vị Thánh đệ tử suy nghĩ như sau: “Thế Tôn đã nói, dục được ví như khúc xương, khổ nhiều, não nhiều, tai họa ở đây càng nhiều hơn”. Sau khi thấy như chân như vậy với chánh trí tuệ, sau khi từ bỏ loại xả thuộc loại đa chủng, y cứ đa chủng, đối với loại xả thuộc loại nhất chủng, y cứ nhất chủng, ở đây, mọi chấp thủ đối với thế vật được đoạn trừ hoàn toàn, không có dư tàn, vị ấy tu tập loại xả như vậy.`, ref: "Trung Bộ 54 – Kinh Gia Chủ Potaliya", url: "https://loicuaducphat.org/mn/mn54.html#content" },

{ text: `Này Gia chủ, ví như con chim kên, con chim diều hâu, hay con chim ưng giành được miếng thịt liền bay bổng lên; các con chim kên khác, chim diều hâu khác, hay chim ưng khác bay đuổi theo, đuổi sát theo giành giựt xé nát miếng thịt ấy. Này Gia chủ, Ông nghĩ thế nào? Nếu con chim kên, chim diều hâu hay chim ưng ấy không vứt bỏ ngay miếng thịt ấy, nó có thể do nhân duyên ấy, đi đến chết hay đi đến khổ gần như chết không?” “Thưa có, bạch Thế Tôn” … Cũng vậy, này Gia chủ, vị Thánh đệ tử suy nghĩ như sau: “Thế Tôn đã nói, dục được ví như miếng thịt, khổ nhiều, não nhiều, tai họa ở đây càng nhiều hơn”. Sau khi thấy như chân như vậy với chánh trí tuệ, sau khi từ bỏ loại xả thuộc loại đa chủng, y cứ đa chủng, đối với loại xả thuộc loại nhất chủng, y cứ nhất chủng, ở đây mọi chấp thủ đối với thế vật được đoạn trừ hoàn toàn, không có dư tàn, vị ấy tu tập loại xả như vậy.`, ref: "Trung Bộ 54 – Kinh Gia Chủ Potaliya", url: "https://loicuaducphat.org/mn/mn54.html#content" },

{ text: `“Này Gia chủ, ví như một người cầm một bó đuốc cỏ đang cháy rực đi ngược gió. Này Gia chủ, Ông nghĩ thế nào, nếu người ấy không vứt bỏ ngay bó đuốc ấy, bó đuốc cỏ đang cháy rực ấy có thể đốt cháy tay, hay đốt cháy cánh tay, hay đốt cháy một thân phần của người ấy, người ấy có thể do nhân duyên ấy, đi đến chết, hay đi đến khổ gần như chết không?” “Thưa có, bạch Thế Tôn.” … Cũng vậy, này Gia chủ, vị Thánh đệ tử suy nghĩ như sau: “Thế Tôn đã nói, dục được ví như bó đuốc cỏ, khổ nhiều, não nhiều, tai họa ở đây càng nhiều hơn”. Sau khi thấy như chân như vậy với chánh trí tuệ, sau khi từ bỏ loại xả thuộc loại đa chủng, y cứ đa chủng, đối với loại xả thuộc loại nhất chủng, y cứ nhất chủng, ở đây mọi chấp thủ đối với thế vật được đoạn trừ hoàn toàn, không có dư tàn, vị ấy tu tập loại xả như vậy.`, ref: "Trung Bộ 54 – Kinh Gia Chủ Potaliya", url: "https://loicuaducphat.org/mn/mn54.html#content" },

{ text: `“Này Gia chủ, ví như một hố than hừng, sâu hơn thân người, đầy những than hừng, cháy không thành ngọn, cháy không thành khói, và một người đi đến muốn sống, muốn không chết, muốn lạc, né tránh khổ. Nhưng có hai nhà lực sĩ, nắm chặt hai cánh tay người ấy và lôi người ấy đến hố than hừng. Này Gia chủ, Ông nghĩ thế nào? Người ấy có co rúm thân, vật qua vật lại phía này phía kia không?” “Bạch Thế Tôn, có. Vì sao vậy? Bạch Thế Tôn, vì người ấy biết: “Nếu ta rơi vào hố than hừng này, do nhân duyên này, ta sẽ đi đến chết hay đau khổ gần như chết. Cũng vậy, này Gia chủ, vị Thánh đệ tử suy nghĩ như sau: “Thế Tôn đã nói, dục được ví như hố than hừng, khổ nhiều, não nhiều, tai họa ở đây càng nhiều hơn”. Sau khi thấy như chân như vậy với chánh trí tuệ, sau khi từ bỏ loại xả thuộc loại đa chủng, y cứ đa chủng, đối với loại xả thuộc loại nhất chủng, y cứ nhất chủng, ở đây mọi chấp thủ đối với thế vật được đoạn trừ hoàn toàn, không có dư tàn, vị ấy tu tập loại xả như vậy.`, ref: "Trung Bộ 54 – Kinh Gia Chủ Potaliya", url: "https://loicuaducphat.org/mn/mn54.html#content" },

{ text: `Này Gia chủ, ví như có người mượn tài vật cho mượn như xe cộ xứng đáng bậc sang trọng, các đồ châu báu trang sức mỹ diệu, và với những đồ vật vay mượn ấy, người ấy đi vào chợ phố, được (tôn trọng) đi trước, được nhiều người vây quanh, và quần chúng thấy người ấy bèn nói: “Người này thật sự giàu sang, và người giàu sang hưởng thọ tài vật như vậy”. Nhưng những người chủ thấy người kia ở chỗ nào liền lấy lui những vật sở hữu của mình. Này Gia chủ, Ông nghĩ thế nào? Có phải sự (trá hình) dị tính của người kia được chấm dứt ở đây?” “Thưa vâng, bạch Thế Tôn. Vì sao vậy? Bạch Thế Tôn, vì những người chủ lấy lui những vật sở hữu của mình.” … Cũng vậy, này Gia chủ, vị Thánh đệ tử suy nghĩ như sau: “Thế Tôn đã nói, dục được ví như tài vật vay mượn, khổ nhiều, não nhiều, tai họa ở đây càng nhiều hơn”. Sau khi thấy như chân như vậy với chánh trí tuệ, sau khi từ bỏ loại xả thuộc loại đa chủng, y cứ đa chủng, đối với loại xả thuộc loại nhất chủng, y cứ nhất chủng, ở đây mọi chấp thủ đối với thế vật được đoạn trừ hoàn toàn, không có dư tàn, vị ấy tu tập loại xả như vậy.`, ref: "Trung Bộ 54 – Kinh Gia Chủ Potaliya", url: "https://loicuaducphat.org/mn/mn54.html#content" },

{ text: `Này Gia chủ, ví như gần thôn làng hay gần thị tứ có một nhóm rừng, ở đấy, có một cây đầy những trái chín, nhưng không có trái nào rơi xuống đất. Rồi một người đi đến, ước mong trái cây, tìm cầu trái cây, đi khắp đó đây để tìm trái cây. Người ấy đi sâu vào ngôi rừng ấy, thấy cây ấy đầy những trái chín. Người ấy có thể nghĩ như sau: “Cây này đầy những trái chín nhưng không có trái nào rơi xuống đất, nhưng ta biết leo cây. Vậy ta hãy leo lên cây ấy ăn cho thỏa thích và bọc đầy áo (để đem về). Rồi người ấy leo lên cây ấy, ăn cho thỏa thích và bọc đầy áo (để đem về). Rồi một người thứ hai đi đến, ước mong trái cây, tìm cầu trái cây, đi khắp đó đây để tìm trái cây, và tay mang một búa sắc bén. Người này đi sâu vào ngôi rừng ấy, thấy cây ấy đầy những trái chín. Người này có thể nghĩ như sau: “Cây này đầy những trái chín, nhưng không có trái nào rơi xuống đất. Nhưng ta không biết leo cây. Vậy ta hãy chặt cây này tận gốc, ăn cho thỏa thích, và bọc đầy áo (để đem về)”. Rồi người này chặt cây ấy tận gốc. Này Gia chủ, Ông nghĩ thế nào? Nếu người kia không leo xuống thật mau, thời cây ấy khi rơi đổ xuống, sẽ làm cho người thứ nhất, hoặc bị gãy tay, hoặc bị gãy chân, hoặc bị gãy một phần thân nào. Và do nhân duyên ấy, sẽ bị chết hay đi đến đau khổ gần như chết?” “Thưa vâng, bạch Thế Tôn.” “Cũng vậy, này Gia chủ, vị Thánh đệ tử suy nghĩ như sau: “Thế Tôn đã nói, dục được ví như cây có trái, khổ nhiều, não nhiều, tai họa ở đây càng nhiều hơn”. Sau khi thấy như chân như vậy với chánh trí tuệ, sau khi từ bỏ loại xả thuộc loại đa chủng, y cứ đa chủng, đối với loại xả thuộc loại nhất chủng, y cứ nhất chủng, ở đây mọi chấp thủ đối với thế vật được đoạn trừ hoàn toàn, không có dư tàn, vị ấy tu tập loại xả như vậy.`, ref: "Trung Bộ 54 – Kinh Gia Chủ Potaliya", url: "https://loicuaducphat.org/mn/mn54.html#content" },

{ text: `Ở đời, bỏ dục vọng,<br>Không nhà, sống xuất gia,<br>Ðoạn trừ dục và hữu,<br>Kẻ ấy Ta mới gọi,<br>Chánh danh Bà-la-môn.<br><br>Ở đời, bỏ tham ác,<br>Không nhà, sống xuất gia,<br>Ðoạn trừ ác và hữu,<br>Kẻ ấy Ta mới gọi,<br>Chánh danh Bà-la-môn.<br><br>Ai từ bỏ nhân ách,<br>Vượt qua cả thiên ách,<br>Ðoạn trừ mọi ách nạn,<br>Thoát ly mọi hệ phược,<br>Kẻ ấy Ta mới gọi,<br>Chánh danh Bà-la-môn.<br><br>Từ bỏ lạc, bất lạc,<br>Thanh lương, không y trú,<br>Chiến thắng mọi thế giới,<br>Bậc anh hùng dũng mãnh,<br>Kẻ ấy Ta mới gọi,<br>Chánh danh Bà-la-môn.<br><br>Ai biết thật đầy đủ,<br>Sự sanh diệt chúng sanh,<br>Không tham trước, Thiện Thệ,<br>Giác ngộ, đạt chánh giác,<br>Kẻ ấy Ta mới gọi,<br>Chánh danh Bà-la-môn.<br><br>Ai không có chấp trước,<br>Ðời trước, sau, đời này,<br>Không chấp, không sở hữu,<br>Kẻ ấy Ta mới gọi,<br>Chánh danh Bà-la-môn.<br><br>Ai biết được đời trước,<br>Thấy được thiện, ác thú,<br>Ðạt được sanh diệt đoạn,<br>Kẻ ấy Ta mới gọi,<br>Chánh danh Bà-la-môn.`, ref: "Trung Bộ 98 – Kinh Vāseṭṭha", url: "https://loicuaducphat.org/mn/mn98.html#content" },

{ text: `Này các Gia chủ, vì những vị Tôn giả Sa-môn, Bà-la-môn ấy không thấy sự nguy hiểm, sự hạ liệt, sự cấu uế của các bất thiện pháp, sự thoát ly, sự lợi ích và sự thanh tịnh của các thiện pháp.`, ref: "Trung Bộ 60 – Kinh Không Gì Chuyển Hướng", url: "https://loicuaducphat.org/mn/mn60.html#content" },


{ text: `Và này Thợ mộc, những bất thiện tư duy này sanh khởi như thế nào? Sự sanh khởi của chúng cũng được nói đến. Cần phải trả lời là từ tưởng sanh khởi. Thế nào là tưởng? Tưởng có nhiều loại, đa chủng, sai biệt: dục tưởng, sân tưởng, hại tưởng, từ đấy những bất thiện tư duy sanh khởi.`, ref: "Trung Bộ 78 – Ðại kinh Samanamandikà", url: "https://loicuaducphat.org/mn/mn78.html#content" },

{ text: `Và này Thợ mộc, những bất thiện tư duy này từ đâu được trừ diệt, không có dư tàn? Sự trừ diệt của chúng cũng được nói đến. Ở đây, này Thợ mộc, vị Tỷ-kheo ly dục, ly bất thiện pháp chứng và trú Thiền thứ nhất, một trạng thái hỷ lạc do ly dục sanh, với tầm, với tứ. Ở đây, những bất thiện tư duy được trừ diệt, không có dư tàn.`, ref: "Trung Bộ 78 – Ðại kinh Samanamandikà", url: "https://loicuaducphat.org/mn/mn78.html#content" },

{ text: `Và sự thực hành như thế nào, này Thợ mộc, là sự thực hành đưa đến diệt trừ các bất thiện tư duy? Ở đây, vị Tỷ-kheo khởi lên ý muốn nỗ lực, tinh tấn, quyết tâm, sách tấn tâm khiến cho các ác, bất thiện pháp chưa sanh không được sanh khởi … khiến cho các ác, bất thiện pháp đã sanh được trừ diệt; khiến cho các thiện pháp chưa sanh nay được sanh khởi; khởi lên ý muốn nỗ lực, tinh tấn, quyết tâm, sách tấn tâm; khiến cho các thiện pháp đã sanh có thể duy trì, không có mơ hồ, được tăng trưởng, được quảng đại, được tu tập, được viên mãn. Sự thực hành như vậy là sự thực hành đưa đến diệt trừ các bất thiện tư duy.`, ref: "Trung Bộ 78 – Ðại kinh Samanamandikà", url: "https://loicuaducphat.org/mn/mn78.html#content" },

{ text: `Này Thợ mộc, thế nào là thiện tư duy? Ly dục tư duy, vô sân tư duy, bất hại tư duy; những pháp này, này Thợ mộc, được gọi là thiện tư duy.`, ref: "Trung Bộ 78 – Ðại kinh Samanamandikà", url: "https://loicuaducphat.org/mn/mn78.html#content" },

{ text: `“Thế giới là thiếu thốn, khao khát, nô lệ cho tham ái”, thưa Ðại vương, đó là thuyết giáo Chánh pháp thứ tư, do Thế Tôn, bậc Tri Giả, Kiến Giả, bậc A-la-hán, Chánh Ðẳng Giác thuyết giảng. Do tôi biết, tôi thấy, tôi nghe thuyết giáo ấy, mà tôi xuất gia, từ bỏ gia đình, sống không gia đình.`, ref: "Trung Bộ 82 – Kinh Raṭṭḥapāla", url: "https://loicuaducphat.org/mn/mn82.html#content" },

{ text: `Hãy nhìn hình bóng trang sức này,<br>Một nhóm vết thương được tích tụ,<br>Bệnh nhiều, tham tưởng cũng khá nhiều,<br>Nhưng không gì kiên cố, thường trú.`, ref: "Trung Bộ 82 – Kinh Raṭṭḥapāla", url: "https://loicuaducphat.org/mn/mn82.html#content" },

{ text: `Hãy nhìn hình bóng trang sức này,<br>Một nhóm vết thương được tích tụ,<br>Bệnh nhiều, tham tưởng cũng khá nhiều,<br>Nhưng không gì kiên cố, thường trú.<br><br>Hãy nhìn dung mạo trang sức này,<br>Với các châu báu, với vòng tai,<br>Một bộ xương được da bao phủ,<br>Ðược y phục làm cho sáng chói.<br><br>Chân được sơn với son với sáp,<br>Mặt được thoa với phấn, với bột,<br>Vừa đủ làm mê hoặc kẻ ngu,<br>Nhưng vô phương kẻ cầu bờ giác.<br><br>Tóc được uốn bảy vòng, bảy lớp,<br>Mắt được xoa với thuốc, với son,<br>Vừa đủ làm mê hoặc kẻ ngu,<br>Nhưng vô phương kẻ cầu bờ giác.`, ref: "Trung Bộ 82 – Kinh Raṭṭḥapāla", url: "https://loicuaducphat.org/mn/mn82.html#content" },

{ text: `Như hộp thuốc trang hoàng mới mẻ,<br>Là uế thân được điểm thời trang,<br>Vừa đủ làm mê hoặc kẻ ngu,<br>Nhưng vô phương kẻ cầu bờ giác.<br><br>Người thợ săn đặt bày lưới sập,<br>Loài nai khôn chẳng chạm bén chân,<br>Ăn lúa xong, chúng ta lên đường,<br>Mặc cho kẻ bắt nai than khóc.`, ref: "Trung Bộ 82 – Kinh Raṭṭḥapāla", url: "https://loicuaducphat.org/mn/mn82.html#content" },

{ text: `Hãy nhìn hình bóng trang sức này,<br>Một nhóm vết thương được tích tụ,<br>Bệnh nhiều, tham tưởng cũng khá nhiều,<br>Nhưng không gì kiên cố, thường trú.<br><br>Hãy nhìn dung mạo trang sức này,<br>Với các châu báu, với vòng tai,<br>Một bộ xương được da bao phủ,<br>Ðược y phục làm cho sáng chói.<br><br>Chân được sơn với son với sáp,<br>Mặt được thoa với phấn, với bột,<br>Vừa đủ làm mê hoặc kẻ ngu,<br>Nhưng vô phương kẻ cầu bờ giác.<br><br>Tóc được uốn bảy vòng, bảy lớp,<br>Mắt được xoa với thuốc, với son,<br>Vừa đủ làm mê hoặc kẻ ngu,<br>Nhưng vô phương kẻ cầu bờ giác.<br><br>Như hộp thuốc trang hoàng mới mẻ,<br>Là uế thân được điểm thời trang,<br>Vừa đủ làm mê hoặc kẻ ngu,<br>Nhưng vô phương kẻ cầu bờ giác.<br><br>Người thợ săn đặt bày lưới sập,<br>Loài nai khôn chẳng chạm bén chân,<br>Ăn lúa xong, chúng ta lên đường,<br>Mặc cho kẻ bắt nai than khóc.`, ref: "Trung Bộ 82 – Kinh Raṭṭḥapāla", url: "https://loicuaducphat.org/mn/mn82.html#content" },
{ text: `Hãy nhìn dung mạo trang sức này,<br>Với các châu báu, với vòng tai,<br>Một bộ xương được da bao phủ,<br>Ðược y phục làm cho sáng chói.`, ref: "Trung Bộ 82 – Kinh Raṭṭḥapāla", url: "https://loicuaducphat.org/mn/mn82.html#content" },

{ text: `Chân được sơn với son với sáp,<br>Mặt được thoa với phấn, với bột,<br>Vừa đủ làm mê hoặc kẻ ngu,<br>Nhưng vô phương kẻ cầu bờ giác.`, ref: "Trung Bộ 82 – Kinh Raṭṭḥapāla", url: "https://loicuaducphat.org/mn/mn82.html#content" },

{ text: `Tóc được uốn bảy vòng, bảy lớp,<br>Mắt được xoa với thuốc, với son,<br>Vừa đủ làm mê hoặc kẻ ngu,<br>Nhưng vô phương kẻ cầu bờ giác.`, ref: "Trung Bộ 82 – Kinh Raṭṭḥapāla", url: "https://loicuaducphat.org/mn/mn82.html#content" },

{ text: `Như hộp thuốc trang hoàng mới mẻ,<br>Là uế thân được điểm thời trang,<br>Vừa đủ làm mê hoặc kẻ ngu,<br>Nhưng vô phương kẻ cầu bờ giác.`, ref: "Trung Bộ 82 – Kinh Raṭṭḥapāla", url: "https://loicuaducphat.org/mn/mn82.html#content" },

{ text: `Người thợ săn đặt bày lưới sập,<br>Loài nai khôn chẳng chạm bén chân,<br>Ăn lúa xong, chúng ta lên đường,<br>Mặc cho kẻ bắt nai than khóc.`, ref: "Trung Bộ 82 – Kinh Raṭṭḥapāla", url: "https://loicuaducphat.org/mn/mn82.html#content" },


{ text: `Dục vọng nhiều loại, ngọt, khả ái,<br>Nhiễu loạn tâm dưới nhiều hình thức,<br>Thấy hoạn nạn trong dục trưởng dưỡng,<br>Nên tôi xuất gia, tâu Ðại vương!<br>Như quả từ đây, người bị rụng,<br>Cả già lẫn trẻ, khi thân hoại,<br>Do thấy chính vậy, tôi xuất gia,<br>Hạnh Sa-môn phải là tối thắng,<br>Thưa Ðại vương!`, ref: "Trung Bộ 82 – Kinh Raṭṭḥapāla", url: "https://loicuaducphat.org/mn/mn82.html#content" },
{ text: `Ai trước phóng dật, sau không phóng dật,<br>Sáng chói đời này, như trăng thoát mây,<br>Ai làm ác nghiệp, nhờ thiện chặn lại,<br>Sáng chói đời này, như trăng thoát mây.`, ref: "Trung Bộ 86 – Kinh Aṅgulimāla", url: "https://loicuaducphat.org/mn/mn86.html#content" },

{ text: `Kẻ ngu vô trí, đam mê phóng dật,<br>Còn người có trí, giữ không phóng dật,<br>Như giữ tài sản, tối thượng, tối quý,<br>Chớ mê phóng dật, chớ mê dục lạc.`, ref: "Trung Bộ 86 – Kinh Aṅgulimāla", url: "https://loicuaducphat.org/mn/mn86.html#content" },

{ text: `Này các Tỷ-kheo, các dục là vô thường, trống rỗng, giả dối, thuộc ngu si tánh. Này các Tỷ-kheo, đây là lời chào xáo của kẻ ngu xây dựng trên giả dối. Các dục hiện tại, và các dục tương lai, các dục tưởng hiện tại và các dục tưởng tương lai, cả hai đều thuộc lãnh vực của ma, là cảnh giới của ma, là chỗ dinh dưỡng của ma, là chỗ ăn uống của ma.`, ref: "Trung Bộ 106 – Kinh Bất Động Lợi Ích", url: "https://loicuaducphat.org/mn/mn106.html#content" },

{ text: `Ở đây, các ác bất thiện ý này dẫn đến tham dục, sân hận, khích động, và chính những pháp ấy tác thành chướng ngại ở đây cho Thánh đệ tử học tập. Ở đây, này các Tỷ-kheo, vị Thánh đệ tử suy nghĩ như sau: “Các dục hiện tại, và các dục tương lai, các dục tưởng hiện tại và các dục tưởng tương lai, cả hai đều thuộc lãnh vực của ma, là cảnh giới của ma, là chỗ dinh dưỡng của ma, là chỗ ăn uống của ma. Vậy ta hãy an trú với tâm quảng đại, đại hành, sau khi chiến thắng thế giới, sau khi xác định vị trí của ý. Khi ta an trú với tâm quảng đại, đại hành chiến thắng thế giới, xác định vị trí của ý, các ác bất thiện ý: tham dục, sân hận, khích động sẽ không khởi lên; với các pháp ấy được đoạn trừ, tâm của ta không trở thành hạn hẹp, trái lại thành vô lượng, khéo tu tập”.`, ref: "Trung Bộ 106 – Kinh Bất Động Lợi Ích", url: "https://loicuaducphat.org/mn/mn106.html#content" },

{ text: `Lại nữa này các Tỷ-kheo, vị Thánh đệ tử suy nghĩ như sau: “Những dục hiện tại và những dục tương lai, những dục tưởng hiện tại, và những dục tưởng tương lai, phàm bất cứ sắc pháp gì, là bốn đại chủng và sắc do bốn đại tạo thành”. Trong khi vị ấy hành trì như vậy, an trú nhiều lần như vậy, tâm trở thành an tịnh trong giới xứ (của nó). Với tâm an tịnh, vị ấy thành tựu Bất động ngay trong hiện tại hay thiên nặng về trí tuệ. Sau khi thân hoại mạng chung, sự tình này xảy ra, thức diễn tiến ấy có thể tùy theo đây đạt đến Bất động.`, ref: "Trung Bộ 106 – Kinh Bất Động Lợi Ích", url: "https://loicuaducphat.org/mn/mn106.html#content" },

{ text: `Lại nữa này các Tỷ-kheo, vị Thánh đệ tử suy nghĩ như sau: “Những dục hiện tại và những dục tương lai, những dục tưởng hiện tại và những dục tưởng tương lai, những sắc pháp hiện tại và những sắc pháp tương lai, những sắc tưởng hiện tại và những sắc tưởng tương lai, cả hai đều vô thường. Cái gì vô thường thời không đáng để được hoan hỷ, không đáng để được hoan nghênh, không đáng để được chấp trước”. Trong khi vị ấy hành trì như vậy, an trú nhiều lần như vậy, tâm trí trở thành an tịnh trong giới xứ (của nó). Với tâm an tịnh, vị ấy thành tựu Bất động ngay trong hiện tại hay thiên nặng về trí tuệ. Sau khi thân hoại mạng chung, sự tình này xảy ra, thức diễn tiến ấy có thể tùy theo đây đạt đến Bất động.`, ref: "Trung Bộ 106 – Kinh Bất Động Lợi Ích", url: "https://loicuaducphat.org/mn/mn106.html#content" },

{ text: `“Hãy đến Tỷ-kheo, hãy hộ trì các căn, khi mắt thấy sắc chớ có nắm giữ tướng chung, chớ có nắm giữ tướng riêng. Những nguyên nhân gì, vì nhãn căn không được chế ngự khiến tham ái, ưu bi, các ác bất thiện pháp khởi lên, vị Tỷ-kheo tự chế ngự nguyên nhân ấy, hộ trì con mắt, thực hành sự hộ trì con mắt. Khi tai nghe tiếng … mũi ngửi hương … lưỡi nếm vị. Thân cảm xúc … ý nhận thức các pháp, vị ấy không nắm giữ tướng chung, không nắm giữ tướng riêng. Những nguyên nhân gì, vì ý căn không được chế ngự, khiến tham ái, ưu bi, các pháp ác bất thiện khởi lên, Tỷ-kheo chế ngự nguyên nhân ấy, hộ trì ý căn, thực hành sự hộ trì ý căn”.`, ref: "Trung Bộ 107 – Kinh Ganaka Moggallāna", url: "https://loicuaducphat.org/mn/mn107.html#content" },

{ text: `Này Ānanda, Ta không quán thấy một sắc pháp nào trong ấy có hoan hỷ, trong ấy có hoan lạc, chịu sự biến dịch, chịu sự đổi khác mà không khởi lên sầu, bi, khổ, ưu, não.`, ref: "Trung Bộ 122 – Kinh Đại Không", url: "https://loicuaducphat.org/mn/mn122.html#content" },

{ text: `Này Ānanda, vị ấy suy nghĩ: “Ðối với những suy tầm hạ liệt, đê tiện, phàm phu, không thuộc bậc Thánh, không liên hệ đến mục đích, không đưa đến yếm ly, ly tham, đoạn diệt, an tịnh, thắng trí, giác ngộ, Niết-bàn, như là dục tầm, sân tầm, hại tầm, ta sẽ không suy nghĩ các loại suy tầm ấy”. Ở đây, vị ấy ý thức rõ ràng như vậy.`, ref: "Trung Bộ 122 – Kinh Đại Không", url: "https://loicuaducphat.org/mn/mn122.html#content" },

{ text: `Này Ānanda, đối với những suy tầm này, thuộc bậc Thánh, có khả năng cầu tiến, hướng dẫn đến sự đoạn trừ hoàn toàn đau khổ, như là ly dục tầm, vô sân tầm, bất hại tầm, vị ấy nghĩ: “Ta sẽ suy tư các loại suy tầm này”. Ở đây, vị ấy ý thức rõ ràng như vậy.`, ref: "Trung Bộ 122 – Kinh Đại Không", url: "https://loicuaducphat.org/mn/mn122.html#content" },


{ text: `Này Aggivessana, nào có lợi ích gì? Vương tử Jayasenna sống giữa các dục, thọ hưởng các dục, bị tư tưởng dục nhai nghiến, bị nhiệt não dục thiêu đốt, tha thiết truy cầu dục, lại có thể biết, có thể thấy, hay có thể chứng quả vị chỉ có ly dục mới biết được, chỉ có ly dục mới thấy được. Chỉ có ly dục mới đạt được, hay chỉ có ly dục mới chứng được; sự kiện như vậy không xảy ra.`, ref: "Trung Bộ 125 – Kinh Ðiều Ngự Địa", url: "https://loicuaducphat.org/mn/mn125.html#content" },


{ text: `Dầu Thiên sứ báo động,<br>Thanh niên vẫn phóng dật,<br>Họ ưu buồn lâu dài,<br>Sanh làm người hạ liệt.<br>Ở đây bậc Chân nhân,<br>Ðược Thiên sứ báo động,<br>Không bao giờ phóng dật,<br>Trong diệu pháp bậc Thánh.<br>Thấy sợ trong chấp thủ,<br>Trong hiện hữu sanh tử.<br>Ðược giải thoát chấp thủ,<br>Sanh tử được đoạn trừ,<br>Ðược yên ổn an lạc,<br>Ngay hiện tại tịch tịnh,<br>Mọi oán hận sợ hãi,<br>Các vị ấy vượt qua,<br>Mọi đau đớn sầu khổ,<br>Thảy đều được siêu thoát.`, ref: "Trung Bộ 130 – Kinh Thiên Sứ", url: "https://loicuaducphat.org/mn/mn130.html#content" },
{ text: `Quá khứ không truy tìm<br>Tương lai không ước vọng.<br>Quá khứ đã đoạn tận,<br>Tương lai lại chưa đến,<br>Chỉ có pháp hiện tại<br>Tuệ quán chính ở đây.<br>Không động, không rung chuyển<br>Biết vậy, nên tu tập,<br>Hôm nay nhiệt tâm làm,<br>Ai biết chết ngày mai?<br>Không ai điều đình được,<br>Với đại quân thần chết,<br>Trú như vậy nhiệt tâm,<br>Ðêm ngày không mệt mỏi,<br>Xứng gọi Nhất dạ Hiền,<br>Bậc an tịnh, trầm lặng.`, ref: "Trung Bộ 131 – Kinh Nhất Dạ Hiền Giả", url: "https://loicuaducphat.org/mn/mn131.html#content" },

{ text: `Và tham ái vô trí thức trước của nó, thuộc tham dục, tham nhiễm; pháp ấy được đoạn tận, chặt tận gốc rễ, làm cho như thân cây tala, không thể hiện hữu nữa trong tương lai, không có khả năng sanh khởi nữa. Và sự phẫn nộ vô trí thức trước của nó, thuộc sân hận, thuộc tội quá; pháp ấy được đoạn tận, cắt tận gốc rễ, làm cho như thân cây tala, không thể hiện hữu nữa trong tương lai, không có khả năng sanh khởi nữa. Và vô minh vô trí thức trước của nó, thuộc si mê, thuộc tội quá; pháp ấy được đoạn tận, cắt tận gốc rễ, làm cho như thân cây tala, không thể hiện hữu trong tương lai, không có khả năng sanh khởi nữa. Do vậy, Tỷ-kheo thành tựu như vậy là thành tựu tối thắng tịch tịnh thắng xứ. Này Tỷ-kheo, như vậy là tối thắng Thánh tịch tịnh, tức là sự tịch tịnh tham sân si.`, ref: "Trung Bộ 140 – Kinh Giới Phân Biệt", url: "https://loicuaducphat.org/mn/mn140.html#content" },

{ text: `Lại nữa, này Sāriputta, Tỷ-kheo cần phải suy tư như sau: “Ta đã đoạn tận năm dục trưởng dưỡng chưa? Này Sāriputta, nếu Tỷ-kheo, trong khi suy tư được biết như sau: “Ta chưa đoạn tận năm dục trưởng dưỡng”, thời này Sāriputta, Tỷ-kheo ấy phải tinh tấn đoạn tận năm dục trưởng dưỡng. Nhưng nếu, này Sāriputta, Tỷ-kheo trong khi suy tư được biết như sau: “Ta đã đoạn tận năm dục trưởng dưỡng”, thời này Sāriputta, Tỷ-kheo ấy phải an trú với hỷ và hân hoan ngày đêm tu học trong các thiện pháp.`, ref: "Trung Bộ 151 – Kinh Khất Thực Thanh Tịnh", url: "https://loicuaducphat.org/mn/mn151.html#content" },

{ text: `- Thưa Tôn giả, làm sao Ngài vượt khỏi bộc lưu?<br>- Này Hiền giả, không đứng lại, không bước tới, Ta vượt khỏi bộc lưu.<br>- Thưa Tôn giả, làm sao không đứng lại, không bước tới, Ngài vượt khỏi bộc lưu?<br>- Này Hiền giả, khi Ta đứng lại, thời Ta chìm xuống. Này Hiền giả, khi Ta bước tới, thời Ta trôi giạt; do vậy, này Hiền giả, không đứng lại, không bước tới, Ta vượt khỏi bộc lưu.<br>(Vị Thiên):<br>Từ lâu, tôi mới thấy<br>Bà-la-môn tịch tịnh.<br>Không đứng, không bước tới,<br>Vượt chấp trước ở đời.`, ref: "Tương Ưng Bộ 1.1", url: "https://loicuaducphat.org/sn/sn1.1.html#content" },

{ text: `- Thưa Tôn giả, Ngài có biết giải thoát, thoát ly, viễn ly cho các chúng sanh không?<br>- Này Hiền giả, Ta có biết giải thoát, thoát ly, viễn ly cho các chúng sanh.<br>- Thưa Tôn giả, như thế nào Ngài biết giải thoát, thoát ly, viễn ly cho các chúng sanh?<br>Hỷ, tái sanh đoạn tận,<br>Tưởng, thức được trừ diệt,<br>Các thọ diệt, tịch tịnh,<br>Như vậy này Hiền giả,<br>Ta biết sự giải thoát,<br>Thoát ly và viễn ly,<br>Cho các loại chúng sanh.`, ref: "Tương Ưng Bộ 1.2", url: "https://loicuaducphat.org/sn/sn1.2.html#content" },

{ text: `… Ðứng một bên, vị Thiên ấy nói lên bài kệ này trước mặt Thế Tôn:<br>Mạng sống bị dắt dẫn,<br>Tuổi thọ chẳng là bao,<br>Bị dẫn đến già nua,<br>Không có nơi dừng bước.<br>Ai đem tâm quán tưởng,<br>Sợ hãi tử vong này,<br>Hãy làm các công đức,<br>Ðưa đến chơn an lạc.<br><br>(Thế Tôn):<br>Mạng sống bị dắt dẫn,<br>Tuổi thọ chẳng là bao,<br>Bị dẫn đến già nua,<br>Không có nơi dừng bước.<br>Ai đem tâm quán tưởng,<br>Sợ hãi tử vong này,<br>Hãy bỏ mọi thế lợi,<br>Tâm hướng cầu tịch tịnh.`, ref: "Tương Ưng Bộ 1.3", url: "https://loicuaducphat.org/sn/sn1.3.html#content" },

{ text: `Những ai đối các pháp,<br>Quá đắm say mê loạn,<br>Bị hướng dẫn lầm lạc,<br>Vòng quanh các dị giáo,<br>Họ mê ngủ triền miên,<br>Họ không có tỉnh giác,<br>Nay thật đã đến thời,<br>Họ cần phải thức tỉnh.<br><br>(Thế Tôn):<br>Những ai đối các pháp,<br>Không đắm say mê loạn,<br>Không bị dẫn lầm lạc,<br>Vòng quanh các dị giáo,<br>Họ chứng Chánh đẳng giác.<br>Họ liễu tri viên mãn,<br>Trên đường không thăng bằng,<br>Họ bước thật thăng bằng.`, ref: "Tương Ưng Bộ 1.8", url: "https://loicuaducphat.org/sn/sn1.8.html#content" },

{ text: `- Này Hiền giả, ta không bỏ hiện tại và chạy theo những gì bị thời gian chi phối. Và này Hiền giả, chính ta bỏ những gì bị thời gian chi phối để chạy theo hiện tại. Này Hiền giả, Thế Tôn đã nói, các dục bị thời gian chi phối, nhiều khổ đau, nhiều phiền não (Upàyàsà); nguy hiểm ở đấy càng nhiều hơn. Còn pháp này thuộc về hiện tại, không bị thời gian chi phối, đến để mà thấy, có khả năng hướng thượng, chỉ người trí mới tự mình giác hiểu.`, ref: "Tương Ưng Bộ 1.20", url: "https://loicuaducphat.org/sn/sn1.20.html#content" },

{ text: `… (Nhân duyên ở Sāvatthi). Ðứng một bên, vị Thiên ấy nói lên bài kệ này trước mặt Thế Tôn:<br>Như kiếm đã chạm da,<br>Như lửa cháy trên đầu,<br>Tỷ-kheo hãy chánh niệm,<br>Xuất gia bỏ ái dục.<br><br>(Thế Tôn):<br>Như kiếm đã chạm da,<br>Như lửa cháy trên đầu,<br>Tỷ-kheo hãy chánh niệm,<br>Xuất gia bỏ thân kiến.`, ref: "Tương Ưng Bộ 1.21", url: "https://loicuaducphat.org/sn/sn1.21.html#content" },

{ text: `Nội triền và ngoại triền,<br>Chúng sanh bị triền phược,<br>Con hỏi Gotama,<br>Ai thoát khỏi triền này?<br><br>(Thế Tôn):<br>Người trú giới có trí,<br>Tu tập tâm và tuệ,<br>Nhiệt tâm và thận trọng,<br>Tỷ-kheo ấy thoát triền.<br>Với ai, đã từ bỏ<br>Tham, sân và vô minh,<br>Bậc Lậu tận, Ứng cúng,<br>Vị ấy thoát triền phược.<br>Chỗ nào danh và sắc,<br>Ðược đoạn tận, vô dư,<br>Ðoạn chướng ngại, sắc tưởng,<br>Chỗ ấy triền phược đoạn.`, ref: "Tương Ưng Bộ 1.23", url: "https://loicuaducphat.org/sn/sn1.23.html#content" },

{ text: `Chỗ nào ý chế ngự,<br>Chỗ ấy đau khổ tận.<br>Ý chế ngự hoàn toàn,<br>Thoát đau khổ hoàn toàn.<br><br>(Thế Tôn):<br>Không nên chế ngự ý,<br>Hoàn toàn về mọi mặt,<br>Chớ có chế ngự ý,<br>Nếu tự chủ đạt được.<br>Chỗ nào ác pháp khởi,<br>Chỗ ấy chế ngự ý.`, ref: "Tương Ưng Bộ 1.24", url: "https://loicuaducphat.org/sn/sn1.24.html#content" },

{ text: `Bốn bánh xe, chín cửa,<br>Ðầy uế, hệ lụy tham,<br>Chìm đắm trong bùn nhơ,<br>Ôi, thưa bậc Ðại Hùng,<br>Sanh thú người như vậy,<br>Tương lai sẽ thế nào?<br><br>(Thế Tôn):<br>Cắt hỷ và buộc ràng,<br>Dục tham và tà ác,<br>Ái căn được đoạn tận,<br>Sanh thú sẽ như vậy.`, ref: "Tương Ưng Bộ 1.29", url: "https://loicuaducphat.org/sn/sn1.29.html#content" },

{ text: `Ðứng một bên, một vị Thiên nói lên bài kệ này trước mặt Thế Tôn:<br>Giữa loài Người chúng ta,<br>Có các dục vô thường.<br>Ai hưởng chúng ở đời,<br>Bị chúng trói, chúng buộc.<br>Phóng dật đối với chúng,<br>Khó thoát ly với chúng,<br>Người nào khó thoát ly,<br>Bị thần chết chinh phục.<br>Họa từ dục vọng sanh,<br>Khổ từ dục vọng khởi,<br>Dục vọng được nhiếp phục,<br>Nhờ vậy họa nhiếp phục,<br>Tai họa được nhiếp phục,<br>Nhờ vậy khổ nhiếp phục.<br>Vật sai biệt ở đời,<br>Chúng không phải các dục,<br>Chính tư niệm tham ái,<br>Là dục vọng con người.<br>Vật sai biệt tồn tại,<br>Như vậy ở trên đời,<br>Do vậy bậc Hiền trí,<br>Ðiều phục các dục vọng.<br>Hãy từ bỏ phẫn nộ,<br>Hãy nhiếp phục kiêu mạn,<br>Hãy vượt qua tất cả,<br>Mọi kiết sử trói buộc.<br>Chớ có quá chấp trước,<br>Ðối với danh sắc ấy,<br>Khổ không thể đến được,<br>Với ai không có gì.<br>Hãy từ bỏ tính toán,<br>Không chạy theo hư tưởng,<br>Cắt đứt mọi tham ái,<br>Với danh sắc ở đời.<br>Vị ấy đoạn phiền trược,<br>Không lo âu, không ái;<br>Chư Thiên và loài Người,<br>Ðời này hay đời sau,<br>Ở cảnh giới chư Thiên,<br>Hay tại mọi trú xứ,<br>Tìm cầu nhưng không gặp,<br>Vết tích của vị ấy,<br>Họ tìm nhưng không thấy,<br>Vị giải thoát như vậy.`, ref: "Tương Ưng Bộ 1.34", url: "https://loicuaducphat.org/sn/sn1.34.html#content" },

{ text: `- Cái gì sanh thành người?<br>Cái gì luôn dong ruổi?<br>Cái gì chịu luân hồi?<br>Cái gì người sợ hãi?<br>- Ái dục sanh thành người,<br>Chính tâm luôn dong ruổi,<br>Chúng sanh chịu luân hồi,<br>Ðau khổ, người sợ hãi.`, ref: "Tương Ưng Bộ 1.55", url: "https://loicuaducphat.org/sn/sn1.55.html#content" },

{ text: `- Cái gì sanh thành người?<br>Cái gì luôn dong ruổi?<br>Cái gì chịu luân hồi?<br>Vì đâu, không giải thoát?<br>- Ái dục sanh thành người,<br>Chính tâm luôn dong ruổi,<br>Chúng sanh chịu luân hồi,<br>Vì khổ, không giải thoát.`, ref: "Tương Ưng Bộ 1.56", url: "https://loicuaducphat.org/sn/sn1.56.html#content" },

{ text: `- Cái gì sanh thành người?<br>Cái gì luôn dong ruổi?<br>Cái gì chịu luân hồi?<br>Cái gì người nương tựa?<br>- Ái dục sanh thành người,<br>Chính tâm luôn dong ruổi,<br>Chúng sanh chịu luân hồi,<br>Chính nghiệp, người nương tựa.`, ref: "Tương Ưng Bộ 1.57", url: "https://loicuaducphat.org/sn/sn1.57.html#content" },

{ text: `- Cái gì gọi phi đạo?<br>Cái gì diệt ngày đêm?<br>Cái gì uế Phạm hạnh?<br>Cái gì tắm không nước?<br>- Tham dục gọi phi đạo,<br>Tuổi tác diệt ngày đêm,<br>Nữ nhân uế Phạm hạnh,<br>Khiến loài Người hệ lụy,<br>Khổ hạnh và Phạm hạnh,<br>Là tắm không cần nước.`, ref: "Tương Ưng Bộ 1.58", url: "https://loicuaducphat.org/sn/sn1.58.html#content" },


{ text: `- Vật gì trói buộc đời?<br>Vật gì dẫn hành đời?<br>Do đoạn trừ pháp gì,<br>Mới được gọi Niết-bàn?<br>- Chính hỷ trói buộc đời,<br>Tầm cầu dẫn hành đời,<br>Do đoạn trừ khát ái,<br>Mới được gọi Niết-bàn.`, ref: "Tương Ưng Bộ 1.64", url: "https://loicuaducphat.org/sn/sn1.64.html#content" },

{ text: `- Vật gì triền phược đời?<br>Vật gì dẫn hành đời?<br>Do đoạn trừ pháp gì,<br>Mọi triền phược đoạn diệt?<br>- Chính hỷ triền phược đời,<br>Tầm cầu dẫn hành đời,<br>Do đoạn trừ khát ái,<br>Mọi triền phược đoạn diệt.`, ref: "Tương Ưng Bộ 1.65", url: "https://loicuaducphat.org/sn/sn1.65.html#content" },

{ text: `- Vật gì áp đảo đời?<br>Vật gì bao phủ đời?<br>Tên gì bắn trúng đời?<br>Bởi gì thường huân tập?<br>- Sự chết áp đảo đời,<br>Già nua bao phủ đời,<br>Tên ái bắn trúng đời,<br>Bởi dục, thường huân tập.`, ref: "Tương Ưng Bộ 1.66", url: "https://loicuaducphat.org/sn/sn1.66.html#content" },

{ text: `- Vật gì treo cột đời?<br>Vật gì bao phủ đời?<br>Vật gì đóng kín đời?<br>Trên gì đời an trú?<br>- Khát ái treo cột đời,<br>Già nua bao phủ đời,<br>Sự chết đóng kín đời,<br>Trên khổ, đời an trú.`, ref: "Tương Ưng Bộ 1.67", url: "https://loicuaducphat.org/sn/sn1.67.html#content" },

{ text: `- Vật gì đóng kín đời?<br>Trên gì đời an trú?<br>Vật gì treo cột đời?<br>Vật gì bao phủ đời?<br>- Sự chết đóng kín đời,<br>Trên khổ, đời an trú,<br>Khát ái treo cột đời,<br>Già nua bao phủ đời.`, ref: "Tương Ưng Bộ 1.68", url: "https://loicuaducphat.org/sn/sn1.68.html#content" },

{ text: `- Vật gì trói buộc đời?<br>Ðiều phục gì được thoát?<br>Vật gì được đoạn trừ,<br>Khiến mọi phược đoạn tận?<br>- Ước muốn trói buộc đời,<br>Ðiều phục dục được thoát,<br>Ước muốn được đoạn trừ,<br>Mọi triền phược đoạn tận.`, ref: "Tương Ưng Bộ 1.69", url: "https://loicuaducphat.org/sn/sn1.69.html#content" },

{ text: `- Ai già, ai không già?<br>Thế nào gọi phi đạo?<br>Vật gì chướng ngại pháp?<br>Vật gì đêm ngày diệt?<br>Vật gì uế Phạm hạnh?<br>Vật gì tắm không nước?<br>Ðời bao nhiêu lỗ trống,<br>Trên ấy, tâm không trú?<br>Con đến hỏi Thế Tôn,<br>Mong biết câu trả lời!<br>- Sắc hữu tình bị già,<br>Danh tánh lại không già,<br>Tham dục gọi phi đạo,<br>Tham ái, chướng ngại pháp.<br>Tuổi tác đêm, ngày diệt,<br>Nữ nhân uế Phạm hạnh,<br>Ðắm trước trong uế này,<br>Là toàn thể chúng sanh.<br>Khổ hạnh và Phạm hạnh,<br>Là tắm không cần nước,<br>Sáu lỗ trống ở đời,<br>Trên ấy, tâm không trú,<br>Biếng nhác và phóng dật,<br>Uể oải, không tự chế,<br>Thụy miên và hôn trầm,<br>Cả sáu lỗ trống này,<br>Cần ly khai tất cả.`, ref: "Tương Ưng Bộ 1.76", url: "https://loicuaducphat.org/sn/sn1.76.html#content" },

{ text: `Ðứng một bên, Thiên tử Tàyana nói lên bài kệ này trước Thế Tôn:<br><br>Ôi này Bà-la-môn,<br>Tinh tấn, cắt dòng nước,<br>Ðoạn trừ và tiêu diệt,<br>Mọi tham đắm dục vọng.<br>Ẩn sĩ không đoạn dục,<br>Không chứng được nhất tâm.<br>Nếu làm việc phải làm,<br>Cần kiên trì, tinh tấn.<br>Xuất gia, nếu biếng nhác,<br>Càng tung vãi bụi trần.<br>Không làm, hơn làm dở,<br>Làm dở sau khổ đau.<br>Ðã làm nên làm tốt,<br>Làm tốt không khổ đau.<br>Như nắm vụng lá cỏ,<br>Có thể bị đứt tay.<br>Sa-môn hạnh vụng tu,<br>Kéo đến cõi địa ngục.<br>Mọi sở hành biếng nhác,<br>Mọi hạnh tu ô nhiễm,<br>Ác hạnh trong Phạm hạnh,<br>Không đưa đến quả lớn.`, ref: "Tương Ưng Bộ 2.8", url: "https://loicuaducphat.org/sn/sn2.8.html#content" },

{ text: `Ðứng một bên, Thiên tử Candana nói lên bài kệ với Thế Tôn:<br>Làm sao vượt bộc lưu,<br>Ngày đêm vững, kiên trì,<br>Không trú, không bám víu,<br>Ai không chìm vực sâu?<br><br>(Thế Tôn):<br>Vị luôn luôn trì giới,<br>Trí tuệ, khéo định tĩnh,<br>Chí siêng năng dõng mãnh,<br>Vượt bộc lưu khó vượt.<br>Vị đoạn, ly dục tưởng,<br>Vượt khỏi sắc triền phược,<br>Ðoạn tận hỷ, hữu ái,<br>Không chìm xuống vực sâu.`, ref: "Tương Ưng Bộ 2.15", url: "https://loicuaducphat.org/sn/sn2.15.html#content" },
{ text: `Ðứng một bên, Thiên tử Sudatta nói lên bài kệ này trước mặt Thế Tôn:<br>Như kiếm đã chạm da,<br>Như lửa cháy trên đầu,<br>Tỷ-kheo hãy chánh niệm,<br>Xuất gia, bỏ ái dục.<br><br>(Thế Tôn):<br>Như kiếm đã chạm da,<br>Như lửa cháy trên đầu,<br>Tỷ-kheo hãy chánh niệm,<br>Xuất gia, bỏ thân kiến.`, ref: "Tương Ưng Bộ 2.16", url: "https://loicuaducphat.org/sn/sn2.16.html#content" },

{ text: `Ðứng một bên, Thiên tử Subrahmà nói lên bài kệ với Thế Tôn:<br>Tâm này thường sợ hãi,<br>Ý này thường dao động,<br>Ðiều mong ước không khởi,<br>Ðiều không mong lại khởi,<br>Nếu có, không sợ hãi,<br>Hãy nói điều con hỏi.<br><br>(Thế Tôn):<br>Không ngoài hạnh giác chi,<br>Không ngoài hộ trì căn,<br>Không ngoài bỏ tất cả,<br>Ta thấy các pháp ấy,<br>Ðưa đến sự an toàn,<br>Cho tất cả chúng sanh.`, ref: "Tương Ưng Bộ 2.17", url: "https://loicuaducphat.org/sn/sn2.17.html#content" },

{ text: `Ðứng một bên, Thiên tử Uttara nói lên bài kệ này trước mặt Thế Tôn:<br>Mạng sống bị dắt dẫn,<br>Tuổi thọ chẳng là bao,<br>Bị dẫn đến già nua,<br>Không có nơi dừng bước.<br>Ai đem tâm quán tưởng,<br>Sợ hãi tử vong này,<br>Hãy làm các công đức,<br>Ðưa đến chơn an lạc.<br><br>Mạng sống bị dắt dẫn,<br>Tuổi thọ chẳng là bao,<br>Bị dẫn đến già nua,<br>Không có nơi dừng bước.<br>Ai đem tâm quán tưởng,<br>Sợ hãi tử vong này,<br>Hãy bỏ mọi thế lợi,<br>Tâm hướng cầu tịch tịnh.`, ref: "Tương Ưng Bộ 2.19", url: "https://loicuaducphat.org/sn/sn2.19.html#content" },

{ text: `Bốn bánh xe chín cửa,<br>Ðầy uế, hệ lụy tham,<br>Chìm đắm trong bùn nhơ,<br>Ôi! Thưa bậc Ðại Hùng,<br>Sanh thú Người như vậy,<br>Tương lai sẽ thế nào?<br><br>(Thế Tôn):<br><br>Cắt hỷ và buộc ràng,<br>Dục tham và tà ác,<br>Ái căn được đoạn tận,<br>Sanh thú sẽ như vậy.`, ref: "Tương Ưng Bộ 2.28", url: "https://loicuaducphat.org/sn/sn2.28.html#content" },

{ text: `Rồi Thế Tôn biết được chính là Ác ma, liền nói lên bài kệ cho Ác ma:<br><br>Phàm những sắc pháp gì,<br>Ðời này hay đời sau,<br>Với màu sắc thù diệu,<br>Chói sáng giữa hư không,<br>Tất cả những sắc ấy,<br>Ðược Ma vương tán thán,<br>Chúng chỉ là bẫy mồi,<br>Quăng ra để diệt cá.`, ref: "Tương Ưng Bộ 2.30", url: "https://loicuaducphat.org/sn/sn2.30.html#content" },

{ text: `Tham, sân, si ba pháp,<br>Là ác tâm cho người,<br>Chúng di hại tự ngã,<br>Chúng tác thành tự ngã,<br>Như vỏ và lõi cây,<br>Tự tác thành trái cây.`, ref: "Tương Ưng Bộ 3.2", url: "https://loicuaducphat.org/sn/sn3.2.html#content" },

{ text: `Thật sự là vậy, thưa Ðại vương. Ít thay là những người trong đời này, sau khi được tài sản phong phú, dồi dào, lại có thể không bị lôi cuốn, không bị chìm đắm, không bị say mê trong các dục và không có những hành vi không tốt đẹp đối với người khác. Trái lại, thật là nhiều thay những người trong đời này, sau khi được tài sản phong phú, dồi dào, có thể bị lôi cuốn, bị chìm đắm, bị say mê trong các dục và có những hành vi không tốt đẹp đối với các người khác.<br><br>Loài người bị đắm say,<br>Trong tài sản, trong dục,<br>Họ tham lam, điên dại,<br>Trong các dục ở đời,<br>Không ý thức rõ ràng,<br>Ðã quá độ say mê,<br>Chẳng khác gì con nai,<br>Không thấy đặt bẫy sập,<br>Về sau họ khổ đau,<br>Chịu quả báo ác nghiệp.`, ref: "Tương Ưng Bộ 3.6", url: "https://loicuaducphat.org/sn/sn3.6.html#content" },

{ text: `Loài Người bị đắm say,<br>Trong tài sản, trong dục,<br>Họ tham lam, điên dại,<br>Trong các dục ở đời.<br>Không ý thức rõ ràng,<br>Ðã quá độ say mê,<br>Chẳng khác gì con cá,<br>Không thấy đặt bẫy sập.<br>Về sau họ khổ đau,<br>Chịu quả báo ác nghiệp.`, ref: "Tương Ưng Bộ 3.7", url: "https://loicuaducphat.org/sn/sn3.7.html#content" },


{ text: `Ngồi xuống một bên, các Tỷ-kheo ấy bạch Thế Tôn:<br>- Ở đây, bạch Thế Tôn, vua Pasenadi nước Kosala bắt trói một số đông người. Một số người bị trói bằng dây, một số người bị trói bằng dây chuyền, một số người bị trói bằng kềm kẹp.<br><br>Rồi Thế Tôn sau khi hiểu biết ý nghĩa này, ngay trong lúc ấy nói lên bài kệ:<br>Bậc có trí nói rằng<br>Trói vậy không vững chắc,<br>Trói bằng sắt, dây gai,<br>Kềm kẹp bằng gỗ mộc;<br>Ðam mê các dục lạc,<br>Với châu báu, trang sức,<br>Và tâm tư tưởng vọng,<br>Hướng về con, về vợ.<br>Bậc có trí nói rằng<br>Trói vậy thật vững chắc.<br>Dầu trói buộc trì xuống,<br>Tế nhị và khó thoát,<br>Các vị chơn xuất gia,<br>Cắt đứt chúng làm đôi,<br>Không ước vọng mong cầu,<br>Từ bỏ mọi dục lạc.`, ref: "Tương Ưng Bộ 3.10", url: "https://loicuaducphat.org/sn/sn3.10.html#content" },

{ text: `- Như vậy là phải, thưa Ðại vương. Như vậy là phải, thưa Ðại vương. Tất cả chúng sanh đều phải chết, đều kết thúc trong sự chết, đều không vượt qua sự chết. Ví như, thưa Ðại vương, tất cả đồ gốm do người thợ gốm làm ra, chưa nung chín hay đã nung chín, tất cả đồ gốm ấy đều phải bể, đều kết thúc trong sự bể, đều không vượt qua sự bể. Cũng vậy, thưa Ðại vương, tất cả chúng sanh đều phải chết, đều kết thúc trong sự chết, đều không vượt qua sự chết.<br><br>Mọi chúng sanh sẽ chết,<br>Mạng sống, chết kết thúc,<br>Tùy nghiệp, họ sẽ đi,<br>Nhận lãnh quả thiện ác,<br>Ác nghiệp, đọa địa ngục,<br>Thiện nghiệp, lên Thiên giới.<br>Do vậy hãy làm lành,<br>Tích lũy cho đời sau,<br>Công đức cho đời sau,<br>Làm hậu cứ cho người.`, ref: "Tương Ưng Bộ 3.22", url: "https://loicuaducphat.org/sn/sn3.22.html#content" },

{ text: `- Thưa Ðại vương, có ba pháp ở đời, khi khởi lên đưa lại bất lợi, đau khổ, bất an trú. Thế nào là ba? Thưa Ðại vương, tham là pháp ở đời, khi khởi lên đưa lại bất lợi, đau khổ, bất an trú. Thưa Ðại vương, sân là pháp ở đời, khi khởi lên đưa lại bất lợi, đau khổ, bất an trú. Thưa Ðại vương, si là pháp ở đời, khi khởi lên đưa lại bất lợi, đau khổ, bất an trú. Thưa Ðại vương, ba pháp này ở đời, khi khởi lên đem lại bất lợi, đau khổ, bất an trú.<br><br>Tham, sân, si ba pháp,<br>Là ác tâm cho người,<br>Chúng di hại tự ngã,<br>Chúng tác thành tự ngã,<br>Như vỏ và lõi cây,<br>Tự tác thành trái cây.`, ref: "Tương Ưng Bộ 3.23", url: "https://loicuaducphat.org/sn/sn3.23.html#content" },

{ text: `Như núi đá rộng lớn,<br>Dựng đứng lên hư không,<br>Tiến tới tràn xung quanh,<br>Áp đè cả bốn phía.<br>Cũng vậy, già và chết<br>Di chuyển đến hữu tình,<br>Giai cấp Sát-đế-lỵ,<br>Bà-la-môn, Phệ-xá,<br>Thủ-đà, Chiên-đà-la<br>Kẻ đổ rác, đổ phân,<br>Không một ai thoát khỏi,<br>Tất cả bị chinh phục.<br>Ở đây không tượng binh,<br>Không xa binh, bộ binh,<br>Không trận chiến chú thuật,<br>Không trận chiến tài sản<br>Có thể giúp chiến thắng,<br>Chống với già, với chết.<br>Do vậy người hiền trí,<br>Thấy rõ phần tự lợi,<br>Người trí đặt tin tưởng,<br>Vào Phật, Pháp và Tăng.<br>Ai với thân, khẩu, ý,<br>Hành trì đúng Chánh pháp,<br>Ðời này được tán thán,<br>Ðời sau, hưởng phước trời.`, ref: "Tương Ưng Bộ 3.25", url: "https://loicuaducphat.org/sn/sn3.25.html#content" },

{ text: `(Thế Tôn):<br>Ta đã được giải thoát,<br>Khỏi bẫy sập của ma,<br>Thoát khỏi dây dục lạc,<br>Cả Thiên giới, Nhân giới.<br>Ta đã được giải thoát,<br>Khỏi triền phược của ma,<br>Này kẻ Tử ma kia,<br>Ông đã bị bại trận.`, ref: "Tương Ưng Bộ 4.4", url: "https://loicuaducphat.org/sn/sn4.4.html#content" },

{ text: `- Này các Tỷ-kheo, Ta đã được giải thoát khỏi tất cả bẫy sập ở Thiên giới và Nhân giới. Này các Tỷ-kheo, các Ông cũng được giải thoát khỏi tất cả bẫy sập ở Thiên giới và Nhân giới. Này các Tỷ-kheo, hãy du hành vì hạnh phúc cho quần chúng, vì an lạc cho quần chúng, vì lòng thương tưởng cho đời, vì lợi ích, vì hạnh phúc, vì an lạc cho chư Thiên và loài Người. Chớ có đi hai người một chỗ. Này các Tỷ-kheo, hãy thuyết pháp sơ thiện, trung thiện, hậu thiện, có nghĩa, có văn. Hãy tuyên thuyết Phạm hạnh hoàn toàn viên mãn thanh tịnh. Có các chúng sanh sanh ra ít nhiễm bụi đời, nếu không được nghe pháp sẽ đi đến hoại diệt. Họ sẽ trở thành những vị thâm hiểu Chánh pháp. Này các Tỷ-kheo, Ta sẽ đi đến Uruvelà, thị trấn Senà để thuyết pháp.`, ref: "Tương Ưng Bộ 4.5", url: "https://loicuaducphat.org/sn/sn4.5.html#content" },

{ text: `- Này các Tỷ-kheo, ngắn ngủi thay là tuổi thọ loài Người ở đời này, rồi phải đi trong tương lai! Hãy làm điều lành. Hãy sống Phạm hạnh. Không có gì sanh ra lại không bị tử vong. Này các Tỷ-kheo, người sống lâu chỉ có một trăm năm, hoặc ít hơn, hoặc nhiều hơn.<br><br>Loài Người thọ mạng ngắn,<br>Người lành phải âu lo,<br>Như cháy đầu, hãy sống,<br>Tử vong rồi phải đến.<br><br>Ngày đêm có trôi qua,<br>Thọ mạng có chấm dứt,<br>Mạng người phải khô cạn,<br>Như suối nhỏ đầu non.`, ref: "Tương Ưng Bộ 4.9", url: "https://loicuaducphat.org/sn/sn4.9.html#content" },
{ text: `Rồi Thế Tôn biết được: “Ðây là Ác ma”, liền nói bài kệ cho Ác ma:<br>Sắc, thanh, vị và hương,<br>Cùng toàn bộ xúc, pháp,<br>Là thế vật rùng rợn,<br>Làm mê loạn ở đời.<br>Ðệ tử bậc Chánh Giác,<br>Chánh niệm, vượt khỏi chúng,<br>Vượt thế lực Ác ma,<br>Như mặt trời sáng chói.`, ref: "Tương Ưng Bộ 4.17", url: "https://loicuaducphat.org/sn/sn4.17.html#content" },

{ text: `Rồi Ác ma biến hình thành một Bà-la-môn, với búi tóc lớn, mặc áo bằng da con linh dương, già yếu, lưng còm như xà nhà, hơi thở hổn hển, tay cầm gậy bằng gỗ udumbara, đi đến các Tỷ-kheo ấy; sau khi đến, nói với các Tỷ-kheo:<br>- Chư Ðại đức xuất gia quá trẻ, niên thiếu, tóc còn đen nhánh, trong tuổi thanh xuân, trong thời trẻ thơ của tuổi đời, không thọ hưởng các dục. Chư Ðại đức hãy thọ hưởng các ái dục của con người, chớ có bỏ hiện tại và chạy theo những gì bị thời gian chi phối.<br><br>- Này Bà-la-môn, chúng tôi không bỏ hiện tại và chạy theo những gì bị thời gian chi phối. Và này Bà-la-môn, chúng tôi bỏ những gì bị thời gian chi phối và chạy theo hiện tại. Này Bà-la-môn, Thế Tôn đã nói các dục bị thời gian chi phối, nhiều khổ đau, nhiều phiền não, tai họa ở đấy càng nhiều hơn. Còn pháp này thuộc về hiện tại, không bị thời gian chi phối, đến để mà thấy, có khả năng hướng thượng, và chỉ người trí mới tự mình giác hiểu.`, ref: "Tương Ưng Bộ 4.21", url: "https://loicuaducphat.org/sn/sn4.21.html#content" },


{ text: `Rồi nữ ma Bất lạc nói lên bài kệ với Thế Tôn:<br>Làm sao vị Tỷ-kheo,<br>Sống giữa nhiều chướng ngại,<br>Ðã vượt năm bộc lưu,<br>Lại gắng vượt thứ sáu?<br>Làm sao Thiền tư được,<br>Giữa rất nhiều dục tưởng,<br>Ðược giữ ngoài vị ấy,<br>Không bắt vị ấy được?<br><br>(Thế Tôn):<br>Với thân được khinh an,<br>Với tâm khéo giải thoát,<br>Không còn các sở hành,<br>Chánh niệm, không tham trước,<br>Biết rõ được Chánh pháp,<br>Không tầm, tu Thiền định.<br>Không phẫn nộ, vọng niệm,<br>Không thụy miên, giải đãi,<br>Như vậy vị Tỷ-kheo,<br>Sống giữa nhiều chướng ngại,<br>Ðã vượt năm bộc lưu,<br>Lại gắng vượt thứ sáu,<br>Như vậy tu Thiền tư,<br>Giữa rất nhiều dục tưởng,<br>Ðược giữ ngoài vị ấy,<br>Không bắt vị ấy được.`, ref: "Tương Ưng Bộ 4.25", url: "https://loicuaducphat.org/sn/sn4.25.html#content" },

{ text: `Tỷ-kheo-ni Alavikà biết được: “Ðấy là Ác ma”, liền nói lên bài kệ:<br><br>Ở đời có xuất ly,<br>Nhờ trí tuệ, ta chứng.<br>Này Bà con phóng dật,<br>Biết sao được pháp ấy?<br>Ái dục như kiếm thương,<br>Ðài chém đầu các uẩn.<br>Ðiều Ông gọi dục lạc,<br>Ta gọi là bất lạc.`, ref: "Tương Ưng Bộ 5.1", url: "https://loicuaducphat.org/sn/sn5.1.html#content" },
{ text: `Tỷ-kheo-ni Vijayà suy nghĩ: “Ðây là Ác ma”, liền nói lên bài kệ với Ác ma:<br><br>Sắc, tiếng, vị, hương, xúc,<br>Làm cho ý đam mê,<br>Ta nhường lại Ác ma,<br>Ta đâu có cần chúng.<br>Với thân bất tịnh này,<br>Dễ hư hoại mong manh,<br>Ta bực phiền, tủi hổ,<br>Dục ái được đoạn tận.<br>Họ sanh hưởng sắc giới,<br>Chúng vọng vô sắc giới,<br>Thiền chứng an tịnh ấy,<br>Mọi nơi, mê ám diệt.`, ref: "Tương Ưng Bộ 5.4", url: "https://loicuaducphat.org/sn/sn5.4.html#content" },

{ text: `(Càlà):<br>Sanh ra rồi phải chết,<br>Ðã sanh thấy khổ đau,<br>Kiết sử trói gia hại,<br>Do vậy không thích sanh.<br>Ðức Phật thuyết giảng pháp,<br>Khiến vượt khỏi tái sanh,<br>Ðoạn trừ mọi khổ não,<br>Giúp ta trú chân thật.<br>Chúng sanh hướng sắc giới,<br>Họ vọng vô sắc giới,<br>Nếu không biết đoạn diệt,<br>Họ đi đến tái sanh.`, ref: "Tương Ưng Bộ 5.6", url: "https://loicuaducphat.org/sn/sn5.6.html#content" },

{ text: `Nội triền và ngoại triền,<br>Chúng sanh bị triền phược,<br>Con hỏi Gotama,<br>Ai thoát triền phược này?<br><br>(Thế Tôn)<br>Người có trí, trú giới,<br>Tu tập tâm và tuệ,<br>Nhiệt tâm và thận trọng,<br>Tỷ-kheo ấy thoát triền.<br>Với ai đã từ bỏ,<br>Tham sân và vô minh,<br>Bậc Ứng cúng lậu tận,<br>Vị ấy thoát triền phược.<br>Chỗ nào danh và sắc<br>Ðược đoạn tận vô dư,<br>Ðoạn chướng ngại sắc tưởng,<br>Chỗ ấy triền phược đoạn.`, ref: "Tương Ưng Bộ 7.6", url: "https://loicuaducphat.org/sn/sn7.6.html#content" },

{ text: `Rồi Tôn giả Vangìsa sau khi tự mình đoạn trừ bất mãn và làm thỏa mãn khởi lên, liền ngay trong lúc ấy nói lên bài kệ này:<br><br>Ta bỏ lạc, bất lạc,<br>Mọi tâm tư gia sự,<br>Không tạo một chỗ nào,<br>Thành cơ sở tham dục.<br>Ai thoát khỏi rừng tham,<br>Thoát ly mọi tham dục,<br>Ly tham không đắm trước,<br>Xứng danh chơn Tỷ-kheo.<br>Phàm địa giới, không giới,<br>Cả sắc giới trong đời,<br>Mọi vật đều biến hoại,<br>Mọi sự đều vô thường.<br>Ai hiểu biết như vậy,<br>Sở hành sẽ chân chính.<br>Chúng sanh thường chấp trước,<br>Ðối với các sanh y,<br>Ðối vật họ thấy, nghe<br>Họ ngửi, nếm, xúc chạm.<br>Ở đây, ai đoạn dục,<br>Tâm tư không nhiễm ô,<br>Không mắc dính chỗ này,<br>Vị ấy danh Mâu-ni.<br>Ðối với sáu mươi pháp,<br>Thuộc vọng tưởng phi pháp,<br>Phàm phu thường chấp trước,<br>Chấp thủ và tham đắm.<br>Tỷ-kheo không phiền não,<br>Không nói lời ác ngữ,<br>Sáng suốt, tâm thường định,<br>Không dối trá, thận trọng,<br>Thoát ly mọi tham ái.<br>Vị Mâu-ni chứng đạt,<br>Cảnh Niết-bàn tịch tịnh,<br>Chờ đón thời mệnh chung,<br>Với tâm tư vắng lặng,<br>Thanh thoát nhập Niết-bàn.`, ref: "Tương Ưng Bộ 8.2", url: "https://loicuaducphat.org/sn/sn8.2.html#content" },

{ text: `Rồi Tôn giả Vangìsa nói lên bài kệ với Tôn giả Ānanda:<br>Dục ái đốt cháy tôi,<br>Tâm tôi bị thiêu cháy.<br>Thật là điều tốt lành,<br>Ðệ tử Gotama,<br>Vì lòng từ thương tưởng,<br>Nói pháp tiêu lửa hừng.<br><br>(Ānanda):<br>Chính vì điên đảo tưởng,<br>Tâm Ông bị thiêu đốt,<br>Hãy từ bỏ tịnh tướng,<br>Hệ lụy đến tham dục,<br>Nhìn các hành vô thường,<br>Khổ đau, không phải ngã,<br>Dập tắt đại tham dục,<br>Chớ để bị cháy dài;<br>Hãy tu tâm bất tịnh,<br>Nhất tâm, khéo định tĩnh,<br>Tu tập thân niệm trú,<br>Hành nhiều hạnh yểm ly;<br>Hãy tập hạnh vô tướng,<br>Ðoạn diệt mạn tùy miên,<br>Nhờ quán sâu kiêu mạn,<br>Hạnh Ông được an tịnh.`, ref: "Tương Ưng Bộ 8.4", url: "https://loicuaducphat.org/sn/sn8.4.html#content" },

{ text: `- Này các Tỷ-kheo, bị vô minh che đậy và bị tham ái hệ phược, thân này của người ngu được sanh khởi. Vô minh ấy, người ngu không đoạn tận. Tham ái ấy, người ngu không tận trừ. Vì sao? Này các Tỷ-kheo, người ngu sống Phạm hạnh không phải vì chơn chánh đoạn trừ khổ đau. Do vậy người ngu, khi thân hoại mạng chung, đi đến một thân khác. Do đi đến một thân khác, người ấy không giải thoát khỏi sanh, già, chết, sầu, bi, khổ, ưu, não. Ta nói rằng: “Người ấy không thoát khỏi đau khổ”.`, ref: "Tương Ưng Bộ 12.19", url: "https://loicuaducphat.org/sn/sn12.19.html#content" },

{ text: `Và này các Tỷ-kheo, bị vô minh che đậy, bị tham ái hệ phược, thân người Hiền trí được sanh khởi. Vô minh ấy, người Hiền trí đoạn tận. Tham ái ấy, người Hiền trí tận trừ. Vì sao? Này các Tỷ-kheo, người Hiền trí sống Phạm hạnh, vì chơn chánh đoạn trừ khổ đau. Do vậy, người Hiền trí, khi thân hoại mạng chung, không đi đến một thân khác. Do không đi đến một thân khác, vị ấy giải thoát khỏi sanh, già, chết, sầu, bi, khổ, ưu, não. Ta nói rằng: “Vị ấy thoát khỏi đau khổ”.`, ref: "Tương Ưng Bộ 12.19", url: "https://loicuaducphat.org/sn/sn12.19.html#content" },
{ text: `- Này các Tỷ-kheo, cái chúng ta tư niệm, tư lường, có thầm ý, cái ấy trở thành sở duyên cho thức an trú. Khi nào sở duyên có mặt thời thức có an trú. Do thức ấy an trú, tăng trưởng, nên trong tương lai, tái hữu sanh khởi. Do sanh khởi tái hữu có mặt trong tương lai, nên già chết, sầu, bi, khổ, ưu, não sanh khởi. Như vậy là sự tập khởi của toàn bộ khổ uẩn này.`, ref: "Tương Ưng Bộ 12.38", url: "https://loicuaducphat.org/sn/sn12.38.html#content" },

{ text: `Này các Tỷ-kheo, nếu không có tư niệm, không có tư lường nhưng nếu có thầm ý, cái ấy trở thành sở duyên cho thức an trú. Khi nào sở duyên có mặt thời thức có an trú. Do thức ấy an trú, tăng trưởng, nên trong tương lai, tái hữu sanh khởi. Do sanh khởi tái hữu có mặt trong tương lai, nên già chết, sầu, bi, khổ, ưu, não sanh khởi. Như vậy là sự tập khởi của toàn bộ khổ uẩn này.`, ref: "Tương Ưng Bộ 12.38", url: "https://loicuaducphat.org/sn/sn12.38.html#content" },

{ text: `Này các Tỷ-kheo, nếu chúng ta không có tư niệm, không có tư lường, không có thầm ý, thời không có sở duyên cho thức an trú. Khi nào sở duyên không có mặt thời thức không an trú. Do thức ấy không an trú và không tăng trưởng, nên trong tương lai tái hữu không sanh khởi. Do sanh khởi tái hữu không có mặt trong tương lai, nên sanh, già chết, sầu, bi, ưu, não được đoạn diệt. Như vậy là sự đoạn diệt của toàn bộ khổ uẩn này.`, ref: "Tương Ưng Bộ 12.38", url: "https://loicuaducphat.org/sn/sn12.38.html#content" },

{ text: `- Này các Tỷ-kheo, cái gì chúng ta tư niệm, chúng ta tư lường, chúng ta có thầm ý, cái ấy trở thành (sở duyên) cho thức an trú. Do sở duyên có mặt nên thức có an trú. Do thức ấy an trú và tăng trưởng nên có sự hạ sanh danh sắc.<br><br>Do duyên danh sắc nên có sáu xứ. Do duyên sáu xứ nên có xúc. Do duyên xúc nên có thọ… ái… thủ… hữu… sanh, già chết, sầu, bi, khổ, ưu, não sanh khởi. Như vậy là sự tập khởi của toàn bộ khổ uẩn này.`, ref: "Tương Ưng Bộ 12.39", url: "https://loicuaducphat.org/sn/sn12.39.html#content" },

{ text: `Này các Tỷ-kheo, nếu chúng ta không tư niệm, không tư lường nhưng có thầm ý, thời cái ấy trở thành sở duyên cho thức an trú. Do sở duyên có mặt nên thức có an trú. Do thức ấy an trú và tăng trưởng nên có sự hạ sanh danh sắc. Do duyên danh sắc nên có sáu xứ… như vậy là sự tập khởi của toàn bộ khổ uẩn này.`, ref: "Tương Ưng Bộ 12.39", url: "https://loicuaducphat.org/sn/sn12.39.html#content" },

{ text: `Này các Tỷ-kheo, nếu chúng ta không tư niệm, không tư lường, không có thầm ý, thời không có sở duyên cho thức an trú. Do sở duyên không có mặt nên thức không an trú. Do thức ấy không an trú và không tăng trưởng nên danh sắc không hạ sanh. Do danh sắc diệt nên sáu xứ diệt… như vậy là sự đoạn diệt của toàn bộ khổ uẩn này.`, ref: "Tương Ưng Bộ 12.39", url: "https://loicuaducphat.org/sn/sn12.39.html#content" },

{ text: `- Ở đây, này các Tỷ-kheo, vị Tỷ-kheo đang tư lường, tư lường như sau: “Sự đau khổ nhiều loại và đa dạng này khởi lên trên đời như già và chết; sự đau khổ này lấy gì làm nhân, lấy gì tập khởi, lấy gì tác sanh, lấy gì làm hiện hữu? Do cái gì có mặt, già chết hiện hữu? Do cái gì không có mặt, già chết không hiện hữu?”<br><br>Tư lường như vậy, vị ấy biết như sau: “Sự đau khổ nhiều loại và đa dạng này khởi lên trên đời như già và chết, sự đau khổ này lấy sanh làm nhân, lấy sanh làm tập khởi, lấy sanh làm tác sanh, lấy sanh làm hiện hữu. Do sanh có mặt, già chết hiện hữu. Do sanh không có mặt, già chết không hiện hữu”.`, ref: "Tương Ưng Bộ 12.51", url: "https://loicuaducphat.org/sn/sn12.51.html#content" },

{ text: `Này các Tỷ-kheo, khi nào vị Tỷ-kheo đoạn tận vô minh, minh được sanh khởi. Vị ấy do vô minh đoạn tận, minh sanh khởi, không có dự tính, không có dụng ý, vị ấy không chấp thủ một sự gì ở đời. Không chấp thủ, vị ấy không sợ hãi. Không sợ hãi, vị ấy hoàn toàn tịch tịnh. Vị ấy biết rõ: “Sanh đã tận, Phạm hạnh đã thành, những việc nên làm đã làm, không còn trở lui trạng thái này nữa”.`, ref: "Tương Ưng Bộ 12.51", url: "https://loicuaducphat.org/sn/sn12.51.html#content" },

{ text: `Nếu vị ấy cảm giác lạc thọ, vị ấy biết lạc thọ ấy vô thường, vị ấy biết không nên tham đắm, vị ấy biết không nên hoan hỷ. Nếu vị ấy cảm giác khổ thọ, vị ấy biết khổ thọ vô thường, vị ấy biết không nên tham đắm, vị ấy biết không nên hoan hỷ. Nếu vị ấy cảm giác bất khổ bất lạc thọ, vị ấy biết thọ ấy vô thường, vị ấy biết không nên tham đắm, vị ấy biết không nên hoan hỷ. Nếu vị ấy cảm giác lạc thọ, thọ ấy được cảm giác với niệm thoát ly. Nếu vị ấy cảm giác khổ thọ, thọ ấy được cảm giác với niệm thoát ly. Nếu vị ấy cảm giác bất khổ bất lạc thọ, thọ ấy được cảm giác với niệm thoát ly .`, ref: "Tương Ưng Bộ 12.51", url: "https://loicuaducphat.org/sn/sn12.51.html#content" },

{ text: `- Này các Tỷ-kheo, kẻ vô văn phàm phu có thể nhàm chán, viễn ly, giải thoát thân do bốn đại tạo thành này. Vì cớ sao? Này các Tỷ-kheo, vì họ thấy được cái thân do bốn đại tạo thành này được tăng, được giảm, được thủ, được xả. Do vậy, ở đây kẻ vô văn phàm phu có thể nhàm chán, viễn ly, giải thoát. Và này các Tỷ-kheo, cái gọi là tâm, là ý, là thức, ở đây, kẻ vô văn phàm phu không đủ để có thể nhàm chán, không đủ để có thể viễn ly, không đủ để có thể giải thoát. Vì sao? Ðã lâu ngày, này các Tỷ-kheo, kẻ vô văn phàm phu đắm trước, xem là của tôi, chấp thủ: “Cái này là của tôi, cái này là tôi, cái này là tự ngã của tôi”. Do vậy, ở đây, kẻ vô văn phàm phu không đủ để có thể nhàm chán, không đủ để có thể viễn ly, không đủ để có thể giải thoát.`, ref: "Tương Ưng Bộ 12.61", url: "https://loicuaducphat.org/sn/sn12.61.html#content" },

{ text: `Này các Tỷ-kheo, những ai trong quá khứ… những ai trong tương lai… những ai trong thời hiện tại là Sa-môn hay Bà-la-môn, thấy những gì ở đời khả ái, hấp dẫn là thường còn, thấy là lạc, thấy là vô bệnh, thấy là an ổn, thấy là tự ngã, những người ấy làm ái tăng trưởng. Những ai làm ái tăng trưởng, những người ấy làm sanh y tăng trưởng. Những ai làm sanh y tăng trưởng, những người ấy làm đau khổ tăng trưởng. Những ai làm đau khổ tăng trưởng, những người ấy không thể giải thoát sanh, già, chết, sầu, bi, khổ, ưu, não. Ta nói rằng họ không thể giải thoát khỏi đau khổ.`, ref: "Tương Ưng Bộ 12.66", url: "https://loicuaducphat.org/sn/sn12.66.html#content" },

{ text: `Này các Tỷ-kheo, những ai trong quá khứ… những ai trong tương lai… những ai trong thời hiện tại là Sa-môn hay Bà-la-môn, thấy những gì khả ái, hấp dẫn ở đời là vô thường, thấy là khổ, thấy là vô ngã, thấy là bệnh, thấy là đáng sợ hãi, họ từ bỏ ái. Những ai từ bỏ ái, những người ấy từ bỏ sanh y. Những ai từ bỏ sanh y, những người ấy từ bỏ đau khổ. Những ai từ bỏ đau khổ, những người ấy được giải thoát khỏi sanh, già, chết, sầu, bi, khổ, ưu, não. Ta nói rằng họ được giải thoát khỏi đau khổ.`, ref: "Tương Ưng Bộ 12.66", url: "https://loicuaducphat.org/sn/sn12.66.html#content" },

{ text: `- Sắc giới, này Gia chủ, là nhà của thức. Thức bị lòng tham sắc giới trói buộc, này Gia chủ, được gọi là du hành có gia đình. Thọ giới, này Gia chủ, là nhà của thức. Thức bị lòng tham thọ giới trói buộc, này Gia chủ, được gọi là du hành có gia đình. Tưởng giới, này Gia chủ, là nhà của thức. Thức bị lòng tham tưởng giới trói buộc, này Gia chủ, được gọi là du hành có gia đình. Hành giới, này Gia chủ, là nhà của thức. Thức bị lòng tham hành giới trói buộc, này Gia chủ, được gọi là du hành có gia đình. Thức giới, này Gia chủ, là nhà của thức. Thức bị lòng tham thức giới trói buộc, này Gia chủ, được gọi là du hành có gia đình. Như vậy, này Gia chủ, là du hành có gia đình.`, ref: "Tương Ưng Bộ 22.3", url: "https://loicuaducphat.org/sn/sn22.3.html#content" },

{ text: `Và này Gia chủ, thế nào là du hành không gia đình? Ðối với sắc giới, này Gia chủ, cái gọi là dục, là tham, là hỷ, là khát ái, những gì thuộc chấp thủ, tâm trú trước, thiên chấp tùy miên; Như Lai đoạn tận chúng, cắt đứt tận gốc rễ, làm cho như thân cây ta-la, làm cho không tái sanh, không thể sanh khởi trong tương lai. Do vậy, Như Lai được gọi là du hành không gia đình. Ðối với thọ giới, này Gia chủ … Ðối với tưởng giới, này Gia chủ … Ðối với hành giới, này Gia chủ … Ðối với thức giới, này Gia chủ, cái gọi là dục, là tham, là hỷ, là khát ái, những gì thuộc chấp thủ, tâm trú trước, thiên chấp tùy miên; Như Lai đoạn tận chúng, cắt đứt tận gốc rễ, làm cho như thân cây ta-la, làm cho không tái sanh, không thể sanh khởi trong tương lai. Do vậy, Như Lai được gọi là du hành không gia đình.`, ref: "Tương Ưng Bộ 22.3", url: "https://loicuaducphat.org/sn/sn22.3.html#content" },

{ text: `Như thế nào là du hành không trú xứ? Sự trói buộc bởi an trú chấp trước vào sắc tướng, này Gia chủ, đối với Như Lai đã được đoạn tận, cắt đứt tận gốc rễ, làm cho như thân cây ta-la, làm cho không tái sanh, không thể sanh khởi trong tương lai. Do vậy, Như Lai được gọi là du hành không trú xứ. Sự trói buộc bởi an trú chấp trước vào thanh tướng … vào hương tướng … vào vị tướng … vào xúc tướng … vào pháp tướng, này Gia chủ, đối với Như Lai đã được đoạn tận, cắt đứt tận gốc rễ, làm cho như thân cây ta-la, làm cho không tái sanh, không thể sanh khởi trong tương lai. Do vậy, Như Lai được gọi là du hành không trú xứ. Như vậy, này Gia chủ, là du hành không trú xứ.`, ref: "Tương Ưng Bộ 22.3", url: "https://loicuaducphat.org/sn/sn22.3.html#content" },


{ text: `Này các Tỷ-kheo, thế nào là sắc tập khởi? Thế nào là thọ tập khởi? Thế nào là tưởng tập khởi? Thế nào là các hành tập khởi? Thế nào là thức tập khởi? Ở đây, này các Tỷ-kheo, Tỷ-kheo hoan hỷ, hoan nghênh, đắm trước rồi an trú. Hoan hỷ, hoan nghênh, đắm trước và an trú gì? Hoan hỷ, hoan nghênh, đắm trước rồi an trú sắc. Do vị ấy hoan hỷ, hoan nghênh, đắm trước rồi an trú sắc, hỷ đối với sắc khởi lên. Do hỷ đối với sắc, thủ đối với sắc khởi lên. Do duyên thủ đối với sắc, hữu khởi lên. Do duyên hữu, sanh khởi lên. Do duyên sanh, già chết, sầu, bi, khổ, ưu, não khởi lên. Như vậy là sự tập khởi của toàn bộ khổ uẩn này.<br><br>Hoan hỷ, hoan nghênh, đắm trước rồi an trú thọ … rồi an trú tưởng … rồi an trú các hành … rồi an trú thức. Do vị ấy hoan hỷ, hoan nghênh, đắm trước rồi an trú thức, hỷ khởi lên. Do hỷ đối với thức, thủ đối với thức khởi lên. Do duyên thủ đối với thức, hữu khởi lên. Do duyên hữu, sanh khởi lên. Do duyên sanh, già chết, sầu, bi, khổ, ưu, não khởi lên. Như vậy là sự tập khởi của toàn bộ khổ uẩn này. Này các Tỷ-kheo, đây là sắc tập khởi, đây là thọ tập khởi, đây là tưởng tập khởi, đây là hành tập khởi, đây là thức tập khởi.`, ref: "Tương Ưng Bộ 22.5", url: "https://loicuaducphat.org/sn/sn22.5.html#content" },

{ text: `- Này các Tỷ-kheo, thế nào là chấp thủ và ưu não? Ở đây, này các Tỷ-kheo, kẻ vô văn phàm phu không thấy rõ các bậc Thánh, không thuần thục pháp các bậc Thánh, không tu tập pháp các bậc Thánh, không thấy rõ các bậc Chân nhân, không thuần thục pháp các bậc Chân nhân, không tu tập pháp các bậc Chân nhân, người ấy quán sắc như là tự ngã, hay tự ngã như là có sắc, hay sắc ở trong tự ngã, hay tự ngã ở trong sắc. Ðối với vị ấy, sắc ấy biến hoại và đổi khác. Ðối với vị ấy, khi sắc ấy biến hoại và đổi khác, thức tùy chuyển theo sự biến hoại của sắc. Các pháp ưu não sanh khởi do thức tùy chuyển theo sự biến hoại của sắc sau khi xâm nhập tâm và an trú. Do tâm bị xâm chiếm nên khủng bố, chướng ngại, khát vọng được sanh khởi và ưu não.`, ref: "Tương Ưng Bộ 22.7", url: "https://loicuaducphat.org/sn/sn22.7.html#content" },

{ text: `Này các Tỷ-kheo, như thế nào là không chấp thủ và không ưu não? Ở đây, này các Tỷ-kheo, vị Ða văn Thánh đệ tử quán sắc: “Ðây không phải của tôi, đây không phải là tôi, đây không phải là tự ngã của tôi”. Sắc ấy của vị này biến hoại, đổi khác. Vị này, khi sắc biến hoại, đổi khác, không khởi lên sầu, bi, khổ, ưu, não. … quán thọ: “Ðây không phải của tôi.”. … quán tưởng: “Ðây không phải của tôi.”. … quán các hành: “Ðây không phải của tôi.”. … quán thức: “Ðây không phải của tôi, đây không phải là tôi, đây không phải tự ngã của tôi”. Thức ấy của vị này biến hoại, đổi khác. Vị này, khi thức ấy biến hoại, đổi khác, không khởi lên sầu, bi, khổ, ưu, não. Như vậy, này các Tỷ-kheo, là không chấp thủ, không ưu não.`, ref: "Tương Ưng Bộ 22.8", url: "https://loicuaducphat.org/sn/sn22.8.html#content" },

{ text: `- Này các Tỷ-kheo, sắc là vô thường, trong quá khứ, trong vị lai, còn nói gì đến hiện tại. Thấy vậy, này các Tỷ-kheo, bậc Ða văn Thánh đệ tử đối với sắc quá khứ không tiếc nuối, đối với sắc vị lai không hoan hỷ, đối với sắc hiện tại hướng đến yếm ly, ly tham, đoạn diệt. Này các Tỷ-kheo, thọ là vô thường … Này các Tỷ-kheo, tưởng là vô thường … Này các Tỷ-kheo, các hành là vô thường, trong quá khứ, trong vị lai, còn nói gì đến hiện tại. Thấy vậy, này các Tỷ-kheo, bậc Ða văn Thánh đệ tử đối với các hành quá khứ không tiếc nuối, đối với các hành vị lai không hoan hỷ, đối với các hành hiện tại hướng đến yếm ly, ly tham, đoạn diệt. Này các Tỷ-kheo, thức là vô thường trong quá khứ, trong vị lai, còn nói gì đến hiện tại. Thấy vậy, này các Tỷ-kheo, bậc Ða văn Thánh đệ tử đối với thức quá khứ không tiếc nuối, đối với thức vị lai không hoan hỷ, đối với thức hiện tại hướng đến yếm ly, ly tham, đoạn diệt.`, ref: "Tương Ưng Bộ 22.9", url: "https://loicuaducphat.org/sn/sn22.9.html#content" },

{ text: `- Sắc, này các Tỷ-kheo, là khổ, quá khứ, vị lai, còn nói gì đến hiện tại. Thấy vậy, này các Tỷ-kheo, vị Ða văn Thánh đệ tử, đối với sắc quá khứ không tiếc nuối, đối với sắc vị lai không hoan hỷ, đối với sắc hiện tại hướng đến yếm ly, ly tham đoạn diệt. Thọ, này các Tỷ-kheo, là khổ … Tưởng, này các Tỷ-kheo, là khổ … Các hành, này các Tỷ-kheo, là khổ … Thức, này các Tỷ-kheo, là khổ, quá khứ, vị lai, còn nói gì đến hiện tại. Thấy vậy, này các Tỷ-kheo, vị Ða văn Thánh đệ tử đối với thức quá khứ không tiếc nuối, đối với thức vị lai không hoan hỷ, đối với thức hiện tại hướng đến yếm ly, ly tham, đoạn diệt.`, ref: "Tương Ưng Bộ 22.10", url: "https://loicuaducphat.org/sn/sn22.10.html#content" },

{ text: `- Sắc, này các Tỷ-kheo, là vô thường; cái gì vô thường là khổ; cái gì khổ là vô ngã; cái gì vô ngã, cần phải như thật quán với chánh trí tuệ: “Cái này không phải của tôi; cái này không phải là tôi; cái này không phải tự ngã của tôi”. Thọ, này các Tỷ-kheo, là vô thường; cái gì vô thường là khổ; cái gì khổ là vô ngã; cái gì vô ngã cần phải như thật quán với chánh trí tuệ: “Cái này không phải của tôi; cái này không phải là tôi; cái này không phải tự ngã của tôi”. Tưởng, này các Tỷ-kheo, là vô thường … Các hành, này các Tỷ-kheo, là vô thường … Thức, này các Tỷ-kheo, là vô thường; cái gì vô thường là khổ; cái gì khổ là vô ngã; cái gì vô ngã cần phải như thật quán với chánh trí tuệ: “Cái này không phải của tôi; cái này không phải là tôi; cái này không phải tự ngã của tôi”. Thấy vậy, này các Tỷ-kheo, vị Ða văn Thánh đệ tử yếm ly đối với sắc … ” … không còn trở lui trạng thái này nữa”.`, ref: "Tương Ưng Bộ 22.15", url: "https://loicuaducphat.org/sn/sn22.15.html#content" },

{ text: `- Sắc, này các Tỷ-kheo, là khổ. Cái gì khổ là vô ngã; cái gì vô ngã cần phải như thật quán với chánh trí tuệ: “Cái này không phải của tôi; cái này không phải là tôi; cái này không phải tự ngã của tôi”. Thọ, này các Tỷ-kheo, là khổ … Tưởng, này các Tỷ-kheo, là khổ … Các hành, này các Tỷ-kheo, là khổ … Thức, này các Tỷ-kheo, là khổ. Cái gì khổ là vô ngã; cái gì vô ngã cần phải như thật quán với chánh trí tuệ: “Cái này không phải của tôi; cái này không phải là tôi; cái này không phải tự ngã của tôi”. Thấy vậy, này các Tỷ-kheo, vị Ða văn Thánh đệ tử yếm ly đối với sắc … ” … không còn trở lui trạng thái này nữa”.`, ref: "Tương Ưng Bộ 22.16", url: "https://loicuaducphat.org/sn/sn22.16.html#content" },

{ text: `Này các Tỷ-kheo, thế nào là gánh nặng? Năm thủ uẩn là câu trả lời. Thế nào là năm? Sắc thủ uẩn, thọ thủ uẩn, tưởng thủ uẩn, hành thủ uẩn, thức thủ uẩn. Này các Tỷ-kheo, đây gọi là gánh nặng. Và này các Tỷ-kheo, thế nào là kẻ mang gánh nặng? Người là câu trả lời. Vị Tôn giả này có tên như thế này, dòng họ như thế này. Này các Tỷ-kheo, đây gọi là kẻ mang gánh nặng! Và này các Tỷ-kheo, thế nào là mang gánh nặng lên? Chính là tham ái này đưa đến tái sanh, câu hữu với hỷ và tham, đi tìm hỷ lạc chỗ này, chỗ kia. Tức là dục ái, hữu ái, phi hữu ái. Này các Tỷ-kheo, đây gọi là mang gánh nặng lên. Này các Tỷ-kheo, thế nào là đặt gánh nặng xuống? Ðây là sự ly tham, đoạn diệt ái ấy một cách hoàn toàn, sự từ bỏ, sự xả ly, sự giải thoát, sự không chấp thủ. Này các Tỷ-kheo, đây gọi là đặt gánh nặng xuống.`, ref: "Tương Ưng Bộ 22.22", url: "https://loicuaducphat.org/sn/sn22.22.html#content" },

{ text: `Năm uẩn là gánh nặng,<br>Kẻ gánh nặng là người;<br>Mang lấy gánh nặng lên,<br>Chính là khổ ở đời.<br>Còn đặt gánh nặng xuống,<br>Tức là lạc, không khổ,<br>Ðặt gánh nặng xuống xong,<br>Không mang thêm gánh khác.<br>Nếu nhổ khát ái lên,<br>Tận cùng đến gốc rễ,<br>Không còn đói và khát,<br>Ðược giải thoát tịnh lạc!`, ref: "Tương Ưng Bộ 22.22", url: "https://loicuaducphat.org/sn/sn22.22.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là các pháp cần phải liễu tri? Sắc, này các Tỷ-kheo, là pháp cần phải liễu tri, thọ là pháp cần phải liễu tri, tưởng là pháp cần phải liễu tri, các hành là pháp cần phải liễu tri, thức là pháp cần phải liễu tri. Những pháp này, này các Tỷ-kheo, là những pháp cần phải liễu tri. Và này các Tỷ-kheo, thế nào là liễu tri? Này các Tỷ-kheo, sự đoạn tận tham, sự đoạn tận sân, sự đoạn tận si, này các Tỷ-kheo, được gọi là liễu tri.`, ref: "Tương Ưng Bộ 22.23", url: "https://loicuaducphat.org/sn/sn22.23.html#content" },

{ text: `- Này các Tỷ-kheo, trước khi Ta giác ngộ, chưa chứng Chánh Ðẳng Giác, còn là Bồ-tát, Ta suy nghĩ như sau: “Cái gì là vị ngọt, cái gì là sự nguy hiểm, cái gì là sự xuất ly của sắc? Cái gì là vị ngọt, cái gì là sự nguy hiểm, cái gì là sự xuất ly của thọ? Cái gì là vị ngọt, cái gì là sự nguy hiểm, cái gì là sự xuất ly của tưởng? Cái gì là vị ngọt, cái gì là sự nguy hiểm, cái gì là sự xuất ly của các hành? Cái gì là vị ngọt, cái gì là sự nguy hiểm, cái gì là sự xuất ly của thức?” Rồi này các Tỷ-kheo, Ta suy nghĩ như sau: “Do duyên sắc, lạc hỷ sanh; cái ấy gọi là vị ngọt của sắc. Sự vô thường, đau khổ, chịu sự biến hoại của sắc; cái ấy gọi là sự nguy hiểm của sắc. Sự nhiếp phục dục và tham đối với sắc, sự đoạn tận dục và tham; cái ấy là xuất ly của sắc”.`, ref: "Tương Ưng Bộ 22.26", url: "https://loicuaducphat.org/sn/sn22.26.html#content" },

{ text: `- Này các Tỷ-kheo, nếu không có vị ngọt của sắc, thời các loài hữu tình không có tham đắm đối với sắc. Và vì rằng, này các Tỷ-kheo, có vị ngọt của sắc cho nên các loài hữu tình có tham đắm đối với sắc. - Này Tỷ-kheo, nếu không có sự nguy hiểm của sắc, thời các loài hữu tình không có yếm ly đối với sắc. Và vì rằng, này các Tỷ-kheo, có sự nguy hiểm của sắc cho nên các loài hữu tình có yếm ly đối với sắc. Và này các Tỷ-kheo, khi nào các loài hữu tình đối với năm thủ uẩn này, như thật thắng tri vị ngọt là vị ngọt, nguy hiểm là nguy hiểm, xuất ly là xuất ly, thời các loài hữu tình ấy, này các Tỷ-kheo, với thế giới chư Thiên, Ma, Phạm thiên, với quần chúng Sa-môn, Bà-la-môn, với chư Thiên và loài Người, có thể sống xuất ly, thoát sự liên hệ, giải thoát, với tâm tự tại.`, ref: "Tương Ưng Bộ 22.28", url: "https://loicuaducphat.org/sn/sn22.28.html#content" },

{ text: `- Này các Tỷ-kheo, cái gọi là sắc sanh, trú, khởi, hiện hữu; cái ấy là khổ sanh, bệnh tật trú, già chết hiện hữu. Này các Tỷ-kheo, cái gọi là thọ sanh, trú, khởi, hiện hữu … tưởng sanh, trú, khởi, hiện hữu … các hành sanh, trú, khởi, hiện, hữu … Này các Tỷ-kheo, cái gọi là thức sanh, trú, khởi, hiện hữu; cái ấy gọi là khổ sanh, bệnh tật trú, già chết hiện hữu. Này các Tỷ-kheo, cái gọi là sắc đoạn diệt, an chỉ, biến mất; cái ấy gọi là khổ đoạn diệt, bệnh tật an chỉ, già chết biến mất. Này các Tỷ-kheo, cái gọi là thọ đoạn diệt … tưởng đoạn diệt … các hành đoạn diệt … Này các Tỷ-kheo, cái gọi là thức đoạn diệt, an chỉ, biến mất; cái ấy là khổ đoạn diệt, bệnh tật an chỉ, già chết biến mất.`, ref: "Tương Ưng Bộ 22.30", url: "https://loicuaducphat.org/sn/sn22.30.html#content" },


{ text: `- Này các Tỷ-kheo, Ta sẽ thuyết về đau khổ và cội gốc của đau khổ. Hãy lắng nghe … Này các Tỷ-kheo, thế nào là đau khổ? Sắc, này các Tỷ-kheo, là đau khổ; thọ là đau khổ; tưởng là đau khổ; các hành là đau khổ; thức là đau khổ. Ðây, này các Tỷ-kheo, gọi là đau khổ. Này các Tỷ-kheo, thế nào là cội gốc của đau khổ? Chính là khát ái này hướng tới tái sanh, câu hữu với hỷ và tham, tìm cầu hỷ lạc chỗ này, chỗ kia; tức là dục ái, hữu ái, phi hữu ái.`, ref: "Tương Ưng Bộ 22.31", url: "https://loicuaducphat.org/sn/sn22.31.html#content" },


{ text: `- Này các Tỷ-kheo, cái gì không phải của các Ông, hãy từ bỏ nó. Từ bỏ nó sẽ đưa lại hạnh phúc, an lạc cho các Ông. Này các Tỷ-kheo, cái gì không phải của các Ông? Sắc, này các Tỷ-kheo, không phải của các Ông, hãy từ bỏ nó. Từ bỏ nó sẽ đưa lại hạnh phúc, an lạc cho các Ông. Thọ, này các Tỷ-kheo, không phải của các Ông, hãy từ bỏ nó. Từ bỏ nó sẽ đưa lại hạnh phúc, an lạc cho các Ông. Tưởng, này các Tỷ-kheo … Các hành, này các Tỷ-kheo … Thức, này các Tỷ-kheo, không phải của các Ông, hãy từ bỏ nó. Từ bỏ nó sẽ đưa lại hạnh phúc, an lạc cho các Ông.`, ref: "Tương Ưng Bộ 22.33", url: "https://loicuaducphat.org/sn/sn22.33.html#content" },


{ text: `- Ðối với vị Tỷ-kheo thực hành pháp và tùy pháp, tùy pháp này có mặt: Ðối với sắc, vị ấy sống nhiều yếm ly; đối với thọ, vị ấy sống nhiều yếm ly; đối với tưởng, vị ấy sống nhiều yếm ly; đối với các hành, vị ấy sống nhiều yếm ly; đối với thức, vị ấy sống nhiều yếm ly. Ai sống nhiều yếm ly đối với sắc … đối với thọ … đối với tưởng … đối với các hành … ai sống nhiều yếm ly đối với thức, vị ấy liễu tri sắc … liễu tri thọ … liễu tri tưởng … liễu tri các hành … liễu tri thức. Do liễu tri sắc … thọ … tưởng … các hành … do liễu tri thức, vị ấy được giải thoát khỏi sắc, giải thoát khỏi thọ, giải thoát khỏi tưởng, giải thoát khỏi các hành, giải thoát khỏi thức, giải thoát khỏi sanh, già chết, sầu, bi, khổ, ưu, não. Ta nói vị ấy giải thoát khỏi đau khổ.`, ref: "Tương Ưng Bộ 22.39", url: "https://loicuaducphat.org/sn/sn22.39.html#content" },


{ text: `Này các Tỷ-kheo, biết sắc là vô thường … Này các Tỷ-kheo, biết thọ là vô thường … Này các Tỷ-kheo, biết tưởng là vô thường … Này các Tỷ-kheo, biết các hành là vô thường … Này các Tỷ-kheo, biết thức là vô thường, biến hoại, ly tham, đoạn diệt; vị ấy thấy tất cả thức xưa và nay là vô thường, khổ, chịu sự biến hoại. Do thấy như thật với chánh trí tuệ như vậy, các sầu, bi, khổ, ưu, não được đoạn tận. Do chúng được đoạn tận, vị ấy không bị ưu, não. Do không bị ưu, não, vị ấy sống an lạc. Do sống an lạc, vị Tỷ-kheo được gọi là vị đã lắng dịu mọi tướng phần, nhất hướng Niết-bàn.`, ref: "Tương Ưng Bộ 22.43", url: "https://loicuaducphat.org/sn/sn22.43.html#content" },


{ text: `- Sắc, này các Tỷ-kheo, là vô thường. Cái gì vô thường là khổ. Cái gì khổ là vô ngã. Cái gì vô ngã, cần phải như thật quán với chánh trí tuệ là: “Cái này không phải của tôi; cái này không phải là tôi; cái này không phải tự ngã của tôi”. Do như thật quán với chánh trí tuệ như vậy, tâm ly tham, được giải thoát, không có chấp thủ các lậu hoặc.`, ref: "Tương Ưng Bộ 22.45", url: "https://loicuaducphat.org/sn/sn22.45.html#content" },


{ text: `Này các Tỷ-kheo, nếu vị Tỷ-kheo đối với sắc giới có tâm ly tham, giải thoát, không có chấp thủ các lậu hoặc, đối với thọ giới … đối với tưởng giới … đối với hành giới … đối với thức giới, có tâm ly tham, giải thoát, không có chấp thủ các lậu hoặc. Do giải thoát, vị ấy an trú. Do an trú, vị ấy tri túc. Do tri túc, vị ấy không ưu não. Do không ưu não, vị ấy tự mình tịch tịnh. Vị ấy biết: ” Sanh đã tận, Phạm hạnh đã thành, những việc nên làm đã làm, không còn trở lui trạng thái này nữa”.`, ref: "Tương Ưng Bộ 22.45", url: "https://loicuaducphat.org/sn/sn22.45.html#content" },


{ text: `- Sắc, này các Tỷ-kheo, đang bốc cháy; thọ đang bốc cháy; tưởng đang bốc cháy; hành đang bốc cháy; thức đang bốc cháy! Thấy vậy, này các Tỷ-kheo, bậc Ða văn Thánh đệ tử nhàm chán đối với sắc … đối với thọ … đối với tưởng … đối với các hành … nhàm chán đối với thức. Do nhàm chán nên ly tham; do ly tham nên giải thoát. Trong sự giải thoát, trí khởi lên: “Ta đã được giải thoát”. Vị ấy biết: “Sanh đã tận, Phạm hạnh đã thành, những việc nên làm đã làm, không còn trở lui trạng thái này nữa”.`, ref: "Tương Ưng Bộ 22.61", url: "https://loicuaducphat.org/sn/sn22.61.html#content" },


{ text: `Này Tỷ-kheo, ai suy tưởng sắc, người ấy bị Ma trói buộc. Ai không suy tưởng, người ấy được giải thoát khỏi Ác ma. Ai suy tưởng thọ … tưởng … các hành … Ai suy tưởng thức, người ấy bị Ma trói buộc. Ai không suy tưởng, người ấy được giải thoát khỏi Ác ma. Này Tỷ-kheo, lời nói vắn tắt này của Ta cần phải hiểu ý nghĩa một cách rộng rãi như vậy.`, ref: "Tương Ưng Bộ 22.64", url: "https://loicuaducphat.org/sn/sn22.64.html#content" },


{ text: `- Này Rādha, phàm có sắc gì quá khứ, vị lai, hiện tại, thuộc nội hay ngoại, thô hay tế, liệt hay thắng, xa hay gần; tất cả sắc cần được thấy như thật với chánh trí tuệ là: “Cái này không phải của tôi, cái này không phải là tôi, cái này không phải tự ngã của tôi”. Phàm có thọ … Phàm có tưởng … Phàm có các hành … Phàm có thức gì quá khứ, vị lai, hiện tại, thuộc nội hay ngoại, thô hay tế, liệt hay thắng, xa hay gần; tất cả thức cần được thấy như thật với chánh trí tuệ là: “Cái này không phải của tôi, cái này không phải là tôi, cái này không phải tự ngã của tôi”. Này Rādha, do biết vậy, do thấy vậy, đối với thân có thức này, và đối với tất cả tướng ở ngoài, không có tư tưởng: “Ngã kiến, ngã sở kiến, ngã mạn tùy miên”.`, ref: "Tương Ưng Bộ 22.71", url: "https://loicuaducphat.org/sn/sn22.71.html#content" },


{ text: `Này các Tỷ-kheo, thế nào gọi là sắc? Bị thay đổi, này các Tỷ-kheo, nên gọi là sắc. Bị thay đổi bởi cái gì? Bị thay đổi bởi lạnh, bị thay đổi bởi nóng, bị thay đổi bởi đói, bị thay đổi bởi khát, bị thay đổi bởi sự xúc chạm của ruồi, muỗi, gió, sức nóng và rắn. Bị thay đổi, này các Tỷ-kheo, nên gọi là sắc. Này các Tỷ-kheo, thế nào gọi là thọ? Ðược cảm thọ, này các Tỷ-kheo, nên gọi là thọ. Cảm thọ gì? Cảm thọ lạc, cảm thọ khổ, cảm thọ phi khổ phi lạc. Ðược cảm thọ, này các Tỷ-kheo, nên gọi là thọ. Này các Tỷ-kheo, thế nào gọi là tưởng? Nhận rõ, này các Tỷ-kheo, nên gọi là tưởng. Nhận rõ gì? Nhận rõ màu xanh, nhận rõ màu vàng, nhận rõ màu đỏ, nhận rõ màu trắng. Nhận rõ, này các Tỷ-kheo, nên gọi là tưởng.`, ref: "Tương Ưng Bộ 22.79", url: "https://loicuaducphat.org/sn/sn22.79.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, vị Ða văn Thánh đệ tử suy nghĩ như sau: “Nay ta bị sắc chinh phục. Trong thời quá khứ, ta cũng bị sắc chinh phục, như ta bị sắc hiện tại chinh phục. Nếu ta hoan hỷ đối với sắc vị lai, thời trong vị lai, ta sẽ bị sắc chinh phục, như nay ta bị sắc hiện tại chinh phục”. Do suy nghĩ như vậy, vị ấy không có luyến tiếc đối với sắc quá khứ, không có hoan hỷ đối với sắc vị lai, và thực hành sự yếm ly, ly tham, đoạn diệt đối với sắc hiện tại.`, ref: "Tương Ưng Bộ 22.79", url: "https://loicuaducphat.org/sn/sn22.79.html#content" },


{ text: `Và như vậy, này các Tỷ-kheo, là thiện gia nam tử xuất gia. Vị ấy có tham dục đối với các dục vọng, tham ái cuồng nhiệt, tâm tư sân hận, tư niệm ô nhiễm, thất niệm, không tỉnh giác, không định tĩnh, tâm tán loạn, các căn không chế ngự. Ví như, này các Tỷ-kheo, một que củi từ chỗ hỏa táng, cả hai đầu đều cháy, ở giữa lại dính phân, không được dùng làm củi trong làng, không được dùng làm củi trong rừng. Dùng ví dụ ấy, Ta tả cho các Ông con người ấy, đã mất cả nhà và tài sản, lại không làm viên mãn mục đích của Sa-môn hạnh.`, ref: "Tương Ưng Bộ 22.80", url: "https://loicuaducphat.org/sn/sn22.80.html#content" },


{ text: `Này các Tỷ-kheo, có ba bất thiện tầm này: dục tầm, sân tầm, hại tầm. Và này các Tỷ-kheo, ba bất thiện tầm này được đoạn diệt không có dư tàn, đối với vị nào tâm đã khéo an trú vào bốn Niệm xứ hay tu tập vô tướng Thiền định. Này các Tỷ-kheo, hãy khéo tu tập vô tướng Thiền định. Này các Tỷ-kheo, vô tướng Thiền định được tu tập, làm cho tăng thịnh, đưa đến quả lớn, lợi ích lớn.`, ref: "Tương Ưng Bộ 22.80", url: "https://loicuaducphat.org/sn/sn22.80.html#content" },


{ text: `Ðối với kẻ vô văn phàm phu, này các Tỷ-kheo, do cảm xúc bởi thọ sanh ra do xúc chạm với vô minh, khát ái sanh. Do khát ái ấy, hành ấy sanh. Như vậy, này các Tỷ-kheo, hành ấy là vô thường, hữu vi, do duyên sanh. Khát ái ấy là vô thường, hữu vi, do duyên sanh. Thọ ấy là vô thường, hữu vi, do duyên sanh. Xúc ấy là vô thường, hữu vi, do duyên sanh. Vô minh ấy là vô thường, hữu vi, do duyên sanh. Này các Tỷ-kheo, do biết như vậy, thấy như vậy, các lậu hoặc được đoạn tận lập tức.`, ref: "Tương Ưng Bộ 22.81", url: "https://loicuaducphat.org/sn/sn22.81.html#content" },


{ text: `- Ví như, này các Tỷ-kheo, sông Hằng này chảy mang theo đống bọt nước lớn. Có người có mắt nhìn đống bọt nước ấy, chuyên chú, như lý quán sát. Do nhìn chuyên chú, như lý quán sát nó, đống bọt nước ấy hiện rõ ra là trống không, hiện rõ ra là rỗng không, hiện rõ ra là không có lõi cứng. Làm sao, này các Tỷ-kheo, lại có lõi cứng trong đống bọt nước được? Cũng vậy, này các Tỷ-kheo, phàm có sắc gì thuộc quá khứ, vị lai, hiện tại, hoặc nội hay ngoại, hoặc thô hay tế, hoặc liệt hay thắng, hoặc xa hay gần; vị Tỷ-kheo thấy sắc, chuyên chú, như lý quán sát sắc. Do vị Tỷ-kheo nhìn chuyên chú, như lý quán sát sắc, sắc ấy hiện rõ ra là trống không, hiện rõ ra là rỗng không, hiện rõ ra là không có lõi cứng. Làm sao, này các Tỷ-kheo, lại có lõi cứng trong sắc được?`, ref: "Tương Ưng Bộ 22.95", url: "https://loicuaducphat.org/sn/sn22.95.html#content" },


{ text: `Sắc ví với đống bọt,<br>Thọ ví bong bóng nước,<br>Tưởng ví ráng mặt trời,<br>Hành ví với cây chuối,<br>Thức ví với ảo thuật,<br>Ðấng bà con mặt trời,<br>Ðã thuyết giảng như vậy.<br><br>Nếu như vậy chuyên chú,<br>Như lý chơn quán sát,<br>Như lý nhìn các pháp,<br>Hiện rõ tánh trống không.<br><br>Bắt đầu với thân này,<br>Bậc Ðại Tuệ thuyết giảng,<br>Ðoạn tận cả ba pháp,<br>Thấy sắc bị quăng bỏ.<br><br>Thân bị quăng, vô tri,<br>Không thọ, sức nóng, thức,<br>Bị quăng đi, nó nằm,<br>Làm đồ ăn kẻ khác.<br><br>Cái thân liên tục này,<br>Ảo sư, kẻ ngu nói,<br>Ðược gọi kẻ sát nhân,<br>Không tìm thấy lõi cây.<br><br>Hãy quán uẩn như vậy,<br>Vị Tỷ-kheo tinh cần,<br>Suốt cả đêm lẫn ngày,<br>Tỉnh giác, chánh tư niệm.<br><br>Hãy bỏ mọi kiết sử,<br>Làm chỗ mình nương tựa,<br>Sống như lửa cháy đầu,<br>Cầu chứng cảnh bất động.`, ref: "Tương Ưng Bộ 22.95", url: "https://loicuaducphat.org/sn/sn22.95.html#content" },

{ text: `- Không có một sắc nào, này Tỷ-kheo, sắc ấy là thường còn, thường hằng, thường trú, không chịu sự biến hoại, vĩnh viễn thường hằng, vĩnh trú. Không có một thọ … một tưởng … các hành … một thức nào, thức ấy là thường còn, thường hằng, thường trú, không chịu sự biến hoại, vĩnh viễn thường hằng, vĩnh trú.`, ref: "Tương Ưng Bộ 22.98", url: "https://loicuaducphat.org/sn/sn22.98.html#content" },


{ text: `- Vô thuỷ, này các Tỷ-kheo, là sự luân hồi này. Ðiểm bắt đầu không thể nêu rõ đối với chúng sanh bị vô minh che đậy, bị khát ái trói buộc, phải lưu chuyển, luân hồi. Có thể có một thời, này các Tỷ kheo, biển lớn đi đến khô cạn, hoàn toàn đi đến khô kiệt, không có hiện hữu. Nhưng này các Tỷ kheo, Ta không có tuyên bố rằng, có sự chấm dứt khổ đau đối với chúng sanh bị vô minh che đậy, bị khát ái trói buộc, phải lưu chuyển, luân hồi. Có thể có một thời, này các Tỷ-kheo, Sineru (Tu-di), Vua các núi, đi đến băng hoại, hoại diệt, không có hiện hữu. Nhưng này các Tỷ-kheo, Ta không có tuyên bố rằng, có sự chấm dứt khổ đau đối với chúng sanh bị vô minh che đậy, bị khát ái trói buộc, phải lưu chuyển, luân hồi! Có thể có một thời, này các Tỷ-kheo, đại địa đi đến băng hoại, hoại diệt, không có hiện hữu. Nhưng này các Tỷ-kheo, Ta không có tuyên bố rằng, có sự chấm dứt khổ đau đối với chúng sanh bị vô minh che đậy, bị khát ái trói buộc, phải lưu chuyển luân hồi!`, ref: "Tương Ưng Bộ 22.99", url: "https://loicuaducphat.org/sn/sn22.99.html#content" },

{ text: `- Vô thuỷ, này các Tỷ-kheo, là sự luân hồi này. Ðiểm bắt đầu không thể nêu rõ đối với chúng sanh bị vô minh che đậy, bị khát ái trói buộc, phải lưu chuyển, luân hồi. Ví như, này các Tỷ-kheo, có con chó bị dây thằng trói chặt vào một cây cột trụ vững chắc. Nếu nó có đi, nó chỉ đi tới cây cột hay cột trụ ấy. Nếu nó đứng, nó chỉ đứng gần cây cột hay cột trụ ấy. Nếu nó ngồi, nó chỉ ngồi gần cây cột hay cột trụ ấy. Nếu nó nằm, nó chỉ nằm gần cây cột hay cột trụ ấy. Cũng vậy, này các Tỷ-kheo, kẻ vô văn phàm phu quán sắc: “Cái này là của tôi, cái này là tôi, cái này là tự ngã của tôi”, quán thọ … quán tưởng … quán các hành … quán thức: “Cái này là của tôi, cái này là tôi, cái này là tự ngã của tôi”. Nếu người ấy có đi, người ấy chỉ đi tới năm thủ uẩn này. Nếu người ấy đứng, người ấy chỉ đứng gần năm thủ uẩn này. Nếu người ấy ngồi, người ấy chỉ ngồi gần năm thủ uẩn này. Nếu người ấy nằm, người ấy chỉ nằm gần năm thủ uẩn này. Do vậy, này các Tỷ-kheo, cần phải luôn luôn quán sát tâm của mình như sau: “Trong một thời gian dài, tâm này bị tham, sân, si nhiễm ô. Do tâm nhiễm ô, này các Tỷ-kheo, chúng sanh bị nhiễm ô. Do tâm thanh tịnh, chúng sanh được thanh tịnh”.`, ref: "Tương Ưng Bộ 22.100", url: "https://loicuaducphat.org/sn/sn22.100.html#content" },


{ text: `Này các Tỷ-kheo, các Ông có thấy một bức họa gọi là danh họa không? - Thưa có, bạch Thế Tôn. - Này các Tỷ-kheo, bức danh họa ấy do tâm tư họa mà thành. Do vậy, này các Tỷ-kheo, tâm còn đa dạng hơn cả danh họa ấy. Do vậy, này các Tỷ-kheo, cần phải luôn luôn quán sát tâm của mình như sau: “Trong một thời gian dài, tâm này bị tham, sân, si làm nhiễm ô. Do tâm nhiễm ô, này các Tỷ-kheo, chúng sanh bị nhiễm ô. Do tâm thanh tịnh, chúng sanh được thanh tịnh”.`, ref: "Tương Ưng Bộ 22.100", url: "https://loicuaducphat.org/sn/sn22.100.html#content" },


{ text: `Này các Tỷ-kheo, Ta không quán thấy một bộ loại nào khác lại đa dạng như tâm. Như các hữu tình thuộc loại bàng sanh; các hữu tình thuộc loại bàng sanh ấy, này các Tỷ-kheo, do tâm tư duy (mà thành). Do vậy, này các Tỷ-kheo, tâm ấy lại đa dạng hơn các hữu tình thuộc loại bàng sanh ấy. Do vậy, này các Tỷ-kheo, cần phải luôn luôn quán sát tâm của mình như sau: “Trong một thời gian dài, tâm này bị tham, sân, si làm nhiễm ô. Do tâm nhiễm ô, này các Tỷ-kheo, chúng sanh bị nhiễm ô. Do tâm thanh tịnh, chúng sanh được thanh tịnh”.`, ref: "Tương Ưng Bộ 22.100", url: "https://loicuaducphat.org/sn/sn22.100.html#content" },


{ text: `Này các Tỷ-kheo, như có Tỷ-kheo sống không chí tâm trong sự tu tập, khởi lên ước muốn như sau: “Mong rằng tâm của ta được giải thoát khỏi các lậu hoặc, không có chấp thủ!” Tuy vậy, tâm của vị ấy cũng không giải thoát khỏi các lậu hoặc, có chấp thủ. Vì sao? Phải nói rằng vì vị ấy không có tu tập. Không có tu tập cái gì? Không có tu tập Bốn niệm xứ. Không có tu tập Bốn chánh cần. Không có tu tập Bốn như ý túc. Không có tu tập Năm căn. Không có tu tập Năm lực. Không có tu tập Bảy giác chi. Không có tu tập Thánh đạo Tám ngành.`, ref: "Tương Ưng Bộ 22.101", url: "https://loicuaducphat.org/sn/sn22.101.html#content" },

{ text: `- Do tu tập, làm cho sung mãn vô thường tưởng, tất cả dục tham được đoạn tận, tất cả sắc tham được đoạn tận, tất cả hữu tham được đoạn tận, tất cả vô minh được đoạn tận, tất cả ngã mạn được tận trừ. Ví như, này các Tỷ-kheo, một người làm ruộng, vào mùa thu, dùng một cái cày lớn cắt đứt tất cả rễ mọc trong khi cày. Cũng vậy, này các Tỷ-kheo, do tu tập, làm cho sung mãn vô thường tưởng, tất cả dục tham được đoạn tận, tất cả sắc tham được đoạn tận, tất cả hữu tham được đoạn tận, tất cả vô minh được đoạn tận, tất cả ngã mạn được tận trừ. Ví như, này các Tỷ-kheo, một người cắt cỏ cắt đứt cây cỏ, nắm lấy đầu ngọn đập lên, đập xuống, đập tả, đập hữu, rồi quăng một bên. Cũng vậy, này các Tỷ-kheo, do tu tập, làm cho sung mãn vô thường tưởng, tất cả dục tham được đoạn tận … tất cả ngã mạn được tận trừ. Ví như, này các Tỷ-kheo, khi một chùm xoài bị cắt đứt từ cành, thời các trái xoài cùng dính vào cành đều bị đứt theo. Cũng vậy, này các Tỷ-kheo, do tu tập, làm cho sung mãn vô thường tưởng, tất cả dục tham được đoạn tận … tất cả ngã mạn được tận trừ.`, ref: "Tương Ưng Bộ 22.102", url: "https://loicuaducphat.org/sn/sn22.102.html#content" },


{ text: `Ví như, này các Tỷ-kheo, trong mùa thu, khi trời mở rộng và gột sạch mây, mặt trời mọc lên trên bầu trời, đuổi sạch tất cả u ám khỏi hư không, bừng sáng, chói sáng và rực sáng. Cũng vậy, này các Tỷ-kheo, do tu tập, làm cho sung mãn vô thường tưởng, tất cả dục tham được đoạn tận, tất cả sắc tham được đoạn tận, tất cả hữu tham được đoạn tận, tất cả vô minh được đoạn tận, tất cả ngã mạn được tận trừ. Tu tập vô thường tưởng như thế nào, này các Tỷ-kheo, làm cho sung mãn như thế nào mà tất cả dục tham được đoạn tận … tất cả ngã mạn được tận trừ? Ðây là sắc; đây là sắc tập khởi; đây là sắc đoạn diệt; đây là thọ … đây là tưởng … đây là các hành … đây là thức; đây là thức tập khởi; đây là thức đoạn diệt. Vô thường tưởng được tu tập như vậy, này các Tỷ-kheo, được làm cho sung mãn như vậy, tất cả dục tham được đoạn tận, tất cả sắc tham được đoạn tận; tất cả hữu tham được đoạn tận; tất cả vô minh được đoạn tận; tất cả ngã mạn được tận trừ.`, ref: "Tương Ưng Bộ 22.102", url: "https://loicuaducphat.org/sn/sn22.102.html#content" },


{ text: `- Này các Tỷ-kheo, Ta sẽ thuyết cho các Ông về Khổ, Khổ tập khởi, Khổ đoạn diệt, Con đường đưa đến khổ đoạn diệt. Hãy lắng nghe. Và này các Tỷ-kheo, thế nào là Khổ? Phải trả lời là năm thủ uẩn. Thế nào là năm? Tức là sắc thủ uẩn … thức thủ uẩn. Ðây gọi là Khổ, này các Tỷ-kheo. Và này các Tỷ-kheo, thế nào là Khổ tập khởi? Chính là khát ái này, đưa đến tái sanh … phi hữu ái. Này các Tỷ-kheo, đây gọi là Khổ tập khởi. Và này các Tỷ-kheo, thế nào là Khổ đoạn diệt? Chính là sự ly tham, đoạn diệt không dư tàn khát ái ấy, sự xả ly, sự từ bỏ, sự giải thoát, sự thoát ly chấp trước. Này các Tỷ-kheo, đây gọi là Khổ đoạn diệt. Và này các Tỷ-kheo, thế nào là Con đường đưa đến khổ đoạn diệt? Chính là con đường Thánh đạo Tám ngành, tức là chánh tri kiến … chánh định. Này các Tỷ-kheo, đây gọi là Con đường đưa đến khổ đoạn diệt.`, ref: "Tương Ưng Bộ 22.104", url: "https://loicuaducphat.org/sn/sn22.104.html#content" },

{ text: `- Này các Tỷ-kheo, Ta sẽ thuyết cho các Ông về các pháp bị trói buộc và sự trói buộc. Hãy lắng nghe. Và này các Tỷ-kheo, thế nào là các pháp bị trói buộc? Thế nào là sự trói buộc? Sắc, này các Tỷ-kheo, là pháp bị trói buộc. Dục và tham đối với sắc là sự trói buộc của sắc. … Thọ … Tưởng … Các hành … Thức, này các Tỷ-kheo, là pháp bị trói buộc. Dục và tham đối với thức là sự trói buộc của thức. Này các Tỷ-kheo, các pháp này, này các Tỷ-kheo, được gọi là các pháp bị trói buộc. Ðây là sự trói buộc.`, ref: "Tương Ưng Bộ 22.120", url: "https://loicuaducphat.org/sn/sn22.120.html#content" },


{ text: `- Thưa Hiền giả Sāriputta, những pháp gì Tỷ-kheo giữ giới cần phải như lý tác ý? - Này Hiền giả Kotthika, Tỷ-kheo giữ giới cần phải như lý tác ý năm thủ uẩn là vô thường, khổ, bệnh hoạn, ung nhọt, mũi tên, bất hạnh, ốm đau, người lạ, hủy hoại, rỗng không, vô ngã. Thế nào là năm? Tức là sắc thủ uẩn, thọ thủ uẩn, tưởng thủ uẩn, hành thủ uẩn, thức thủ uẩn. Này Hiền giả Kotthika, vị Tỷ-kheo giữ giới cần phải như lý tác ý năm thủ uẩn là vô thường, khổ, bệnh hoạn, ung nhọt, mũi tên, bất hạnh, ốm đau, người lạ, hủy hoại, rỗng không, vô ngã.`, ref: "Tương Ưng Bộ 22.122", url: "https://loicuaducphat.org/sn/sn22.122.html#content" },

{ text: `“Vô minh, vô minh”, bạch Thế Tôn, được nói đến như vậy. Bạch Thế Tôn, thế nào là vô minh? Và cho đến như thế nào được gọi là vô minh? - Ở đây, này Tỷ-kheo, kẻ vô văn phàm phu, không như thật biết rõ: “Sắc chịu sự tập khởi” là sắc chịu sự tập khởi, không như thật biết rõ: “Sắc chịu sự đoạn diệt” là sắc chịu sự đoạn diệt, không như thật biết rõ: “Sắc chịu sự tập khởi và đoạn diệt” là sắc chịu sự tập khởi và đoạn diệt. Như vậy, này Tỷ-kheo, gọi là vô minh. Cho đến như vậy được gọi là vô minh.`, ref: "Tương Ưng Bộ 22.126", url: "https://loicuaducphat.org/sn/sn22.126.html#content" },

{ text: `- Sắc là than đỏ, này các Tỷ-kheo! Thọ là than đỏ! Tưởng là than đỏ! Các hành là than đỏ! Thức là than đỏ! Thấy vậy, này các Tỷ-kheo, bậc Ða văn Thánh đệ tử nhàm chán đối với sắc, nhàm chán đối với thọ, nhàm chán đối với tưởng, nhàm chán đối với các hành, nhàm chán đối với thức. Do nhàm chán nên ly tham, do ly tham nên giải thoát. Trong sự giải thoát, trí khởi lên: “Ta đã được giải thoát”. Vị ấy biết rõ: “Sanh đã tận, Phạm hạnh đã thành, các việc nên làm đã làm, không còn trở lui trạng thái này nữa”.`, ref: "Tương Ưng Bộ 22.136", url: "https://loicuaducphat.org/sn/sn22.136.html#content" },

{ text: `- Cái gì vô thường, này các Tỷ-kheo, ở đây các Ông cần phải đoạn trừ lòng dục. Này các Tỷ-kheo, cái gì là vô thường? Này các Tỷ-kheo, sắc là vô thường. … Thọ … Tưởng … Các hành … Thức là vô thường, ở đây, các Ông cần phải đoạn trừ lòng dục. Cái gì vô thường, này các Tỷ-kheo, ở đây các Ông cần phải đoạn trừ lòng dục.`, ref: "Tương Ưng Bộ 22.137", url: "https://loicuaducphat.org/sn/sn22.137.html#content" },


{ text: `- Ðối với vị thiện nam tử vì lòng tin xuất gia, này các Tỷ-kheo, đây là thuận pháp: Hãy sống nhàm chán nhiều đối với sắc… đối với thọ… đối với tưởng… đối với các hành, hãy sống nhàm chán nhiều đối với thức. Ai sống nhàm chán nhiều đối với sắc… đối với thọ… đối với tưởng… đối với các hành, ai sống nhàm chán nhiều đối với thức thời sẽ biến tri sắc… thọ… tưởng… các hành, biến tri thức. Vị nào biến tri sắc, biến tri thọ, biến tri tưởng, biến tri các hành, biến tri thức, thời được giải thoát khỏi sắc, được giải thoát khỏi thọ, được giải thoát khỏi tưởng, được giải thoát khỏi các hành, được giải thoát khỏi thức, được giải thoát khỏi sanh, già, chết, sầu, bi, khổ, ưu, não. Ta nói vị ấy được giải thoát khỏi đau khổ.`, ref: "Tương Ưng Bộ 22.146", url: "https://loicuaducphat.org/sn/sn22.146.html#content" },


{ text: `- Bạch Thế Tôn, chánh quán với mục đích gì? - Chánh quán, này Rādha, với mục đích nhàm chán. - Bạch Thế Tôn, nhàm chán với mục đích gì? - Nhàm chán, này Rādha, với mục đích ly tham. - Bạch Thế Tôn, ly tham với mục đích gì? - Ly tham, này Rādha, với mục đích được giải thoát. - Bạch Thế Tôn, giải thoát với mục đích gì? - Giải thoát, này Rādha, với mục đích Niết-bàn. - Bạch Thế Tôn, Niết-bàn với mục đích gì? - Này Rādha, Ông đi quá xa với câu hỏi này, không thế nắm được giới hạn của câu hỏi. Nhập vào Niết-bàn, này Rādha, là sự thực hành Phạm hạnh; Niết-bàn là mục tiêu cuối cùng; Niết-bàn là cứu cánh.`, ref: "Tương Ưng Bộ 23.1", url: "https://loicuaducphat.org/sn/sn23.1.html#content" },


{ text: `- Nếu có sắc, này Rādha, thời có chết, hay có sát giả, hay có bị chết. Do vậy, này Rādha, Ông hãy thấy sắc là sự chết, hãy thấy là sát giả, hãy thấy là bị chết, hãy thấy là bệnh, hãy thấy là ung nhọt, hãy thấy là mũi tên, hãy thấy là bất hạnh, hãy thấy tự tánh là bất hạnh. Những ai thấy sắc như vậy là thấy chơn chánh.`, ref: "Tương Ưng Bộ 23.1", url: "https://loicuaducphat.org/sn/sn23.1.html#content" },


{ text: `Ví như, này Rādha, các đứa con trai hay các đứa con gái chơi với cái nhà bằng đất. Cho đến khi đối với những nhà bằng đất ấy, lòng tham chưa thoát ly, lòng dục chưa thoát ly, lòng ái chưa thoát ly, lòng khát chưa thoát ly, lòng nhiệt tình chưa thoát ly, lòng khát ái chưa thoát ly, thời chúng còn tham dính vào, thích chơi, chất chứa, và đắm trước những nhà bằng đất ấy. Nhưng khi nào các đứa con trai hay các đứa con gái ấy đối với những nhà bằng đất kia, lòng tham đã thoát ly, lòng dục đã thoát ly, lòng ái đã thoát ly, lòng khát đã thoát ly, lòng nhiệt tình đã thoát ly, lòng khát ái đã thoát ly, thời với tay và với chân, chúng phá tan, phá vỡ, phá sập, không chơi với những căn nhà bằng đất ấy. Cũng vậy, này Rādha, Ông hãy phá tan, phá vỡ, phá sập, không chơi với sắc, chú tâm hướng đến đoạn diệt khát ái đối với sắc. Ðoạn diệt khát ái, này Rādha, là Niết-bàn.`, ref: "Tương Ưng Bộ 23.2", url: "https://loicuaducphat.org/sn/sn23.2.html#content" },


{ text: `“Chúng sanh, chúng sanh”, bạch Thế Tôn, được nói đến như vậy. Cho đến như thế nào, bạch Thế Tôn, được gọi là chúng sanh? - Này Rādha, dục nào, tham nào, hỷ nào, khát ái nào đối với sắc, triền phược ở đấy, triền miên ở đấy, do vậy gọi là chúng sanh … thọ … tưởng … các hành … Dục nào, tham nào, hỷ nào, khát ái nào đối với thức, triền phược ở đấy, triền miên ở đấy, do vậy gọi là chúng sanh.`, ref: "Tương Ưng Bộ 23.2", url: "https://loicuaducphat.org/sn/sn23.2.html#content" },


{ text: `“Ðoạn diệt sợi dây tái sanh. Ðoạn diệt sợi dây tái sanh”, bạch Thế Tôn, được nói đến như vậy. Thế nào là sợi dây tái sanh, bạch Thế Tôn? Thế nào là sự đoạn diệt sợi dây tái sanh? - Này Rādha, phàm dục gì, tham gì, hỷ gì, khát ái gì, phàm những chấp thủ phương tiện, tâm kiên trú, thiên chấp tùy miên gì đối với sắc, như vậy gọi là sợi dây tái sanh. Sự đoạn diệt chúng là sự đoạn diệt sợi dây tái sanh. … đối với thọ … với tưởng … với các hành … Phàm dục gì, tham gì, hỷ gì, khát ái gì, phàm những chấp thủ phương tiện, tâm kiên trú, thiên chấp tùy miên gì đối với thức, đó gọi là sợi dây tái sanh. Sự đoạn diệt chúng là sự đoạn diệt sợi dây tái sanh.`, ref: "Tương Ưng Bộ 23.3", url: "https://loicuaducphat.org/sn/sn23.3.html#content" },

{ text: `- Này Rādha, phàm có dục nào, tham nào, hỷ nào, khát ái nào đối với sắc, hãy từ bỏ chúng. Như vậy, sắc sẽ được đoạn tận, cắt đứt tận gốc rễ, làm cho như thân cây ta-la, làm cho không thể tái sanh, không thể sanh khởi trong tương lai. … đối với thọ … đối với tưởng … đối với các hành … Này Rādha, phàm có dục nào, tham nào, hỷ nào, khát ái nào, đối với thức, hãy từ bỏ chúng. Như vậy, thức sẽ được đoạn tận, cắt đứt tận gốc rễ, làm cho như thân cây ta-la, làm cho không thể tái sanh, không thể sanh khởi trong tương lai.`, ref: "Tương Ưng Bộ 23.9", url: "https://loicuaducphat.org/sn/sn23.9.html#content" },

{ text: `- Này các Tỷ-kheo, sự sanh, sự trú, sự thành, sự xuất hiện của mắt là sự sanh của khổ, sự trú của bệnh hoạn, sự xuất hiện của già chết. Sự sanh, sự trú, sự thành, sự xuất hiện của tai … của mũi … của lưỡi … của thân … của ý là sự sanh của khổ, sự trú của bệnh hoạn, sự xuất hiện của già chết. Sự diệt, sự lắng dịu, sự chấm dứt của sắc là sự diệt của khổ, sự lắng dịu của bệnh hoạn, sự chấm dứt của già chết. Sự diệt, sự lắng dịu, sự chấm dứt của tai … của mũi … của lưỡi … của thân … của ý là sự diệt của khổ, sự lắng dịu của bệnh hoạn, sự chấm dứt của già chết.`, ref: "Tương Ưng Bộ 26.1", url: "https://loicuaducphat.org/sn/sn26.1.html#content" },

{ text: `- Này các Tỷ-kheo, dục tham đối với mắt là tùy phiền não của tâm. Dục tham đối với tai là tùy phiền não của tâm. Dục tham đối với mũi là tùy phiền não của tâm. Dục tham đối với lưỡi là tùy phiền não của tâm. Dục tham đối với thân là tùy phiền não của tâm. Dục tham đối với ý là tùy phiền não của tâm. Này các Tỷ-kheo, khi nào vị Tỷ-kheo đối với sáu xứ này, đoạn tận được tùy phiền não, thời tâm vị ấy hướng về ly dục. Do biến mãn với ly dục, tâm vị ấy được xem là kham nhẫn, chứng tri đối với các pháp cần phải giác ngộ.`, ref: "Tương Ưng Bộ 27.1", url: "https://loicuaducphat.org/sn/sn27.1.html#content" },

{ text: `- Ai ưa thích các sắc, này các Tỷ-kheo, người ấy ưa thích khổ. Ai ưa thích khổ, Ta nói người ấy không thoát khỏi khổ. Ai ưa thích các tiếng … các hương … các vị … các xúc … Ai ưa thích các pháp, người ấy ưa thích khổ. Ai ưa thích khổ, Ta nói người ấy không thoát khỏi khổ. Ai không ưa thích các sắc, này các Tỷ-kheo, người ấy không ưa thích khổ. Ai không ưa thích khổ, Ta nói người ấy thoát khỏi khổ. Ai không ưa thích các tiếng … các hương … các vị … các xúc … Ai không ưa thích các pháp, người ấy không ưa thích khổ. Ai không ưa thích khổ, Ta nói người ấy thoát khỏi khổ.`, ref: "Tương Ưng Bộ 35.20", url: "https://loicuaducphat.org/sn/sn35.20.html#content" },

{ text: `Mắt, này các Tỷ-kheo, bị bốc cháy. Các sắc bị bốc cháy. Nhãn thức bị bốc cháy. Nhãn xúc bị bốc cháy. Do duyên nhãn xúc khởi lên cảm thọ gì, lạc, khổ hay bất khổ bất lạc; cảm thọ ấy bị bốc cháy. Bị bốc cháy bởi cái gì? Bị bốc cháy bởi lửa tham, lửa sân, lửa si. Ta nói rằng bị bốc cháy bởi sanh, già, chết, sầu, bi, khổ, ưu, não … Tai … Mũi … Lưỡi bị bốc cháy. Các vị bị bốc cháy. Thiệt thức bị bốc cháy. Thiệt xúc bị bốc cháy. Do duyên thiệt xúc khởi lên cảm thọ gì, lạc, khổ hay bất khổ bất lạc; cảm thọ ấy bị bốc cháy. Bị bốc cháy bởi cái gì? Bị bốc cháy bởi lửa tham, lửa sân, lửa si. Ta nói rằng bị bốc cháy bởi sanh, già, chết, sầu, bi, khổ, ưu, não … Thân … Ý bị bốc cháy. Các pháp bị bốc cháy. Ý thức bị bốc cháy. Ý xúc bị bốc cháy. Do duyên ý xúc khởi lên cảm thọ gì, lạc, khổ, hay bất khổ bất lạc; cảm thọ ấy bị bốc cháy. Bị bốc cháy bởi cái gì? Bị bốc cháy bởi lửa tham, lửa sân, lửa si. Ta nói rằng bị bốc cháy bởi sanh, già, chết, sầu, bi, khổ, ưu, não.`, ref: "Tương Ưng Bộ 35.28", url: "https://loicuaducphat.org/sn/sn35.28.html#content" },


{ text: `- Do biết như thế nào, bạch Thế Tôn, do thấy như thế nào, vô minh được đoạn tận, minh được sanh khởi? - Này Tỷ-kheo, do biết, do thấy mắt là vô thường, vô minh được đoạn tận, minh được sanh khởi. Do biết, do thấy các sắc là vô thường, vô minh được đoạn tận, minh được sanh khởi … nhãn thức … nhãn xúc … Do duyên nhãn xúc khởi lên cảm thọ gì, lạc, khổ hay bất khổ bất lạc; do biết, do thấy cảm thọ ấy là vô thường, vô minh được đoạn tận, minh được sanh khởi. Tai … Mũi … Lưỡi … Thân … Do biết, do thấy ý là vô thường, vô minh được đoạn tận, minh được sanh khởi … Các pháp … Ý thức … Ý xúc … Do duyên ý xúc khởi lên cảm thọ gì, lạc, khổ, hay bất khổ bất lạc; do biết, do thấy cảm thọ ấy là vô thường, vô minh được đoạn tận, minh được sanh khởi. Do biết như vậy, này các Tỷ-kheo, do thấy như vậy, vô minh được đoạn tận, minh được sanh khởi.`, ref: "Tương Ưng Bộ 35.53", url: "https://loicuaducphat.org/sn/sn35.53.html#content" },


{ text: `Và này các Tỷ-kheo, thế nào là pháp đưa đến liễu tri tất cả chấp thủ? Do duyên mắt và các sắc khởi lên nhãn thức. Do ba pháp này hợp lại có xúc. Do duyên xúc có thọ. Thấy vậy, này các Tỷ-kheo, bậc Ða văn Thánh đệ tử nhàm chán đối với mắt, nhàm chán đối với các sắc, nhàm chán đối với nhãn thức, nhàm chán đối với nhãn xúc, nhàm chán đối với với thọ. Do nhàm chán, vị ấy ly tham. Do ly tham, vị ấy được giải thoát. Nhờ giải thoát, vị ấy biết rõ: “Ta đã liễu tri chấp thủ”. Do duyên tai và các tiếng khởi lên nhĩ thức … Do duyên mũi và các hương … Do duyên lưỡi và các vị … Do duyên thân và các xúc … Do duyên ý và các pháp khởi lên ý thức. Do ba pháp này hợp lại có xúc. Do duyên xúc có thọ. Thấy vậy, này các Tỷ-kheo, bậc Ða văn Thánh đệ tử nhàm chán đối với ý, nhàm chán đối với các pháp, nhàm chán đối với ý thức, nhàm chán đối với ý xúc, nhàm chán đối với thọ. Do nhàm chán, vị ấy ly tham. Do ly tham, vị ấy được giải thoát. Nhờ giải thoát, vị ấy biết rõ: “Ta đã liễu tri chấp thủ”. Như vậy, này các Tỷ-kheo, là pháp đưa đến liễu tri tất cả chấp thủ.`, ref: "Tương Ưng Bộ 35.60", url: "https://loicuaducphat.org/sn/sn35.60.html#content" },


{ text: `Này Migajāla, có những pháp do ý nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu Tỷ-kheo hoan hỷ, tán dương và trú với lòng tham luyến pháp ấy; do vị ấy hoan hỷ, tán dương và trú với lòng tham luyến pháp ấy nên hỷ khởi lên. Do hỷ có mặt nên dục tham có mặt. Do dục tham có mặt nên triền phược có mặt. Bị trói buộc bởi hỷ triền phược, này Migajāla, nên Tỷ-kheo được gọi là người sống có người thứ hai. Tỷ-kheo sống như vậy, này Migajāla, dầu cho đến ở các trú xứ xa vắng, các khóm rừng, các khu rừng, ít tiếng động, ít ồn ào, khỏi hơi thở quần chúng, vắng người, thích hợp với tịnh; dầu vậy, vẫn được gọi là sống với người thứ hai. Vì sao? Vì rằng ái, người thứ hai, chưa được đoạn tận cho nên được gọi là sống có người thứ hai.`, ref: "Tương Ưng Bộ 35.63", url: "https://loicuaducphat.org/sn/sn35.63.html#content" },

{ text: `Và này Migajala, có các sắc do mắt nhận thức, khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu Tỷ-kheo không hoan hỷ, không tán dương và trú với lòng không tham luyến pháp ấy; thời do vị ấy không hoan hỷ, không tán dương và trú với lòng không tham luyến pháp ấy, nên hỷ đoạn diệt; thời do hỷ không có mặt nên dục tham không có mặt. Do dục tham không có mặt nên triền phược không có mặt. Do không bị trói buộc bởi hỷ triền phược, này Migajāla, nên Tỷ-kheo được gọi là người trú một mình.`, ref: "Tương Ưng Bộ 35.63", url: "https://loicuaducphat.org/sn/sn35.63.html#content" },

{ text: `Này Migajāla, có những pháp do ý nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu Tỷ-kheo không hoan hỷ, không tán dương và trú với tâm không tham luyến pháp ấy; thời do vị ấy không hoan hỷ, không tán dương, trú với tâm không tham luyến pháp ấy nên hỷ đoạn diệt. Do hỷ không có mặt nên dục tham không có mặt. Do dục tham không có mặt nên triền phược không có mặt. Do không bị trói buộc bởi hỷ triền phược, này Migajāla, nên Tỷ-kheo được gọi là người trú một mình. Tỷ-kheo sống như vậy, này Migajāla, dầu có ở giữa làng tràn đầy những Tỷ-kheo, Tỷ-kheo-ni, nam cư sĩ, nữ cư sĩ, vua chúa, đại thần của vua, các ngoại đạo và các đệ tử các ngoại đạo, vị ấy vẫn được gọi là vị sống một mình. Vì sao? Vì rằng ái, người thứ hai, được đoạn tận, do vậy được gọi là sống một mình.`, ref: "Tương Ưng Bộ 35.63", url: "https://loicuaducphat.org/sn/sn35.63.html#content" },

{ text: `- Này Migajāla, có những sắc do mắt nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu Tỷ-kheo hoan hỷ, tán dương, sống với tâm tham luyến sắc ấy; do vị ấy hoan hỷ, tán dương, sống với tâm tham luyến sắc ấy nên hỷ sanh. Này Migajāla, Ta nói rằng do hỷ tập khởi nên khổ tập khởi … Các tiếng … Các hương … … Các vị … Các xúc … Này Migajāla, có những pháp do ý nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu Tỷ-kheo hoan hỷ, tán dương, sống với tâm tham luyến pháp ấy; do vị ấy hoan hỷ, tán dương sống với tâm tham luyến pháp ấy nên hỷ sanh. Này Migajāla, Ta nói rằng do hỷ tập khởi nên khổ tập khởi.`, ref: "Tương Ưng Bộ 35.64", url: "https://loicuaducphat.org/sn/sn35.64.html#content" },

{ text: `Này Migajāla, có những sắc do mắt nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu Tỷ-kheo không hoan hỷ, không tán dương, sống với tâm không tham luyến sắc ấy; do vị ấy không hoan hỷ, không tán dương, sống với tâm không tham luyến, không an trú tham luyến sắc ấy nên hỷ diệt. Này Migajāla, Ta nói rằng do hoan hỷ đoạn diệt nên khổ đoạn diệt … Các tiếng … Các hương … … Các vị … Các xúc … Này Migajāla, có những pháp do ý nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu Tỷ-kheo không hoan hỷ, không tán dương, sống với tâm không tham luyến pháp ấy; do vị ấy không hoan hỷ, không tán dương, sống với tâm không tham luyến pháp ấy nên hỷ diệt. Này Migajāla, Ta nói rằng do hỷ đoạn diệt nên khổ đoạn diệt.`, ref: "Tương Ưng Bộ 35.64", url: "https://loicuaducphat.org/sn/sn35.64.html#content" },


{ text: `:“Thiết thực hiện tại, thiết thực hiện tại (Sanditthiko)”, bạch Thế Tôn, như vậy được nói đến. Cho đến như thế nào, bạch Thế Tôn, là thiết thực hiện tại, có kết quả tức thời, đến để mà thấy, có khả năng hướng thượng, được những người có trí tự mình giác hiểu? Ở đấy, này Upavāna, sau khi mắt thấy sắc, Tỷ-kheo cảm thọ sắc, nhưng không cảm thọ tham sắc, và không có nội tham đối với sắc; vị ấy biết rõ: “Tôi không có nội tham đối với sắc”. Cho đến chừng nào, này Upavāna, sau khi mắt thấy sắc, Tỷ-kheo cảm thọ sắc, nhưng không cảm thọ tham sắc, và không có nội tham đối với các sắc; vị ấy biết rõ: “Tôi không có nội tham đối với các sắc”. Như vậy, này Upavāna, là thiết thực hiện tại, có kết quả tức thời, đến để mà thấy, có khả năng hướng thượng, được những người trí tự mình giác hiểu.`, ref: "Tương Ưng Bộ 35.70", url: "https://loicuaducphat.org/sn/sn35.70.html#content" },

{ text: `- Bạch Thế Tôn, con không hiểu pháp Thế Tôn dạy về mục đích thanh tịnh trì giới. - Này Tỷ-kheo, nếu Ông không hiểu pháp Ta dạy về mục đích thanh tịnh trì giới, thời này Tỷ-kheo, Ông hiểu pháp Ta dạy như thế nào? - Bạch Thế Tôn, con hiểu pháp do Thế Tôn dạy là tham và đoạn tham. - Lành thay, lành thay, này Tỷ-kheo! Lành thay, này Tỷ-kheo! Ông hiểu pháp Ta dạy là tham và đoạn tham. Với mục đích tham và đoạn tham, này Tỷ-kheo, là pháp Ta dạy. Ông nghĩ thế nào, này Tỷ-kheo, mắt là thường hay vô thường? - Là vô thường, bạch Thế Tôn … - Tai … Mũi … Lưỡi … Thân … Ý là thường hay vô thường? - Là vô thường, bạch Thế Tôn. - Cái gì vô thường là khổ hay lạc? - Cái gì vô thường, khổ, chịu sự biến hoại, có hợp lý chăng nếu quán cái ấy là: “Cái này là của tôi, cái này là tôi, cái này là tự ngã của tôi”? - Thưa không, bạch Thế Tôn. - Thấy vậy, này Tỷ-kheo, bậc Ða văn Thánh đệ tử nhàm chán đối với mắt … ” … không còn trở lui trạng thái này nữa”.`, ref: "Tương Ưng Bộ 35.74", url: "https://loicuaducphat.org/sn/sn35.74.html#content" },

{ text: `Ngồi xuống một bên, Tôn giả Rādha bạch Thế Tôn: - Lành thay, bạch Thế Tôn, nếu Thế Tôn vắn tắt thuyết pháp cho con. Sau khi nghe pháp của Thế Tôn con sẽ sống một mình, an tịnh, không phóng dật, nhiệt tâm, tinh cần. - Cái gì vô thường, này Rādha, ở đây Ông cần phải đoạn tận lòng dục. Và này Rādha, cái gì là vô thường? Mắt, này Rādha, là vô thường, ở đây Ông cần phải đoạn tận lòng dục. Các sắc là vô thường … Nhãn thức là vô thường … Nhãn xúc … Do duyên nhãn xúc khởi lên cảm thọ gì, lạc, khổ, hay bất khổ bất lạc; cảm thọ ấy là vô thường. Ở đây, Ông cần phải đoạn tận lòng dục … Tai … Mũi … … Lưỡi … Thân … Ý là vô thường, ở đây Ông cần phải đoạn tận lòng dục. Các pháp … Ý thức … Do duyên ý xúc khởi lên cảm thọ gì, lạc, khổ, hay bất khổ bất lạc; cảm thọ ấy là vô thường. Ở đây, Ông cần phải đoạn tận lòng dục. Phàm cái gì là vô thường, này Rādha, ở đây, Ông cần phải đoạn tận lòng dục.`, ref: "Tương Ưng Bộ 35.76", url: "https://loicuaducphat.org/sn/sn35.76.html#content" },

{ text: `- Phàm cái gì là khổ, này Rādha, ở đây Ông cần phải đoạn tận lòng dục. Và này Rādha, cái gì là khổ? Mắt, này Rādha, là khổ; ở đây, Ông cần phải đoạn tận lòng dục. Các pháp … Nhãn thức … Nhãn xúc … Do duyên ý xúc, khởi lên cảm thọ gì, lạc, khổ, hay bất khổ bất lạc; cảm thọ ấy là khổ. Ở đây, Ông cần phải đoạn tận lòng dục. Phàm cái gì là khổ, này Rādha, ở đây, Ông cần phải đoạn tận lòng dục.`, ref: "Tương Ưng Bộ 35.77", url: "https://loicuaducphat.org/sn/sn35.77.html#content" },


{ text: `:“Trống không là thế giới, trống không là thế giới”, bạch Thế Tôn, như vậy được nói đến. Cho đến như thế nào, bạch Thế Tôn, được gọi trống không là thế giới? - Vì rằng, này Ānanda, thế giới là không tự ngã, và không thuộc tự ngã, nên thế giới được gọi là trống không. Và cái gì, này Ānanda, là không tự ngã và không thuộc tự ngã? Mắt, này Ānanda, là không tự ngã và không thuộc tự ngã. Các sắc là không tự ngã, hay không thuộc tự ngã. Nhãn thức là không tự ngã, hay không thuộc tự ngã. Nhãn xúc là không tự ngã, hay không thuộc tự ngã … Do duyên ý xúc khởi lên cảm thọ gì, lạc, khổ, hay bất khổ bất lạc; cảm thọ ấy không có tự ngã hay không thuộc tự ngã. Và vì rằng, này Ānanda, không có tự ngã, hay không thuộc tự ngã nên được gọi trống không là thế giới này.`, ref: "Tương Ưng Bộ 35.85", url: "https://loicuaducphat.org/sn/sn35.85.html#content" },


{ text: `- Ái nhiễm, này các Tỷ-kheo, là bệnh tật; ái nhiễm là mụt nhọt; ái nhiễm là mũi tên. Do vậy, này các Tỷ-kheo, Như Lai sống không ái nhiễm, không bị mũi tên làm bị thương. Do vậy, này các Tỷ-kheo, nếu Tỷ-kheo có ước vọng gì, hãy ước sống không ái nhiễm, không bị mũi tên làm bị thương. Chớ có nghĩ đến mắt, chớ có nghĩ đến trong mắt, chớ có nghĩ đến từ mắt, chớ có nghĩ đến: “Mắt là của tôi”. Chớ có nghĩ đến các sắc, chớ có nghĩ đến trong các sắc, chớ có nghĩ đến từ các sắc, chớ có nghĩ đến: “Các sắc là của tôi”. Chớ có nghĩ đến nhãn thức, chớ có nghĩ đến trong nhãn thức, chớ có nghĩ đến từ nhãn thức, chớ có nghĩ đến: “Nhãn thức là của tôi”. Chớ có nghĩ đến nhãn xúc, chớ có nghĩ đến trong nhãn xúc, chớ có nghĩ đến từ nhãn xúc, chớ có nghĩ đến: “Nhãn xúc là của tôi”. Do duyên nhãn xúc khởi lên cảm thọ gì, lạc, khổ hay bất khổ bất lạc; chớ có nghĩ đến cảm thọ ấy, chớ có nghĩ đến trong cảm thọ ấy, chớ có nghĩ đến từ cảm thọ ấy, chớ có nghĩ đến: “Cảm thọ ấy là tôi”. Chớ có nghĩ đến tất cả, chớ có nghĩ đến trong tất cả, chớ có nghĩ đến từ tất cả, chớ có nghĩ đến: “Tất cả là của tôi”. Vị ấy do không nghĩ đến nên không chấp thủ một vật gì ở đời. Do không chấp thủ, vị ấy không có dao động. Do không dao động, vị ấy tự mình tịch tịnh một cách hoàn toàn. Vị ấy biết rõ: “Sanh đã tận, Phạm hạnh đã thành, những việc nên làm đã làm, không còn trở lui trạng thái này nữa”.`, ref: "Tương Ưng Bộ 35.90", url: "https://loicuaducphat.org/sn/sn35.90.html#content" },


{ text: `- Có sáu xúc xứ này, này các Tỷ-kheo, không nhiếp phục, không phòng hộ, không bảo vệ, không thâu nhiếp, đem lại đau khổ. Thế nào là sáu? Mắt xúc xứ, này các Tỷ-kheo, không nhiếp phục, không phòng hộ, không bảo vệ, không thâu nhiếp, đem lại đau khổ … Tai … Mũi … … Lưỡi … Thân … Ý xúc xứ, này các Tỷ-kheo, không nhiếp phục, không phòng hộ, không bảo vệ, không thâu nhiếp, đem lại đau khổ. Sáu xúc xứ này, này các Tỷ-kheo, không nhiếp phục, không phòng hộ, không bảo vệ, không thâu nhiếp, đem lại đau khổ.`, ref: "Tương Ưng Bộ 35.94", url: "https://loicuaducphat.org/sn/sn35.94.html#content" },


{ text: `Có sáu xúc này, này các Tỷ-kheo, khéo nhiếp phục, khéo phòng hộ, khéo bảo vệ, khéo thâu nhiếp, đem lại an lạc. Thế nào là sáu? Mắt xúc xứ, này các Tỷ-kheo, khéo nhiếp phục, khéo phòng hộ, khéo bảo vệ, khéo thâu nhiếp, đem lại an lạc … Tai … Mũi … … Lưỡi … Thân … Ý xúc xứ, này các Tỷ-kheo, khéo nhiếp phục, khéo phòng hộ, khéo bảo vệ, khéo thâu nhiếp, đem lại an lạc. Sáu xúc xứ này, này các Tỷ-kheo, khéo nhiếp phục, khéo phòng hộ, khéo bảo vệ, khéo thâu nhiếp, đem lại an lạc.`, ref: "Tương Ưng Bộ 35.94", url: "https://loicuaducphat.org/sn/sn35.94.html#content" },


{ text: `Hỡi các vị Tỷ-kheo,<br>Chính sáu xúc xứ này,<br>Chỗ nào không thâu nhiếp,<br>Chỗ ấy có đau khổ.<br>Những ai học biết được,<br>Chế ngự, phòng hộ chúng,<br>Với lòng tin làm bạn,<br>Sống thoát ly dục vọng.<br><br>Thấy sắc pháp khả ái,<br>Thấy sắc không khả ái,<br>Hãy nhiếp phục đường tham,<br>Ðối các sắc khả ái,<br>Chớ khiến ý nhiễm ô:<br>“Ðối sắc, ta không thích”.<br><br>Sau khi nghe các tiếng,<br>Khả ái, không khả ái,<br>Chớ để tâm say mê,<br>Với các tiếng khả ái.<br>Hãy nhiếp phục lòng sân,<br>Với tiếng không khả ái,<br>Chớ khiến ý nhiễm ô:<br>“Ðối tiếng, ta không thích”.<br><br>Sau khi ngửi các hương,<br>Thơm dịu, thật khả ái,<br>Sau khi ngửi các hương,<br>Bất tịnh, thật đáng ghét;<br>Hãy nhiếp phục lòng sân,<br>Ðối các hương đáng ghét,<br>Còn đối hương khả ái,<br>Chớ để dục chi phối.<br><br>Nếm xong vị ngon ngọt,<br>Và nếm vị không ngon,<br>Chớ có sanh tham luyến,<br>Khi hưởng nếm vị ngon,<br>Chớ nói lời chống đối,<br>Khi nếm vị không ngon.<br><br>Khi cảm thọ lạc xúc,<br>Chớ đắm say tham luyến,<br>Khi cảm thọ khổ xúc,<br>Chớ bị xúc động mạnh.<br>Ðối với cả hai xúc,<br>Lạc, khổ đều niệm xả,<br>Không thích, không chống đối,<br>Bất cứ loại xúc nào.<br><br>Ðối với các người khác,<br>Mê theo hý luận tưởng,<br>Họ mê theo hý luận,<br>Họ hành theo hư tưởng;<br>Hãy đoạn trừ tất cả,<br>Gia sự do ý tạo,<br>Hãy nhiếp các hành động,<br>Hướng đến hạnh viễn ly.<br><br>Như vậy đối sáu xứ,<br>Khi ý khéo tu tập,<br>Nếu có cảm xúc gì,<br>Tâm không bị dao động.<br>Tỷ-kheo hãy nhiếp phục,<br>Cả hai tham sân ấy,<br>Hãy đến bờ bên kia,<br>Vượt buộc ràng sanh tử.`, ref: "Tương Ưng Bộ 35.94", url: "https://loicuaducphat.org/sn/sn35.94.html#content" },


{ text: `- Ông nghĩ thế nào, này Màlukyaputta? Các sắc do mắt nhận thức, Ông không thấy, trước đây Ông không thấy, nay Ông không thấy, và Ông không muốn thấy; ở đây đối với chúng, Ông có lòng dục, tham hay khát ái không? - Thưa không, bạch Thế Tôn. - Các tiếng do tai nhận thức … Các hương do mũi nhận thức … Các vị do lưỡi nhận thức … Các xúc do thân nhận thức, Ông không cảm thọ, trước đây Ông không cảm thọ, nay Ông không cảm thọ, và Ông không muốn cảm thọ; ở đây đối với chúng, Ông có lòng dục, tham hay khát ái không? - Thưa không, bạch Thế Tôn.<br><br>Thấy sắc, niệm mê say,<br>Tác ý đến ái tướng,<br>Tâm tham đắm cảm thọ,<br>Tham luyến sắc an trú.<br>Vị ấy, thọ tăng trưởng,<br>Nhiều loại, từ sắc sinh,<br>Tham dục và hại tâm,<br>Não hại tâm vị ấy,<br>Như vậy, khổ tích lũy,<br>Ðược gọi xa Niết- bàn.<br><br>Nghe tiếng, niệm mê say,<br>Tác ý đến ái tướng,<br>Tâm tham đắm cảm thọ,<br>Tham luyến tiếng an trú.<br>Vị ấy, thọ tăng trưởng,<br>Nhiều loại, từ tiếng sanh,<br>Tham dục và hại tâm,<br>Não hại tâm vị ấy,<br>Như vậy, khổ tích lũy,<br>Ðựơc gọi xa Niết-bàn.<br><br>Nếm vị, niệm mê say,<br>Tác ý đến ái tướng,<br>Tâm tham đắm cảm thọ,<br>Tham luyến vị an trú.<br>Vị ấy, thọ tăng trưởng,<br>Nhiều loại, từ vị sanh,<br>Tham dục và hại tâm,<br>Não hại tâm vị ấy,<br>Như vậy, khổ tích lũy,<br>Ðược gọi xa Niết-bàn.`, ref: "Tương Ưng Bộ 35.95", url: "https://loicuaducphat.org/sn/sn35.95.html#content" },


{ text: `Vị ấy không tham sắc,<br>Thấy sắc, không ái luyến,<br>Tâm không dính cảm thọ,<br>Không luyến sắc an trú.<br>Theo sắc, vị ấy thấy,<br>Tùy sắc, thọ cảm giác,<br>Tiêu mòn, không tích lũy,<br>Như vậy, chánh niệm hành,<br>Như vậy, khổ không chứa.<br>Ðược gọi gần Niết-bàn<br><br>Vị ấy không tham tiếng,<br>Nghe tiếng, không ái luyến,<br>Tâm không dính cảm thọ,<br>Không luyến tiếng an trú.<br>Theo tiếng, vị ấy nghe,<br>Tùy tiếng, thọ cảm giác.<br>Tiêu mòn, không tích lũy,<br>Như vậy, chánh niệm hành,<br>Như vậy, khổ không chứa,<br>Ðược gọi gần Niết-bàn.<br><br>Vị ấy không tham hương,<br>Ngửi hương, không ái luyến,<br>Tâm không dính cảm thọ,<br>Không luyến hương an trú.<br>Theo hương, vị ấy ngửi,<br>Tùy hương, thọ cảm giác,<br>Tiêu mòn, không tích lũy,<br>Như vậy, chánh niệm hành,<br>Như vậy, khổ không chứa.<br>Ðược gọi gần Niết-bàn.<br><br>Vị ấy không tham vị,<br>Nếm vị, không ái luyến,<br>Tâm không dính cảm thọ,<br>Không luyến vị an trú.<br>Theo vị, vị ấy nếm.<br>Tùy vị, thọ cảm giác,<br>Tiêu mòn, không tích lũy,<br>Như vậy, chánh niệm hành,<br>Như vậy, khổ không chứa.<br>Ðược gọi gần Niết-bàn.<br><br>Vị ấy không tham xúc,<br>Cảm xúc, không ái luyến,<br>Tâm không dính cảm thọ,<br>Không luyến xúc an trú,<br>Theo xúc, vị ấy cảm,<br>Tùy xúc, thọ cảm giác,<br>Tiêu mòn, không tích lũy,<br>Như vậy, chánh niệm hành,<br>Như vậy, khổ không chứa,<br>Ðược gọi gần Niết-bàn.`, ref: "Tương Ưng Bộ 35.95", url: "https://loicuaducphat.org/sn/sn35.95.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là trú phóng dật? Ai sống không nhiếp hộ nhãn căn, này các Tỷ-kheo, thời tâm người ấy bị nhiễm đối với các sắc do mắt nhận biết. Với người tâm bị nhiễm ô thời không có hân hoan. Do không có hân hoan nên không có hỷ. Do không có hỷ nên không có khinh an. Do không khinh an nên khổ an trú. Với người đau khổ, tâm không có thể định tĩnh. Do tâm không định tĩnh, các pháp không hiển lộ. Do các pháp không hiển lộ, người ấy được gọi là người an trú phóng dật … nhĩ căn … tỷ căn … … thiệt căn … thân căn … Ai sống không nhiếp hộ ý căn, tâm bị nhiễm ô đối với các pháp do ý nhận biết. Với người tâm bị nhiễm ô thời không có hân hoan. Do không hân hoan nên không có hỷ. Do không có hỷ nên không có khinh an. Do không có khinh an nên khổ an trú. Với người đau khổ, tâm không có thể định tĩnh. Do tâm không định tĩnh, các pháp không hiển lộ. Do các pháp không hiển lộ, người ấy được gọi là người an trú phóng dật. Như vậy, này các Tỷ-kheo, là an trú phóng dật.`, ref: "Tương Ưng Bộ 35.97", url: "https://loicuaducphat.org/sn/sn35.97.html#content" },


{ text: `Và như thế nào, này các Tỷ-kheo, là an trú không phóng dật? Ai sống nhiếp hộ nhãn căn, tâm không bị nhiễm ô đối với các sắc do mắt nhận biết. Với người tâm không bị nhiễm ô thời hân hoan sanh. Do có hân hoan nên hỷ sanh. Do có hỷ sanh nên thân được khinh an. Do thân khinh an nên cảm lạc thọ. Với người an lạc, tâm được định tĩnh. Do tâm định tĩnh, các pháp được hiển lộ. Do các pháp được hiển lộ, người ấy được gọi là người trú không phóng dật … nhĩ căn … tỷ căn … … thiệt căn … thân căn … Ai sống nhiếp hộ ý căn, tâm không bị nhiễm ô đối với các pháp do ý nhận biết. Với người tâm không bị nhiễm ô thời hân hoan sanh. Do có hân hoan nên hỷ sanh. Do có hỷ tâm nên thân được khinh an. Do thân khinh an nên cảm lạc thọ. Với người an lạc, tâm được định tĩnh. Do tâm định tĩnh, các pháp được hiển lộ. Do các pháp được hiển lộ, người ấy được gọi là người trú không phóng dật. Như vậy, này các Tỷ-kheo, là trú không phóng dật.`, ref: "Tương Ưng Bộ 35.97", url: "https://loicuaducphat.org/sn/sn35.97.html#content" },

{ text: `Và thế nào, này các Tỷ-kheo, là không nhiếp hộ? Và này các Tỷ-kheo, có những sắc do mắt nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu một Tỷ-kheo hoan hỷ sắc ấy, tán dương và an trú với tâm tham luyến; thời này các Tỷ-kheo, Tỷ-kheo ấy cần phải hiểu rằng: “Ta đã làm thối thất các thiện pháp”. Như Lai gọi đây là pháp thối đọa … Có những tiếng do tai nhận thức … Có những hương do mũi nhận thức … Có những vị do lưỡi nhận thức … Có những xúc do thân cảm giác … Có những pháp do ý nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu một Tỷ-kheo hoan hỷ pháp ấy, tán dương và an trú với tâm tham luyến; thời này các Tỷ-kheo, Tỷ-kheo ấy cần phải hiểu rằng: “Ta đã làm thối thất các thiện pháp”. Và Như Lai gọi đây là thối thất. Như vậy, này các Tỷ-kheo, là không nhiếp hộ.`, ref: "Tương Ưng Bộ 35.98", url: "https://loicuaducphat.org/sn/sn35.98.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là nhiếp hộ? Này các Tỷ-kheo, có những sắc do mắt nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu một Tỷ-kheo không hoan hỷ sắc ấy, không tán dương và an trú với tâm không tham luyến; thời này các Tỷ-kheo, Tỷ-kheo ấy cần phải hiểu rằng: “Ta không làm thối thất các thiện pháp”. Và Như Lai gọi đây là không thối thất … Có những tiếng do tai nhận thức … Có những hương do mũi nhận thức … Có những vị do lưỡi nhận thức … Có những xúc do thân cảm giác … Và này các Tỷ-kheo, có những pháp do ý nhận thức khả lạc, khả hỷ, khả ý, khả ái liên hệ đến dục, hấp dẫn. Nếu một Tỷ-kheo không hoan hỷ pháp ấy, không tán dương và an trú với tâm không tham luyến; này các Tỷ-kheo, Tỷ-kheo ấy cần phải hiểu rằng: “Ta không làm thối thất các thiện pháp”. Và Như Lai gọi đây là không thối thất. Như vậy, này các Tỷ-kheo, là có nhiếp hộ.`, ref: "Tương Ưng Bộ 35.98", url: "https://loicuaducphat.org/sn/sn35.98.html#content" },

{ text: `- Cái gì không phải của các Ông, này các Tỷ-kheo, hãy từ bỏ nó. Từ bỏ nó, sẽ đưa lại hạnh phúc an lạc cho các Ông. Và này các Tỷ-kheo, cái gì không phải của các Ông? Mắt, này các Tỷ-kheo, không phải của các Ông. Hãy từ bỏ nó. Từ bỏ nó, sẽ đưa lại hạnh phúc, an lạc cho các Ông. Các sắc không phải của các Ông. Hãy từ bỏ chúng. Từ bỏ chúng, sẽ đưa lại hạnh phúc, an lạc cho các Ông. Nhãn thức không phải của các Ông. Hãy từ bỏ nó. Từ bỏ nó, sẽ đưa lại hạnh phúc, an lạc cho các Ông. Nhãn xúc không phải của các Ông. Hãy từ bỏ nó. Từ bỏ nó, sẽ đưa lại hạnh phúc, an lạc cho các Ông. Phàm duyên nhãn xúc khởi lên cảm thọ gì, lạc, khổ, hay bất khổ bất lạc; cảm thọ ấy không phải của các Ông. Hãy từ bỏ nó. Từ bỏ nó, sẽ đưa lại hạnh phúc, an lạc cho các Ông … Tai … Mũi … … Lưỡi … Thân … Ý không phải của các Ông. Hãy từ bỏ nó. Từ bỏ nó, sẽ đưa lại hạnh phúc, an lạc cho các Ông. Các pháp không phải của các Ông. Hãy từ bỏ chúng. Từ bỏ chúng, sẽ đưa lại hạnh phúc, an lạc cho các Ông. Ý thức không phải của các Ông. Hãy từ bỏ nó. Từ bỏ nó, sẽ đưa lại hạnh phúc, an lạc cho các Ông. Ý xúc không phải của các Ông. Hãy từ bỏ nó. Từ bỏ nó, sẽ đưa lại hạnh phúc, an lạc cho các Ông. Phàm duyên ý xúc khởi lên cảm thọ gì, lạc, khổ, hay bất khổ bất lạc; cảm thọ ấy không phải của các Ông. Hãy từ bỏ nó. Từ bỏ nó, sẽ đưa lại hạnh phúc, an lạc cho các Ông.`, ref: "Tương Ưng Bộ 35.101", url: "https://loicuaducphat.org/sn/sn35.101.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là khổ tập khởi? Do duyên mắt và các sắc khởi lên nhãn thức. Do ba pháp này họp lại nên có xúc. Do duyên xúc nên có thọ. Do duyên thọ nên có ái. Ðây là khổ tập khởi. Do duyên tai … Do duyên mũi … Do duyên lưỡi … Do duyên thân … Do duyên ý và các pháp khởi lên ý thức. Do ba pháp này họp lại nên có xúc. Do duyên xúc nên có thọ. Do duyên thọ nên có ái. Ðây là khổ tập khởi, này các Tỷ-kheo.`, ref: "Tương Ưng Bộ 35.106", url: "https://loicuaducphat.org/sn/sn35.106.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là khổ đoạn diệt? Do duyên mắt và các sắc khởi lên nhãn thức. Do ba pháp này họp lại nên có xúc. Do duyên xúc nên có thọ. Do duyên thọ nên có ái. Do ly tham, đoạn diệt ái ấy một cách hoàn toàn nên thủ diệt. Do thủ diệt nên hữu diệt. Do hữu diệt nên sanh diệt. Do sanh diệt nên già chết, sầu, bi, khổ, ưu, não diệt. Ðây là toàn bộ khổ uẩn này đoạn diệt. Ðây là khổ chấm dứt. Do duyên tai … Do duyên mũi … Do duyên lưỡi … Do duyên thân … Do duyên ý và các pháp khởi lên ý thức. Do ba pháp này họp lại nên có xúc. Do duyên xúc nên có thọ. Do duyên thọ nên có ái. Do ly tham, đoạn diệt ái ấy một cách hoàn toàn nên thủ diệt. Do thủ diệt nên hữu diệt. Do hữu diệt nên sanh diệt. Do sanh diệt nên già, chết, sầu, bi, ưu, não diệt. Ðây là toàn bộ khổ uẩn này đoạn diệt. Ðây là khổ chấm dứt.`, ref: "Tương Ưng Bộ 35.106", url: "https://loicuaducphat.org/sn/sn35.106.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là thế giới tập khởi? Do duyên mắt và các sắc khởi lên nhãn thức. Do ba pháp này họp lại nên có xúc. Do duyên xúc nên có thọ. Do duyên thọ nên có ái. Do duyên ái nên có thủ. Do duyên thủ nên có hữu. Do duyên hữu nên có sanh. Do duyên sanh nên có già chết, sầu, bi, khổ, ưu, não sanh khởi. Ðây là thế giới tập khởi. Do duyên tai … Do duyên mũi … Do duyên lưỡi … Do duyên thân … Và do duyên ý và các pháp khởi lên ý thức. Do ba pháp này họp lại nên có xúc. Do duyên xúc nên có thọ. Do duyên thọ nên có ái. Do duyên ái nên có thủ. Do duyên thủ nên có hữu. Do duyên hữu nên có sanh. Do duyên sanh nên có già, chết, sầu, bi, khổ, ưu, não sanh khởi. Này các Tỷ-kheo, đây là thế giới tập khởi.`, ref: "Tương Ưng Bộ 35.107", url: "https://loicuaducphat.org/sn/sn35.107.html#content" },

{ text: `- Này các Tỷ-kheo, có những sắc do mắt nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu một Tỷ-kheo hoan hỷ sắc ấy, tán dương, tham luyến an trú; thời này các Tỷ-kheo, đây gọi là Tỷ-kheo đã đi đến trú xứ của Ma, đã bị Ma chinh phục. Lưới bẫy của Ma đoanh vây vị ấy. Bị Ma trói buộc, vị ấy bị Ác ma muốn làm gì vị ấy thì làm … Này các Tỷ-kheo, có những pháp do ý nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu Tỷ-kheo hoan hỷ pháp ấy, tán dương, tham luyến an trú; thời này các Tỷ-kheo, đây gọi là Tỷ-kheo đã đi đến trú xứ của Ma, đã bị Ma chinh phục. Lưới bẫy của Ma đoanh vây vị ấy. Bị Ma trói buộc, vị ấy bị Ác ma muốn làm gì vị ấy thì làm.`, ref: "Tương Ưng Bộ 35.114", url: "https://loicuaducphat.org/sn/sn35.114.html#content" },


{ text: `- Này các Tỷ-kheo, trước khi Ta chưa giác ngộ, chưa thành Chánh đẳng Chánh giác, còn là Bồ-tát, Ta khởi lên ý nghĩ như sau: “Năm dục trưởng dưỡng mà tâm Ta trước kia cảm xúc, đã thuộc quá khứ, đã đoạn diệt, đã biến hoại; ở đây, tâm Ta đi đến cuồng nhiệt khi chúng có mặt hiện tại, và trở thành giảm thiểu khi chúng chưa đến, còn ở vị lai”. Rồi, này các Tỷ-kheo, Ta suy nghĩ như sau: “Năm dục trưởng dưỡng mà tâm Ta trước kia cảm xúc, đã thuộc quá khứ, đã đoạn diệt, đã biến hoại. Ở đây, vì lợi ích cho chính Ta, hãy sống không phóng dật, gìn giữ tâm chánh niệm”. Do vậy, này các Tỷ-kheo, đối với năm dục trưởng dưỡng mà tâm các Ông trước đây cảm xúc, đã thuộc quá khứ, đã đoạn diệt, đã biến hoại; ở đây, tâm các Ông đi đến cuồng nhiệt khi chúng có mặt hiện tại, và trở thành giảm thiểu khi chúng chưa đến, còn ở vị lai. Do vậy, này các Tỷ-kheo, đối với năm dục trưởng dưỡng mà tâm các Ông trước đây cảm xúc, đã thuộc quá khứ, đã đoạn diệt, đã biến hoại. Ở đây, vì lợi ích cho chính các Ông, hãy sống không phóng dật, gìn giữ tâm chánh niệm.`, ref: "Tương Ưng Bộ 35.117", url: "https://loicuaducphat.org/sn/sn35.117.html#content" },


{ text: `Và này Thiên chủ, có những sắc do mắt nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu Tỷ-kheo không hoan hỷ sắc ấy, không tán dương, không tham luyến an trú; thời do vị ấy không hoan hỷ sắc ấy, không tán dương, không tham luyến an trú, không y cứ cái ấy, thức khởi lên không chấp thủ cái ấy. Do không chấp thủ, này Thiên chủ, Tỷ-kheo nhập Niết-bàn. Có những tiếng do tai nhận thức … Có những hương do mũi nhận thức … Có những vị do lưỡi nhận thức … Có những xúc do thân cảm giác … Này Thiên chủ, có những pháp do ý nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu Tỷ-kheo không hoan hỷ pháp ấy, không tán dương, không tham luyến an trú; thời do Tỷ-kheo ấy không hoan hỷ pháp ấy, không tán dương, không tham luyến an trú, không y cứ vào cái ấy, thức khởi lên không chấp thủ cái ấy. Không chấp thủ, này Thiên chủ, Tỷ-kheo ấy nhập Niết-bàn. Này Thiên chủ, đây là nhân, đây là duyên, do vậy ở đây một số loài hữu tình ngay trong hiện tại nhập Niết-bàn.`, ref: "Tương Ưng Bộ 35.118", url: "https://loicuaducphat.org/sn/sn35.118.html#content" },

{ text: `Ngồi xuống một bên, Tỷ-kheo ấy nói với Tôn giả Sāriputta: - Tỷ-kheo đồng trú, thưa Tôn giả Sāriputta, đã từ bỏ học pháp và hoàn tục. - Này Hiền giả, như vậy xẩy đến cho vị nào không hộ trì các căn, không tiết độ trong ăn uống, không chú tâm tỉnh giác. Cho đến trọn đời, vị ấy có thể tiếp tục đời sống Phạm hạnh hoàn toàn thanh tịnh, sự việc như vậy không xảy ra. Này Hiền giả, một Tỷ-kheo hộ trì các căn, tiết độ trong ăn uống, chú tâm tỉnh giác. Cho đến trọn đời, vị ấy có thể tiếp tục đời sống Phạm hạnh hoàn toàn thanh tịnh, sự việc như vậy có xảy ra. Do vậy, này Hiền giả, cần phải học tập như sau: “Chúng tôi sẽ hộ trì các căn, tiết độ trong ăn uống, chú tâm tỉnh giác”. Như vậy, này Hiền giả, ông cần phải học tập.`, ref: "Tương Ưng Bộ 35.120", url: "https://loicuaducphat.org/sn/sn35.120.html#content" },

{ text: `Và này Hiền giả, thế nào là hộ trì các căn? Này Hiền giả, khi mắt thấy sắc, Tỷ-kheo không nắm giữ tướng chung, không nắm giữ tướng riêng. Những nguyên nhân gì, vì đó nhãn căn không được chế ngự, khiến tham ái, ưu bi, các ác bất thiện pháp khởi lên, Tỷ-kheo tự chế ngự những nguyên nhân ấy, hộ trì nhãn căn, thực hành sự hộ trì nhãn căn. Khi tai nghe tiếng … khi mũi ngửi hương … khi lưỡi nếm vị … khi thân cảm xúc … khi ý nhận thức các pháp, vị ấy không nắm giữ tướng chung, không nắm giữ tướng riêng. Những nguyên nhân gì, vì đó ý căn không được chế ngự, khiến tham ái, ưu bi, các ác bất thiện pháp khởi lên, Tỷ-kheo tự chế ngự những nguyên nhân ấy, hộ trì ý căn, thực hành sự hộ trì ý căn. Như vậy, này Hiền giả, là sự hộ trì các căn.`, ref: "Tương Ưng Bộ 35.120", url: "https://loicuaducphat.org/sn/sn35.120.html#content" },


{ text: `- Thưa Tôn giả Bharadvāja, do nhân gì, do duyên gì, những Tỷ-kheo trẻ tuổi này, còn non trẻ, tóc đen nhánh, đầy đủ với tuổi trẻ hiền thiện, trong lúc tuổi còn thanh xuân lại không tham nhiễm dục vọng, thực hành Phạm hạnh hoàn toàn thanh tịnh cho đến trọn đời, và sống toàn thời gian một cách hoàn mãn? - Thưa Ðại vương, Thế Tôn, bậc Tri giả, Kiến giả, bậc A-la-hán, Chánh Ðẳng Giác đã nói như sau: “Hãy đến, này các Tỷ-kheo, đối với những người chỉ là mẹ, hãy an trú tâm người mẹ. Ðối với những người chỉ là chị, hãy an trú tâm người chị. Ðối với người chỉ là con gái, hãy an trú tâm người con gái. Thưa Ðại Vương, đây là nhân, đây là duyên, do vậy các Tỷ-kheo trẻ tuổi này, còn non trẻ, tóc đen nhánh, đầy đủ với tuổi trẻ hiền thiện, trong lúc tuổi còn thanh xuân lại không tham nhiễm dục vọng, thực hành Phạm hạnh hoàn toàn thanh tịnh cho đến trọn đời, và sống toàn thời gian một cách hoàn mãn.`, ref: "Tương Ưng Bộ 35.127", url: "https://loicuaducphat.org/sn/sn35.127.html#content" },

{ text: `- Tham vọng, này Tôn giả Bharadvāja, là tâm. Ðôi khi đối với những người chỉ là mẹ, tham pháp khởi lên. Ðối với những người chỉ là chị, tham pháp khởi lên. Ðối với những người chỉ là con gái, tham pháp khởi lên. Này Bharadvāja, có một nhân khác, có một duyên khác, do vậy các Tỷ-kheo trẻ tuổi này … một cách hoàn mãn? - Thưa Ðại vương, Thế Tôn, bậc Tri giả, Kiến giả, bậc A-la-hán, Chánh Ðẳng Giác đã nói như sau: “Hãy đến, này các Tỷ-kheo, hãy quán sát thân này dưới từ bàn chân trở lên, trên từ đảnh tóc trở xuống, bao bọc bởi da và chứa đầy bất tịnh sai biệt. Trong thân này, đây là tóc, lông, móng, răng, da, thịt, gân, xương, tủy, thận, tim, gan, hoành cách mô, lá lách, phổi, ruột, bao tử, phân, mật, đàm, mủ, máu, mồ hôi, mỡ, nước mắt, mỡ da, nước miếng, nước mủ, nước ở khớp xương, nước tiểu. Thưa Ðại vương, đây là nhân, đây là duyên, do vậy các Tỷ-kheo trẻ tuổi này thực hành Phạm hạnh hoàn toàn thanh tịnh cho đến trọn đời, và sống toàn thời gian một cách hoàn mãn.`, ref: "Tương Ưng Bộ 35.127", url: "https://loicuaducphat.org/sn/sn35.127.html#content" },

{ text: `- Thật vi diệu thay, thưa Tôn giả Bharadvāja! Thật hy hữu thay, thưa Tôn giả Bharadvāja, là lời khéo nói này của Thế Tôn, bậc Tri giả, Kiến giả, bậc A-la-hán, Chánh Ðẳng Giác. Chính nhân này, thưa Tôn giả Bharadvāja, chính duyên này, do vậy các Tỷ-kheo trẻ tuổi này, còn non trẻ, tóc đen nhánh, đầy đủ với tuổi trẻ hiền thiện, trong lúc tuổi còn thanh xuân, lại không tham nhiễm dục vọng, thực hành Phạm hạnh hoàn toàn thanh tịnh cho đến trọn đời, sống toàn thời gian một cách hoàn mãn. Tôi cũng vậy, thưa Tôn giả Bharadvāja, khi nào tôi vào trong nội cung với thân không phòng hộ, với lời nói không phòng hộ, với tâm không phòng hộ, với niệm không an trú, với các căn không chế ngự; thời trong khi ấy, tham pháp chinh phục tôi. Nhưng thưa Tôn giả Bharadvāja, trong khi tôi vào nội cung, với thân được phòng hộ, với lời nói được phòng hộ, với tâm được phòng hộ, với niệm được an trú, với các căn được chế ngự; thời trong khi ấy, tham pháp không chinh phục tôi.`, ref: "Tương Ưng Bộ 35.127", url: "https://loicuaducphat.org/sn/sn35.127.html#content" },


{ text: `“Này Gia chủ, có những sắc do mắt nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu Tỷ-kheo hoan hỷ sắc ấy, tán dương, tham luyến an trú, y cứ vào đấy, thức khởi lên chấp thủ cái ấy. Này Gia chủ, Tỷ-kheo có chấp thủ, không được hoàn toàn tịch tịnh... Này Gia chủ, có những vị do lưỡi nhận thức ... Này Gia chủ, có những pháp do ý nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu Tỷ-kheo hoan hỷ pháp ấy, tán dương, tham luyến an trú. Do hoan hỷ pháp ấy, tán dương, tham luyến an trú, y cứ vào đấy, thức khởi lên chấp thủ cái ấy. Do có chấp thủ, này Gia chủ, Tỷ-kheo ấy không nhập Niết-bàn. Này Gia chủ, đây là nhân, đây là duyên, do vậy, ở đây, một số các loài hữu tình ngay trong hiện tại không được hoàn toàn tịch tịnh.`, ref: "Tương Ưng Bộ 35.124", url: "https://loicuaducphat.org/sn/sn35.124.html#content" },

{ text: `Này Gia chủ, có những sắc do mắt nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu Tỷ-kheo không hoan hỷ sắc ấy, không tán dương, không tham luyến an trú, không y cứ vào đấy, thức không khởi lên chấp thủ cái ấy. Này Gia chủ, Tỷ-kheo không có chấp thủ, được hoàn toàn tịch tịnh... Này Gia chủ, có những vị do lưỡi nhận thức ... Này Gia chủ, có những pháp do ý nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu Tỷ-kheo không hoan hỷ pháp ấy, không tán dương, không tham luyến an trú. Do không hoan hỷ pháp ấy, không tán dương, không tham luyến an trú, không y cứ vào đấy, thức không khởi lên chấp thủ cái ấy. Do không có chấp thủ, này Gia chủ, Tỷ-kheo ấy nhập Niết-bàn. Này Gia chủ, đây là nhân, đây là duyên, do vậy, ở đây, một số loài hữu tình ngay trong hiện tại được hoàn toàn tịch tịnh”.`, ref: "Tương Ưng Bộ 35.124", url: "https://loicuaducphat.org/sn/sn35.124.html#content" },

{ text: `Này các Tỷ-kheo, con Chó Rừng từ đàng xa trông thấy con Rùa, đi đến con Rùa sau khi đến, đứng một bên và nghĩ rằng: ‘Khi nào con Rùa này thò ra thân phần nào và cổ là thứ năm, ngay tại chỗ ấy, ta sẽ nắm lấy, bẻ gãy và ăn’. Nhưng, này các Tỷ-kheo, vì rằng con Rùa không thò ra một thân phần nào và cổ là thứ năm, nên con Chó Rừng nhàm chán con Rùa và bỏ đi, không nắm được cơ hội. Cũng vậy, này các Tỷ-kheo, Ác ma thường xuyên không gián đoạn, đứng trong tư thế rình mò các Ông với ý nghĩ: ‘Rất có thể ta nắm được cơ hội để bắt gặp từ con mắt ... từ cái lưỡi... hay từ ý’. Do vậy, này các Tỷ-kheo, hãy sống hộ trì các căn. Khi mắt thấy sắc, không nắm giữ tướng chung, không nắm giữ tướng riêng. Những nguyên nhân gì khiến nhãn căn không được chế ngự, khiến tham ái, ưu bi, các ác bất thiện pháp khởi lên, hãy tự chế ngự những nguyên nhân ấy, hộ trì nhãn căn, thực hành hộ trì nhãn căn. Khi tai nghe tiếng ... mũi ngửi mùi ... lưỡi nếm vị ... thân cảm xúc ... ý nhận thức các pháp, không nắm giữ tướng chung, không nắm giữ tướng riêng. Những nguyên nhân gì khiến ý căn không được chế ngự, khiến tham ái, ưu bi, các ác bất thiện pháp khởi lên, hãy tự chế ngự những nguyên nhân ấy, hộ trì ý căn, thực hành hộ trì ý căn. Này các Tỷ-kheo, khi nào các Ông sống hộ trì các căn, thời Ác ma nhàm chán các Ông và sẽ bỏ đi, không nắm giữ được cơ hội, như con Chó Rừng đối với con Rùa.`, ref: "Tương Ưng Bộ 35.240", url: "https://loicuaducphat.org/sn/sn35.240.html#content" },

{ text: `- Tôn giả Kaccāna có nói đến hộ trì các căn. Cho đến như thế nào, thưa Tôn giả Kaccāna, là hộ trì các căn? - Ở đây, này Bà-la-môn, có người sau khi mắt thấy sắc, có tâm hướng đến các sắc khả ái, có tâm ghét bỏ các sắc không khả ái, sống với niệm không an trú, với tâm nhỏ hẹp. Người ấy không như thật biết rõ tâm giải thoát và tuệ giải thoát. Do vậy, các ác bất thiện pháp đã khởi lên, không có đoạn diệt không có dư tàn. … sau khi tai nghe tiếng … sau khi mũi ngửi hương … sau khi lưỡi nếm vị … sau khi thân cảm xúc … … sau khi ý biết các pháp, tâm hướng đến các pháp khả ái, tâm ghét bỏ các pháp không khả ái, sống với niệm không an trú, với tâm nhỏ hẹp. Người ấy không như thật biết rõ tâm giải thoát và tuệ giải thoát. Do vậy, các ác bất thiện pháp đã khởi lên, không có đoạn diệt không có dư tàn. Như vậy, này Bà-la-môn, là các căn không có hộ trì.`, ref: "Tương Ưng Bộ 35.132", url: "https://loicuaducphat.org/sn/sn35.132.html#content" },


{ text: `- Thật là vi diệu, thưa Tôn giả Kaccāna, thật là hy hữu, thưa Tôn giả Kaccāna, cách thức Tôn giả Kaccāna đã định nghĩa các căn không hộ trì. Các căn có hộ trì, các căn có hộ trì, Tôn giả Kaccāna đã nói như vậy; cho đến như thế nào, thưa Tôn giả Kaccāna, là các căn có hộ trì? - Ở đây, này Bà-la-môn, Tỷ-kheo sau khi mắt thấy sắc, tâm không hướng đến các sắc khả ái, tâm không ghét bỏ các sắc không khả ái, sống với niệm an trú, với tâm vô lượng. Vị ấy như thật biết rõ tâm giải thoát và tuệ giải thoát. Do vậy, các ác bất thiện pháp đã khởi lên được đoạn diệt không có dư tàn. … sau khi tai nghe tiếng … sau khi mũi ngửi hương … sau khi lưỡi nếm vị … sau khi thân cảm xúc … … sau khi ý nhận biết các pháp, tâm không hướng đến các pháp khả ái, tâm không ghét bỏ các pháp không khả ái, sống với niệm an trú, với tâm vô lượng. Vị ấy như thật biết rõ tâm giải thoát và tuệ giải thoát. Do vậy, các ác bất thiện pháp đã khởi lên được đoạn diệt không có dư tàn. Như vậy, này Bà-la-môn, là các căn được hộ trì.`, ref: "Tương Ưng Bộ 35.132", url: "https://loicuaducphat.org/sn/sn35.132.html#content" },

{ text: `Này các Tỷ-kheo, có những sắc do mắt nhận thức khả ái và không khả ái. Dầu chúng xúc chạm tâm nhiều lần, chúng không chi phối được tâm và tồn tại. Do tâm không bị chi phối, tinh cần, tinh tấn khởi lên, không có biếng nhác; niệm được an trú, không có thất thoát; thân được khinh an, không có cuồng nhiệt; tâm được định tĩnh, nhất tâm. Này các Tỷ-kheo, thấy được quả không phóng dật này, đối với những Tỷ-kheo ấy. Ta tuyên bố rằng, cần phải cố gắng không phóng dật đối với sáu xúc xứ. Này các Tỷ-kheo, có những tiếng do tai nhận thức … có những hương do mũi nhận thức … có những vị do lưỡi nhận thức … có những xúc do thân nhận thức … Này các Tỷ-kheo, có những pháp do ý nhận thức khả ái và không khả ái. Dầu chúng xúc chạm tâm nhiều lần, chúng không chi phối được tâm và tồn tại. Do tâm không bị chi phối, tinh cần, tinh tấn khởi lên, không có biếng nhác; niệm được an trú, không có thất thoát; thân được khinh an, không cuồng nhiệt; tâm được định tĩnh, nhất tâm. Này các Tỷ-kheo, thấy được quả không phóng dật này, đối với những Tỷ-kheo ấy, Ta tuyên bố rằng, cần phải cố gắng không phóng dật đối với sáu xúc xứ.`, ref: "Tương Ưng Bộ 35.134", url: "https://loicuaducphat.org/sn/sn35.134.html#content" },


{ text: `Này các Tỷ-kheo, chư Thiên và Người đời thích thú sắc, bị sắc kích thích. Khi sắc biến hoại, ly tham, đoạn diệt, này các Tỷ-kheo, chư Thiên và Người đời sống đau khổ … thích thú tiếng … thích thú hương … thích thú vị … thích thú xúc … Này các Tỷ-kheo, chư Thiên và Người đời thích thú pháp, bị pháp kích thích. Khi pháp biến hoại, ly tham, đoạn diệt, này các Tỷ-kheo, chư Thiên và Người đời sống đau khổ. Này các Tỷ-kheo, Như Lai, bậc A-la-hán, Chánh Ðẳng Giác, sau khi như thật biết rõ sự tập khởi, sự đoạn diệt, vị ngọt, sự nguy hiểm và xuất ly của sắc, không có thích thú sắc, không có ưa thích sắc, không bị sắc kích thích. Khi sắc biến hoại, ly tham, đoạn diệt, này các Tỷ-kheo, Như Lai sống an lạc … không thích thú tiếng … không thích thú hương … không thích thú vị … không thích thú xúc … Sau khi như thật biết rõ sự tập khởi, sự đoạn diệt, vị ngọt, sự nguy hiểm và sự xuất ly của pháp, Như Lai không thích thú pháp, không ưa thích pháp, không bị pháp kích thích. Khi pháp biến hoại, ly tham, đoạn diệt, Như Lai sống an lạc.`, ref: "Tương Ưng Bộ 35.136", url: "https://loicuaducphat.org/sn/sn35.136.html#content" },


{ text: `Sắc, thanh, hương, vị, xúc,<br>Và toàn thể các pháp,<br>Khả lạc, hỷ, khả ý,<br>Như vậy, chúng được gọi.<br><br>Chư Thiên và Người đời,<br>Xem chúng là khả lạc,<br>Chỗ nào chúng đoạn diệt,<br>Thiên, Nhân thấy đau khổ.<br><br>Bậc Thánh thấy an lạc,<br>Khi thân kiến đoạn diệt,<br>Bậc Thánh xem trái ngược,<br>Mọi quan điểm của đời.<br><br>Ðiều người gọi là lạc,<br>Bậc Thánh gọi là khổ.<br>Ðiều người gọi là khổ,<br>Thánh nhân biết là lạc.<br><br>Thấy pháp khó nhận biết,<br>Kẻ vô trí mê loạn,<br>Tối tăm đối vô minh,<br>Mù lòa đối không thấy.<br><br>Thiện nhân mắt rộng mở,<br>Thấy rõ ràng ánh sáng,<br>Sống gần, biết rõ ràng,<br>Thuần thục trong pháp lớn.<br><br>Bị tham sanh chinh phục,<br>Bị dòng hữu cuốn trôi,<br>Bị Ác ma chi phối,<br>Không giác ngộ pháp này.<br><br>Ngoài Thánh không có ai,<br>Giác ngộ con đường này,<br>Con đường đạt Niết-bàn,<br>Chánh trí thoát lậu hoặc.`, ref: "Tương Ưng Bộ 35.136", url: "https://loicuaducphat.org/sn/sn35.136.html#content" },


{ text: `Này các Tỷ-kheo, có những sắc do mắt nhận thức khả lạc, khả hỷ, khá ý, khả ái, liên hệ đến dục, hấp dẫn. Này các Tỷ-kheo, đây không gọi là biển trong giới luật của bậc Thánh. Ở đây, thế giới này với Thiên giới, với Ma giới, với Phạm thiên giới, với quần chúng Sa-môn, Bà-la-môn, với chư Thiên và loài Người, phần lớn chìm đắm trong ấy, bị rối ren như cuộn chỉ, bị bao trùm như cuộn dây, thành như sợi dây bện bằng cỏ, không thể vượt qua cõi dữ, ác thú, đọa xứ, luân hồi! Này các Tỷ-kheo, có những tiếng do tai nhận thức … có những hương do mũi nhận thức … có những vị do lưỡi nhận thức … có những xúc do thân nhận thức … Này các Tỷ-kheo, có những pháp do ý nhận thức khả lạc, khả hỷ, khả ái, khả ý, liên hệ đến dục, hấp dẫn. Này các Tỷ-kheo, đây không gọi là biển trong giới luật của bậc Thánh. Ở đây, thế giới này với Thiên giới, với Ma giới, với Phạm thiên giới, với quần chúng Sa-môn, Bà-la-môn, với chư Thiên và loài Người, phần lớn chìm đắm trong ấy, bị rối ren như cuộn chỉ, bị bao trùm như cuộn dây, thành như sợi dây bện bằng cỏ, không thể vượt qua cõi dữ, ác thú, đọa xứ, luân hồi!`, ref: "Tương Ưng Bộ 35.229", url: "https://loicuaducphat.org/sn/sn35.229.html#content" },


{ text: `- Và này chư Hiền, thế nào là nhiễm dục lậu? Ở đây, này chư Hiền, Tỷ-kheo khi mắt thấy sắc, thiên chấp sắc khả ái, ghét bỏ các sắc không khả ái, sống với thân niệm không an trú, với tâm nhỏ hẹp. Vị ấy không như thật rõ biết tâm giải thoát, tuệ giải thoát. Chính ở đây, các ác bất thiện pháp ấy khởi lên không được trừ diệt không có dư tàn … Khi lưỡi nếm vị … Khi ý biết các pháp, thiên chấp pháp khả ái, ghét bỏ pháp không khả ái, sống với thân niệm không an trú, với tâm nhỏ hẹp. Vị ấy không như thật rõ biết tâm giải thoát, tuệ giải thoát ấy. Chính ở đây, các ác bất thiện pháp ấy khởi lên không được trừ diệt không có dư tàn. Này chư Hiền, đây gọi là Tỷ-kheo bị nhiễm dục lậu đối với các sắc do mắt nhận thức … đối với các vị do lưỡi nhận thức … đối với các pháp do ý nhận thức. Tỷ-kheo sống như vậy, này chư Hiền, nếu Māra có đến vị ấy, ngang qua mắt, Māra nắm được cơ hội, Māra nắm được đối tượng … Nếu Māra có đến vị ấy, ngang qua lưỡi, Māra nắm được cơ hội, Māra nắm được đối tượng … Nếu Māra có đến vị ấy, ngang qua ý, Māra nắm được cơ hội, Māra nắm được đối tượng.`, ref: "Tương Ưng Bộ 35.243", url: "https://loicuaducphat.org/sn/sn35.243.html#content" },


{ text: `Và này chư Hiền, thế nào là không nhiễm dục lậu? Ở đây, này chư Hiền, Tỷ-kheo khi mắt thấy sắc, không thiên chấp sắc khả ái, không ghét bỏ sắc không khả ái, sống an trú thân niệm, với tâm vô lượng. Vị ấy như thật rõ biết tâm giải thoát, tuệ giải thoát. Chính ở nơi đây, các ác bất thiện pháp khởi lên được đoạn diệt không có dư tàn … Khi lưỡi nếm vị … Khi ý biết các pháp, vị ấy không thiên chấp các pháp khả ái, không ghét bỏ các pháp không khả ái, sống an trú thân niệm, với tâm vô lượng. Vị ấy như thật biết rõ tâm giải thoát, tuệ giải thoát. Chính ở nơi đây, các ác bất thiện pháp khởi lên được đoạn diệt không có dư tàn. Này chư Hiền, đây gọi là vị Tỷ-kheo không bị nhiễm dục lậu đối với các sắc do mắt nhận thức … đối với các vị do lưỡi nhận thức … đối với các pháp do ý nhận thức … Tỷ-kheo sống như vậy, này chư Hiền, nếu Māra có đến vị ấy, ngang qua mắt, Māra không nắm được cơ hội, Māra không nắm được đối tượng … Nếu Māra có đến vị ấy, ngang qua lưỡi, Māra không nắm được cơ hội, Māra không nắm được đối tượng … Nếu Māra có đến vị ấy, ngang qua ý, Māra không nắm được cơ hội, Māra không nắm được đối tượng.`, ref: "Tương Ưng Bộ 35.243", url: "https://loicuaducphat.org/sn/sn35.243.html#content" },


{ text: `Và này các Tỷ-kheo, như thế nào là Tỷ-kheo thấy được các dục? Khi các dục được thấy, thời dục, dục ái, dục mê, dục nhiệt não đối với các dục không có tùy miên. Ví như, này các Tỷ-kheo, có một hố than sâu hơn thân người, đầy vun than hừng, không có ngọn, không có khói. Rồi có người đi đến, muốn sống, không muốn chết, muốn lạc, ghét bỏ khổ. Rồi hai người lực sĩ đến, kẹp người ấy vào trong các cánh tay, và kéo người ấy đến hố than hừng. Người ấy vật vã thân bên này, bên kia. Vì sao? Này các Tỷ-kheo, người ấy được biết rằng: “Ta sẽ rơi vào trong hố than hừng này. Do nhân này, ta sẽ đi đến chết hay đau khổ gần như chết”. Cũng vậy, này các Tỷ-kheo, Tỷ-kheo thấy các dục như hố than hừng và ai thấy được các dục, thời dục, dục ái, dục mê, dục nhiệt não đối với các dục không có tùy miên.`, ref: "Tương Ưng Bộ 35.244", url: "https://loicuaducphat.org/sn/sn35.244.html#content" },



{ text: `Và này các Tỷ-kheo, thế nào là không hộ trì? Ở đây, này các Tỷ-kheo, Tỷ-kheo khi mắt thấy sắc, thiên chấp các sắc khả ái, ghét bỏ các sắc không khả ái, sống với thân niệm không an trú, với tâm nhỏ hẹp. Vị ấy không như thật rõ biết tâm giải thoát, tuệ giải thoát. Chính ở nơi đây, các ác bất thiện pháp ấy khởi lên không được đoạn diệt không có dư tàn. Như vậy, này các Tỷ-kheo, là không hộ trì.`, ref: "Tương Ưng Bộ 35.244", url: "https://loicuaducphat.org/sn/sn35.244.html#content" },


{ text: `Và này các Tỷ-kheo, thế nào là được hộ trì? Ở đây, này các Tỷ-kheo, Tỷ-kheo khi mắt thấy sắc, không thiên chấp các sắc khả ái, không ghét bỏ các sắc không khả ái, sống với thân niệm an trú, với tâm vô lượng. Vị ấy như thật rõ biết tâm giải thoát, tuệ giải thoát. Chính ở nơi đây, các ác bất thiện pháp ấy khởi lên được đoạn diệt không có dư tàn … khi lưỡi nếm vị … khi ý biết pháp, không thiên chấp các pháp khả ái, không ghét bỏ các pháp không khả ái, sống với thân niệm an trú, với tâm vô lượng. Vị ấy như thật rõ biết tâm giải thoát, tuệ giải thoát. Chính ở đây, các ác bất thiện pháp ấy khởi lên được đoạn diệt không có dư tàn. Như vậy, này các Tỷ-kheo, là có hộ trì.`, ref: "Tương Ưng Bộ 35.244", url: "https://loicuaducphat.org/sn/sn35.244.html#content" },


{ text: `- Này các Tỷ-kheo, có ba cảm thọ này. Thế nào là ba? Lạc thọ, khổ thọ, bất khổ bất lạc thọ. Lạc thọ, này các Tỷ-kheo, cần phải thấy là khổ. Khổ thọ cần phải thấy là mũi tên. Bất khổ bất lạc thọ cần phải thấy là vô thường. Khi nào, này các Tỷ-kheo, Tỷ-kheo thấy được lạc thọ là khổ, thấy được khổ thọ là mũi tên, thấy được bất khổ bất lạc thọ là vô thường; thời này các Tỷ-kheo, đây gọi là Tỷ-kheo có chánh kiến, ái được đoạn tận, kiết sử được hủy hoại. Với minh kiến chơn chánh đối với ngã mạn, vị ấy đoạn tận khổ đau.<br><br>Ai thấy lạc là khổ,<br>Thấy khổ là mũi tên,<br>Với bất khổ bất lạc,<br>Thấy thọ là vô thường,<br>Tỷ-kheo ấy chánh kiến,<br>Liễu tri các cảm thọ.<br><br>Vị ấy liễu tri thọ,<br>Hiện tại không lậu hoặc,<br>Mạng chung, bậc Pháp trú,<br>Ðại trí vượt ước lường.`, ref: "Tương Ưng Bộ 36.5", url: "https://loicuaducphat.org/sn/sn36.5.html#content" },


{ text: `Ví như, này các Tỷ-kheo, có người bị người ta bắn với mũi tên, rồi họ bắn người ấy với mũi tên thứ hai. Như vậy, này các Tỷ-kheo, người ấy cảm giác cảm thọ cả hai mũi tên. Cũng vậy, này các Tỷ-kheo, kẻ vô văn phàm phu khi cảm xúc khổ thọ; thời sầu muộn, than vãn, khóc lóc, đấm ngực, đi đến bất tỉnh. Người ấy cảm giác hai cảm thọ, cảm thọ về thân và cảm thọ về tâm. Cảm xúc bởi khổ thọ ấy, người ấy cảm thấy sân hận. Do cảm thấy sân hận đối với khổ thọ ấy, sân tùy miên đối với khổ thọ được tồn chỉ tùy miên. Cảm xúc bởi khổ thọ, người ấy hoan hỷ dục lạc. Vì sao? Vì rằng, này các Tỷ-kheo, kẻ vô văn phàm phu không tìm thấy một sự xuất ly khổ thọ nào khác, ngoài dục lạc. Do hoan hỷ dục lạc ấy, tham tùy miên đối với lạc thọ tồn tại. Người ấy không như thật rõ biết sự tập khởi, sự đoạn diệt, vị ngọt, sự nguy hiểm và sự xuất ly của các cảm thọ ấy. Do người ấy không như thật rõ biết sự tập khởi, sự đoạn diệt, vị ngọt, sự nguy hiểm và sự xuất ly của các cảm thọ ấy, nên vô minh tùy miên đối với bất khổ bất lạc thọ tồn tại. Nếu người ấy cảm thọ cảm giác lạc thọ, người ấy cảm thọ cảm giác như người bị trói buộc. Nếu người ấy cảm thọ cảm giác khổ thọ, người ấy cảm thọ cảm giác như người bị trói buộc. Nếu người ấy cảm thọ cảm giác bất khổ bất lạc thọ, người ấy cảm thọ cảm giác như người bị trói buộc. Này các Tỷ-kheo, đây gọi là kẻ vô văn phàm phu bị trói buộc bởi sanh, già, chết, sầu, bi, khổ, ưu, não. Ta nói rằng người ấy bị trói buộc bởi đau khổ.`, ref: "Tương Ưng Bộ 36.6", url: "https://loicuaducphat.org/sn/sn36.6.html#content" },

{ text: `Ví như, này các Tỷ-kheo, có người bị người ta bắn một mũi tên. Họ không bắn tiếp người ấy với mũi tên thứ hai. Như vậy, này các Tỷ-kheo, người ấy cảm giác cảm thọ của một mũi tên. Cũng vậy, này các Tỷ-kheo, bậc Ða văn Thánh đệ tử khi cảm xúc khổ thọ; vị ấy không sầu muộn, không than vãn, không khóc lóc, không đấm ngực, không đi đến bất tỉnh. Vị ấy cảm giác chỉ một cảm thọ, cảm thọ về thân, không phải cảm thọ về tâm. Vị ấy không cảm thấy sân hận đối với khổ thọ ấy. Do không cảm thấy sân hận đối với khổ thọ ấy, sân tùy miên đối với khổ thọ không có tồn tại. Cảm xúc bởi khổ thọ, vị ấy không hoan hỷ dục lạc. Vì sao? Vì bậc Ða văn Thánh đệ tử có tuệ tri một sự xuất ly khác đối với khổ thọ, ngoài dục lạc. Vì vị ấy không hoan hỷ dục lạc, tham tùy miên đối với dục lạc không có tồn tại. Vị ấy như thật tuệ tri sự tập khởi, sự đoạn diệt, vị ngọt, sự nguy hiểm và sự xuất ly của những cảm thọ ấy. Vì rằng, vị ấy như thật tuệ tri sự tập khởi, sự đoạn diệt, vị ngọt, sự nguy hiểm và sự xuất ly của các cảm thọ ấy. Vì rằng, vị ấy như thật tuệ tri sự tập khởi, sự đoạn diệt, vị ngọt, sự nguy hiểm và sự xuất ly của các cảm thọ ấy, đối với bất khổ bất lạc thọ, vô minh tùy miên không có tồn tại. Nếu vị ấy cảm thọ lạc thọ, vị ấy cảm thọ lạc thọ như người không bị trói buộc. Nếu vị ấy cảm thọ cảm giác khổ thọ, vị ấy cảm thọ cảm giác như người không bị trói buộc. Nếu vị ấy cảm thọ cảm giác bất khổ bất lạc thọ, vị ấy cảm thọ cảm giác như người không bị trói buộc. Này các Tỷ-kheo, đây gọi là Tỷ-kheo không bị trói buộc bởi sanh, già, chết, sầu, bi, khổ, ưu, ão. Ta nói rằng vị ấy không bị trói buộc bởi đau khổ.`, ref: "Tương Ưng Bộ 36.6", url: "https://loicuaducphat.org/sn/sn36.6.html#content" },


{ text: `Nếu vị ấy cảm thọ cảm giác lạc thọ, vị ấy tuệ tri: “Thọ ấy là vô thường”. Vị ấy tuệ tri: “Ta không chấp trước thọ ấy”. Vị ấy tuệ tri: “Ta không hoan hỷ thọ ấy”. Nếu vị ấy cảm thọ khổ thọ … Nếu vị ấy cảm thọ bất khổ bất lạc thọ, vị ấy tuệ tri: “Thọ ấy là vô thường”. Vị ấy tuệ tri: “Ta không chấp trước thọ ấy”. Vị ấy tuệ tri: “Ta không hoan hỷ thọ ấy”. Nếu vị ấy cảm thọ cảm giác lạc thọ, vị ấy cảm giác thọ ấy như người không bị trói buộc. Nếu vị ấy cảm thọ cảm giác khổ thọ, vị ấy cảm thọ cảm giác thọ ấy như người không bị trói buộc. Nếu vị ấy cảm thọ cảm giác bất khổ bất lạc thọ, vị ấy cảm thọ cảm giác thọ ấy như người không bị trói buộc. Khi vị ấy cảm thọ một cảm thọ cùng tận sức chịu đựng của thân, vị ấy tuệ tri: “Ta đang cảm thọ một cảm thọ cùng tận đến sức chịu đựng của thân”. Khi vị ấy cảm thọ một cảm thọ cùng tận chịu đựng của sinh mạng, vị ấy tuệ tri: “Ta đang cảm thọ một cảm thọ cùng tận đến sức chịu đựng của sinh mạng”. Vị ấy tuệ tri rằng: “Sau khi thân hoại mạng chung, ở đây, một cảm thọ cảm giác không có gì đáng hoan hỷ, sẽ đi đến lắng dịu”.`, ref: "Tương Ưng Bộ 36.7", url: "https://loicuaducphat.org/sn/sn36.7.html#content" },

{ text: `Có hai cực đoan mà người xuất gia không nên thực hành: Một là say đắm dục lạc đối với các dục vọng hạ liệt, đê tiện, phàm phu, không xứng Thánh hạnh, không liên hệ đến mục đích. Hai là hành hạ tự thân, khổ đau, không xứng bậc Thánh, không liên hệ đến mục đích. Từ bỏ hai cực đoan này là con đường trung đạo, đã được Như Lai giác ngộ, tác thành mắt, tác thành trí, đưa đến an tịnh, thắng trí, giác ngộ, Niết-bàn.<br><br>Thế nào là con đường trung đạo ấy, này Thôn trưởng, đã được Như Lai giác ngộ, tác thành mắt, tác thành trí, đưa đến an tịnh, thắng trí, giác ngộ, Niết-bàn? Ðây là con đường Thánh đạo Tám ngành, tức là chánh tri kiến, chánh tư duy, chánh ngữ, chánh nghiệp, chánh mạng, chánh tinh tấn, chánh niệm, chánh định. Ðây là con đường trung đạo, này Thôn trưởng, được Như Lai giác ngộ, tác thành mắt, tác thành trí, đưa đến an tịnh, thắng trí, giác ngộ, Niết-bàn.`, ref: "Tương Ưng Bộ 42.12", url: "https://loicuaducphat.org/sn/sn42.12.html#content" },

{ text: `Thưa Tôn giả Gotama, con có khởi lên phân vân và nghi ngờ như sau: “Như thế nào, cần phải thấu hiểu pháp của Sa-môn Gotama?” - Này Vaccha, thôi vừa rồi sự phân vân của Ông. Thôi vừa rồi sự nghi ngờ của Ông. Chính do trên điểm Ông phân vân mà nghi ngờ được khởi lên. Ta tuyên bố sự sanh khởi, này Vaccha, đối với những ai có chấp thủ, không phải đối với ai không có chấp thủ. Ví như, này Vaccha, một ngọn lửa cháy đỏ khi nào có nhiên liệu, không phải không có nhiên liệu. Cũng vậy, này Vaccha, Ta tuyên bố về sanh khởi đối với người có chấp thủ (sanh y), không phải với người không có chấp thủ. - Thưa Tôn giả Gotama, trong khi có gió thổi ngọn lửa đi thật xa, thời Tôn giả Gotama tuyên bố cái gì làm nhiên liệu cho ngọn lửa này? - Này Vaccha, trong khi có gió thổi ngọn lửa đi thật xa, thời Ta nói chính gió là nhiên liệu. Trong khi ấy, này Vaccha, chính gió là nhiên liệu (upàdàna). - Thưa Tôn giả Gotama, trong khi một loài hữu tình quăng bỏ thân này để sanh vào một thân khác, thời Tôn giả Gotama tuyên bố cái gì làm nhiên liệu cho thân này? - Này Vaccha, trong khi một loài hữu tình quăng bỏ thân này và sanh vào một thân khác, này Vaccha, Ta tuyên bố rằng trong khi ấy chính ái (tanhà) là nhiên liệu (upàdàna).`, ref: "Tương Ưng Bộ 44.9", url: "https://loicuaducphat.org/sn/sn44.9.html#content" },


{ text: `- Khi nào vô minh dẫn đầu, này các Tỷ-kheo, đưa đến sự thành tựu các pháp bất thiện, thời vô tàm, vô quý nối tiếp theo. Với kẻ bị vô minh chi phối, vô trí, này các Tỷ-kheo, tà kiến sanh. Ðối với kẻ có tà kiến, tà tư duy sanh. Ðối với kẻ có tà tư duy, tà ngữ sanh. Ðối với kẻ có tà ngữ, tà nghiệp sanh. Ðối với kẻ có tà nghiệp, tà mạng sanh. Ðối với kẻ có tà mạng, tà tinh tấn sanh. Ðối với kẻ có tà tinh tấn, tà niệm sanh. Ðối với kẻ có tà niệm, tà định sanh.<br><br>Khi nào minh dẫn đầu, này các Tỷ-kheo, đưa đến sự thành tựu các thiện pháp, thời tàm và quý nối tiếp theo. Với kẻ được minh chi phối, có trí, này các Tỷ-kheo, chánh kiến sanh. Ðối với vị chánh kiến, chánh tư duy sanh. Ðối với vị chánh tư duy, chánh ngữ sanh. Ðối với vị chánh ngữ, chánh nghiệp sanh. Ðối với vị chánh nghiệp, chánh mạng sanh. Ðối với vị chánh mạng, chánh tinh tấn sanh. Ðối với vị chánh tinh tấn, chánh niệm sanh. Ðối với vị chánh niệm, chánh định sanh.`, ref: "Tương Ưng Bộ 45.1", url: "https://loicuaducphat.org/sn/sn45.1.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là chánh tinh tấn? Ở đây, này các Tỷ-kheo, với mục đích khiến cho các ác, bất thiện pháp từ trước chưa sanh không cho sanh khởi, khởi lên ý muốn, cố gắng, tinh tấn, sách tấn, trì tâm; với mục đích khiến cho các ác, bất thiện pháp đã sanh được trừ diệt, khởi lên ý muốn, cố gắng, tinh tấn, sách tấn, trì tâm; với mục đích khiến cho các thiện pháp từ trước chưa sanh nay được sanh khởi, khởi lên ý muốn, cố gắng, tinh tấn, sách tấn, trì tâm; với mục đích khiến cho các thiện pháp đã được sanh có thể duy trì, không có lu mờ, được tăng trưởng, được quảng đại, được tu tập, được viên mãn, khởi lên ý muốn, cố gắng, tinh tấn, sách tấn, trì tâm. Này các Tỷ-kheo, đây gọi là chánh tinh tấn.`, ref: "Tương Ưng Bộ 45.8", url: "https://loicuaducphat.org/sn/sn45.8.html#content" },


{ text: `Này Tỷ-kheo, Ta nói rằng có ba thọ này: lạc thọ, khổ thọ, bất khổ bất lạc thọ. Ba thọ này được Ta nói đến. Nhưng này Tỷ-kheo, Ta lại nói: “Phàm cái gì được cảm thọ, cái ấy nằm trong đau khổ”. Chính vì liên hệ đến tánh vô thường của các hành mà lời ấy được Ta nói lên: “Phàm cái gì được cảm thọ, cái ấy nằm trong đau khổ”. Chính vì liên hệ đến tánh đoạn tận, tánh tiêu vong, tánh ly tham, tánh đoạn diệt, tánh biến hoại của các hành mà lời ấy được Ta nói lên: “Phàm cái gì được cảm thọ, cái ấy nằm trong đau khổ”.`, ref: "Tương Ưng Bộ 36.11", url: "https://loicuaducphat.org/sn/sn36.11.html#content" },


{ text: `- Cũng vậy, bạch chư Thượng tọa, con mắt không phải là trói buộc của các sắc; các sắc không phải là trói buộc của con mắt. Và ở đây, do duyên cả hai khởi lên dục tham gì, dục tham ấy ở đây chính là trói buộc. Cái tai không phải là trói buộc của các tiếng … Mũi không phải là trói buộc của các hương … Lưỡi không phải là trói buộc của các vị … Thân không phải là trói buộc của các xúc … Ý không phải là trói buộc của các pháp. Các pháp cũng không phải là trói buộc của ý. Và ở đây, do duyên cả hai khởi lên dục tham gì, dục tham ấy ở đây chính là trói buộc.`, ref: "Tương Ưng Bộ 41.1", url: "https://loicuaducphat.org/sn/sn41.1.html#content" },


{ text: `- Ví như, này các Tỷ-kheo, cái thân này y cứ món ăn, duyên món ăn được an trú; không có món ăn thì không an trú. Cũng vậy, này các Tỷ-kheo, năm triền cái y cứ món ăn, duyên món ăn được an trú; không có món ăn thì không an trú. Và này các Tỷ-kheo, món ăn nào đối với dục tham chưa sanh được sanh khởi; hay đối với dục tham đã sanh được tăng trưởng, quảng đại? Này các Tỷ-kheo, có tịnh tướng, ở đây, nếu phi như lý tác ý được làm cho sung mãn, thời tịnh tướng này là món ăn khiến cho dục tham chưa sanh được sanh khởi; hay đối với dục tham đã sanh khiến cho tăng trưởng, quảng đại.`, ref: "Tương Ưng Bộ 46.2", url: "https://loicuaducphat.org/sn/sn46.2.html#content" },

{ text: `Chính cấu uế của vàng, này các Tỷ-kheo, do những cấu uế ấy, vàng bị uế nhiễm, không có nhu nhuyến, không có kham nhậm, không có chói sáng, dễ bị bể vụn, và không chân chánh chịu sử dụng. Cũng vậy, này các Tỷ-kheo, có năm cấu uế này của tâm, chính những cấu uế ấy khiến tâm bị uế nhiễm, không có nhu nhuyến, không có kham nhậm, không có chói sáng, dễ bị bể vụn, không chân chánh được định tĩnh để đoạn diệt các lậu hoặc. Thế nào là năm? Dục tham, này các Tỷ-kheo, là cấu uế của tâm. Do cấu uế ấy, tâm bị uế nhiễm, không có nhu nhuyến, không có kham nhậm, không có chói sáng, dễ bị bể vụn, không chân chánh được định tĩnh để đoạn diệt các lậu hoặc. … (Với sân, hôn trầm thụy miên, trạo hối, nghi) Những pháp này, này các Tỷ-kheo, là năm cấu uế của tâm. Chính do những cấu uế ấy, tâm không có nhu nhuyến, không có kham nhậm, không có chói sáng, dễ bị bể vụn, và không chân chánh được định tĩnh để đoạn diệt các lậu hoặc.`, ref: "Tương Ưng Bộ 46.33", url: "https://loicuaducphat.org/sn/sn46.33.html#content" },

{ text: `Này các Tỷ-kheo, ở đây, có thiện nam tử đoạn trừ các dục vọng, xuất gia, từ bỏ gia đình, sống không gia đình, nhưng bị những dục vọng ấy, hay bị những dục vọng tệ hại hơn làm cho người ấy bị phá hủy, bị hư hại, ngã xuống, nằm rạp xuống. Năm chướng ngại, triền cái này, này các Tỷ-kheo, bao trùm tâm, làm cho yếu ớt trí tuệ. Thế nào là năm? Dục tham, này các Tỷ-kheo, là chướng ngại, triền cái, bao trùm tâm, làm cho yếu ớt trí tuệ. Sân, này các Tỷ-kheo, là chướng ngại, triền cái, bao trùm tâm, làm cho yếu ớt trí tuệ. Hôn trầm thụy miên … Trạo hối … Nghi hoặc, này các Tỷ-kheo, là chướng ngại, triền cái, bao trùm tâm, làm cho yếu ớt trí tuệ. Này các Tỷ-kheo, năm chướng ngại, triền cái này bao trùm tâm và làm cho yếu ớt trí tuệ. Bảy giác chi này, này các Tỷ-kheo, không phải là chướng ngại, triền cái, không bao trùm tâm, được tu tập, được làm cho sung mãn, đưa đến chứng ngộ quả minh và giải thoát. Thế nào là bảy? Niệm giác chi, này các Tỷ-kheo, không phải là chướng ngại, triền cái, không bao trùm tâm, được tu tập, được làm cho sung mãn, đưa đến chứng ngộ quả minh và giải thoát … Xả giác chi, này các Tỷ-kheo, không phải là chướng ngại, triền cái, không bao trùm tâm, được tu tập, được làm cho sung mãn, đưa đến chứng ngộ quả minh và giải thoát. Bảy giác chi này, này các Tỷ-kheo, không phải là chướng ngại, triền cái, không bao trùm tâm, được tu tập, được làm cho sung mãn, đưa đến chứng ngộ quả minh và giải thoát.`, ref: "Tương Ưng Bộ 46.39", url: "https://loicuaducphat.org/sn/sn46.39.html#content" },


{ text: `- Ðống bất thiện, này các Tỷ-kheo, nếu có ai nói là năm triền cái, người ấy nói một cách chơn chánh. Toàn bộ đống bất thiện này, này các Tỷ-kheo, tức là năm triền cái. Thế nào là năm? Dục tham triền cái, sân triền cái, hôn trầm thụy miên triền cái, trạo hối triền cái, nghi hoặc triền cái. Ðống bất thiện này, này các Tỷ-kheo, nếu có ai nói là năm triền cái, người ấy nói một cách chơn chánh. Toàn bộ đống bất thiện này, này các Tỷ-kheo, tức là năm triền cái. Ðống thiện, này các Tỷ-kheo, nếu có ai nói là bốn niệm xứ, người ấy nói một cách chơn chánh. Toàn bộ đống thiện này, này các Tỷ-kheo, tức là bốn niệm xứ. Thế nào là bốn? Ở đây, này các Tỷ-kheo, Tỷ-kheo trú, quán thân trên thân, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời … quán thọ trên các thọ … quán tâm trên tâm … quán pháp trên các pháp, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời. Ðống thiện này, này các Tỷ-kheo, nếu có ai nói là bốn niệm xứ, người ấy nói một cách chơn chánh. Toàn bộ đống thiện này, này các Tỷ-kheo, tức là bốn niệm xứ.`, ref: "Tương Ưng Bộ 47.5", url: "https://loicuaducphat.org/sn/sn47.5.html#content" },


{ text: `- Thuở xưa, này các Tỷ-kheo, một con chim ưng cái thình lình vồ xuống và chụp lấy một con chim cút. Rồi này các Tỷ-kheo, con chim cút bị con chim ưng cái bắt, than khóc như sau: “- Như thế này, thật bất hạnh cho tôi! Thật thiếu công đức cho tôi! Vì rằng tôi đã đi không phải chỗ hành xứ của mình, đi vào cảnh giới của người khác. Nếu tôi đi trong chỗ hành xứ của tôi, trong cảnh giới của cha mẹ tôi, thời con chim ưng này không thể hơn tôi, nếu phải đánh nhau”. “- Này Chim cút, thế nào là chỗ hành xứ của ngươi, thế nào là cảnh giới của cha mẹ ngươi?” : “Là vạt đất được lưỡi cày xới lên”. Rồi này các Tỷ-kheo, con chim ưng cái không có siết mạnh sức mạnh của mình, không có bóp chặt sức mạnh của mình, thả con chim cút rồi nói: : “Hãy đi, này Chim cút. Sau khi đi tại chỗ ấy, ta sẽ không thả cho ngươi”. Rồi này các Tỷ-kheo, con chim cút đi đến vạt đất được lưỡi cày xới lên, leo lên một hòn đất lớn, đứng trên ấy và nói với con chim ưng: “- Này, hãy đến ta, Chim ưng! Này, hãy đến ta, này Chim ưng!” Rồi này các Tỷ-kheo, con chim ưng cái siết mạnh sức mạnh của mình, bóp chặt sức mạnh của mình, xếp cả hai cánh, thình lình vồ lấy con chim cút. Này các Tỷ-kheo, khi con chim cút biết được: “Con chim ưng này đang vồ mạnh xuống ta”, liền nấp sau hòn đất ấy. Này các Tỷ-kheo, ở đây, con chim ưng bị bể ngực. Cũng vậy, này các Tỷ-kheo, đối với ai đi tới chỗ không phải hành xứ của mình, đi đến cảnh giới của người khác. Do vậy, này các Tỷ-kheo, chớ có đi đến chỗ không phải hành xứ của mình, chỗ cảnh giới của người khác. Này các Tỷ-kheo, đi đến chỗ không phải hành xứ của mình, đi đến cảnh giới của người khác, thời Ác ma nắm được cơ hội, Ác ma nắm được đối tượng.`, ref: "Tương Ưng Bộ 47.6", url: "https://loicuaducphat.org/sn/sn47.6.html#content" },


{ text: `Cũng vậy, này các Tỷ-kheo, đối với ai đi tới chỗ không phải hành xứ của mình, đi đến cảnh giới của người khác. Do vậy, này các Tỷ-kheo, chớ có đi đến chỗ không phải hành xứ của mình, chỗ cảnh giới của người khác. Này các Tỷ-kheo, đi đến chỗ không phải hành xứ của mình, đi đến cảnh giới của người khác, thời Ác ma nắm được cơ hội, Ác ma nắm được đối tượng. Này các Tỷ-kheo, chỗ nào không phải hành xứ của Tỷ-kheo? Chỗ nào là cảnh giới của người khác? Chính là năm dục công đức. Thế nào là năm? Có các sắc do mắt nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Có các tiếng do tai nhận thức … Có các hương do mũi nhận thức … Có các vị do lưỡi nhận thức … Có các xúc do thân nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Này các Tỷ-kheo, đây là chỗ không phải hành xứ của Tỷ-kheo, chỗ cảnh giới của người khác. Này các Tỷ-kheo, hãy đi đến chỗ hành xứ của mình, chỗ cảnh giới của cha mẹ mình. Này các Tỷ-kheo, đi đến chỗ hành xứ của mình, đến cảnh giới của cha mẹ mình, thời Ác ma không nắm được cơ hội, không nắm được đối tượng. Và này các Tỷ-kheo, chỗ nào là chỗ hành xứ của Tỷ-kheo? Chỗ nào là cảnh giới của cha mẹ? Chính là bốn niệm xứ. Thế nào là bốn? Ở đây, này các Tỷ-kheo, Tỷ-kheo trú, quán thân trên thân, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời; trú, quán thọ trên các thọ…; trú, quán tâm trên tâm…; trú, quán pháp trên các pháp, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời. Này các Tỷ-kheo, đây là chỗ hành xứ của mình, chỗ cảnh giới của cha mẹ mình.`, ref: "Tương Ưng Bộ 47.6", url: "https://loicuaducphat.org/sn/sn47.6.html#content" },


{ text: `- Này các Tỷ-kheo, tại núi chúa Tuyết sơn có khoảnh đất gồ ghề, không thăng bằng, chỗ ấy không có các loài vượn, loài người qua lại. Này các Tỷ-kheo, tại núi chúa Tuyết sơn có những khoảng đất ghồ ghề, không bằng phẳng, chỗ ấy chỉ có loài vượn qua lại, không có loài người. Tại núi chúa Tuyết sơn, có những khoảnh đất bằng phẳng, khả ái. Tại chỗ ấy có các loài vượn và loài người qua lại. Tại đấy, này các Tỷ-kheo, những người thợ săn đặt các bẫy nhựa trên những con đường có vượn qua lại để bắt các con vượn. Ở đây, này các Tỷ-kheo, những con vượn nào tánh không ngu si, không tham ăn, thấy bẫy nhựa ấy liền tránh xa. Còn con vượn nào ngu si, tham ăn, thấy bẫy nhựa ấy, thò tay nắm lấy và bị dính vào đấy. “Ta sẽ gỡ bàn tay ra”, nó thò bàn tay thứ hai nắm lấy và bị dính ở đấy. “Ta sẽ gỡ hai tay ra”, nó giơ chân nắm lấy và bị dính ở đấy. “Ta sẽ gỡ hai bàn tay và bàn chân ra”, nó giơ bàn chân thứ hai nắm lấy và bị dính ở đấy. “Ta sẽ gỡ cả hai tay và hai chân”, nó dùng miệng ngậm lấy và bị mắc dính ở đấy. Như vậy, này các Tỷ-kheo, con vượn bị bắt năm chỗ, liền rên la nằm xuống, rơi vào bất hạnh, rơi vào khổ não, bị người thợ săn muốn làm gì thì làm. Này các Tỷ-kheo, người thợ săn đâm chết nó, nướng nó trên đống than củi, và ra đi, theo sở thích của mình. Cũng vậy, này các Tỷ-kheo, là người đi đến chỗ không phải hành xứ của mình, chỗ cảnh giới của người khác. Này các Tỷ-kheo, đi đến chỗ không phải hành xứ của mình, chỗ cảnh giới của người khác, Ác ma nắm được cơ hội, Ác ma nắm được đối tượng.`, ref: "Tương Ưng Bộ 47.7", url: "https://loicuaducphat.org/sn/sn47.7.html#content" },

{ text: `Này các Tỷ-kheo, thế nào là Tỷ-kheo trú dưới thế nào, thời trên như vậy; trên thế nào thời dưới như vậy? Ở đây, này các Tỷ-kheo, Tỷ-kheo quán thân này, từ bàn chân trở lên, từ đầu tóc trở xuống, bao bọc bởi da, đều đầy những vật bất tịnh; thân này có tóc, lông, móng, răng, da, thịt, dây gân, xương, tủy, thận, tim, gan, hoành cách mô, lá lách, phổi, ruột, màng ruột, bao tử, phân, mật, đàm, mủ, máu, mồ hôi, mỡ, nước mắt, mỡ da, nước miếng, nước mũi, nước ở khớp xương, nước tiểu. Như vậy, này các Tỷ-kheo, Tỷ-kheo trú dưới thế nào, thời trên như vậy; trên thế nào, thời dưới như vậy.`, ref: "Tương Ưng Bộ 51.20", url: "https://loicuaducphat.org/sn/sn51.20.html#content" },

{ text: `- Này các Tỷ-kheo, do không giác ngộ, do không thông đạt bốn Thánh đế mà Ta và các Ông lâu ngày phải dong ruổi, lưu chuyển như thế này. Thế nào là bốn? Do không giác ngộ, do không thông đạt Thánh đế về Khổ, này các Tỷ-kheo, nên Ta và các Ông lâu ngày phải dong ruổi, lưu chuyển như thế này … Thánh đế về Khổ tập … Thánh đế về Khổ diệt … Do không giác ngộ, do không thông đạt Thánh đế về Con Ðường đưa đến Khổ diệt, này các Tỷ-kheo, nên Ta và các Ông lâu ngày phải dong ruổi, lưu chuyển như thế này. Nhưng nay, này các Tỷ-kheo, Thánh đế về Khổ này đã được giác ngộ, đã được thông đạt Thánh đế về Khổ tập đã được giác ngộ, đã được thông đạt Thánh đế về Khổ diệt đã được giác ngộ, đã được thông đạt Thánh đế về Con Ðường đưa đến Khổ diệt đã được giác ngộ, đã được thông đạt. Ðược chặt đứt là hữu ái, được đoạn tận là những gì đưa đến tái sanh. Nay không còn tái sanh nữa. Thế Tôn thuyết giảng như vậy … bậc Ðạo Sư lại nói thêm:<br><br>Do không như thật thấy,<br>Bốn sự thật bậc Thánh,<br>Phải lâu ngày luân chuyển,<br>Trải qua nhiều đời sống.<br>Khi chúng được thấy rõ,<br>Mầm tái sanh nhổ sạch,<br>Gốc khổ được đoạn tận,<br>Nay không còn tái sanh.`, ref: "Tương Ưng Bộ 56.21", url: "https://loicuaducphat.org/sn/sn56.21.html#content" },


{ text: `“Vật gì dẫn dắt đời?<br>Vật gì tự não hại?<br>Và có một pháp nào,<br>Mọi vật đều tùy thuộc?”<br><br>“Chính ái dẫn dắt đời,<br>Chính ái tự não hại,<br>Chính ái là một pháp,<br>Mọi vật đều tùy thuộc.”`, ref: "Tương Ưng Bộ 1.63", url: "https://loicuaducphat.org/sn/sn1.63.html#content" },


{ text: `“Này các Tỷ-kheo, cái gì chúng ta tư niệm, cái gì chúng ta tư lường, cái gì chúng ta có thầm ý, cái ấy trở thành sở duyên cho thức an trú. Do sở duyên có mặt nên thức an trú. Do thức ấy an trú và tăng trưởng nên có thiên về, hướng về (hệ trước: nati). Do có thiên về, hướng về nên có sự đi đến tái sanh. Do có sự đi đến tái sanh nên có từ bỏ và sanh khởi. Do có từ bỏ và sanh khởi nên trong tương lai sanh, già chết, sầu, bi, khổ, ưu, não, sanh khởi. Như vậy là sự tập khởi của toàn bộ khổ uẩn này. Này các Tỷ-kheo, nếu không có tư niệm, tư lường, không có thầm ý, thời không có sở duyên cho thức an trú. Do sở duyên không có mặt nên thức không có an trú. Do thức ấy không an trú, không tăng trưởng nên không có thiên về, hướng về. Do không có thiên về, hướng về nên không có đi đến tái sanh. Do không có sự đi đến tái sanh nên không có từ bỏ và sanh khởi. Do không có từ bỏ và sanh khởi nên trong tương lai sanh, già chết, sầu, bi, khổ, ưu, não đoạn diệt. Như vậy là sự đoạn diệt của toàn bộ khổ uẩn này.”`, ref: "Tương Ưng Bộ 12.40", url: "https://loicuaducphat.org/sn/sn12.40.html#content" },


{ text: `“Này các Tỷ-kheo, ví như duyên dầu và duyên tim, ngọn đèn dầu được cháy đỏ. Tại đấy có người thỉnh thoảng rót thêm dầu và khơi tim lên. Này các Tỷ-kheo, ngọn đèn dầu ấy được nuôi dưỡng như vậy, được tiếp tế như vậy, có thể cháy đỏ trong một thời gian dài. Cũng vậy, này các Tỷ-kheo, ai sống thấy vị ngọt trong các pháp kiết sử, ái được tăng trưởng. Do duyên ái, thủ sanh khởi... (như trên)... Như vậy là toàn bộ khổ uẩn này tập khởi. Này các Tỷ-kheo, ví như duyên dầu và duyên tim, ngọn đèn dầu được cháy đỏ. Tại đấy không có người thỉnh thoảng rót thêm dầu và khơi tim lên. Như vậy, này các Tỷ-kheo, ngọn đèn dầu ấy do chính nhiên liệu được tiếp tế trước tiêu diệt, do nhiên liệu khác không được đem thêm, không được nuôi dưỡng, sẽ bị tắt. Cũng vậy, này các Tỷ-kheo, ai sống thấy sự nguy hiểm trong các pháp kiết sử, ái được đoạn diệt. Do ái diệt nên thủ diệt. .. (như trên)... Như vậy là toàn bộ khổ uẩn này đoạn diệt”.`, ref: "Tương Ưng Bộ 12.54", url: "https://loicuaducphat.org/sn/sn12.54.html#content" },


{ text: `“Này các Tỷ-kheo, ví như có một cây lớn, các rễ của cây ấy đâm sâu xuống dưới và đâm ngang, tất cả rễ ấy đều đem lên nhựa sống cho cây ấy. Này các Tỷ-kheo, cây lớn ấy được nuôi dưỡng như vậy, được tiếp tế như vậy, có thể đứng vững trong một thời gian dài. Cũng vậy, này các Tỷ-kheo, ai sống thấy vị ngọt trong các pháp được chấp thủ, ái được tăng trưởng. Do duyên ái nên thủ sanh khởi... (như trên)... Như vậy là toàn bộ khổ uẩn này tập khởi. Này các Tỷ-kheo, ví như một cây lớn, có người đến, cầm cái cuốc và cái giỏ. Người ấy chặt đứt rễ của cây ấy. Sau khi chặt đứt rễ, người ấy đào một cái mương. Sau khi đào cái mương, người ấy nhổ các rễ lớn... (như trên)... hay đổ tro vào dòng nước mạnh cho nước cuốn đi. Cũng vậy, này các Tỷ-kheo, cây lớn ấy, rễ bị cắt đứt, làm thành như thân cây ta-la, làm cho cây ấy không thể tái sanh, trong tương lai không thể sống lại được. Cũng vậy, này các Tỷ-kheo, ai sống thấy sự nguy hiểm trong các pháp được chấp thủ, ái được đoạn diệt. Do ái diệt nên thủ diệt... (như trên)... Như vậy là toàn bộ khổ uẩn này đoạn diệt”.`, ref: "Tương Ưng Bộ 12.56", url: "https://loicuaducphat.org/sn/sn12.56.html#content" },


{ text: `Sâu xa thay, này Ānanda, là định lý Duyên khởi này, và sâu xa thật là định nghĩa này. Này Ānanda, chính vì không hiểu rõ pháp này, không giác ngộ, không chứng nhập pháp này mà chúng sanh nay bị rối ren như cuộn chỉ, bị phủ đầy bởi bệnh cằn cỗi, như cỏ munjà, như cây lau, không thoát khỏi sự luân hồi trong cõi dữ, ác thú, đọa xứ. Này Ānanda, ai sống thấy vị ngọt trong các pháp được chấp thủ, ái được tăng trưởng. Do duyên ái, hữu có mặt. Do duyên hữu, sanh có mặt. Do duyên sanh, già chết, sầu, bi, khổ, ưu, não sanh khởi. Như vậy là toàn bộ khổ uẩn này tập khởi. Này Ānanda, ví như một cây lớn, các rễ của cây ấy đâm xuống và đâm ngang, tất cả rễ ấy đều hút lên nhựa sống cho cây ấy. Này Ānanda, cây lớn ấy được nuôi dưỡng như vậy, được tiếp tế như vậy, có thể đứng vững trong một thời gian dài. Cũng vậy, này Ānanda, ai sống thấy vị ngọt trong các pháp được chấp thủ, ái được tăng trưởng. Do duyên ái, thủ có mặt. Do duyên thủ, hữu có mặt... (như trên)... Như vậy là toàn bộ khổ uẩn này tập khởi.`, ref: "Tương Ưng Bộ 12.60", url: "https://loicuaducphat.org/sn/sn12.60.html#content" },


{ text: `“Sắc, này các Tỷ-kheo, là vô thường. Cái gì là nhân, cái gì là duyên cho sắc sanh khởi; cái ấy cũng vô thường. Sắc đã được cái vô thường làm cho sanh khởi, này các Tỷ-kheo, từ đâu có thể thường được. Thọ, này các Tỷ-kheo, là vô thường. Cái gì là nhân, cái gì là duyên cho thọ sanh khởi; cái ấy cũng vô thường. Thọ đã được cái vô thường làm cho sanh khởi, này các Tỷ-kheo, từ đâu có thể thường được. Tưởng, này các Tỷ-kheo, là vô thường... Các hành, này các Tỷ-kheo, là vô thường. Cái gì là nhân, cái gì là duyên cho hành sanh khởi; cái ấy cũng vô thường. Hành đã được cái vô thường làm cho sanh khởi, này các Tỷ-kheo, từ đâu có thể thường được. Thức, này các Tỷ-kheo, là vô thường. Cái gì là nhân, cái gì là duyên cho thức sanh khởi; cái ấy cũng vô thường. Thức đã được cái vô thường làm cho sanh khởi, này các Tỷ-kheo, từ đâu có thể thường được. Thấy vậy, này các Tỷ-kheo, vị Ða văn Thánh đệ tử yếm ly đối với sắc... ‘... không còn trở lui với trạng thái này nữa”.`, ref: "Tương Ưng Bộ 22.18", url: "https://loicuaducphat.org/sn/sn22.18.html#content" },


{ text: `“Sắc, này các Tỷ-kheo, là khổ. Cái gì là nhân, cái gì là duyên cho sắc sanh khởi; cái ấy cũng khổ. Sắc đã được cái khổ làm cho sanh khởi, này các Tỷ-kheo, từ đâu có thể lạc được. Thọ, này các Tỷ-kheo, là khổ... Tưởng, này các Tỷ-kheo, là khổ... Các hành, này các Tỷ-kheo, là khổ... Thức, này các Tỷ-kheo, là khổ. Cái gì là nhân, cái gì là duyên cho thức sanh khởi; cái ấy cũng khổ. Thức đã được cái khổ làm cho sanh khởi, này các Tỷ-kheo, từ đâu có thể lạc được. Thấy vậy, này các Tỷ-kheo, vị Ða văn Thánh đệ tử yếm ly đối với sắc... ‘... không còn trở lui trạng thái này nữa”.`, ref: "Tương Ưng Bộ 22.19", url: "https://loicuaducphat.org/sn/sn22.19.html#content" },


{ text: `‘Ðối với sắc, này các Hiền giả, ai đã viễn ly tham, đã viễn ly dục, đã viễn ly ái, đã viễn ly khát, đã viễn ly nhiệt tình, đã viễn ly khát ái, khi sắc ấy biến hoại, đổi khác, sẽ không khởi lên sầu, bi, khổ, ưu, não. Ðối với thọ ... đối với tưởng ... đối với các hành ... đối với các hành, ai đã viễn ly tham, đã viễn ly dục, đã viễn ly ái, đã viễn ly khát, đã viễn ly nhiệt tình, đã viễn ly khát ái, khi các hành ấy biến hoại, đổi khác, sẽ không khởi lên sầu, bi, khổ, ưu, não. Đối với thức, ai đã viễn ly tham, đã viễn ly dục, đã viễn ly ái, đã viễn ly khát, đã viễn ly nhiệt tình, đã viễn ly khát ái, khi thức ấy biến hoại, đổi khác, sẽ không khởi lên sầu, bi, khổ, ưu, não. Do thấy sự lợi ích này, này các Hiền giả, bậc Ðạo Sư của chúng tôi nói đến sự điều phục dục và tham đối với sắc ... đối với thọ ... đối với tưởng ... đối với các hành; bậc Ðạo Sư của chúng tôi nói đến sự điều phục dục và tham đối với thức’. Và này các Hiền giả, vì rằng đạt được và an trú trong các thiện pháp, và ngay trong đời sống hiện tại, sống được an lạc, không bị chướng ngại, không bị ưu não, không bị nhiệt não, và sau khi thân hoại mạng chung, sẽ được sanh thiện thú. Do vậy, đây là sự thành tựu các thiện pháp, được Thế Tôn tán thán.`, ref: "Tương Ưng Bộ 22.2", url: "https://loicuaducphat.org/sn/sn22.2.html#content" },


{ text: `“Này các Tỷ-kheo, Ta đã đi tìm cầu vị ngọt của sắc. Vị ngọt của sắc là gì, Ta đã chứng đắc. Vị ngọt của sắc như thế nào, Ta đã khéo thấy với trí tuệ. Này các Tỷ-kheo, Ta đã đi tìm cầu sự nguy hiểm của sắc. Sự nguy hiểm của sắc là gì, Ta đã chứng đắc. Sự nguy hiểm của sắc như thế nào, Ta đã khéo thấy với trí tuệ. Này các Tỷ-kheo, Ta đã đi tìm cầu sự xuất ly của sắc. Sự xuất ly của sắc là gì, Ta đã chứng đắc. Sự xuất ly của sắc như thế nào, Ta đã khéo thấy với trí tuệ. Này các Tỷ-kheo, Ta đi tìm cầu vị ngọt của thọ... Này các Tỷ-kheo, Ta đi tìm cầu vị ngọt của tưởng ... Này các Tỷ-kheo, Ta đã đi tìm cầu vị ngọt của các hành ... Này các Tỷ-kheo, Ta đã đi tìm cầu vị ngọt của thức. Vị ngọt của thức là gì, Ta đã chứng đắc. Vị ngọt của thức như thế nào, Ta đã khéo thấy với trí tuệ. Này các Tỷ-kheo, Ta đã đi tìm cầu sự nguy hiểm của thức. Nguy hiểm của thức là gì, Ta đã chứng đắc. Nguy hiểm của thức như thế nào, Ta đã khéo thấy với trí tuệ. Này các Tỷ-kheo, Ta đã đi tìm cầu sự xuất ly của thức. Xuất ly của thức là gì, Ta đã chứng đắc. Xuất ly của thức như thế nào, Ta đã khéo thấy với trí tuệ. Này các Tỷ-kheo, cho đến khi nào đối với năm thủ uẩn này, Ta chưa như thật biết vị ngọt là vị ngọt, nguy hiểm là sự nguy hiểm, xuất ly là xuất ly, thời này các Tỷ-kheo, Ta không tuyên bố rằng... Sa-môn, Bà-la-môn, chư Thiên và loài Người. Và tri kiến như sau khởi lên nơi Ta: ‘Tâm Ta giải thoát, bất động. Ðây là đời sống cuối cùng, nay không còn tái sanh nữa’.”`, ref: "Tương Ưng Bộ 22.27", url: "https://loicuaducphat.org/sn/sn22.27.html#content" },

{ text: `“Này các Tỷ-kheo, ai ưa thích sắc, người ấy ưa thích khổ. Ai ưa thích khổ, Ta nói, người ấy không giải thoát khỏi khổ. Này các Tỷ-kheo, ai ưa thích thọ...ai ưa thích tưởng...ai ưa thích các hành...ai ưa thích thức, người ấy ưa thích khổ. Ai ưa thích khổ, Ta nói, người ấy không giải thoát khỏi khổ. Và này các Tỷ-kheo, ai không ưa thích sắc, người ấy không ưa thích khổ. Ai không ưa thích khổ, Ta nói, người ấy giải thoát khỏi khổ. Và này các Tỷ-kheo, ai không ưa thích thọ...ai không ưa thích tưởng...ai không ưa thích các hành...ai không ưa thích thức, người ấy không ưa thích khổ. Ai không ưa thích khổ, Ta nói, người ấy giải thoát khỏi khổ”.`, ref: "Tương Ưng Bộ 22.29", url: "https://loicuaducphat.org/sn/sn22.29.html#content" },


{ text: `Này các Tỷ-kheo, tham luyến là không giải thoát. Do tham luyến sắc, này các Tỷ-kheo, thức có chân đứng được an trú. Với sắc là sở duyên, với sắc là trú xứ, (thức) hướng tìm hỷ, đi đến tăng trưởng, tăng thịnh, lớn mạnh. Hay do tham luyến thọ ... tham luyến tưởng ... tham luyến hành, này các Tỷ-kheo, thức có chân đứng được an trú. Với hành là sở duyên, với hành là trú xứ, (thức) hướng tìm hỷ, đi đến tăng trưởng, tăng thịnh, lớn mạnh. Này các Tỷ-kheo, ai nói như sau: ‘Ngoài sắc, ngoài thọ, ngoài tưởng, ngoài các hành, tôi sẽ chỉ rõ sự đến hay đi, sự diệt hay sanh, sự tăng trưởng, sự tăng thịnh hay sự lớn mạnh của thức’, sự việc như vậy không xảy ra. Này các Tỷ-kheo, nếu vị Tỷ-kheo đoạn tận tham đối với sắc giới; do tham được đoạn tận, sở duyên được cắt đứt, chỗ y chỉ của thức không có hiện hữu. Này các Tỷ-kheo, nếu vị Tỷ-kheo đoạn tận tham đối với thọ giới... đối với tưởng giới... đối với hành giới... Này các Tỷ-kheo, nếu vị Tỷ-kheo đoạn tận tham đối với thức giới, do tham được đoạn tận, sở duyên được cắt đứt, chỗ y chỉ của thức không có hiện hữu. Không có chỗ y chỉ ấy, thức không tăng thịnh, không có hành động, được giải thoát. Do giải thoát nên được kiên trú; do kiên trú nên được tri túc; do tri túc nên không có ưu não; do không có ưu não nên tự mình cảm thấy tịch tịnh hoàn toàn. Vị ấy biết: ‘Sanh đã tận, Phạm hạnh đã thành, những việc nên làm đã làm, không còn trở lui trạng thái này nữa’.`, ref: "Tương Ưng Bộ 22.53", url: "https://loicuaducphat.org/sn/sn22.53.html#content" },


{ text: `Do tham luyến sắc, này các Tỷ-kheo, thức có chân đứng được an trú. Với sắc là sở duyên, với sắc là trú xứ, (thức) hướng tìm hỷ, đi đến tăng trưởng, tăng thịnh, lớn mạnh. Do tham luyến thọ... Do tham luyến tưởng... Do tham luyến các hành, này các Tỷ-kheo, thức có chân đứng được tồn tại. Với hành là sở duyên, với hành là trú xứ, (thức) hướng tìm hỷ, đi đến tăng trưởng, tăng thịnh, lớn mạnh. Này các Tỷ-kheo, ai nói như sau: ‘Ngoài sắc, ngoài thọ, ngoài tưởng, ngoài các hành, tôi sẽ chỉ rõ sự đến hay đi, sự diệt hay sanh, sự tăng trưởng, tăng thịnh hay sự lớn mạnh của thức’, sự việc như vậy không xảy ra. Này các Tỷ-kheo, nếu vị Tỷ-kheo đoạn tận tham đối với sắc giới; do tham được đoạn tận, sở duyên được cắt đứt, chỗ y chỉ của thức không có hiện hữu. Này các Tỷ-kheo, nếu vị Tỷ-kheo đoạn tận tham đối với thọ giới... đối với tưởng giới... đối với hành giới... đối với thức giới; do tham được đoạn tận, sở duyên được cắt đứt, chỗ y chỉ của thức không có hiện hữu. Không có chỗ y chỉ như vậy, thức không tăng thịnh, không có hành động, được giải thoát; do giải thoát nên được kiên trú; do kiên trú nên được tri túc; do tri túc nên không có ưu não; do không có ưu não nên tự mình cảm thấy tịch tịnh hoàn toàn. Vị ấy biết: ‘Sanh đã tận, Phạm hạnh đã thành, những việc nên làm đã làm, không còn trở lui trạng thái này nữa’.”`, ref: "Tương Ưng Bộ 22.54", url: "https://loicuaducphat.org/sn/sn22.54.html#content" },

{ text: `“Này Mahāli, có nhân, có duyên là sự nhiễm ô của chúng sanh. Này Mahāli, có nhân, có duyên, chúng sanh bị nhiễm ô. Này Mahāli, có nhân có duyên là sự thanh tịnh của chúng sanh. Có nhân, có duyên, chúng sanh được thanh tịnh”. “Nhưng bạch Thế Tôn, do nhân gì, do duyên gì là sự nhiễm ô của chúng sanh? Do có nhân gì, do có duyên gì chúng sanh bị nhiễm ô?” “Này Mahāli, nếu sắc nhất hướng khổ, rơi trên đau khổ, nhập cuộc với khổ, không nhập cuộc với lạc, thời chúng sanh không tham đắm đối với sắc. Và vì rằng, này Mahāli, sắc là lạc, rơi trên lạc, nhập cuộc với lạc, không nhập cuộc với khổ, cho nên chúng sanh tham đắm đối với sắc. Do tham đắm nên bị triền phược, do bị triền phược nên bị nhiễm ô. Này Mahāli, đây là nhân, đây là duyên cho sự nhiễm ô chúng sanh. Do có nhân như vậy, do có duyên như vậy, chúng sanh sẽ bị nhiễm ô.`, ref: "Tương Ưng Bộ 22.60", url: "https://loicuaducphat.org/sn/sn22.60.html#content" },


{ text: `“Bạch Thế Tôn, thế nào là nhân, thế nào là duyên cho sự thanh tịnh của chúng sanh? Do có nhân như thế nào, có duyên như thế nào, chúng sanh được thanh tịnh?” “Này Mahāli, nếu sắc là nhất hướng lạc, rơi trên lạc, nhập cuộc với lạc, không nhập cuộc với khổ, thời chúng sanh không nhàm chán đối với sắc. Và vì rằng, này Mahāli, sắc là khổ, rơi trên khổ, nhập cuộc với khổ, không nhập cuộc với lạc, do vậy chúng sanh mới yếm ly đối với sắc. Do yếm ly nên ly tham; do ly tham nên giải thoát. Này Mahāli, đây là nhân, đây là duyên cho sự thanh tịnh của chúng sanh. Do có nhân như vậy, do có duyên như vậy, chúng sanh được thanh tịnh. Này Mahāli, nếu thọ là nhất hướng lạc... Này Mahāli, nếu tưởng là nhất hướng lạc... Này Mahāli, nếu các hành là nhất hướng lạc... Này Mahāli, nếu thức là nhất hướng lạc, rơi trên lạc, nhập cuộc với lạc, không nhập cuộc với khổ, thời chúng sanh không nhàm chán đối với thức. Và vì rằng, này Mahāli, thức là khổ, rơi trên khổ, nhập cuộc với khổ, không nhập cuộc với lạc, do vậy chúng sanh mới yếm ly đối với thức. Do yếm ly nên ly tham, do ly tham nên giải thoát. Này Mahāli, đây là nhân, đây là duyên cho sự thanh tịnh của chúng sanh. Do có nhân như vậy, do có duyên như vậy, chúng sanh được thanh tịnh”.`, ref: "Tương Ưng Bộ 22.60", url: "https://loicuaducphat.org/sn/sn22.60.html#content" },


{ text: `“Ai chấp trước, này Tỷ-kheo, người ấy bị Ma trói buộc. Ai không chấp trước, người ấy được giải thoát khỏi Ác ma”. “Bạch Thế Tôn, con đã hiểu, bạch Thiện Thệ, con đã hiểu”. “Như thế nào, này Tỷ-kheo, Ông hiểu một cách rộng rãi ý nghĩa lời Ta nói một cách vắn tắt?” “Ai chấp trước sắc, bạch Thế Tôn, người ấy bị Ma trói buộc. Ai không chấp trước, người ấy được giải thoát khỏi Ác ma. Ai chấp trước thọ, người ấy bị Ma trói buộc. Ai không chấp trước, người ấy được giải thoát khỏi Ác ma. Ai chấp trước tưởng... Ai chấp trước các hành... Ai chấp trước thức, người ấy bị Ma trói buộc. Ai không chấp trước, người ấy được giải thoát khỏi Ác ma. Bạch Thế Tôn, lời nói vắn tắt này của Thế Tôn, con hiểu ý nghĩa một cách rộng rãi như vậy”. “Lành thay, lành thay, này Tỷ-kheo! Lành thay, này Tỷ-kheo! Như vậy Ông hiểu một cách rộng rãi ý nghĩa lời nói vắn tắt này của Ta. Ai chấp trước sắc, này Tỷ-kheo, người ấy bị Ma trói buộc. Ai không chấp trước, người ấy được giải thoát khỏi Ác ma. Ai chấp trước thọ... Ai chấp trước tưởng... Ai chấp trước các hành... Ai chấp trước thức, người ấy bị Ma trói buộc. Ai không chấp trước, người ấy được giải thoát khỏi Ác ma.`, ref: "Tương Ưng Bộ 22.63", url: "https://loicuaducphat.org/sn/sn22.63.html#content" },

{ text: `“Này các Tỷ-kheo, kẻ vô văn phàm phu không như thật biết rõ sự tập khởi, sự đoạn diệt, vị ngọt, sự nguy hiểm và sự xuất ly của sắc. của thọ... của tưởng... của các hành... Không như thật biết rõ sự tập khởi, sự đoạn diệt, vị ngọt, sự nguy hiểm và sự xuất ly của thức. Này các Tỷ-kheo, bậc Ða văn Thánh đệ tử như thật biết rõ sự tập khởi, sự đoạn diệt, vị ngọt, sự nguy hiểm và sự xuất ly của sắc. của thọ... của tưởng... của các hành... như thật biết rõ sự tập khởi, sự đoạn diệt, vị ngọt, sự nguy hiểm và sự xuất ly của thức”.`, ref: "Tương Ưng Bộ 22.74", url: "https://loicuaducphat.org/sn/sn22.74.html#content" },


{ text: `“Này các Tỷ-kheo, sắc là vô thường. Cái gì vô thường là khổ. Cái gì khổ là vô ngã. Cái gì vô ngã cần phải như thật thấy với chánh trí tuệ là: ‘Cái này không phải của tôi, cái này không phải là tôi, cái này không phải tự ngã của tôi’. Thọ... tưởng... các hành là vô thường... Thức là vô thường. Cái gì vô thường là khổ. Cái gì khổ là vô ngã. Cái gì vô ngã cần phải như thật thấy với chánh trí tuệ là: ‘Cái này không phải của tôi, cái này không phải là tôi, cái này không phải tự ngã của tôi’. Này các Tỷ-kheo, do thấy vậy, bậc Ða văn Thánh đệ tử nhàm chán đối với sắc... đối với thọ... đối với tưởng... đối với các hành. .. đối với thức. Do nhàm chán nên ly tham. Do ly tham, nên được giải thoát. Trong sự giải thoát, trí khởi lên: Ta đã được giải thoát. Vị ấy biết rõ: ‘Sanh đã tận, Phạm hạnh đã thành, những việc gì nên làm đã làm, không còn trở lui trạng thái này nữa’.<br><br>An lạc, A-la-hán,<br>Bậc khát ái không còn,<br>Ngã mạn khéo chặt đứt,<br>Lươi si bị phá rách.<br><br>Họ đạt được bất động,<br>Tâm viễn ly ô trược,<br>Không nhiễm trước thế gian,<br>Bậc Phạm thiên vô lậu.<br><br>Họ biến tri năm uẩn.<br>Do hành bảy Chánh pháp.<br>Bậc Chân nhân tán thán,<br>Con đích tôn chư Phật.<br><br>Ðầy đủ bảy món báu,<br>Ba học đều thành tựu,<br>Bậc đại hùng du hành,<br>Ðoạn tận mọi sợ hãi.<br><br>Ðầy đủ mười uy lực,<br>Bậc Long tượng Thiền định.<br>Họ tối thắng ở đời,<br>Khát ái được đoạn tận.<br><br>Thành tựu vô học trí,<br>Thân này thân tối hậu,<br>Cứu cánh của Phạm hạnh,<br>Ðạt được không nhờ ai.<br><br>Ðối các tưởng, không động,<br>Giải thoát khỏi tái sanh,<br>Ðạt được điều phục địa,<br>Họ chiến thắng ở đời.<br><br>Trên, dưới cùng bề ngang,<br>Họ không có hỷ lạc,<br>Họ rống tiếng sư tử,<br>Phật vô thượng ở đời!`, ref: "Tương Ưng Bộ 22.76", url: "https://loicuaducphat.org/sn/sn22.76.html#content" },

{ text: `Khi cảm giác lạc thọ, vị ấy biết rõ: ‘Là vô thường’; vị ấy biết rõ: ‘Là không nên đắm trước’; vị ấy biết rõ: ‘Là không nên hoan hỷ’. Khi cảm giác khổ thọ, vị ấy biết rõ: ‘Là vô thường’; vị ấy biết rõ: ‘Là không nên đắm trước’; vị ấy biết rõ: ‘Là không nên hoan hỷ’. Khi cảm giác bất khổ bất lạc khổ, vị ấy biết rõ: ‘Là vô thường’; vị ấy biết rõ: ‘Là không nên đắm trước’; vị ấy biết rõ: ‘Là không nên hoan hỷ’. Nếu vị ấy cảm giác lạc thọ, vị ấy cảm thọ không có hệ lụy. Nếu vị ấy cảm giác khổ thọ, vị ấy cảm thọ không có hệ lụy. Nếu vị ấy cảm giác bất khổ bất lạc thọ, vị ấy cảm thọ không có hệ lụy. Nếu vị ấy cảm thọ một cảm thọ cùng tận về thân, vị ấy biết rõ: ‘Ta đang cảm giác một cảm thọ cùng tận về thân’. Nếu vị ấy cảm giác một cảm thọ cùng tận về sinh mạng, vị ấy biết rõ: ‘Ta đang cảm giác một cảm thọ cùng tận về sinh mạng’. Vị ấy biết rõ rằng: ‘Khi thân hoại mạng chung trên cho đến khi sinh mạng đi đến chỗ cùng tận, ở đây tất cả những gì vị ấy cảm thọ, tất cả những gì vị ấy hoan hỷ, sẽ trở thành thanh lương!’ Ví như, này Assaji, do duyên dầu, do duyên tim bấc, một cây đèn dầu được cháy đỏ. Khi dầu và tim bấc của ngọn đèn ấy đoạn tận, không có mang lại nhiên liệu, ngọn đèn ấy sẽ tắt. Cũng vậy, này Assaji, Tỷ-kheo, khi cảm giác một cảm thọ cùng tận về thân, vị ấy biết rõ: ‘Ta đang cảm giác một cảm thọ cùng tận về thân’. Khi cảm giác một cảm thọ cùng tận về sinh mạng, vị ấy biết rõ: ‘Ta đang cảm giác một cảm thọ cùng tận về sinh mạng’. Sau khi thân hoại mạng chung trên cho đến khi sinh mạng đi đến chỗ cùng tận, ở đây tất cả những gì vị ấy cảm thọ, tất cả những gì vị ấy hoan hỷ, sẽ trở thành thanh lương!”`, ref: "Tương Ưng Bộ 22.88", url: "https://loicuaducphat.org/sn/sn22.88.html#content" },

{ text: `“‘Māra, Māra’, bạch Thế Tôn, như vậy được gọi đến. Thế nào là Māra, bạch Thế Tôn?” “Sắc, này Rādha, là Māra. Thọ là Māra. Tưởng là Māra. Hành là Māra. Thức là Māra. Do thấy vậy, này Rādha, bậc Ða văn Thánh đệ tử nhàm chán đối với sắc, nhàm chán đối với thọ, nhàm chán đối với tưởng, nhàm chán đối với các hành, nhàm chán đối thức. Do nhàm chán, vị ấy ly tham. Do ly tham, vị ấy giải thoát. Trong sự giải thoát, trí khởi lên: Ta đã được giải thoát. Vị ấy biết rõ: ‘Sanh đã tận, Phạm hạnh đã thành, những việc nên làm đã làm, không còn trở lui trạng thái này nữa’.”`, ref: "Tương Ưng Bộ 23.11", url: "https://loicuaducphat.org/sn/sn23.11.html#content" },

{ text: `“Cái gì không phải của các Ông, này các Tỷ-kheo, hãy từ bỏ nó. Từ bỏ nó, sẽ đưa lại hạnh phúc an lạc cho các Ông. Và này các Tỷ-kheo, cái gì không phải của các Ông? Mắt, này các Tỷ-kheo, không phải của các Ông. Hãy từ bỏ nó. Từ bỏ nó, sẽ đưa lại hạnh phúc, an lạc cho các Ông. Các sắc không phải của các Ông. Hãy từ bỏ chúng. Từ bỏ chúng, sẽ đưa lại hạnh phúc, an lạc cho các Ông. Nhãn thức không phải của các Ông. Hãy từ bỏ nó. Từ bỏ nó, sẽ đưa lại hạnh phúc, an lạc cho các Ông. Nhãn xúc không phải của các Ông. Hãy từ bỏ nó. Từ bỏ nó, sẽ đưa lại hạnh phúc, an lạc cho các Ông. Ví như, này các Tỷ-kheo, trong rừng Thắng Lâm này có người mang đi, hay mang đốt, hay làm theo những gì người ấy muốn, tất cả cỏ, củi, nhánh cây hay lá, thời các Ông có nghĩ như sau: ‘Người ấy mang chúng tôi đi, hay đốt chúng tôi, hay làm gì chúng tôi theo ý người ấy muốn’?” “Thưa không, bạch Thế Tôn”. “Vì sao?” “Vì chúng không phải tự ngã hay không thuộc về tự ngã”. “Cũng vậy, này các Tỷ-kheo, mắt không phải của các Ông. Hãy từ bỏ nó. Từ bỏ nó, sẽ đưa đến hạnh phúc, an lạc cho các Ông. Các sắc không phải của các Ông ... Nhãn thức không phải của các Ông ... Nhãn xúc không phải của các Ông... Do duyên ý xúc khởi lên cảm thọ gì, lạc, khổ, hay bất khổ bất lạc; cảm thọ ấy không phải của các Ông. Hãy từ bỏ nó. Từ bỏ nó, sẽ đưa đến hạnh phúc, an lạc cho các Ông”.`, ref: "Tương Ưng Bộ 35.101", url: "https://loicuaducphat.org/sn/sn35.101.html#content" },


{ text: `Này các Tỷ-kheo, có những sắc do mắt nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu một Tỷ-kheo hoan hỷ sắc ấy, tán dương, tham luyến an trú; thời này các Tỷ-kheo, đây gọi là Tỷ-kheo đã đi đến trú xứ của Ma, đã bị Ma chinh phục. Lưới bẫy của Ma đoanh vây vị ấy. Bị Ma trói buộc, vị ấy bị Ác ma muốn làm gì vị ấy thì làm. Này các Tỷ-kheo, có những sắc do mắt nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu Tỷ-kheo không hoan hỷ sắc ấy, không tán dương, không tham luyến an trú; thời này các Tỷ-kheo, đây gọi là Tỷ-kheo không đi đến trú xứ của Ma, không bị Ma chinh phục. Lưới bẫy của Ma không đoanh vây vị ấy. Ðược giải thoát khỏi Ma trói buộc, vị ấy không bị Ác ma muốn làm gì vị ấy thì làm.`, ref: "Tương Ưng Bộ 35.114", url: "https://loicuaducphat.org/sn/sn35.114.html#content" },


{ text: `Này các Tỷ-kheo, chư Thiên và Người đời thích thú sắc, bị sắc kích thích. Khi sắc biến hoại, ly tham, đoạn diệt, này các Tỷ-kheo, chư Thiên và Người đời sống đau khổ. Này các Tỷ-kheo, chư Thiên và Người đời thích thú thanh, bị thanh kích thích. Khi sắc biến hoại, ly tham, đoạn diệt, này các Tỷ-kheo, chư Thiên và Người đời sống đau khổ. Thích thú hương ... thích thú vị ... thích thú xúc ... Này các Tỷ-kheo, chư Thiên và Người đời thích thú pháp, bị pháp kích thích. Khi pháp biến hoại, ly tham, đoạn diệt, này các Tỷ-kheo, chư Thiên và Người đời sống đau khổ.<br><br>“Sắc, thanh, hương, vị, xúc,<br>Và toàn thể các pháp,<br>Khả lạc, hỷ, khả ý,<br>Như vậy, chúng được gọi.<br><br>Chư Thiên và Người đời,<br>Xem chúng là khả lạc,<br>Chỗ nào chúng đoạn diệt,<br>Thiên, Nhân thấy đau khổ.<br><br>Bậc Thánh thấy an lạc,<br>Khi thân kiến đoạn diệt,<br>Bậc Thánh xem trái ngược,<br>Mọi quan điểm của đời.<br><br>Ðiều người gọi là lạc,<br>Bậc Thánh gọi là khổ.<br>Ðiều người gọi là khổ,<br>Thánh nhân biết là lạc.<br><br>Thấy pháp khó nhận biết,<br>Kẻ vô trí mê loạn,<br>Tối tăm đối vô minh,<br>Mù lòa đối không thấy.<br><br>Bậc trí là rộng mở,<br>Như ánh sáng thấu tỏ,<br>Kẻ ngu, dầu ở gần,<br>Không nhận hiểu Đạo Pháp.<br><br>Bị tham sanh chinh phục,<br>Cuốn trôi theo dòng hữu,<br>Bị Ác ma chi phối,<br>Không giác ngộ pháp này.<br><br>Không ai ngoài bậc thánh,<br>Giác ngộ con đường này,<br>Con đường đạt Niết-bàn,<br>Chánh trí thoát lậu hoặc”.`, ref: "Tương Ưng Bộ 35.136", url: "https://loicuaducphat.org/sn/sn35.136.html#content" },


{ text: `“Bạch Thế Tôn, lành thay, nếu Thế Tôn thuyết pháp vắn tắt cho con. Sau khi nghe pháp từ Thế Tôn, con sẽ sống một mình an tịnh, không phóng dật, nhiệt tâm, tinh cần”. “Cái gì khổ, này Koṭṭhita, ở đấy Ông cần phải đoạn trừ lòng dục. Này Koṭṭhita, cái gì là khổ? Mắt là khổ, này Koṭṭhita, ở đấy Ông cần phải đoạn trừ lòng dục. Các sắc là khổ, ở đấy Ông cần phải đoạn trừ lòng dục. Nhãn thức là khổ, ở đấy Ông cần phải đoạn trừ lòng dục. Nhãn xúc là khổ, ở đấy Ông cần phải đoạn trừ lòng dục. Phàm duyên nhãn xúc khởi lên cảm thọ gì, lạc, khổ, hay bất khổ bất lạc; cảm thọ ấy là khổ, ở đấy Ông cần phải đoạn trừ lòng dục.`, ref: "Tương Ưng Bộ 35.163", url: "https://loicuaducphat.org/sn/sn35.163.html#content" },


{ text: `“Nếu sắc không có vị ngọt, này các Tỷ-kheo, chúng sanh có thể không tham luyến sắc. Và vì rằng, này các Tỷ-kheo, sắc có vị ngọt nên chúng sanh tham luyến sắc. Nếu sắc không có nguy hiểm, này các Tỷ-kheo, thời chúng sanh có thể không nhàm chán đối với sắc. Và vì rằng sắc có nguy hiểm nên chúng sanh nhàm chán đối với sắc. Nếu sắc không có xuất ly, này các Tỷ-kheo, thời chúng sanh không có thể xuất ly khỏi sắc. Và vì rằng sắc có xuất ly nên chúng sanh có xuất ly khỏi sắc. Cho đến khi nào, này các Tỷ-kheo, chúng sanh đối với sáu nội xứ này không như thật liễu tri vị ngọt là vị ngọt, nguy hiểm là nguy hiểm, xuất ly là xuất ly; cho đến khi ấy, này các Tỷ-kheo, các chúng sanh ấy cùng với các thế giới như Thiên giới, Ma giới, Phạm thiên giới, cùng với quần chúng Sa-môn, Bà-la-môn, chư Thiên và loài Người, đã không sống với tâm được ly chấp trước, ly hệ phược, được giải thoát, không bị giới hạn. Và vì rằng, này các Tỷ-kheo, chúng sanh đối với sáu nội xứ này đã như thật liễu tri vị ngọt là vị ngọt, nguy hiểm là nguy hiểm, xuất ly là xuất ly; cho nên, này các Tỷ-kheo, các chúng sanh cùng với các thế giới như Thiên giới, Ma giới, Phạm thiên giới, cùng với quần chúng Sa-môn, Bà-la-môn, chư Thiên và loài Người, đã sống với tâm được ly chấp trước, ly hệ phược, được giải thoát, không bị giới hạn”.`, ref: "Tương Ưng Bộ 35.18", url: "https://loicuaducphat.org/sn/sn35.18.html#content" },

{ text: `“Ai ưa thích mắt, này các Tỷ-kheo, người ấy ưa thích khổ. Ai ưa thích khổ, Ta nói người ấy không thoát khỏi khổ. Ai ưa thích tai... mũi... Ai ưa thích lưỡi, này các Tỷ-kheo, người ấy ưa thích khổ. Ai ưa thích khổ, Ta nói người ấy không thoát khỏi khổ. Ai ưa thích thân... Ai ưa thích ý, người ấy ưa thích khổ. Ai ưa thích khổ, Ta nói người ấy không thoát khỏi khổ”. “Và ai không ưa thích mắt, này các Tỷ-kheo, người ấy không ưa thích khổ. Ai không ưa thích khổ, Ta nói người ấy thoát khỏi khổ. Ai không ưa thích tai ... mũi ... Ai không ưa thích lưỡi, người ấy không ưa thích khổ. Ai không ưa thích khổ, Ta nói người ấy thoát khỏi khổ. Ai không ưa thích thân ... Ai không ưa thích ý, người ấy không ưa thích khổ. Ai không ưa thích khổ, Ta nói người ấy thoát khỏi khổ”.`, ref: "Tương Ưng Bộ 35.19", url: "https://loicuaducphat.org/sn/sn35.19.html#content" },


{ text: `“‘Biển, biển’, này các Tỷ-kheo, kẻ vô văn phàm phu nói như vậy. Cái ấy, này các Tỷ-kheo, không phải là biển trong giới luật của bậc Thánh. Cái ấy (của kẻ phàm phu) là một khối nước lớn, một dòng nước lớn. Này các Tỷ-kheo, có những sắc do mắt nhận thức khả lạc, khả hỷ, khá ý, khả ái, liên hệ đến dục, hấp dẫn. Này các Tỷ-kheo, đây không gọi là biển trong giới luật của bậc Thánh. Ở đây, thế giới này với Thiên giới, với Ma giới, với Phạm thiên giới, với quần chúng Sa-môn, Bà-la-môn, với chư Thiên và loài Người, phần lớn chìm đắm trong ấy, bị rối ren như cuộn chỉ, bị bao trùm như cuộn dây, thành như sợi dây bện bằng cỏ, không thể vượt qua cõi dữ, ác thú, đọa xứ, luân hồi!<br><br>Vô minh, tham, sân diệt,<br>Biển này nhiều thú dữ,<br>Cùng các loại la-sát,<br>Nước xoáy, sóng hiểm nguy,<br>Vượt qua thật là khó.<br><br>Vượt trói buộc, thoát chết,<br>Không còn có sanh y,<br>Ðoạn tận mọi khổ đau,<br>Không còn phải tái sanh.<br>Sanh tử được đoạn diệt,<br>Bậc không thể so sánh,<br>Ta nói, vị như vậy,<br>Ðã hóa mù Thần chết.`, ref: "Tương Ưng Bộ 35.229", url: "https://loicuaducphat.org/sn/sn35.229.html#content" },


{ text: `“Ví như, này các Tỷ-kheo, một người câu cá trong hồ nước sâu, quăng xuống một lưỡi câu có mắc mồi. Một con cá, với mắt nhìn vào mồi, nuốt lưỡi câu ấy. Như vậy, này các Tỷ-kheo, con cá ấy vì nuốt lưỡi câu, đi đến bất hạnh, đi đến ách nạn, bị người câu cá muốn làm gì thì làm. Cũng vậy, này các Tỷ-kheo, có sáu lưỡi câu này ở trong đời, đưa đến bất hạnh cho các loài hữu tình, đưa đến tai hại cho các loài chúng sanh. Thế nào là sáu? Này các Tỷ-kheo, có những sắc do mắt nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu Tỷ-kheo hoan hỷ sắc ấy, tán dương, tham luyến an trú. Thời này các Tỷ-kheo, Tỷ-kheo ấy được gọi là đã nuốt lưỡi câu của Ác ma, đã đi đến bất hạnh, đã đi đến ách nạn, đã bị Ác ma muốn làm gì thì làm ... Có những tiếng do tai nhận thức ... Có những hương do mũi nhận thức ... Này các Tỷ-kheo, có những vị do lưỡi nhận thức ... Có những xúc do thân nhận thức ... Này các Tỷ-kheo, có những pháp do ý nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu Tỷ-kheo hoan hỷ pháp ấy, tán dương, tham luyến an trú. Thời này các Tỷ-kheo, Tỷ-kheo ấy được gọi là đã nuốt lưỡi câu của Ác ma, đã đi đến bất hạnh, đã đi đến ách nạn, đã bị Ác ma muốn làm gì thì làm.`, ref: "Tương Ưng Bộ 35.230", url: "https://loicuaducphat.org/sn/sn35.230.html#content" },


{ text: `Này các Tỷ-kheo, có những sắc do mắt nhận thức khả lạc, khả hỷ, khả ái, liên hệ đến dục, hấp dẫn. Nếu Tỷ-kheo không hoan hỷ các sắc ấy, không tán dương, không tham luyến an trú. Thời này các Tỷ-kheo, Tỷ-kheo ấy được gọi là không nuốt lưỡi câu của Ác ma, đã bẻ gãy lưỡi câu, đã bẻ nát lưỡi câu, không đi đến bất hạnh, không đi đến ách nạn, không bị Ác ma muốn làm gì thì làm. Này các Tỷ-kheo, có những tiếng do tai nhận thức ... Có những hương do mũi nhận thức ... Có những vị do lưỡi nhận thức ... Có những xúc do thân nhận thức ... Này các Tỷ-kheo, có những pháp do ý nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu Tỷ-kheo không hoan hỷ pháp ấy, không tán dương, không tham luyến an trú. Thời này các Tỷ-kheo, Tỷ-kheo ấy được gọi là vị không nuốt lưỡi câu của Ác ma, đã bẻ gãy lưỡi câu, đã bẻ nát lưỡi câu, không đi đến bất hạnh, không đi đến ách nạn, không bị Ác ma muốn làm gì thì làm”.`, ref: "Tương Ưng Bộ 35.230", url: "https://loicuaducphat.org/sn/sn35.230.html#content" },

{ text: `“Ái nhiễm, này các Tỷ-kheo, là bệnh tật; ái nhiễm là mụt nhọt; ái nhiễm là mũi tên. Do vậy, này các Tỷ-kheo, Như Lai sống không ái nhiễm, không bị mũi tên làm bị thương. Do vậy, này các Tỷ-kheo, nếu Tỷ-kheo có ước vọng gì, hãy ước ‘sống không ái nhiễm, không bị mũi tên làm bị thương’. Chớ có nghĩ đến mắt, chớ có nghĩ đến trong mắt, chớ có nghĩ đến từ mắt, chớ có nghĩ đến: “Mắt là của tôi”. Chớ có nghĩ đến các sắc, chớ có nghĩ đến trong các sắc, chớ có nghĩ đến từ các sắc, chớ có nghĩ đến: “Các sắc là của tôi”. Chớ có nghĩ đến nhãn thức, chớ có nghĩ đến trong nhãn thức, chớ có nghĩ đến từ nhãn thức, chớ có nghĩ đến: “Nhãn thức là của tôi”. Chớ có nghĩ đến nhãn xúc, chớ có nghĩ đến trong nhãn xúc, chớ có nghĩ đến từ nhãn xúc, chớ có nghĩ đến: “Nhãn xúc là của tôi”. Do duyên nhãn xúc khởi lên cảm thọ gì, lạc, khổ hay bất khổ bất lạc; chớ có nghĩ đến cảm thọ ấy, chớ có nghĩ đến trong cảm thọ ấy, chớ có nghĩ đến từ cảm thọ ấy, chớ có nghĩ đến: “Cảm thọ ấy là tôi”. Vị ấy do không nghĩ đến nên không chấp thủ một vật gì ở đời. Do không chấp thủ, vị ấy không có dao động. Do không dao động, vị ấy tự mình tịch tịnh một cách hoàn toàn. Vị ấy biết rõ: ‘Sanh đã tận, Phạm hạnh đã thành, những việc nên làm đã làm, không còn trở lui trạng thái này nữa’.”`, ref: "Tương Ưng Bộ 35.90", url: "https://loicuaducphat.org/sn/sn35.90.html#content" },

{ text: `Và thế nào, này các Tỷ-kheo, là không nhiếp hộ? Và này các Tỷ-kheo, có những sắc do mắt nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu một Tỷ-kheo hoan hỷ sắc ấy, tán dương và an trú với tâm tham luyến; thời này các Tỷ-kheo, Tỷ-kheo ấy cần phải hiểu rằng: ‘Ta đã làm thối thất các thiện pháp’. Như Lai gọi đây là pháp thối đọa... Và này các Tỷ-kheo, có những tiếng do tai nhận thức ... Có những hương do mũi nhận thức... Và này các Tỷ-kheo, có những vị do lưỡi nhận thức ... Và này các Tỷ-kheo, có những pháp do ý nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu một Tỷ-kheo hoan hỷ sắc ấy, tán dương và an trú với tâm tham luyến; thời này các Tỷ-kheo, Tỷ-kheo ấy cần phải hiểu rằng: ‘Ta đã làm thối thất các thiện pháp. Và Như Lai gọi đây là thối thất’. Như vậy, này các Tỷ-kheo, là không nhiếp hộ.`, ref: "Tương Ưng Bộ 35.98", url: "https://loicuaducphat.org/sn/sn35.98.html#content" },


{ text: `“Này các Tỷ-kheo, nếu các du sĩ ngoại đạo hỏi các Ông như sau: ‘Vì mục đích gì, này chư Hiền, Phạm hạnh được sống dưới Sa-môn Gotama?’ Ðược hỏi vậy, này các Tỷ-kheo, các Ông cần phải trả lời các du sĩ ngoại đạo ấy như sau: ‘Do mục đích đoạn tận tham, này chư Hiền, Phạm hạnh được sống dưới Sa-môn Gotama’. Này các Tỷ-kheo, nhưng nếu các du sĩ ngoại đạo hỏi các Ông như sau: ‘Có con đường nào, có đạo lộ nào, này chư Hiền, đưa đến đoạn tận tham?’ Ðược hỏi như vậy, này các Tỷ-kheo, các Ông phải trả lời cho các du sĩ ngoại đạo ấy như sau: ‘Có con đường, có đạo lộ đưa đến đoạn tận tham’. Và này các Tỷ-kheo, thế nào là con đường, thế nào là đạo lộ đưa đến đoạn tận tham? Chính là Thánh đạo Tám ngành này, tức là chánh tri kiến ... chánh định. Này các Tỷ-kheo, đây là con đường, đây là đạo lộ đưa đến đoạn tận tham. Ðược hỏi vậy, này các Tỷ-kheo, các Ông cần phải trả lời như vậy cho các du sĩ ngoại đạo ấy”.`, ref: "Tương Ưng Bộ 45.41", url: "https://loicuaducphat.org/sn/sn45.41.html#content" },


{ text: `Có hai cực đoan này, này các Tỷ-kheo, một người xuất gia không nên thực hành theo. Thế nào là hai? Một là đắm say trong các dục, hạ liệt, đê tiện, phàm phu, không xứng bậc Thánh, không liên hệ đến mục đích. Hai là tự hành khổ mình, khổ đau, không xứng bậc Thánh, không liên hệ đến mục đích. Tránh xa hai cực đoan này, này các Tỷ-kheo, là con đường Trung đạo, do Như Lai chánh giác, tác thành mắt, tác thành trí, đưa đến an tịnh, thắng trí, giác ngộ, Niết-bàn. Và thế nào là con đường Trung đạo, này các Tỷ-kheo, do Như Lai chánh giác, tác thành mắt, tác thành trí, đưa đến an tịnh, thắng trí, giác ngộ, Niết-bàn? Chính là con đường Thánh đạo Tám ngành, tức là: chánh tri kiến, chánh tư duy, chánh ngữ, chánh nghiệp, chánh mạng, chánh tinh tấn, chánh niệm, chánh định. Ðây là con đường trung đạo, này các Tỷ-kheo, do Như Lai chánh giác, tác thành mắt, tác thành trí, đưa đến an tịnh, thắng trí, giác ngộ, Niết-bàn. Ðây là Thánh đế về Khổ, này các Tỷ-kheo. Sanh là khổ, già là khổ, bệnh là khổ, chết là khổ, sầu, bi, khổ, ưu, não là khổ, oán gặp nhau là khổ, ái biệt ly là khổ, cầu không được là khổ. Tóm lại, năm thủ uẩn là khổ. Ðây là Thánh đế về Khổ tập, này các Tỷ-kheo. Chính là ái này đưa đến tái sanh, câu hữu với hỷ và tham, tìm cầu hỷ lạc chỗ này chỗ kia. Tức là dục ái, hữu ái, phi hữu ái. Ðây là Thánh đế về Khổ diệt, này các Tỷ-kheo. Chính là ly tham, đoạn diệt, không có dư tàn khát ái ấy, sự quăng bỏ, từ bỏ, giải thoát, không có chấp trước. Ðây là Thánh đế về Con Ðường đưa đến Khổ diệt, này các Tỷ-kheo. Chính là con đường Thánh đạo Tám ngành, tức là: chánh tri kiến, chánh tư duy, chánh ngữ, chánh nghiệp, chánh mạng, chánh tinh tấn, chánh niệm, chánh định.`, ref: "Tương Ưng Bộ 56.11", url: "https://loicuaducphat.org/sn/sn56.11.html#content" },

  { text: `Ta không thấy một sắc nào khác, này các Tỷ-kheo, xâm chiếm và ngự trị tâm người đàn ông như sắc người đàn bà. Này các Tỷ-kheo, sắc người đàn bà xâm chiếm và ngự trị tâm người đàn ông.`, ref: "Tăng Chi Bộ 1.1", url: "https://loicuaducphat.org/an/an1.1.html#content" },

{ text: `Ta không thấy một sắc nào khác, này các Tỷ-kheo, xâm chiếm và ngự trị tâm người đàn bà như sắc người đàn ông. Này các Tỷ-kheo, sắc người đàn ông xâm chiếm và ngự trị tâm người đàn bà.`, ref: "Tăng Chi Bộ 1.6", url: "https://loicuaducphat.org/an/an1.6.html#content" },

{ text: `Ta không thấy một tiếng nào khác, này các Tỷ-kheo, xâm chiếm và ngự trị tâm người đàn ông, như tiếng người đàn bà. Này các Tỷ-kheo, tiếng người đàn bà xâm chiếm và ngự trị tâm người đàn ông.`, ref: "Tăng Chi Bộ 1.2", url: "https://loicuaducphat.org/an/an1.2.html#content" },

{ text: `Ta không thấy một pháp nào khác, này các Tỷ-kheo, dẫn đến dục tham chưa sanh được sanh khởi, hay dục tham đã sanh được tăng trưởng quảng đại, này các Tỷ-kheo, như tịnh tướng. Tịnh tướng, này các Tỷ-kheo, nếu không như lý tác ý, đưa đến dục tham chưa sanh được sanh khởi, hay dục tham đã sanh được tăng trưởng quảng đại.`, ref: "Tăng Chi Bộ 1.11", url: "https://loicuaducphat.org/an/an1.11.html#content" },

{ text: `Ta không thấy một pháp nào khác, này các Tỷ-kheo, đưa đến dục tham chưa sanh không sanh khởi, hay dục tham đã sanh được đoạn tận, này các Tỷ-kheo, như bất tịnh tướng. Bất tịnh tướng, này các Tỷ-kheo, nếu như lý tác ý, thời dục tham chưa sanh không sanh khởi, hay dục tham đã sanh được đoạn tận.`, ref: "Tăng Chi Bộ 1.16", url: "https://loicuaducphat.org/an/an1.16.html#content" },


{ text: `Phàm những pháp nào, này các Tỷ-kheo, là bất thiện, thuộc thành phần bất thiện, đứng về phía bất thiện, tất cả các pháp ấy đều được ý đi trước. Ý khởi trước các pháp ấy. Các pháp bất thiện theo sau.`, ref: "Tăng Chi Bộ 1.56", url: "https://loicuaducphat.org/an/an1.56.html#content" },

{ text: `Ta không thấy một pháp nào khác, này các Tỷ-kheo, do pháp ấy, các pháp bất thiện chưa sanh được sanh khởi, và các pháp thiện đã sanh bị đoạn tận, này các Tỷ-kheo, như phóng dật. Với người phóng dật, này các Tỷ-kheo, các pháp bất thiện chưa sanh được sanh khởi, và các pháp thiện đã sanh bị đoạn tận.`, ref: "Tăng Chi Bộ 1.58", url: "https://loicuaducphat.org/an/an1.58.html#content" },


{ text: `Ta không thấy một pháp nào khác, này các Tỷ-kheo, do pháp ấy, các pháp thiện chưa sanh được sanh khởi, và các pháp bất thiện đã sanh được đoạn tận, này các Tỷ-kheo, như ít dục. Với người có ít dục, này các Tỷ-kheo, các pháp thiện chưa sanh được sanh khởi, và các pháp bất thiện đã sanh được đoạn tận.`, ref: "Tăng Chi Bộ 1.63", url: "https://loicuaducphat.org/an/an1.63.html#content" },

{ text: `Ta không thấy một pháp nào khác, này các Tỷ-kheo, do pháp ấy, các pháp bất thiện chưa sanh được sanh khởi, và các pháp thiện đã sanh bị đoạn tận, này các Tỷ-kheo, như là dục lớn. Với người có dục lớn, này các Tỷ-kheo, các pháp bất thiện chưa sanh được sanh khởi, và các pháp thiện đã sanh bị đoạn tận.`, ref: "Tăng Chi Bộ 1.62", url: "https://loicuaducphat.org/an/an1.62.html#content" },

{ text: `“Này các Tỷ-kheo, các pháp ác, bất thiện khởi lên có tướng, không phải không có tướng. Do đoạn tận chính tướng ấy, như vậy các pháp ác, bất thiện ấy, không có mặt.” Này các Tỷ-kheo, các pháp ác, bất thiện khởi lên có nhân duyên, không phải không có nhân duyên. Do đoạn tận chính nhân duyên ấy, như vậy các pháp ác, bất thiện ấy, không có mặt. Này các Tỷ-kheo, các pháp ác, bất thiện khởi lên có sắc, không phải không có sắc. Do đoạn tận chính duyên ấy, các pháp ác, bất thiện ấy, không có mặt. Này các Tỷ-kheo, các pháp ác, bất thiện khởi lên có thọ, không phải không có thọ. Do đoạn tận chính duyên ấy, các pháp ác, bất thiện ấy, không có mặt. Này các Tỷ-kheo, các pháp ác, bất thiện khởi lên có tưởng, không phải không có tưởng. Do đoạn tận chính duyên ấy, các pháp ác, bất thiện ấy, không có mặt. Này các Tỷ-kheo, các pháp ác, bất thiện khởi lên có thức, không phải không có thức. Do đoạn tận chính duyên ấy, các pháp ác, bất thiện ấy, không có mặt.`, ref: "Tăng Chi Bộ 2.77", url: "https://loicuaducphat.org/an/an2.77.html#content" },

{ text: `Thật vậy, này các Bà-la-môn, thế giới này đã bị già, bệnh, chết dắt dẫn. Thế giới đã bị già, bệnh, chết dắt dẫn như vậy, này các Bà-la-môn, thời chế ngự thân, chế ngự lời nói, chế ngự ý trong đời này, đối với kẻ đã đi đến cõi chết, phải là chỗ nương tựa, là hang trú ẩn, là hòn cù lao (hay ngọn đèn), là chỗ quy y và là đích xứ nó đến.<br><br>Trong ngôi nhà bị cháy,<br>Ðồ đạc được đem ra,<br>Ðồ ấy lợi cho họ,<br>Không phải đồ bị cháy,<br>Cũng vậy đời bị cháy,<br>Do già chết thiêu đốt,<br>Nhờ bố thí tự cứu,<br>Khéo cứu, đồ bố thí.<br>Ở đây, chế ngự thân,—<br>Chế ngự lời và ý,—<br>Kẻ ấy dầu có chết,<br>Cũng được hưởng an lạc,<br>Vì khi còn đang sống,<br>Ðã làm các công đức.”`, ref: "Tăng Chi Bộ 3.52", url: "https://loicuaducphat.org/an/an3.52.html#content" },


{ text: `Cho đến như thế nào, thưa Tôn giả Gotama, pháp là thiết thực hiện tại, không có thời gian, đến để mà thấy, có khả năng hướng thượng, được người trí tự mình giác hiểu?” “Bị tham ái làm say đắm, này Bà-la-môn, bị chinh phục, tâm bị xâm chiếm, nên suy nghĩ điều hại mình, suy nghĩ điều hại người, suy nghĩ điều hại cả hai, cảm thọ tâm khổ tâm ưu. Tham ái được đoạn trừ, thời không nghĩ đến tự hại, không nghĩ đến hại người, không nghĩ đến hại cả hai, không cảm thọ tâm khổ tâm ưu. Bị tham ái làm say đắm, này Bà-la-môn, bị chinh phục, tâm bị xâm chiếm, vị ấy làm ác hạnh về thân, làm ác hạnh về lời nói, làm ác hạnh về ý. Tham ái được đoạn trừ, vị ấy không làm ác hạnh về thân, không làm ác hạnh về lời nói, không làm ác hạnh về ý. Bị tham ái làm say đắm, này Bà-la-môn, bị chinh phục, tâm bị xâm chiếm, vị ấy không như thật rõ biết lợi ích của mình, không như thật rõ biết lợi ích của người, không như thật rõ biết lợi ích của cả hai. Tham ái được đoạn trừ, vị ấy như thật rõ biết lợi ích của mình, như thật rõ biết lợi ích của người, như thật rõ biết lợi ích của cả hai Như vậy, này Bà-la-môn, pháp là thiết thực hiện tại, không có thời gian, đến để mà thấy, có khả năng hướng thượng, được người trí tự mình giác hiểu.`, ref: "Tăng Chi Bộ 3.54", url: "https://loicuaducphat.org/an/an3.54.html#content" },

{ text: `Do nhân gì, này chư Hiền, do duyên gì tham chưa sanh được sanh khởi, và tham sanh rồi đưa đến tăng trưởng, quảng đại?’ Cần phải trả lời là “Tịnh tướng”. Với ai không như lý tác ý tịnh tướng, thời tham chưa sanh được sanh khởi, và tham đã sanh được tăng trưởng quảng đại. Ðây là nhân, này các Hiền giả, đây là duyên, tham chưa sanh được sanh khởi, và tham đã sanh được tăng trưởng quảng đại.`, ref: "Tăng Chi Bộ 3.68", url: "https://loicuaducphat.org/an/an3.68.html#content" },


{ text: `Do nhân gì, này các chư Hiền, do duyên gì tham chưa sanh không sanh khởi, hay tham đã sanh được đoạn tận?’ Cần phải trả lời là “Tướng bất tịnh”. Với ai như lý tác ý tướng bất tịnh, thời tham chưa sanh không sanh khởi, hay tham đã sanh được đoạn tận. Ðây là nhân, này các Hiền giả, đây là duyên khiến tham chưa sanh không sanh khởi, hay tham đã sanh được đoạn tận.`, ref: "Tăng Chi Bộ 3.68", url: "https://loicuaducphat.org/an/an3.68.html#content" },

{ text: `Rồi Tôn giả Ānanda đi đến Tỷ-kheo-ni ấy, sau khi đến, ngồi trên chỗ đã soạn sẵn. Sau khi ngồi, Tôn giả Ānanda nói với Tỷ-kheo-ni ấy: “Này chị, thân này do đồ ăn được tác thành, y cứ vào đồ ăn. Đồ ăn cần phải đoạn tận. Này chị, thân này do ái được tác thành, y cứ vào ái. Ái cần phải đoạn tận. Này chị, thân này do kiêu mạn được tác thành, y cứ vào kiêu mạn. Kiêu mạn cần phải đoạn tận. Này chị, thân này do dâm dục được tác thành, y cứ vào dâm dục. Dâm dục, sự phá đổ cây cầu được Thế Tôn nói đến. ‘Này chị, thân này do đồ ăn được tác thành, y cứ vào đồ ăn. Đồ ăn cần phải đoạn tận’. Như vậy, được nói đến. Chính do duyên gì được nói đến?`, ref: "Tăng Chi Bộ 4.159", url: "https://loicuaducphat.org/an/an4.159.html#content" },


{ text: `Này các Tỷ-kheo, ai sống thấy vị ngọt trong các pháp có thể khởi lên kiết sử, này các Tỷ-kheo, tham không đoạn tận, sân không đoạn tận, si không đoạn tận. Do tham không đoạn tận, sân không đoạn tận, si không đoạn tận, nên không giải thoát khỏi sanh, già, chết, sầu, bi, khổ, ưu, não. Ta nói rằng người ấy không giải thoát khỏi khổ đau.`, ref: "Tăng Chi Bộ 2.6", url: "https://loicuaducphat.org/an/an2.6.html#content" },

{ text: `Này các Tỷ-kheo, ai sống thấy nhàm chán trong các pháp có thể khởi lên kiết sử, này các Tỷ-kheo, tham được đoạn tận, sân được đoạn tận, si được đoạn tận. Do tham được đoạn tận, sân được đoạn tận, si được đoạn tận, nên được giải thoát khỏi sanh, già, chết, sầu, bi, khổ, ưu, não. Ta nói rằng người ấy giải thoát khỏi khổ đau.`, ref: "Tăng Chi Bộ 2.6", url: "https://loicuaducphat.org/an/an2.6.html#content" },

{ text: `Vị trưởng lão, này Bà-la-môn, 80 tuổi hay 90 tuổi, hay 100 tuổi đời, nếu vị ấy thọ hưởng các dục vọng, sống giữa các dục vọng, bị đốt cháy bởi lửa nhiệt não của dục vọng, bị nhai nghiến bởi các tầm tư dục vọng, cố gắng tìm cầu các dục vọng; người như vậy được gọi là kẻ ngu, không phải là bậc trưởng lão. Dầu cho này Bà-la-môn, một người còn trẻ, một thanh niên trẻ trung với tóc đen nhánh, đầy đủ tuổi trẻ hiền thiện trong thời sơ khởi của tuổi đời, mà người ấy không hưởng thọ các dục vọng, không sống giữa các dục vọng, không bị đốt cháy bởi lửa nhiệt não của dục vọng, không bị nhai nghiến bởi các tầm tư dục vọng, không có cố gắng tìm cầu các dục vọng; người như vậy được gọi là bậc có trí, bậc trưởng lão.`, ref: "Tăng Chi Bộ 2.38", url: "https://loicuaducphat.org/an/an2.38.html#content" },

{ text: `Có hai loại lạc này, này các Tỷ-kheo. Thế nào là hai? Dục lạc và viễn ly lạc. Những pháp này, này các Tỷ-kheo, là hai lạc. Tối thắng trong hai lạc này, này các Tỷ-kheo, tức là viễn ly lạc.`, ref: "Tăng Chi Bộ 2.65", url: "https://loicuaducphat.org/an/an2.65.html#content" },


{ text: `- Hoàng Tử nghĩ thế nào, này Hoàng tử, với người gia chủ hay người con của người gia chủ ấy, khởi lên những nhiệt não về thân hay về tâm, do tham ái sanh. Bị nung đốt bởi những nhiệt não do tham ái sanh, người ấy có cảm thấy đau khổ không?<br>- Thưa có, bạch Thế Tôn.<br>- Người gia chủ hay con của người gia chủ ấy, này Hoàng Tử, bị nung đốt bởi những nhiệt não do tham ái sanh, cảm thấy đau khổ. Tham ái ấy, Như Lai đã đoạn tận, cắt đứt từ gốc rễ, làm cho như thân cây tala, làm cho không thể hiện hữu, làm cho không thể sanh khởi trong tương lai. Do vậy ta cảm thấy an lạc.`, ref: "Tăng Chi Bộ 3.35", url: "https://loicuaducphat.org/an/an3.35.html#content" },


{ text: `Thật vậy, này các Bà-la-môn, thế giới này đã bị già, bệnh, chết dắt dẫn. Thế giới đã bị già, bệnh, chết dắt dẫn như vậy, này các Bà-la-môn, thời chế ngự thân, chế ngự lời nói, chế ngự ý trong đời này, đối với kẻ đã đi đến cõi chết, phải là chỗ nương tựa, là hang trú ẩn, là hòn cù lao (hay ngọn đèn), là chỗ quy y và là đích xứ đi đến.`, ref: "Tăng Chi Bộ 3.51", url: "https://loicuaducphat.org/an/an3.51.html#content" },

{ text: `Ðời sống bị dắt dẫn<br>Mạng sống chẳng là bao<br>Bị già kéo dẫn đi<br>Không có nơi nương tựa<br>Hãy luôn luôn quán tưởng<br>Sợ hãi tử vong này<br>Hãy làm các công đức<br>Ðưa đến chơn an lạc.<br>Ở đây chế ngự thân,<br>Chế ngự lời và ý,<br>Kẻ ấy dầu có chết,<br>Cũng được hưởng an lạc,<br>Vì khi còn đang sống<br>Ðã làm các công đức.`, ref: "Tăng Chi Bộ 3.51", url: "https://loicuaducphat.org/an/an3.51.html#content" },


{ text: `Bị tham ái làm say đắm, này Bà-la-môn, bị chinh phục, tâm bị xâm chiếm, nên suy nghĩ điều hại mình, suy nghĩ điều hại người, suy nghĩ điều hại cả hai, cảm thọ tâm khổ tâm ưu. Tham ái được đoạn trừ, thời không nghĩ đến tự hại, không nghĩ đến hại người, không nghĩ đến hại cả hai, không cảm thọ tâm khổ tâm ưu. Như vậy, này Bà-la-môn, pháp là thiết thực hiện tại, không có thời gian, đến để mà thấy, có khả năng hướng thượng, được người trí tự mình giác hiểu.`, ref: "Tăng Chi Bộ 3.53", url: "https://loicuaducphat.org/an/an3.53.html#content" },

{ text: `Vị ấy rõ biết như sau: “Trước ta có tham, tham ấy là bất thiện. Nay ta không có nữa. Như vầy là thiện. Trước ta có sân, sân ấy là bất thiện. Nay ta không có nữa. Như vầy là thiện. Trước ta có si, si ấy là bất thiện. Nay ta không có nữa. Như vậy là thiện”. Như vậy, ngay trong đời sống hiện tại, vị ấy được giải thoát khỏi hy cầu, được tịch tịnh, được thanh lương, cảm thấy an lạc, tự mình an trú trong Phạm thể.`, ref: "Tăng Chi Bộ 3.66", url: "https://loicuaducphat.org/an/an3.66.html#content" },



{ text: `Cái gì là tham, này các Tỷ-kheo, cái ấy bất thiện. Ai với lòng tham có làm gì về thân, về lời, về ý, cái ấy bất thiện. Với ai có lòng tham, bị lòng tham chinh phục, tâm không được tự chủ, vu cáo làm người khác đau khổ, bằng cách sát hại, trói buộc, tịch thu tài sản, mắng nhiếc hay tẩn xuất, dựa trên: “Ta là sức mạnh, ta có sức mạnh.” Cái ấy là bất thiện. Như vậy, rất nhiều ác bất thiện pháp này sanh từ tham, duyên khởi từ tham, tập khởi từ tham, khởi lên nơi người ấy.`, ref: "Tăng Chi Bộ 3.69", url: "https://loicuaducphat.org/an/an3.69.html#content" },


{ text: `Này các Tỷ-kheo, nếu không có vị ngọt ở đời, thời các loài hữu tình không có tham nhiễm đối với đời. Vì rằng, này các Tỷ-kheo, có vị ngọt ở đời, nên các loài hữu tình có tham nhiễm ở đời. Này các Tỷ-kheo, nếu không có nguy hại ở đời, thời các loài hữu tình không có nhàm chán đối với đời. Vì rằng, này các Tỷ-kheo, có nguy hại ở đời, nên các loài hữu tình có nhàm chán đối với đời. Này các Tỷ-kheo, nếu không có xuất ly ra khỏi đời, thời các loài hữu tình không có xuất ly đối với đời. Vì rằng, này các Tỷ-kheo, có xuất ly đối với đời, nên các loài hữu tình có xuất ly ra khỏi đời.`, ref: "Tăng Chi Bộ 3.105", url: "https://loicuaducphat.org/an/an3.105.html#content" },


{ text: `Này gia chủ, ví như ngôi nhà nóc nhọn vụng lợp, thời nóc nhọn không được phòng hộ, rui kèo không được phòng hộ, vách tường không được phòng hộ; nóc nhọn bị đầy ứ, rỉ nước, các rui kèo bị đầy ứ rỉ nước, các vách tường bị đầy ứ, rỉ nước, nóc nhọn bị hủ bại, rui kèo bị hủ bại, vách tường bị hủ bại. Cũng vậy, này gia chủ, khi tâm không được phòng hộ, thời thân nghiệp cũng không được phòng hộ, khẩu nghiệp ... ý nghiệp ...  thời thân nghiệp đầy ứ tham dục và rỉ chảy; khẩu nghiệp đầy ứ tham dục và rỉ chảy; ý nghiệp đầy ứ tham dục và rỉ chảy; Với ai thân nghiệp đầy ứ tham dục và rỉ chảy, khẩu nghiệp đầy ứ tham dục và rỉ chảy, ý nghiệp đầy ứ tham dục và rỉ chảy, thời thân nghiệp bị hủ bại, khẩu nghiệp ... ý nghiệp bị hủ bại. Với ai thân nghiệp bị hủ bại, khẩu nghiệp ... ý nghiệp bị hủ bại, thời sự chết không được hiền thiện, mạng chung không được hiền thiện.`, ref: "Tăng Chi Bộ 3.109", url: "https://loicuaducphat.org/an/an3.109.html#content" },


{ text: `Tai mắt không giữ gìn<br>Các căn không phòng hộ<br>Ruồi lằng sẽ bu đậu<br>Các tư duy tham ái<br>Tỷ-kheo làm thối nát<br>Ðầy ứ những mùi hôi<br>Xa thay là Niết-bàn!<br>Chịu phần về bất hạnh<br>Tại làng hay trong rừng<br>Tự ngã không an tịnh<br>Kẻ ngu và không trí<br>Ði đứng đầy ruồi lằng<br>Ai đầy đủ giới luật<br>Thích tịch tịnh trí tuệ<br>Sống an tịnh hạnh phúc<br>Mọi ruồi lằng diệt trừ`, ref: "Tăng Chi Bộ 3.128", url: "https://loicuaducphat.org/an/an3.128.html#content" },

{ text: `Những ai sống ở đời<br>Không chế ngự các dục<br>Không từ bỏ ly tham<br>Thọ hưởng các dục vọng<br>Họ đi đến sanh già<br>Ðến rồi lại đến nữa<br>Bị khát ái trói buộc<br>Họ đi thuận dòng đời<br>Do vậy bậc có trí<br>Ở đời, trú chánh niệm<br>Không thọ hưởng các dục<br>Không hành trì điều ác<br>Dầu chịu sự khổ đau<br>Từ bỏ các dục vọng<br>Họ được gọi hạng người<br>Ði ngược lại dòng đời.`, ref: "Tăng Chi Bộ 4.5", url: "https://loicuaducphat.org/an/an4.5.html#content" },


{ text: `Người có ái làm bạn<br>Sẽ luân chuyển dài dài<br>Khi hiện hữu chỗ này<br>Khi hiện hữu chỗ khác<br>Người ấy không dừng được<br>Sự luận chuyển tái sanh<br>Rõ biết nguy hại này<br>Chính ái sanh đau khổ<br>Tỷ-kheo từ bỏ ái<br>Không nắm giữ chấp thủ<br>An trú, không thất niệm<br>Vị ấy sống xuất gia.`, ref: "Tăng Chi Bộ 4.9", url: "https://loicuaducphat.org/an/an4.9.html#content" },


{ text: `Ở đây, này các Tỷ-kheo, có hạng người như thật quán tri sự tập khởi, sự chấm dứt, vị ngọt, sự nguy hại, sự xuất ly của các dục. Do như thật quán tri sự tập khởi, sự chấm dứt, vị ngọt, sự nguy hại, sự xuất ly của các dục, nên dục tham, dục hỷ, dục luyến, dục đam mê, dục khát, dục não, dục chấp thủ, dục ái trong các dục không xâm chiếm và tồn tại. Này các Tỷ-kheo, đây gọi là ly dục ách.`, ref: "Tăng Chi Bộ 4.10", url: "https://loicuaducphat.org/an/an4.10.html#content" },

{ text: `Này Gia chủ, Thánh đệ tử ấy, sau khi biết được dục tham là uế nhiễm của tâm, từ bỏ dục tham, uế nhiễm của tâm; sau khi biết được sân hận là uế nhiễm của tâm, từ bỏ sân hận, uế nhiễm của tâm; sau khi biết được hôn trầm thụy miên là uế nhiễm của tâm, từ bỏ hôn trầm thụy miên, uế nhiễm của tâm; sau khi biết được trạo hối là uế nhiễm của tâm, từ bỏ trạo hối, uế nhiễm của tâm; sau khi biết được nghi là uế nhiễm của tâm, từ bỏ nghi, uế nhiễm của tâm; này Gia chủ, đây gọi là vị Thánh đệ tử có đại trí tuệ, có trí tuệ rộng lớn, bước vào giới vức minh kiến, đầy đủ trí tuệ. Ðây gọi là đầy đủ trí tuệ.`, ref: "Tăng Chi Bộ 4.61", url: "https://loicuaducphat.org/an/an4.61.html#content" },

{ text: `Tham ái vật đẹp đẽ,<br>Thích thú sắc khả ái,<br>Bị cột bởi vô minh,<br>Các hữu tình hạ liệt,<br>Càng tăng trưởng trói buộc.<br>Cho đến kẻ có trí,<br>Làm các việc bất thiện,<br>Sanh từ tham, sân, si,<br>Khiến phiền muộn, khó chịu,<br>Làm đau khổ sanh khởi,<br>Kẻ vô minh bao vây,<br>Kẻ mù không có mắt,<br>Tự tánh họ là vậy,<br>Họ không thể nghĩ rằng,<br>Ta có thể như vậy.`, ref: "Tăng Chi Bộ 4.66", url: "https://loicuaducphat.org/an/an4.66.html#content" },


{ text: `Khi nào, này các Tỷ-kheo, Tỷ-kheo đối với các pháp khiến cho tham đắm, tâm không tham đắm, tự ngã được ly tham; đối với các pháp khiến cho sân hận, tâm không sân hận, tự ngã được ly sân; đối với các pháp khiến cho si mê, tâm không si mê, tự ngã được ly si; đối với các pháp khiến cho say đắm, tâm không say đắm, tự ngã được ly đắm say; thời vị ấy không có sợ hãi, không có dao động, không có hốt hoảng, không rơi vào hoảng sợ, không có đi do nhân các Sa-môn có nói gì.`, ref: "Tăng Chi Bộ 4.117", url: "https://loicuaducphat.org/an/an4.117.html#content" },


{ text: `Và này các Tỷ-kheo, thế nào là đạo hành nhiếp phục? Ở đây, này các Tỷ-kheo, Tỷ-kheo khi mắt thấy sắc, không nắm giữ tướng chung, không nắm giữ tướng riêng. Phàm do nhân duyên gì với nhãn căn này không được chế ngự, khiến cho tham ái, ưu bi, các ác bất thiện khởi lên, vị ấy chế ngự nguyên nhân ấy, hộ trì nhãn căn, sống với sự chế ngự nhãn căn. Khi tai nghe tiếng ... khi mũi ngửi hương ... khi lưỡi nếm vị ... khi thân cảm xúc ... khi ý biết pháp, không nắm giữ tướng chung, không nắm giữ tướng riêng. Phàm do nhân duyên gì ý căn này không được chế ngự, khiến cho tham ái, ưu bi, các ác bất thiện khởi lên, vị ấy chế ngự nguyên nhân ấy, thọ trì ý căn, sống với sự chế ngự ý căn. Này các Tỷ-kheo, đây gọi là đạo hành nhiếp phục.`, ref: "Tăng Chi Bộ 4.164", url: "https://loicuaducphat.org/an/an4.164.html#content" },


{ text: `Và này các Tỷ-kheo, thế nào gọi là đạo hành an tịnh? Ở đây, này các Tỷ-kheo, Tỷ-kheo không có chấp nhận dục tầm khởi lên, từ bỏ, tẩy sạch, làm cho an tịnh, chấm dứt, khiến đi đến không sanh hữu, không có chấp nhận sân tầm khởi lên ... không có chấp nhận hại tầm khởi lên ... không có chấp nhận các pháp ác bất thiện tầm khởi lên, từ bỏ, tẩy sạch, làm cho an tịnh, chấm dứt, khiến đi đến không sanh hữu. Này các Tỷ-kheo, đây gọi là đạo hành an tịnh.`, ref: "Tăng Chi Bộ 4.164", url: "https://loicuaducphat.org/an/an4.164.html#content" },


{ text: `Ở đây, này Bà-la-môn, có người không ly tham đối với các dục, không ly ham muốn, không ly luyến ái, không ly khát ái, không ly nhiệt não, không ly tham ái. Rồi một chứng bệnh trầm trọng khởi lên cho người ấy. Người ấy bị cảm thọ chứng bệnh trầm trọng ấy, suy nghĩ như sau: “Thật sự các dục khả ái sẽ bỏ ta”, hay “Ta sẽ từ bỏ các dục khả ái”. Người ấy sầu muộn, than vãn, khóc lóc, đập ngực, rơi vào bất tỉnh. Này Bà-la-môn, đây là người bản tánh bị chết, sợ hãi, rơi vào run sợ khi nghĩ đến chết.`, ref: "Tăng Chi Bộ 4.184", url: "https://loicuaducphat.org/an/an4.184.html#content" },


{ text: `Lại nữa, này các du sĩ, Bà-la-môn nói như sau: “Mọi dục là vô thường, khổ, chịu sự biến hoại”. Người Bà-la-môn nói như vậy là nói sự thật, không nói láo. Lại nữa do thắng tri sự thật hàm chứa ở đấy, (trong lời nói ấy), người ấy thực hành nhàm chán, ly tham, đoạn diệt đối với các dục.`, ref: "Tăng Chi Bộ 4.185", url: "https://loicuaducphat.org/an/an4.185.html#content" },

{ text: `Ái, này các Tỷ-kheo, là lưới triền khiến cho lưu chuyển luân hồi được rộng ra, bám dính vào; chính do ái ấy, thế giới này bị hoại vong, trói buộc, rối loạn như một cuộn chỉ, rối ren như một ổ kén, quyện lại như cỏ mujia và lau sậy babbaja, không thể nào ra khỏi khổ xứ, ác thú, đọa xứ, sanh tử.`, ref: "Tăng Chi Bộ 4.199", url: "https://loicuaducphat.org/an/an4.199.html#content" },


{ text: `Này các Tỷ-kheo, có bốn pháp phi Thánh cầu này. Thế nào là bốn? Ở đây, này các Tỷ-kheo, có người tự mình bị già, tầm cầu cái bị già; tự mình bị bệnh, tầm cầu cái bị bệnh; tự mình bị chết, tầm cầu cái bị chết; tự mình bị uế nhiễm, tầm cầu cái bị uế nhiễm. Này các Tỷ-kheo, có bốn pháp phi Thánh cầu này.`, ref: "Tăng Chi Bộ 4.255", url: "https://loicuaducphat.org/an/an4.255.html#content" },


{ text: `Này các Tỷ-kheo, có bốn pháp Thánh cầu này. Thế nào là bốn? Ở đây, này các Tỷ-kheo, có người tự mình bị già, sau khi biết sự nguy hại của bị già, tầm cầu cái không bị già, vô thượng an ổn khỏi các khổ ách, Niết-bàn; tự mình bị bệnh, sau khi biết sự nguy hại của bị bệnh, tầm cầu cái không bệnh, vô thượng an ổn khỏi các khổ ách, Niết-bàn; tự mình bị chết, sau khi biết sự nguy hại của bị chết, tầm cầu cái không chết, vô thượng an ổn khỏi các khổ ách, Niết-bàn; tự mình uế nhiễm, sau khi biết sự nguy hại của uế nhiễm, tầm cầu cái không bị uế nhiễm, vô thượng an ổn khỏi các khổ ách, Niết-bàn. Này các Tỷ-kheo, có bốn pháp Thánh cầu này.`, ref: "Tăng Chi Bộ 4.255", url: "https://loicuaducphat.org/an/an4.255.html#content" },

{ text: `Phần lớn, này các Tỷ-kheo, các loại hữu tình tìm được lạc thú trong các dục. Với thiện nam tử, này các Tỷ-kheo, đã bỏ một bên lưỡi liềm và đòn gánh, xuất gia, từ bỏ gia đình, sống không gia đình, vị ấy vừa đủ để được gọi: “Vị thiện nam tử vì lòng tin xuất gia”. Vì cớ sao?<br>Các dục, này các Tỷ-kheo, được tìm thấy với tuổi trẻ, các dục này hay các dục khác. Và này các Tỷ-kheo, các dục hạ liệt, các dục trung đẳng, và các dục tối thắng, tất cả dục đều được chấp nhận là các dục.`, ref: "Tăng Chi Bộ 5.7", url: "https://loicuaducphat.org/an/an5.7.html#content" },

{ text: `Này các Tỷ-kheo, có năm uế nhiễm này của tâm, do các uế nhiễm ấy, tâm bị uế nhiễm, không nhu nhuyến, không dễ sử dụng, không sáng chói, bị bể vụn, không chơn chánh định tĩnh để đoạn diệt các lậu hoặc. Thế nào là năm? Tham dục, sân, hôn trầm thụy miên, trạo hối, nghi. Có năm uế nhiễm này của tâm, này các Tỷ-kheo, do năm uế nhiễm ấy, tâm bị uế nhiễm không được nhu nhuyến, không dễ sử dụng, không sáng chói, bị bể vụn, không chơn chánh, định tĩnh để đoạn diệt các lậu hoặc.`, ref: "Tăng Chi Bộ 5.23", url: "https://loicuaducphat.org/an/an5.23.html#content" },

{ text: `Và khi nào, này các Tỷ-kheo, tâm được giải thoát khỏi năm uế nhiễm này: tham dục, sân, hôn trầm thụy miên, trạo hối, nghi. Khi ấy tâm ấy được nhu nhuyến, dễ sử dụng, sáng chói, không bể vụn, chơn chánh định tĩnh để đoạn diệt các lậu hoặc. Tùy thuộc theo pháp gì cần phải được giác ngộ với thắng trí, tâm vị ấy hướng đến để được giác ngộ với thắng trí. Tại đây, tại đấy vị ấy có khả năng, có năng lực đạt đến pháp ấy, dầu thuộc loại xứ nào.`, ref: "Tăng Chi Bộ 5.23", url: "https://loicuaducphat.org/an/an5.23.html#content" },

{ text: `Này Nàgita, với những ai nặng nề về ái lạc, này Nàgita, sự biến hoại, đổi khác, sầu bi khổ ưu não khởi lên. Ðấy là kết quả tất nhiên cho người ấy. Những ai chuyên chú tâm về tướng bất tịnh, này Nàgita, thời sự nhàm chán đối với tịnh tướng được an trú. Ðấy là kết quả tất nhiên cho người ấy. Ai sống tùy quán vô thường trong sáu xúc xứ, này Nàgita, thời sự nhàm chán đối với xúc được an trú. Ðấy là kết quả tất nhiên cho người ấy. Ai sống tùy quán sanh diệt đối với năm thủ uẩn, này Nàgita, thời sự nhàm chán đối với chấp thủ được an trú. Ðấy là kết quả tất nhiên cho người ấy.`, ref: "Tăng Chi Bộ 5.30", url: "https://loicuaducphat.org/an/an5.30.html#content" },

{ text: `Dục tham, này các Tỷ-kheo, là chướng ngại triền cái bao phủ tâm, làm yếu ớt trí tuệ. Sân, này các Tỷ-kheo, là chướng ngại triền cái bao phủ tâm làm yếu ớt trí tuệ. Hôn trầm thụy miên, này các Tỷ-kheo, là chướng ngại, triền cái bao phủ tâm, làm yếu ớt trí tuệ. Trạo hối, này các Tỷ-kheo, là chướng ngại, triền cái bao phủ tâm, làm yếu ớt trí tuệ. Nghi, này các Tỷ-kheo, là chướng ngại, triền cái bao phủ tâm, làm yếu ớt trí tuệ. Những pháp này, này các Tỷ-kheo, là năm chướng ngại triền cái bao phủ tâm, làm yếu ớt trí tuệ.`, ref: "Tăng Chi Bộ 5.51", url: "https://loicuaducphat.org/an/an5.51.html#content" },

{ text: `Nói đến một đống bất thiện, này các Tỷ-kheo, nói một cách chơn chánh là nói đến năm triền cái. Thật vậy, này các Tỷ-kheo, toàn bộ đống bất thiện tức là năm triền cái. Thế nào là năm? Dục tham triền cái, sân triền cái, hôn trầm thụy miên triền cái, trạo hối triền cái, nghi triền cái. Nói đến một đống bất thiện, này các Tỷ-kheo, nói một cách chơn chánh là nói đến năm triền cái. Thật vậy, này các Tỷ-kheo, toàn bộ đống bất tiện này, này các Tỷ-kheo, tức là năm triền cái.`, ref: "Tăng Chi Bộ 5.52", url: "https://loicuaducphat.org/an/an5.52.html#content" },


{ text: `Này các Tỷ-kheo, nếu có ai nói rằng: “Là bẫy mồi toàn diện của Màra”, thời người ấy đã nói một cách chơn chánh về nữ nhân, thật là “một bẫy mồi hoàn toàn của Màra”.`, ref: "Tăng Chi Bộ 5.55", url: "https://loicuaducphat.org/an/an5.55.html#content" },


{ text: `Hãy nói chuyện với người,<br>Có kiếm ở trong tay,<br>Nói chuyện với ác quỷ,<br>Hay ngồi thật gần kề.<br>Con rắn có nọc độc,<br>Bị cắn liền mệnh chung,<br>Nhưng chớ có một mình,<br>Nói chuyện với nữ nhân.<br>Thất niệm, họ trói lại,<br>Với nhìn, với nụ cười,<br>Với xiêm áo hở hang,<br>Với lời nói ngọt lịm,<br>Người ấy vẫn không thỏa,<br>Bất tỉnh bị mệnh chung.<br>Năm dục trưởng dưỡng ấy,<br>Ðược thấy trong nữ sắc<br>Sắc, thanh, hương, vị, xúc,<br>Hấp dẫn và đẹp ý.<br>Bị thác nước dục vọng,<br>Tràn ngập và cuốn trôi,<br>Kẻ ngu si vô trí,<br>Không liễu tri các dục.<br>Loài người khi mạng chung,<br>Sanh thú hữu, phi hữu,<br>Họ phải bị dẫn đầu,<br>Trong nhiều kiếp luân hồi.<br>Ai liễu tri các dục,<br>Sở hành không sợ hãi,<br>Họ đến bờ bên kia,<br>Ðạt được lậu hoặc tận.`, ref: "Tăng Chi Bộ 5.55", url: "https://loicuaducphat.org/an/an5.55.html#content" },

{ text: `Này Tỷ-kheo, khi một người sống với các căn không được bảo vệ, với ăn uống không có tiết độ, không có chú tâm cảnh giác, không có quán nhìn các thiện pháp, không có trước đêm và sau đêm chuyên chú tu tập các pháp giác chi. Do vậy, thân Thầy cảm thấy như bị say ngọt, mắt Thầy không thấy rõ phương hướng, pháp không được Thầy nhớ đến. Hôn trầm thụy miên chinh phục tâm Thầy và an trú. Không có hoan hỷ, Thầy sống Phạm hạnh. Thầy có những nghi ngờ đối với Chánh pháp. Do vậy, này Tỷ-kheo, Thầy phải học tập như sau: “Ta sẽ bảo vệ các căn, có tiết độ trong ăn uống, chú tâm cảnh giác, quán nhìn các Thiện pháp, trước đêm và sau đêm ta sẽ sống chuyên chú tu tập các pháp giác chi”.`, ref: "Tăng Chi Bộ 5.56", url: "https://loicuaducphat.org/an/an5.56.html#content" },


{ text: `Này Tỷ-kheo, khi một người sống với các căn được bảo vệ, với ăn uống có tiết độ, có chú tâm cảnh giác, có quán nhìn các thiện pháp, trước đêm và sau đêm sống chuyên chú tu tập các pháp giác chi. Do vậy, thân không cảm thấy như bị say ngọt, các phương hướng được hiện rõ, và pháp được người ấy nhớ rõ. Hôn trầm thụy miên không còn chinh phục tâm của vị ấy. Với tâm hoan hỷ, vị ấy sống Phạm hạnh. Vị ấy không còn nghi ngờ đối với các thiện pháp. Vậy này các Tỷ-kheo, các Thầy cần phải học tập như sau: “Ta sẽ bảo vệ các căn, có tiết độ trong ăn uống, chuyên tâm cảnh giác quán nhìn các thiện pháp, trước đêm và sau đêm, ta sẽ sống chuyên chú tu tập các pháp giác chi”.`, ref: "Tăng Chi Bộ 5.56", url: "https://loicuaducphat.org/an/an5.56.html#content" },


{ text: `Bị bệnh và bị già,<br>Lại thêm phải bị chết,<br>Pháp yếu là như vậy,<br>Hữu tình là như vậy.<br>Phàm phu sanh nhàm chán,<br>Thật không hợp cho Ta,<br>Nếu Ta cũng nhàm chán,<br>Ðối với các chúng sanh,<br>Cùng chung một số phận.<br>Trong khi đời sống Ta,<br>Không khác gì đời họ,<br>Ta được sống như vậy,<br>Biết pháp không sanh y,<br>Kiêu mạn trong không bệnh,<br>Trong tuổi trẻ sinh mạng,<br>Tất cả Ta nhiếp phục<br>Phát xuất từ an ổn,<br>Ta thấy hạnh viễn ly,<br>Ta phát tâm dõng mãnh,<br>Thấy được cảnh Niết-bàn.<br>Nay Ta không có thể,<br>Hưởng thọ các dục vọng,<br>Ta sẽ không thối đọa,<br>Chứng cứu cánh Phạm hạnh.`, ref: "Tăng Chi Bộ 5.57", url: "https://loicuaducphat.org/an/an5.57.html#content" },


{ text: `Có năm tưởng này, này các Tỷ-kheo, được tu tập, được làm cho sung mãn, đưa đến quả lớn, lợi ích lớn, thể nhập vào bất tử, đưa đến cứu cánh bất tử. Thế nào là năm? Tưởng bất tịnh, tưởng chết, tưởng nguy hại, tưởng ghê tởm các món ăn, tưởng không có hân hoan đối với tất cả thế giới. Năm tưởng này, này các Tỷ-kheo, được tu tập, được làm cho sung mãn, đưa đến quả lớn, lợi ích lớn, thể nhập vào bất tử, đưa đến cứu cánh bất tử.`, ref: "Tăng Chi Bộ 5.61", url: "https://loicuaducphat.org/an/an5.61.html#content" },


{ text: `Có năm tưởng này, này các Tỷ-kheo, được tu tập, được làm cho sung mãn, đưa đến quả lớn lợi ích, thể nhập vào bất tử, đưa đến cứu cánh bất tử. Thế nào là năm? Tưởng vô thường, tưởng vô ngã, tưởng chết, tưởng ghê tởm các món ăn, tưởng không có hân hoan đối với tất cả thế giới. Những pháp này là năm tưởng, này các Tỷ-kheo, được tu tập, được làm cho sung mãn, đưa đến quả lớn, lợi ích lớn, thể nhập vào bất tử, đưa đến cứu cánh bất tử.`, ref: "Tăng Chi Bộ 5.62", url: "https://loicuaducphat.org/an/an5.62.html#content" },


{ text: `Năm pháp này, này các Tỷ-kheo, được tu tập, được làm cho sung mãn, đưa đến đoạn diệt các lậu hoặc. Thế nào là năm? Ở đây, này các Tỷ-kheo, vị Tỷ-kheo trú quán bất tịnh trên thân, với tưởng ghê tởm đối với các món ăn, với tưởng không hoan hỷ đối với tất cả thế giới, quán vô thường đối với tất cả hành, với tưởng về chết, nội tâm khéo an trú. Năm pháp này, này các Tỷ-kheo, được tu tập, được làm cho sung mãn, đưa đến đoạn diệt các lậu hoặc.`, ref: "Tăng Chi Bộ 5.70", url: "https://loicuaducphat.org/an/an5.70.html#content" },


{ text: `Và này các Tỷ-kheo, do duyên lợi ích gì, này các Tỷ-kheo, Tỷ-kheo có thể trú với tưởng ghê tởm đối với vật không ghê tởm? ‘Mong rằng, đối với các pháp khả ái, tham chớ có khởi lên nơi ta.’ Do duyên lợi ích này, này các Tỷ-kheo, Tỷ-kheo nên sống với tưởng ghê tởm đối với vật không ghê tởm. Và này các Tỷ-kheo, do duyên lợi ích thế nào, Tỷ-kheo nên sống với tưởng không ghê tởm đối với vật ghê tởm? ‘Mong rằng đối với các pháp đáng sân hận, lòng sân chớ có khởi lên nơi ta’. Do duyên lợi ích này, này các Tỷ-kheo, Tỷ-kheo nên sống với tưởng không ghê tởm đối với vật ghê tởm. Và này các Tỷ-kheo, do duyên lợi ích thế nào, Tỷ-kheo sau khi từ bỏ cả hai vật không ghê tởm và ghê tởm, trú xả, chánh niệm tỉnh giác? ‘Mong rằng dầu là vật gì, tại chỗ nào và như thế nào, đối với các pháp khả ái, lòng tham chớ có khởi lên nơi ta! Mong rằng dầu là vật gì, tại chỗ nào là như thế nào, đối với các pháp đáng được sân hận, lòng sân chớ có khởi lên nơi ta! Mong rằng dầu là vật gì, tại chỗ nào và như thế nào, đối với các pháp có thể làm cho si mê, lòng si không khởi lên nơi ta.’ Do duyên lợi ích này, này các Tỷ-kheo, Tỷ-kheo sau khi từ bỏ cả hai vật không ghê tởm và ghê tởm, trú xả, chánh niệm tỉnh giác.”`, ref: "Tăng Chi Bộ 5.144", url: "https://loicuaducphat.org/an/an5.144.html#content" },


{ text: `Ta không thấy một xúc nào khác, này các Tỷ-kheo, xâm chiếm và ngự trị tâm người đàn ông, như xúc người đàn bà. Này các Tỷ-kheo, xúc người đàn bà xâm chiếm và ngự trị tâm người đàn ông.`, ref: "Tăng Chi Bộ 1.5", url: "https://loicuaducphat.org/an/an1.5.html#content" },

{ text: `Ta không thấy một pháp nào khác, này các Tỷ-kheo, do pháp ấy, các pháp bất thiện chưa sanh được sanh khởi, và các pháp thiện đã sanh bị đoạn tận, này các Tỷ-kheo, như không như lý tác ý. Với người không như lý tác ý, này các Tỷ-kheo, các pháp bất thiện chưa sanh được sanh khởi, và các pháp thiện đã sanh bị đoạn tận.`, ref: "Tăng Chi Bộ 1.66", url: "https://loicuaducphat.org/an/an1.66.html#content" },

{ text: `Ta không thấy một pháp nào khác, này các Tỷ-kheo, do pháp ấy, các pháp bất thiện chưa sanh được sanh khởi, và các pháp thiện đã sanh bị đoạn tận, này các Tỷ-kheo, như không tỉnh giác. Với người không tỉnh giác, này các Tỷ-kheo, các pháp bất thiện chưa sanh được sanh khởi, và các pháp thiện đã sanh bị đoạn tận.`, ref: "Tăng Chi Bộ 1.68", url: "https://loicuaducphat.org/an/an1.68.html#content" },

{ text: `Ta không thấy một pháp nào khác, này các Tỷ-kheo, do pháp ấy, các pháp bất thiện chưa sanh được sanh khởi, và các pháp thiện đã sanh được đoạn tận, này các Tỷ-kheo, như hệ lụy với các pháp bất thiện, và không hệ lụy với các pháp thiện. Do hệ lụy với các pháp bất thiện, này các Tỷ-kheo, do không hệ lụy với các pháp thiện, các pháp bất thiện chưa sanh được sanh khởi, và các pháp thiện đã sanh bị đoạn tận.`, ref: "Tăng Chi Bộ 1.72", url: "https://loicuaducphat.org/an/an1.72.html#content" },


{ text: `Ta không thấy một pháp nào khác, này các Tỷ-kheo, do pháp ấy, các giác chi chưa sanh được sanh khởi và các giác chi đã sanh đi đến tụ tập viên mãn, này các Tỷ-kheo, như như lý tác ý. Do như lý tác ý, này các Tỷ kheo các giác chi chưa sanh được sanh khởi, và các giác chi đã sanh đi đến tu tập viên mãn.`, ref: "Tăng Chi Bộ 1.75", url: "https://loicuaducphat.org/an/an1.75.html#content" },

{ text: `Ta không thấy một pháp nào khác, này các Tỷ-kheo, có thể đưa đến bất lợi lớn, này các Tỷ-kheo, như là phóng dật. Phóng dật, này các Tỷ-kheo, đưa đến bất lợi lớn.`, ref: "Tăng Chi Bộ 1.82", url: "https://loicuaducphat.org/an/an1.82.html#content" },

{ text: `Ta không thấy một pháp nào khác, này các Tỷ-kheo, có thể đưa đến ích lợi lớn, này các Tỷ-kheo, như là không phóng dật. Không phóng dật, này các Tỷ-kheo, đưa đến ích lợi lớn.`, ref: "Tăng Chi Bộ 1.83", url: "https://loicuaducphat.org/an/an1.83.html#content" },

{ text: `Và này các Tỷ-kheo, như thế nào là Tỷ-kheo đã được đoạn tận hoàn toàn các tầm cầu? Ở đây, này các Tỷ-kheo, Tỷ-kheo đã đoạn tận dục tầm cầu, đã đoạn tận hữu tầm cầu, Phạm hạnh tầm cầu được khinh an. Như vậy, này Tỷ-kheo, là Tỷ-kheo đã đoạn tận hoàn toàn các tầm cầu. Và này các Tỷ-kheo, như thế nào là Tỷ-kheo các tư duy không có uế trược? Ở đây, này các Tỷ-kheo, Tỷ-kheo đã đoạn tận dục tư duy, đã đoạn tận sân tư duy, đã đoạn tận hại tư duy. Như vậy, này các Tỷ-kheo, là các tư duy không có uế trược. Và này các Tỷ-kheo, thế nào là Tỷ-kheo tâm hành được khinh an? Ở đây, này các Tỷ-kheo, Tỷ-kheo đoạn khổ, đoạn lạc, chấm dứt hỷ ưu đã cảm thọ trước, chứng đạt và an trú Thiền Thứ tư, không khổ, không lạc, xả niệm thanh tịnh. Như vậy, này các Tỷ-kheo, là Tỷ-kheo tâm hành được khinh an. Và này các Tỷ-kheo, như thế nào là Tỷ-kheo tâm được khéo giải thoát? Ở đây, này các Tỷ-kheo, Tỷ-kheo tâm được giải thoát khỏi tham, tâm được giải thoát khỏi sân, tâm được giải thoát khỏi si. Như vậy, này các Tỷ-kheo, là Tỷ-kheo tâm được khéo giải thoát. Và này các Tỷ-kheo, như thế nào là Tỷ-kheo với tuệ khéo giải thoát? Ở đây, này các Tỷ-kheo, Tỷ-kheo rõ biết rằng: “Tham ái đã được đoạn tận nơi ta, được chặt đứt từ gốc rễ, làm cho như thân cây tàla, làm cho không thể tái sanh, làm cho không thể sanh khởi trong tương lai”, rõ biết rằng: “Sân đã được đoạn tận nơi ta… trong tương lai”, rõ biết rằng: “Si đã được đoạn tận nơi ta, được chặt đứt từ gốc rễ, làm cho thân cây tàla, làm cho không thể tái sanh, làm cho không thể sanh khởi trong tương lai.” Như vậy, này các Tỷ-kheo, là Tỷ-kheo với tuệ khéo giải thoát. Này các Tỷ-kheo, tất cả những vị Thánh nào trong quá khứ đã sống theo Thánh cư, tất cả những vị ấy đã sống theo mười Thánh cư này. Này các Tỷ-kheo, tất cả những vị Thánh nào trong tương lai sẽ sống theo Thánh cư, tất cả những vị ấy sẽ sống theo mười Thánh cư này. Này các Tỷ-kheo, tất cả những vị Thánh nào trong hiện tại sống theo Thánh cư, tất cả những vị ấy đang sống theo mười Thánh cư này. Này các Tỷ-kheo, đây là mười Thánh cư mà các vị Thánh đã sống, đang sống, và sẽ sống.”`, ref: "Tăng Chi Bộ 10.20", url: "https://loicuaducphat.org/an/an10.20.html#content" },

{ text: `Ðể thắng tri tham ái, này các Tỷ-kheo, mười pháp cần phải tu tập. Thế nào là mười? Bất tịnh tưởng, tưởng chết, tưởng nhàm chán trong các món ăn, tưởng không hoan hỷ đối với tất cả thế giới, tưởng vô thường, tưởng khổ trong vô thường, tưởng vô ngã trong khổ, tưởng đoạn tận, tưởng ly tham, tưởng đoạn diệt. Ðể thắng tri tham, này các Tỷ-kheo, mười pháp này cần phải tu tập.`, ref: "Tăng Chi Bộ 10.237", url: "https://loicuaducphat.org/an/an10.237.html#content" },

{ text: `Này các Hiền giả, nếu Tỷ-kheo quán sát như vậy, biết rằng: “Ta sống nhiều với tâm tham; ta sống nhiều với tâm sân; ta sống nhiều với tâm bị hôn trầm thụy miên chi phối; ta sống nhiều với trạo cử; ta sống nhiều với nghi ngờ; ta sống nhiều với phẫn nộ; ta sống nhiều với tâm bị nhiễm ô; ta sống nhiều với thân nhiệt nóng; ta sống nhiều với biếng nhác; ta sống nhiều với không định tĩnh”, thời Tỷ-kheo ấy cần phải quyết định, ước muốn, tinh tấn, nỗ lực, dõng mãnh, bất thối, chánh niệm, tỉnh giác để đoạn tận các pháp ác bất thiện ấy. Ví như, này các Hiền giả, khi khăn bị cháy, hay khi đầu bị cháy, cần phải quyết định, ước muốn, tinh tấn, nỗ lực, dõng mãnh, bất thối, chánh niệm, tỉnh giác để dập tắt khăn hay đầu bị cháy ấy. Cũng vậy, này các Hiền giả, Tỷ kheo ấy cần phải quyết định, ước muốn, tinh tấn, nỗ lực, dõng mãnh, bất thối, chánh niệm, tỉnh giác để đoạn tận các pháp bất thiện ấy. Này các Hiền giả, nếu Tỷ-kheo quán sát như vậy biết rằng: “Ta sống nhiều với tâm không tham, ta sống nhiều với tâm không sân, ta sống nhiếu với tâm không hôn trầm thụy miên; ta sống nhiều với tâm không trạo cử; ta sống nhiều với tâm nghi ngờ được vượt qua; ta sống nhiều với tâm không phẫn nộ; ta sống nhiều với tâm không nhiễm ô; ta sống nhiều với thân không nhiệt nóng; ta sống nhiều với tâm tinh tấn, tinh cần; ta sống nhiều với tâm định tĩnh”, thời Tỷ-kheo ấy, sau khi an trú trong các thiện pháp ấy, rồi hơn nữa cần chú tâm đoạn diệt các lậu hoặc.`, ref: "Tăng Chi Bộ 10.52", url: "https://loicuaducphat.org/an/an10.52.html#content" },

{ text: `Này Sàriputta, trong khi Thánh đệ tử đạt được và an trú hỷ do viễn ly sanh, trong thời gian ấy, năm sự kiện không xảy ra cho người ấy: Khổ và ưu liên hệ đến dục trong thời gian ấy không xảy ra cho người ấy. Lạc và hỷ liên hệ đến dục trong thời gian ấy không xảy ra cho người ấy. Khổ và ưu liên hệ đến bất thiện trong thời gian ấy không xảy ra cho người ấy. Lạc và hỷ liên hệ đến bất thiện trong thời gian ấy không xảy ra cho người ấy. Khổ và ưu liên hệ đến thiện, trong thời gian ấy không xảy ra cho người ấy. Này Sàriputta, trong khi vị Thánh đệ tử đạt đến và an trú hỷ do viễn ly sanh, trong thời gian ấy, năm sự kiện này không xảy ra cho người ấy.`, ref: "Tăng Chi Bộ 5.176", url: "https://loicuaducphat.org/an/an5.176.html#content" },

{ text: `Này các Tỷ-kheo, có năm nguy hại này đối với người thất niệm, không tỉnh giác rơi vào giấc ngủ. Thế nào là năm? Ngủ một cách khổ sở; thức dậy một cách khổ sở; thấy ác mộng; chư Thiên không phòng hộ; bất tịnh chảy ra, mộng tinh, di tinh. Này các Tỷ-kheo, có năm nguy hại này đối với người thất niệm, không tỉnh giác rơi vào giấc ngủ. Này các Tỷ-kheo, có năm lợi ích này đối với người trú niệm, tỉnh giác rơi vào giấc ngủ. Thế nào là năm? Ngủ một các ngon lành; thức dậy một cách ngon lành; không thấy ác mộng; chư Thiên phòng hộ; bất tịnh không chảy ra. Này các Tỷ-kheo, có năm lợi ích này đối với người trú niệm, tỉnh giác rơi vào giấc ngủ.`, ref: "Tăng Chi Bộ 5.210", url: "https://loicuaducphat.org/an/an5.210.html#content" },


{ text: `“Này các Tỷ-kheo, có năm tâm triền phược này. Thế nào là năm? Ở đây, này các Tỷ-kheo, Tỷ-kheo đối với các dục, không phải không tham ái, không phải không dục cầu, không phải không ái luyến, không phải không khao khát, không phải không nhiệt não, không phải không khát ái. Này các Tỷ-kheo, Tỷ-kheo nào đối với cái dục, không phải không tham ái… không phải không khát ái, tâm của vị ấy không hướng về nỗ lực, chuyên cần, kiên trì, tinh tấn. Nếu tâm của ai không hướng về nỗ lực, chuyên cần, kiên trì, tinh tấn, như vậy là tâm triền phược thứ nhất.”`, ref: "Tăng Chi Bộ 5.206", url: "https://loicuaducphat.org/an/an5.206.html#content" },

{ text: `“Này các Tỷ-kheo, có ba pháp này. Thế nào là ba? Dục tầm, sân tầm, hại tầm. Này các Tỷ-kheo, có ba pháp này. Ðể đoạn tận ba pháp đó, ba pháp cần phải tu tập. Thế nào là ba? Ðể đoạn tận dục tầm, xuất ly tầm phải tu tập. Ðể đoạn tận sân tầm, vô sân tầm cần phải tu tập, Ðể đoạn tận hại tầm, bất hại tầm cần phải tu tập. Ðể đoạn tận ba pháp kia, này các Tỷ-kheo, ba pháp này cần phải tu tập.”`, ref: "Tăng Chi Bộ 6.109", url: "https://loicuaducphat.org/an/an6.109.html#content" },

{ text: `Sợ hãi, này các Tỷ-kheo, là đồng nghĩa với các dục. Khổ, này các Tỷ-kheo, là đồng nghiệp với các dục. Bệnh, này các Tỷ-kheo, là đồng nghĩa với các dục. Cục bướu, này các Tỷ-kheo, là đồng nghĩa với các dục. Tham dính, này các Tỷ-kheo, là đồng nghĩa với các dục. Bùn lầy, này các Tỷ-kheo, là đồng nghĩa với các dục. Và này các Tỷ-kheo, vì sao sợ hãi là đồng nghĩa với các dục? Này các Tỷ-kheo, say đắm bởi tham dục, bị trói buộc bởi các tham ước muốn, ngay trong hiện tại không thoát khỏi sợ hãi, đời sau cũng không thoát khỏi sợ hãi. Do vậy, sợ hãi là đồng nghĩa với các dục.`, ref: "Tăng Chi Bộ 6.23", url: "https://loicuaducphat.org/an/an6.23.html#content" },


{ text: `Với căn không phòng hộ, này các Tỷ-kheo, với người khiếm khuyết phòng hộ các căn, giới đi đến hủy hoại; với giới không có, có ai khiếm khuyết về giới, chánh định đi đến hủy hoại. Với chánh định không có, với ai khiếm khuyết chánh định, tri kiến như thật đi đến hủy hoại. Với tri kiến như thật không có, với ai khiếm khuyết tri kiến như thật, nhàm chán, ly tham đi đến hủy hoại. Với nhàm chán, ly tham không có, với ai khiếm khuyết nhàm chán, ly tham, giải thoát tri kiến đi đến hủy hoại. Ví như, này các Tỷ-kheo, một cây, với cành và lá khiếm khuyết, thời các chồi non không đi đến viên mãn, vỏ cây không đi đến viên mãn, giác cây không đi đến viên mãn, lõi cây không đi đến viên mãn. Cũng vậy, này các Tỷ-kheo, với căn không phòng hộ, với người khiếm khuyết phòng hộ các căn... giải thoát tri kiến đi đến hủy hoại.`, ref: "Tăng Chi Bộ 6.50", url: "https://loicuaducphat.org/an/an6.50.html#content" },

{ text: `Với các căn được phòng hộ, này các Tỷ-kheo, với người đầy đủ các căn được phòng hộ, giới đi đến đầy đủ. Với giới có mặt, với người đầy đủ giới, chánh định đi đến đầy đủ. Với chánh định có mặt, với người đầy đủ chánh định, tri kiến như thật đi đến đầy đủ. Với tri kiến như thật có mặt, với người đầy đủ tri kiến như thật, nhàm chán, ly tham đi đến đầy đủ. Với nhàm chán, ly tham có mặt, với người đầy đủ nhàm chán, ly tham, giải thoát tri kiến đi đến đầy đủ. Ví như, này các Tỷ-kheo, một cây với cành và lá đầy đủ, thời chồi non đi đến viên mãn, vỏ cây đi đến viên mãn, giác cây đi đến viên mãn, lõi cây đi đến viên mãn. Cũng vậy, này các Tỷ-kheo, với căn được phòng hộ, với người đầy đủ phòng hộ các căn, giới đi đến đầy đủ... giải thoát tri kiến đi đến đầy đủ.`, ref: "Tăng Chi Bộ 6.50", url: "https://loicuaducphat.org/an/an6.50.html#content" },

{ text: `Với ai hướng xuất ly,<br>Tâm xu hướng viễn ly,<br>Với ai hướng vô sân,<br>Tâm xu hướng thủ diệt,<br>Với ai hướng ái diệt,<br>Tâm xu hướng vô si,<br>Có thấy xứ sanh khởi,<br>Tâm được chánh giải thoát.<br>Với vị chánh giải thoát,<br>Vị Tỷ-kheo tâm tịnh,<br>Không cần làm thêm gì,<br>Không có gì phải làm.<br>Như hòn núi đá tảng,<br>Gió không thể dao động,<br>Cũng vậy, toàn thể sắc,<br>Vị, tiếng, và hương, xúc,<br>Cho đến tất cả pháp,<br>Khả ái, không khả ái,<br>Không có thể dao động,<br>Một vị được như vậy,<br>Tâm kiên trú, giải thoát,<br>Thấy tánh diệt của chúng.`, ref: "Tăng Chi Bộ 6.55", url: "https://loicuaducphat.org/an/an6.55.html#content" },


{ text: `Xúc, này các Tỷ-kheo, là cực đoan. Xúc tập khởi là cực đoan thứ hai. Xúc diệt là chặng giữa. Ái là người dệt vải; vì rằng ái dệt nên khiến cho vị ấy phải sanh ở hữu này. Cho đến như vậy, này các Tỷ-kheo, Tỷ-kheo thắng tri được điều có thể thắng tri, liễu tri được điều có thể liễu tri. Do thắng tri được điều có thể thắng tri, liễu tri được điều có thể liễu tri, ngay trong hiện tại, vị ấy có thể chấm dứt khổ đau.<br>Ai biết hai cực đoan,<br>Giữa bậc Trí không nhiễm,<br>Ta gọi bậc Ðại nhân,<br>Ðây, vượt người dệt vải.`, ref: "Tăng Chi Bộ 6.61", url: "https://loicuaducphat.org/an/an6.61.html#content" },

{ text: `Này các Tỷ-kheo, có năm dục trưởng dưỡng này: Các sắc do mắt nhận thức, khả lạc, khả ý, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Các tiếng do tai nhận thức... các hương do mũi nhận thức... các vị do lưỡi nhận thức... các xúc do thân nhận thức... khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Này các Tỷ-kheo, dầu chúng không phải dục, chúng được gọi là dục trưởng dưỡng trong giới luật của bậc Thánh.`, ref: "Tăng Chi Bộ 6.63", url: "https://loicuaducphat.org/an/an6.63.html#content" },


{ text: `Các tư duy tham ái,<br>Là dục của con người,<br>Các hoa mỹ ở đời,<br>Chúng không phải là dục,<br>Các tư duy tham ái<br>Là dục của con người,<br>Các hoa mỹ an trú<br>Như vậy ở trên đời,<br>Ở đây những bậc Trí,<br>Nhiếp phục được lòng dục.`, ref: "Tăng Chi Bộ 6.63", url: "https://loicuaducphat.org/an/an6.63.html#content" },

{ text: `‘Cho đến trọn đời, các vị A-la-hán đoạn tận phi Phạm hạnh, hành Phạm hạnh, sống xa lánh, từ bỏ dâm dục hèn hạ. Hôm nay, đêm này và ngày nay, ta cũng đoạn tận phi Phạm hạnh, hành Phạm hạnh, sống xa lánh, từ bỏ dâm dục hèn hạ. Với chi phần này, Ta theo gương vị A-la-hán, ta sẽ thực hành ngày trai giới.’`, ref: "Tăng Chi Bộ 8.41", url: "https://loicuaducphat.org/an/an8.41.html#content" },

{ text: `Ðể thắng tri tham, này các Tỷ-kheo, sáu pháp cần phải tu tập. Thế nào là sáu? Tưởng vô thường, tưởng khổ trong vô thường, tưởng vô ngã trong khổ, tưởng đoạn tận, tưởng ly tham, tưởng đoạn diệt. Ðể thắng tri tham, này các Tỷ-kheo, sáu pháp này cần phải tu tập.`, ref: "Tăng Chi Bộ 6.142", url: "https://loicuaducphat.org/an/an6.142.html#content" },


{ text: `Tưởng bất tịnh, này các Tỷ-kheo, được tu tập, được làm cho sung mãn, có quả lớn, có lợi ích lớn, thể nhập vào bất tử, lấy bất tử làm cứu cánh, được nói đến như vậy. Do duyên gì được nói đến như vậy? Này các Tỷ-kheo, khi một Tỷ-kheo sống nhiều với các tưởng bất tịnh, thời tâm thối lui, tâm trở lưng, quay lưng để không đắm vào các dâm dục; do đó tâm vị ấy không căng thẳng, thanh thản, khởi lên nhàm chán. Ví như, này các Tỷ-kheo, lông gà hay là dây gân quăng vào lửa thời thối lui, trở lưng, quay lưng, và không căng thẳng; cũng vậy, này các Tỷ-kheo, khi một Tỷ-kheo sống nhiều với các tưởng bất tịnh, thời tâm thối lui, tâm trở lưng, quay lưng để không đắm vào các dâm dục; do đó tâm vị ấy không căng thẳng, thanh thản, khởi lên nhàm chán. Này các Tỷ-kheo, nếu Tỷ-kheo sống nhiều với các tưởng bất tịnh, nhưng tâm lại chạy theo, đắm vào dâm dục, không khởi lên nhàm chán, thời Tỷ-kheo ấy cần phải hiểu rằng: “Tưởng bất tịnh không được ta tu tập; ở nơi ta không có sự sai khác trước và sau. Ta không đạt được quả tu tập”. Ở đấy, vị ấy tỉnh giác như vậy. Này các Tỷ-kheo, nếu Tỷ-kheo sống nhiều với các tưởng bất tịnh, thời tâm thối lui, tâm trở lưng, quay lưng để không đắm vào các dâm dục; do đó tâm vị ấy không căng thẳng, thanh thản, khởi lên nhàm chán, thời Tỷ-kheo ấy cần phải hiểu rằng: “Tưởng bất tịnh được ta tu tập; ở nơi ta có sự sai khác trước và sau. Ta đạt được quả tu tập”. Ở đấy, vị ấy tỉnh giác như vậy. Tưởng bất tịnh, này các Tỷ-kheo, được tu tập, được làm cho sung mãn, có quả lớn, có lợi ích lớn, thể nhập vào bất tử, lấy bất tử làm cứu cánh, được nói đến như vậy, do duyên này được nói đến như vậy.`, ref: "Tăng Chi Bộ 7.49", url: "https://loicuaducphat.org/an/an7.49.html#content" },

{ text: `Một nữ nhân, này các Tỷ-kheo, tác ý nội nữ căn, nữ hành, nữ y phục, nữ loại, nữ dục, nữ thanh, nữ trang sức, thời nữ nhân ấy tham đắm trong ấy, thích thú tại đấy. Do tham đắm trong ấy, thích thú tại đấy nên tác ý đến nam căn ở ngoài, nam hành, nam y phục, nam loại, nam dục, nam thanh, nam trang sức mà nữ nhân ấy tham đắm trong ấy, thích thú tại đấy. Do tham đắm trong ấy, thích thú tại đấy nên nữ nhân ấy ước muốn có sự hệ lụy ở ngoài. Do duyên với hệ lụy ấy, khởi lên lạc, hỷ nên nữ nhân ấy ước muốn lạc hỷ ấy. Này các Tỷ-kheo, do thích thú trong nữ tánh của mình, các loài hữu tình đi đến hệ lụy với những người đàn ông. Như vậy, này các Tỷ-kheo, nữ nhân không có thoát được nữ tánh của mình.`, ref: "Tăng Chi Bộ 7.51", url: "https://loicuaducphat.org/an/an7.51.html#content" },


{ text: `Một nam nhân, này các Tỷ-kheo, tác ý nội nam căn, nam hành, nam y phục, nam loại, nam dục, nam thanh, nam trang sức mà nữ nhân ấy tham đắm trong ấy, thích thú tại đấy. Do tham đắm trong ấy, thích thú tại đấy nên tác ý đến nữ căn ở ngoài, nữ hành, nữ y phục, nữ loại, nữ dục, nữ thanh, nữ trang sức mà nam nhân ấy tham đắm trong ấy, thích thú tại đấy. Do tham đắm trong ấy, thích thú tại đấy nên nam nhân ấy ước muốn có sự hệ lụy ở ngoài. Do duyên với hệ lụy ấy, khởi lên lạc hỷ nên nam nhân ấy ước muốn lạc hỷ ấy. Này các Tỷ-kheo, do thích thú trong nam tánh của mình, các loài hữu tình đi đến hệ lụy với những người đàn bà. Như vậy, này các Tỷ-kheo, nam nhân không thoát khỏi nam tánh của mình.`, ref: "Tăng Chi Bộ 7.51", url: "https://loicuaducphat.org/an/an7.51.html#content" },

{ text: `Này các Tỷ-kheo, tà hạnh trong các dục được thực hiện, được tu tập, được làm cho sung mãn, đưa đến địa ngục, đưa đến loại bàng sanh, đưa đến cõi ngạ quỷ. Quả dị thục hết sức nhẹ của tà hạnh trong các dục là được làm người với sự oán thù của kẻ địch.`, ref: "Tăng Chi Bộ 8.40", url: "https://loicuaducphat.org/an/an8.40.html#content" },

{ text: `Sợ hãi, này các Tỷ-kheo, là đồng nghĩa với các dục. Ðau khổ, này các Tỷ-kheo, là đồng nghĩa với các dục. Bệnh tật, này các Tỷ-kheo, là đồng nghĩa với các dục. Cục bướu, này các Tỷ-kheo, là đồng nghĩa với các dục. Mũi tên, này các Tỷ-kheo, là đồng nghĩa với các dục. Trói buộc, này các Tỷ-kheo, là đồng nghĩa với các dục. Bùn, này các Tỷ-kheo, là đồng nghĩa với các dục. Thai tạng, này các Tỷ-kheo, là đồng nghĩa với các dục.<br>Như thế nào, này các Tỷ-kheo, sợ hãi là đồng nghĩa với các dục? Vì rằng, những ai bị dục ái nhiễm, những ai bị dục tham trói buộc, không được giải thoát khỏi sợ hãi hiện tại, không được giải thoát khỏi sợ hãi trong tương lai; do vậy, sợ hãi là đồng nghĩa với các dục.`, ref: "Tăng Chi Bộ 8.56", url: "https://loicuaducphat.org/an/an8.56.html#content" },

{ text: `Sợ hãi, khổ và bệnh<br>Cục bướu và mũi tên<br>Trói buộc và bùn lầy<br>Cả hai cùng thai tạng<br>Chúng được gọi tình dục<br>Chỗ phàm phu ái nhiễm<br>Chìm đắm trong sắc đẹp<br>Chúng lại vào thai tạng<br>Khi Tỷ-kheo nhiệt tình<br>Không thả lỏng tỉnh giác<br>Vượt đường hiểm nạn này<br>Con đường khó vượt qua<br>Vị ấy nhìn chúng sanh<br>Ðang sống trong sợ hãi<br>Vì bị sanh và già<br>Ám ảnh và chinh phục.`, ref: "Tăng Chi Bộ 8.56", url: "https://loicuaducphat.org/an/an8.56.html#content" },


{ text: `“Nội tâm ta sẽ an trú, khéo vững trú. Các pháp ác, bất thiện sanh khởi không có xâm chiếm tâm và không có chân đứng”. Như vậy, này Tỷ-kheo, Thầy cần phải học tập.`, ref: "Tăng Chi Bộ 8.63", url: "https://loicuaducphat.org/an/an8.63.html#content" },

{ text: `“Ta sẽ sống quán thân trên thân, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời”. Như vậy, này Tỷ-kheo, Thầy cần phải học tập. Này Tỷ-kheo, khi nào định này của Thầy được tu tập, được làm cho sung mãn như vậy, khi ấy, này Tỷ-kheo, Thầy cần phải tu tập định này với tầm với tứ; cần phải tu tập không tầm, với tứ; cần phải tu tập không tầm, không tứ; cần phải tu tập có hỷ, cần phải tu tập không hỷ; cần phải tu tập câu hữu với lạc; cần phải tu tập câu hữu với xả. Này Tỷ-kheo, khi nào định này của Thầy được tu tập, được làm cho sung mãn như vậy, khi ấy này Tỷ-kheo, chỗ nào, chỗ nào Thầy đi, chỗ ấy Thầy đi được an ổn; chỗ nào, chỗ nào Thầy sẽ đứng, chỗ ấy Thầy đứng được an ổn; chỗ nào, chỗ nào sẽ Thầy ngồi, chỗ ấy Thầy ngồi được an ổn; chỗ nào, chỗ nào Thầy sẽ nằm, chỗ ấy Thầy sẽ nằm được an ổn.`, ref: "Tăng Chi Bộ 8.63", url: "https://loicuaducphat.org/an/an8.63.html#content" },


{ text: `Và này các Tỷ-kheo, khi Tỷ-kheo ấy đã trú trong năm pháp này, bốn pháp nữa cần phải tu tập. Cần phải tu tập tưởng bất tịnh để đoạn tận tham ái, cần phải tu tập từ tâm để đoạn tận sân, cần phải tu tập niệm hơi thở vô, hơi thở ra để cắt đứt tầm, cần phải tu tập tưởng vô thường để phá hoại ngã mạn. Này các Tỷ-kheo, với Tỷ-kheo có tưởng vô thường, tưởng vô ngã được an trú; với Tỷ-kheo có tưởng vô ngã, ngã mạn bị phá hoại, ngay trong hiện tại, đạt được Niết-bàn.`, ref: "Tăng Chi Bộ 9.1", url: "https://loicuaducphat.org/an/an9.1.html#content" },

{ text: `Ung nhọt, này các Tỷ-kheo, là đồng nghĩa với thân này do bốn đại tác thành, do cha mẹ sinh ra, do cơm cháo chất chứa nuôi dưỡng, vô thường, biến hoại, tan nát, hủy hoại, hoại diệt, có chín miệng vết thương, có chín miệng nứt rạn. Từ đấy có cái gì chảy ra, chắc chắn bất tịnh rỉ chảy, chắc chắn hôi thúi rỉ chảy, chắc chắn nhàm chán rỉ chảy; có cái gì nứt chảy, chắc chắn bất tịnh nứt chảy, chắc chắn hôi thúi nứt chảy, chắc chắn nhàm chán nứt chảy. Do vậy, này các Tỷ-kheo, các Thầy hãy nhàm chán thân này.`, ref: "Tăng Chi Bộ 9.15", url: "https://loicuaducphat.org/an/an9.15.html#content" },


{ text: `- Này các Tỷ-kheo, có chín tưởng này được tu tập, được làm cho sung mãn, có quả lớn, có lợi ích lớn, thể nhập vào bất tử, lấy bất tử làm cứu cánh. Thế nào là chín? Tưởng bất tịnh, tưởng chết, tưởng ghê tởm đối với các món ăn, tưởng không ưa thích đối với tất cả thế giới, tưởng vô thường, tưởng khổ trên vô thường, tưởng vô ngã trên khổ, tưởng đoạn tận, tưởng ly tham. Này các Tỷ-kheo, chín tưởng này được tu tập, được làm sung mãn, có quả lớn, có lợi ích lớn, thể nhập vào bất tử, lấy bất tử làm cứu cánh.`, ref: "Tăng Chi Bộ 9.16", url: "https://loicuaducphat.org/an/an9.16.html#content" },

{ text: `“Cho đến trọn đời, các vị A-la-hán đoạn tận phi Phạm hạnh, hành Phạm hạnh, sống xa lìa, từ bỏ dâm dục hèn hạ. Hôm nay, đêm này và ngày này, ta cũng đoạn phi Phạm hạnh, hành Phạm hạnh, sống xa lìa, từ bỏ dâm dục hèn hạ. Với chi phần này, ta theo gương vị A-la-hán, sẽ thực hành ngày trai giới”. Ðây là chi phần thứ ba được thành tựu.`, ref: "Tăng Chi Bộ 9.18", url: "https://loicuaducphat.org/an/an9.18.html#content" },

{ text: `- Này các Tỷ-kheo, Ta sẽ thuyết về chín pháp lấy ái làm cội gốc. Hãy nghe và khéo tác ý, Ta sẽ giảng. Và này các Tỷ-kheo, thế nào là chín pháp lấy ái làm cội gốc? Do duyên ái nên cầu tìm; do duyên cầu tìm nên có được; do duyên có được nên có quyết định; do duyên quyết định nên có dục tham; do duyên dục tham nên đắm trước; do duyên đắm trước nên có chấp trước; do duyên chấp trước nên có xan tham; do duyên xan tham nên có thủ hộ, chấp trượng, chấp kiếm, đấu tranh, tránh tranh, kháng tranh, ly gián ngữ, vọng ngữ, rất nhiều các ác, bất thiện pháp khởi lên. Này các Tỷ-kheo, đây là chín pháp lấy ái làm cội gốc.`, ref: "Tăng Chi Bộ 9.23", url: "https://loicuaducphat.org/an/an9.23.html#content" },

{ text: `- Này các Tỷ-kheo, có năm dục trưởng dưỡng này. Thế nào là năm? Các sắc do mắt nhận thức, khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn, các tiếng do tai nhận thức khả lạc... hấp dẫn. Này các Tỷ-kheo, có năm dục trưởng dưỡng này. Này các Tỷ-kheo, để đoạn tận năm dục trưởng dưỡng này, Bốn niệm xứ này phải tu tập.`, ref: "Tăng Chi Bộ 9.65", url: "https://loicuaducphat.org/an/an9.65.html#content" },

{ text: `Cũng vậy, này các Tỷ-kheo, Tỷ-kheo quán sát như vậy, được nhiều lợi ích trong các thiện pháp. “Có phải ta sống nhiều với tham? Có phải ta sống nhiều với không tham? Có phải ta sống nhiều với tâm có sân? Có phải ta sống nhiều vớt tâm không có sân? Có phải ta sống nhiều với hôn trầm thụy miên chi phối, hay ta sống nhiều với hôn trầm thụy miên được từ bỏ? Có phải ta sống nhiều với trạo cử, hay ta sống nhiều với không trạo cử? Có phải ta sống nhiều với nghi ngờ, hay ta sống nhiều vượt qua được nghi ngờ? Có phải ta sống nhiều với phẫn nộ, hay ta sống nhiều không bị phẫn nộ? Có phải ta sống nhiều với tâm bị ô nhiễm, hay ta sống nhiều với tâm không bị ô nhiễm? Có phải ta sống nhiều với thân nhiệt nóng, hay ta sống nhiều với thân không nhiệt nóng? Có phải ta sống nhiều với biếng nhác, hay ta sống nhiều với tinh tấn, tinh cần? Có phải ta sống nhiều với không định tĩnh, hay ta sống nhiều với định tĩnh? “`, ref: "Tăng Chi Bộ 10.51", url: "https://loicuaducphat.org/an/an10.51.html#content" },


{ text: `Này các Tỷ-kheo, nếu Tỷ-kheo quán sát như vậy, biết rằng: “Ta sống nhiều với tâm tham; ta sống nhiều với tâm sân; ta sống nhiều với tâm bị hôn trầm thụy miên chi phối; ta sống nhiều với trạo cử; ta sống nhiều với nghi ngờ; ta sống nhiều với phẫn nộ; ta sống nhiều với tâm bị nhiễm ô; ta sống nhiều với thân nhiệt nóng; ta sống nhiều với biếng nhác; ta sống nhiều với không định tĩnh”, thời Tỷ-kheo ấy cần phải quyết định, ước muốn, tinh tấn, nỗ lực, dõng mãnh, bất thối, chánh niệm, tỉnh giác để đoạn tận các pháp ác bất thiện ấy. Ví như, này các Tỷ-kheo, khi khăn bị cháy, hay khi đầu bị cháy, cần phải quyết định, ước muốn, tinh tấn, nỗ lực, dõng mãnh, bất thối, chánh niệm, tỉnh giác để dập tắt khăn hay đầu bị cháy ấy. Cũng vậy này Tỷ kheo, Tỷ kheo ấy cần phải quyết định, ước muốn, tinh tấn, nỗ lực, dõng mãnh, bất thối, chánh niệm, tỉnh giác để đoạn tận các pháp bất thiện ấy.`, ref: "Tăng Chi Bộ 10.51", url: "https://loicuaducphat.org/an/an10.51.html#content" },


{ text: `- Này các Tỷ-kheo, có mười tưởng này, được tu tập, được làm cho sung mãn, đưa đến quả lớn, lợi ích lớn, thể nhập vào bất tử, lấy bất tử làm cứu cánh. Thế nào là mười? Tưởng vô thường, tưởng vô ngã, tưởng chết, tưởng nhàm chán trong các món ăn, tưởng không hoan hỷ đối với tất cả thế giới, tưởng xương, tưởng trùng ăn, tưởng xanh bầm, tưởng nứt nẻ, tưởng trương phồng. Này các Tỷ-kheo, mười tưởng này được tụ tập, được làm cho sung mãn, đưa đến quả lớn, lợi ích lớn, thể nhập vào bất tử, lấy bất tử làm cứu cánh.`, ref: "Tăng Chi Bộ 10.57", url: "https://loicuaducphat.org/an/an10.57.html#content" },

{ text: `- Này các Tỷ-kheo, mười tưởng này được tu tập, được làm cho sung mãn, đưa đến quả lớn, lợi ích lớn, thể nhập vào bất tử, lấy bất tử làm cứu cánh. Thế nào là mười? Tưởng bất tịnh, tưởng chết, tưởng nhàm chán trong các món ăn, tưởng không hoan hỷ đối với tất cả thế giới, tưởng vô thường, tưởng khổ trên vô thường, tưởng vô ngã trên khổ, tưởng đoạn tận, tưởng ly tham, tưởng đoạn diệt. Này các Tỷ-kheo, mười tưởng này, được tu tập, được làm cho sung mãn, đưa đến quả lớn, lợi ích lớn, thể nhập vào bất tử, lấy bất tử làm cứu cánh.`, ref: "Tăng Chi Bộ 10.56", url: "https://loicuaducphat.org/an/an10.56.html#content" },

{ text: `Này các Tỷ-kheo, các Thầy cần phải học tập như sau: “Tâm chúng ta sẽ được thực hành tích tập như khi xuất gia; các pháp bất thiện được sanh không có chinh phục tâm và không tồn tại; tâm chúng ta sẽ được thực hành tích tập với tưởng vô thường; tâm chúng ta sẽ được thực hành tích tập với tưởng vô ngã; tâm chúng ta sẽ được thực hành tích tập với tưởng bất tịnh; tâm chúng ta sẽ được thực hành tích tập với tưởng nguy hại; sau khi biết được thế giới thăng bằng và không thăng bằng, tâm chúng ta sẽ được thực hành tích tập với tưởng ấy. Sau khi biết được thế giới sanh khởi và đoạn diệt, tâm chúng ta sẽ được thực hành tích tập với tưởng ấy. Sau khi biết được thế giới tập khởi và chấm dứt, tâm chúng ta sẽ được thực hành tích tập với tưởng ấy; tâm chúng ta sẽ được thực hành tích tập với tưởng đoạn tận; tâm chúng ta sẽ được thực hành tích tập với tưởng ly tham, và tâm chúng ta sẽ được thực hành tích tập với tưởng đoạn diệt.” Như vậy, này các Tỷ-kheo, các Thầy cần phải học tập.`, ref: "Tăng Chi Bộ 10.59", url: "https://loicuaducphat.org/an/an10.59.html#content" },


{ text: `Và này Ananda, thế nào là tưởng nguy hại? Ở đây, này Ananda, Tỷ-kheo đi đến khu rừng, đi đến gốc cây, hay đi đến ngôi nhà trống, quán sát như sau: “Nhiều khổ là thân này, nhiều sự nguy hại. Như vậy trong thân này, nhiều loại bệnh khởi lên. Ví như bệnh đau mắt, bệnh đau về tai, bệnh đau mũi, bệnh đau lưỡi, bệnh đau thân, bệnh đau đầu, bệnh đau vành tai, bệnh đau miệng, bệnh đau răng, bệnh ho, bệnh suyễn, bệnh sổ mũi, bệnh sốt, bệnh già yếu, bệnh đau yếu, bệnh đau bụng, bất tỉnh, kiết lỵ, bệnh đau bụng quặn, bệnh thổ tả, bệnh hủi, bệnh ung nhọt, bệnh ghẻ lở, bệnh ho lao, bệnh trúng gió, bệnh da, bệnh ngứa, bệnh da đóng vảy, bệnh hắc lào lang ben, bệnh ghẻ, bệnh huyết đảm (mật trong máu), bệnh đái đường, bệnh trĩ, bệnh mụt nhọt, bệnh ung nhọt ung loét, các bệnh khởi lên do mật, bệnh khởi lên từ đàm, niêm dịch, các bệnh khởi lên từ gió; bệnh do hòa hợp các thể dịch sinh ra; các bệnh do thời tiết sinh ra, các bệnh do làm việc quá độ sanh, các bệnh do sự trùng hợp các sự kiêng; các bệnh do nghiệp thuần thục, lạnh, nóng, đói, khát, đại tiện, tiểu tiện”. Như vậy, vị ấy sống, quán sự nguy hại trong thân này.`, ref: "Tăng Chi Bộ 10.60", url: "https://loicuaducphat.org/an/an10.60.html#content" },


{ text: `- Thưa Hiền giả Sàriputta, thế nào là lạc, thế nào là khổ?<br>- Này Hiền giả, tái sanh là khổ, không tái sanh là lạc. Khi có tái sanh, này Hiền giả, chờ đợi là khổ này: Lạnh, nóng, đói, khát, đại tiện, tiểu tiện, xúc chạm với lửa, xúc chạm với trượng, xúc chạm với kiếm. Cho đến bà con và bạn bè, khi gặp nhau, hội ngộ với nhau cũng não hại. Này Hiền giả, tái sanh là khổ, khi có tái sanh, chờ đợi là khổ này. Khi không có tái sanh, này Hiền giả, chờ đợi là lạc này: Không lạnh, không nóng, không đói, không khát, không đại tiện, không tiểu tiện, không có xúc chạm với lửa, không có xúc chạm với trượng, không có xúc chạm với kiếm. Cho đến bà con bạn bè, khi gặp nhau, khi hội ngộ với nhau không có não hại. Này Hiền giả, khi không có tái sanh, chờ đợi là lạc này.`, ref: "Tăng Chi Bộ 10.65", url: "https://loicuaducphat.org/an/an10.65.html#content" },

{ text: `Ít người giữa nhân loại,<br>Ðến được bờ bên kia,<br>Còn số người còn lại,<br>Xuôi ngược chạy bờ này.<br>Những ai hành trì pháp,<br>Theo Chánh pháp khéo dạy,<br>Sẽ đến bờ bên kia,<br>Vượt ma giới khó thoát.<br>Kẻ trí bỏ pháp đen,<br>Tu tập theo pháp trắng,<br>Bỏ nhà, sống không nhà,<br>Sống viễn ly khổ lạc.<br>Hãy cầu vui Niết-bàn,<br>Bỏ dục, không chướng ngại,<br>Kẻ trí tự rửa sạch,<br>Cấu uế từ nội tâm.<br>Những ai với chánh tâm,<br>Khéo tu tập giác chi,<br>Từ bỏ mọi ái nhiễm<br>Hoan hỷ không chấp thủ,<br>Không lậu hoặc, sáng chói,<br>Sống tịch tịnh ở đời.`, ref: "Tăng Chi Bộ 10.117", url: "https://loicuaducphat.org/an/an10.117.html#content" },

                { text: `"Ý dẫn đầu các pháp,<br>Ý làm chủ, ý tạo;<br>Nếu với ý ô nhiễm,<br>Nói lên hay hành động,<br>Khổ não bước theo sau,<br>Như xe, chân vật kéo ".<br><br>"Ý dẫn đầu các pháp,<br>Ý làm chủ, ý tạo,<br>Nếu với ý thanh tịnh,<br>Nói lên hay hành động,<br>An lạc bước theo sau,<br>Như bóng, không rời hình ".`, ref: "Kinh Pháp Cú 1-20", url: "https://loicuaducphat.org/dhp/dhp1-20.html#content" },


{ text: `"Ai sống nhìn tịnh tướng,<br>không hộ trì các căn,<br>ăn uống thiếu tiết độ,<br>biếng nhác, chẳng tinh cần.<br>Ma uy hiếp kẻ ấy,<br>như cây yếu trước gió ".<br><br>"Ai sống quán bất tịnh,<br>Khéo hộ trì các căn,<br>ăn uống có tiết độ,<br>có lòng tin, tinh cần,<br>Ma không uy hiếp được,<br>Như núi đá, trước gió"`, ref: "Kinh Pháp Cú 1-20", url: "https://loicuaducphat.org/dhp/dhp1-20.html#content" },

{ text: `"Như ngôi nhà vụng lợp,<br>Mưa liền xâm nhập vào.<br>Cũng vậy tâm không tu,<br>Tham dục liền xâm nhập."<br><br>"Như ngôi nhà khéo lợp,<br>Mưa không xâm nhập vào.<br>Cũng vậy tâm khéo tu,<br>Tham dục không xâm nhập."`, ref: "Kinh Pháp Cú 1-20", url: "https://loicuaducphat.org/dhp/dhp1-20.html#content" },

{ text: `"Tâm hoảng hốt giao động,<br>Khó hộ trì, khó nhiếp,<br>Người trí làm tâm thẳng,<br>Như thợ tên, làm tên."<br><br>"Như cá quăng trên bờ,<br>Vất ra ngoài thủy giới;<br>Tâm này vũng vẫy mạnh,<br>Hãy đoạn thế lực Ma."<br><br>"Khó nắm giữ, khinh động,<br>Theo các dục quay cuồng.<br>Lành thay, điều phục tâm;<br>Tâm điều, an lạc đến."<br><br>"Tâm khó thấy, tế nhị,<br>Theo các dục quay cuồng.<br>Người trí phòng hộ tâm,<br>Tâm hộ, an lạc đến."`, ref: "Kinh Pháp Cú 33-43", url: "https://loicuaducphat.org/dhp/dhp33-43.html#content" },

{ text: `"Biết thân như đồ gốm,<br>Trú tâm như thành trì,<br>Chống ma với gươm trí;<br>Giữ chiến thắng không tham"<br><br>"Không bao lâu thân này,<br>Sẽ nằm dài trên đất,<br>Bị vất bỏ, vô thức,<br>Như khúc cây vô dụng."`, ref: "Kinh Pháp Cú 33-43", url: "https://loicuaducphat.org/dhp/dhp33-43.html#content" },

{ text: `"Biết thân như bọt nước,<br>Ngộ thân là như huyễn,<br>Bẻ tên hoa của ma,<br>Vượt tầm mắt thần chết."<br><br>"Người nhặt các loại hoa,<br>Ý đắm say, tham nhiễm,<br>Bị thần chết mang đi,<br>Như lụt trôi làng ngủ."<br><br>"Người nhặt các loại hoa,<br>Ý đắm say tham nhiễm,<br>Các dục chưa thỏa mãn,<br>Ðã bị chết chinh phục."`, ref: "Kinh Pháp Cú 44-59", url: "https://loicuaducphat.org/dhp/dhp44-59.html#content" },

{ text: `"Người trị thủy dẫn nước,<br>Kẻ làm tên nắn tên,<br>Người thợ mộc uốn gỗ,<br>Bậc trí nhiếp tự thân."<br><br>"Như đá tảng kiên cố,<br>Không gió nào giao động,<br>Cũng vậy, giữa khen chê,<br>Người trí không giao động."<br><br>"Như hồ nước sâu thẳm,<br>Trong sáng, không khuấy đục,<br>Cũng vậy, nghe chánh pháp,<br>Người trí hưởng tịnh lạc."<br><br>"Người hiền bỏ tất cả,<br>Người lành không bàn dục,<br>Dầu cảm thọ lạc khổ,<br>Bậc trí không vui buồn."`, ref: "Kinh Pháp Cú 76-89", url: "https://loicuaducphat.org/dhp/dhp76-89.html#content" },

{ text: `"Cười gì, hân hoan gì,<br>Khi đời mãi bị thiêu?<br>Bị tối tăm bao trùm,<br>Sao không tìm ngọn đèn?"<br><br>"Hãy xem bong bóng đẹp,<br>Chỗ chất chứa vết thương,<br>Bệnh hoạn nhiều suy tư,<br>Thật không gì trường cửu."<br><br>"Sắc này bị suy già,<br>Ổ tật bệnh, mỏng manh,<br>Nhóm bất tịnh, đỗ vỡ,<br>Chết chấm dứt mạng sống."<br><br>"Như trái bầu mùa thu,<br>Bị vất bỏ quăng đi,<br>Nhóm xương trắng bồ câu,<br>Thấy chúng còn vui gì?"`, ref: "Kinh Pháp Cú 146-156", url: "https://loicuaducphat.org/dhp/dhp146-156.html#content" },

{ text: `"Thành này làm bằng xương,<br>Quét tô bằng thịt máu,<br>Ở đây già và chết,<br>Mạn, lừa đảo chất chứa."<br><br>"Xe vua đẹp cũng già.<br>Thân này rồi sẽ già,<br>Pháp bậc thiện, không già.<br>Như vậy bậc chí thiện<br>Nói lên cho bậc thiện."<br><br>"Người ít nghe kém học,<br>Lớn già như trâu đực.<br>Thịt nó tuy lớn lên,<br>Nhưng tuệ không tăng trưởng."`, ref: "Kinh Pháp Cú 146-156", url: "https://loicuaducphat.org/dhp/dhp146-156.html#content" },

{ text: `"Lang thang bao kiếp sống<br>Ta tìm nhưng chẳng gặp,<br>Người xây dựng nhà này,<br>Khổ thay, phải tái sanh."<br><br>"Ôi! Người làm nhà kia<br>Nay ta đã thấy ngươi!<br>Ngươi không làm nhà nữa.<br>Ðòn tay ngươi bị gẫy,<br>Kèo cột ngươi bị tan<br>Tâm ta đạt tịch diệt,<br>Tham ái thảy tiêu vong."`, ref: "Kinh Pháp Cú 146-156", url: "https://loicuaducphat.org/dhp/dhp146-156.html#content" },

{ text: `"Ai sống trước buông lung,<br>Sau sống không phóng dật,<br>Chói sáng rực đời này.<br>Như trăng thoát mây che."<br><br>"Ai dùng các hạnh lành,<br>Làm xóa mờ nghiệp ác,<br>Chói sáng rực đời này,<br>Như trăng thoát mây che."<br><br>"Ðời này thật mù quáng,<br>Ít kẻ thấy rõ ràng.<br>Như chim thoát khỏi lưới,<br>Rất ít đi thiên giới."<br><br>"Như chim thiên nga bay,<br>Thần thông liệng giữa trời;<br>Chiến thắng ma, ma quân,<br>Kẻ trí thoát đời này."`, ref: "Kinh Pháp Cú 167-178", url: "https://loicuaducphat.org/dhp/dhp167-178.html#content" },


{ text: `"Dầu mưa bằng tiền vàng,<br>Các dục khó thỏa mãn.<br>Dục đắng nhiều ngọt ít,<br>Biết vậy là bậc trí."<br><br>"Ðệ tử bậc chánh giác,<br>Không tìm cầu dục lạc,<br>Dầu là dục chư thiên,<br>Chỉ ưa thích ái diệt."`, ref: "Kinh Pháp Cú 179-196", url: "https://loicuaducphat.org/dhp/dhp179-196.html#content" },


{ text: `"Ái luyến sinh sầu ưu,<br>Ái luyến sinh sợ hải.<br>Ai giải thoát ái luyến<br>Không sầu, đâu sợ hãi?"<br><br>"Hỷ ái sinh sầu ưu,<br>Hỷ ái sinh sợ hãi.<br>Ai giải thoát hỷ ái,<br>Không sầu, đâu sợ hãi?<br><br>"Dục ái sinh sầu ưu,<br>Dục ái sinh sợ hãi,<br>Ai thoát khỏi dục ái,<br>Không sầu, đâu sợ hãi?"<br><br>"Tham ái sinh sầu ưu,<br>Tham ái sinh sợ hãi.<br>Ai thoát khỏi tham ái,<br>Không sầu, đâu sợ hãi."`, ref: "Kinh Pháp Cú 209-220", url: "https://loicuaducphat.org/dhp/dhp209-220.html#content" },


{ text: `"Tất cả hành vô thường "<br>Với Tuệ, quán thấy vậy<br>Ðau khổ được nhàm chán;<br>Chính con đường thanh tịnh."<br><br>"Tất cả hành khổ đau<br>Với Tuệ quán thấy vậy,<br>Ðau khổ được nhàm chán;<br>Chính con đường thanh tịnh."<br><br>"Tất cả pháp vô ngã,<br>Với Tuệ quán thấy vậy,<br>Ðau khổ được nhàm chán<br>Chính con đường thanh tịnh."`, ref: "Kinh Pháp Cú 273-289", url: "https://loicuaducphat.org/dhp/dhp273-289.html#content" },

{ text: `"Ðốn rừng không đốn cây<br>Từ rừng, sinh sợ hãi;<br>Ðốn rừng và ái dục,<br>Tỷ kheo, hãy tịch tịnh."<br><br>"Khi nào chưa cắt tiệt,<br>Ái dục giữa gái trai,<br>Tâm ý vẫn buộc ràng,<br>Như bò con vú mẹ."<br><br>"Tự cắt giây ái dục,<br>Như tay bẻ sen thu,<br>Hãy tu đạo tịch tịnh,<br>Niết-Bàn, Thiện Thệ dạy."`, ref: "Kinh Pháp Cú 273-289", url: "https://loicuaducphat.org/dhp/dhp273-289.html#content" },

{ text: `"Người sống đời phóng dật,<br>Ái tăng như giây leo.<br>Nhảy đời này đời khác,<br>Như vượn tham quả rừng."<br><br>"Ai sống trong đời này,<br>Bị ái dục buộc ràng<br>Sầu khổ sẽ tăng trưởng,<br>Như cỏ Bi gặp mưa."<br><br>"Ai sống trong đời này<br>Ái dục được hàng phục<br>Sầu rơi khỏi người ấy<br>Như giọt nước lá sen."`, ref: "Kinh Pháp Cú 334-359", url: "https://loicuaducphat.org/dhp/dhp334-359.html#content" },

{ text: `"Ðây điều lành Ta dạy,<br>Các người tụ họp đây.<br>Hãy nhổ tận gốc ái<br>Như nhổ gốc cỏ Bi.<br>Chớ để ma phá hoại,<br>Như giòng nước cỏ lau."<br><br>"Như cây bị chặt đốn,<br>Gốc chưa hại vẫn bền<br>Ái tùy miên chưa nhổ,<br>Khổ này vẫn sanh hoài."<br><br>"Ba mươi sáu dòng Ái,<br>Trôi người đốn khả ái.<br>Các tư tưởng tham ái.<br>Cuốn trôi người tà kiến."`, ref: "Kinh Pháp Cú 334-359", url: "https://loicuaducphat.org/dhp/dhp334-359.html#content" },


{ text: `"Dòng ái dục chảy khắp,<br>Như giây leo mọc tràn,<br>Thấy giây leo vừa sanh,<br>Với tuệ, hãy đoạn gốc."<br><br>"Người đời nhớ ái dục,<br>Ưa thích các hỷ lạc.<br>Tuy mong cầu an lạc,<br>Họ vẫn phải sanh già."<br><br>"Người bị ái buộc ràng,<br>Vùng vẫy và hoảng sợ,<br>Như thỏ bị sa lưới.<br>Họ sanh ái trói buộc,<br>Chịu khổ đau dài dài."<br><br>"Người bị ái buộc ràng,<br>Vùng vẫy và hoảng sợ,<br>Như thỏ bị sa lưới.<br>Do vậy vị tỷ kheo,<br>Mong cầu mình ly tham<br>Nên nhiếp phục ái dục."`, ref: "Kinh Pháp Cú 334-359", url: "https://loicuaducphat.org/dhp/dhp334-359.html#content" },

{ text: `"Người đắm say ái dục<br>Tự lao mình xuống dòng<br>Như nhện sa lưới dệt.<br>Người trí cắt trừ nó,<br>Bỏ mọi khổ, không màng."`, ref: "Kinh Pháp Cú 334-359", url: "https://loicuaducphat.org/dhp/dhp334-359.html#content" },


{ text: `"Người tà ý nhiếp phục,<br>Tham sắc bén nhìn tịnh,<br>Người ấy ái tăng trưởng,<br>Làm giây trói mình chặt."<br><br>"Ai vui, an tịnh ý,<br>Quán bất tịnh, thường niệm,<br>Người ấy sẽ diệt ái,<br>Cắt đứt Ma trói buộc."<br><br>"Ai tới đích, không sợ,<br>Ly ái, không nhiễm ô<br>Nhổ mũi tên sanh tử,<br>Thân này thân cuối cùng."`, ref: "Kinh Pháp Cú 334-359", url: "https://loicuaducphat.org/dhp/dhp334-359.html#content" },

{ text: `"Lành thay, phòng hộ mắt!<br>Lành thay, phòng hộ tai.<br>Lành thay, phòng hộ mũi,<br>Lành thay, phòng hộ lưỡi."<br><br>"Lành thay,phòng hộ thân!<br>Lành thay, phòng hộ lời,<br>Lành thay, phòng hộ ý.<br>Lành thay, phòng tất cả.<br>Tỷ kheo phòng tất cả.<br>Thoát được mọi khổ đau."<br><br>"Người chế ngự tay chân,<br>Chế ngự lời và đầu,<br>Vui thích nội thiền định.<br>Ðộc thân, biết vừa đủ,<br>Thật xứng gọi tỷ kheo."`, ref: "Kinh Pháp Cú 360-382", url: "https://loicuaducphat.org/dhp/dhp360-382.html#content" },

{ text: `"Tỷ kheo, hãy tu thiền,<br>Chớ buông lung phóng dật,<br>Tâm chớ đắm say dục,<br>Phóng dật, nuốt sắt nóng<br>Bị đốt, chớ than khổ!"<br><br>"Không trí tuệ, không thiền,<br>Không thiền, không trí tuệ.<br>Người có thiền có tuệ,<br>Nhất định gần Niết-Bàn."<br><br>"Bước vào ngôi nhà trống,<br>Tỷ kheo tâm an tịnh,<br>Thọ hưởng vui siêu nhân<br>Tịnh quán theo chánh pháp."<br><br>"Người luôn luôn chánh niệm,<br>Sự sanh diệt các uẩn,<br>Ðược hoan hỷ, hân hoan,<br>Chỉ bậc bất tử biết."`, ref: "Kinh Pháp Cú 360-382", url: "https://loicuaducphat.org/dhp/dhp360-382.html#content" },

{ text: `"Hỡi này Bà là môn,<br>Hãy tinh tấn đoạn dòng,<br>Từ bỏ các dục lạc,<br>Biết được hành đoạn diệt,<br>Người là bậc vô vi."<br><br>"Nhờ thường trú hai pháp<br>Ðến được bờ bên kia.<br>Bà-la-môn có trí,<br>Mọi kiết sử dứt sạch."<br><br>"Không bờ này, bờ kia<br>Cả hai bờ không có,<br>Lìa khổ, không trói buộc<br>Ta gọi Bà-la-môn."<br><br>"Tu thiền, trú ly trần<br>Phận sự xong, vô lậu,<br>Ðạt được đích tối thượng,<br>Ta gọi Bà-la-môn."`, ref: "Kinh Pháp Cú 383-423", url: "https://loicuaducphat.org/dhp/dhp383-423.html#content" },


{ text: `"Người không còn tham ái,<br>Có trí, không nghi hoặc,<br>Thể nhập vào bất tử,<br>Ta gọi Bà-la-môn."<br><br>"Người sống ở đời này<br>Không nhiễm cả thiện ác,<br>Không sầu, sạch không bụi<br>Ta gọi Bà-la-môn."<br><br>"Như trăng, sạch không uế<br>Sáng trong và tịnh lặng,<br>Hữu ái, được đoạn tận,<br>Ta gọi Bà là môn."<br><br>"Vượt đường nguy hiểm này,<br>Nhiếp phục luân hồi, si,<br>Ðến bờ kia thiền định<br>Không dục ái, không nghi,<br>Không chấp trước, tịch tịnh,<br>Ta gọi Bà-la-môn."`, ref: "Kinh Pháp Cú 383-423", url: "https://loicuaducphat.org/dhp/dhp383-423.html#content" },

{ text: `"Ai ở đời, đoạn dục,<br>Bỏ nhà, sống xuất gia,<br>Dục hữu được đoạn tận,<br>Ta gọi Bà-la-môn."<br><br>"Ai ở đời đoạn ái<br>Bỏ nhà, sống xuất gia,<br>Ái hữu được đoạn tận,<br>Ta gọi Bà-la-môn."<br><br>"Bỏ trói buộc loài người,<br>Vượt trói buộc cõi trời.<br>Giải thoát mọi buộc ràng,<br>Ta gọi Bà-la-môn."<br><br>"Bỏ điều ưa, điều ghét,<br>Mát lạnh, diệt sanh y<br>Bậc anh hùng chiến thắng,<br>Nhiếp phục mọi thế giới,<br>Ta gọi Bà-la-môn."`, ref: "Kinh Pháp Cú 383-423", url: "https://loicuaducphat.org/dhp/dhp383-423.html#content" },

{ text: `Viễn ly là an lạc,<br>Với người biết tri túc,<br>Với người có nghe pháp,<br>Với người có chánh kiến<br><br>Không sân là an lạc,<br>Những ai ở trên đời,<br>Ðối hữu tình chúng sanh<br>Biết tự chế, ngăn ngừa.<br><br>Ly tham là an lạc,<br>Vượt các dục ở đời,<br>Ai nhiếp phục ngã mạn,<br>Ðây an lạc tối thượng.`, ref: "Udana 2.1", url: "https://loicuaducphat.org/ud/ud2.1.html#content" },

{ text: `Ai vượt khỏi bùn này,<br>Ðè bẹp gai của dục,<br>Ðạt được si đoạn diệt,<br>Vị Tỷ-kheo như vậy,<br>Không cảm thọ khổ lạc!`, ref: "Udana 3.2", url: "https://loicuaducphat.org/ud/ud3.2.html#content" },

{ text: `Ai đã thắng gai dục,<br>Nắng, gia hại, trói buộc,<br>Vị ấy đứng bất động,<br>Như núi vững an trú,<br>Vị Tỷ-kheo như vầy,<br>Lạc khổ không dao động.`, ref: "Udana 3.3", url: "https://loicuaducphat.org/ud/ud3.3.html#content" },

{ text: `Do duyên sanh y, khổ này được sanh khởi. Chính do đoạn diệt tất cả sanh y, khổ không có hiện hữu.<br><br>Hãy xem đời rộng này,<br>Bị vô minh chi phối,<br>Các sanh loại được sanh,<br>Ưa thích được sanh khởi,<br>Không thoát được sanh hữu.<br><br>Với ai đốt sanh hữu,<br>Tất cả mọi thời, xứ,<br>Tất cả sanh hữu này,<br>Vô thường khổ biến hoại,<br><br>Như vậy, thấy như thật,<br>Với chơn chánh trí tuệ,<br>Hữu ái được đoạn tận,<br>Phi hữu ái hoan hỷ.<br><br>Ðoạn diệt ái hoàn toàn,<br>Ly tham, diệt, hoàn toàn,<br>Như vậy là Niết Bàn,<br>Tỷ-kheo ấy mát lạnh,<br>Không chấp thủ tái sanh,<br>Nhiếp phục được ma vương,<br>Trận chiến đã chiến thắng,<br>Vị Tỷ-kheo như vậy,<br>Vượt qua mọi sanh hữu.`, ref: "Udana 3.10", url: "https://loicuaducphat.org/ud/ud3.10.html#content" },

{ text: `Lại nữa, này Meghiya, với vị Tỷ-kheo khéo an trú trong năm pháp này, bốn pháp cần phải tu tập thêm: Bất tịnh cần phải tu tập để đoạn tận tham; Từ cần phải tu tập để đoạn tận sân; Niệm hơi thở vô hơi thở ra cần phải tu tập để trừ khử tầm tư; Vô thường tưởng cần phải tu tập để nhổ lên kiêu mạn, tôi là. Này Meghiya, với ai có tưởng vô thường, tưởng vô ngã được an trú. Với ai có tưởng vô ngã, vị ấy đạt được sự nhổ lên kiêu mạn: tôi là, Niết-bàn ngay trong hiện tại.`, ref: "Udana 4.1", url: "https://loicuaducphat.org/ud/ud4.1.html#content" },

{ text: `Tâm ai như tảng đá,<br>An trú không dao động,<br>Không tham vật khả ái,<br>Ðáng phẫn nộ, không sân,<br>Tâm ai tu như vậy,<br>Từ đâu khổ đến được?`, ref: "Udana 4.4", url: "https://loicuaducphat.org/ud/ud4.4.html#content" },

{ text: `"Ở đây, bạch Thế Tôn, nhiều người ở Sàvatthi, phần lớn đắm say quá độ về các dục, sống say đắm, tham đắm, tham muốn, tham mê, bị trói buộc, bị mê say trong các dục." Thế Tôn, sau khi hiểu biết ý nghĩa này, ngay trong lúc ấy, nói lên lời cảm hứng này:<br><br>Chúng sanh bị tham đắm,<br>Trong các loại ái dục,<br>Họ không thấy lỗi lầm,<br>Trong phiền não kiết sử,<br><br>Chắc chắn các chúng sanh,<br>Trói buộc trong kiết sử,<br>Họ không vượt qua được,<br>Dòng lũ lớn rộng này.`, ref: "Udana 7.3", url: "https://loicuaducphat.org/ud/ud7.3.html#content" },

{ text: `Rồi Thế Tôn thấy các người ấy ở Sàvatthi, phần lớn đắm say quá độ về các dục, sống say đắm, tham đắm, tham muốn, tham mê, bị trói buộc, bị mê say trong các dục. Rồi Thế Tôn, sau khi hiểu biết ý nghĩa này, ngay trong lúc ấy, nói lên lời cảm hứng này:<br><br>Bị mù bởi các dục,<br>Bị bao phủ bởi lưới,<br>Bị ái dục bao trùm,<br>Lại còn bị trói buộc,<br>Bởi trói buộc phóng dật,<br>Như cá mắc miệng lưới,<br>Họ đi đến già chết,<br>Như con bê bú sữa.`, ref: "Udana 7.4", url: "https://loicuaducphat.org/ud/ud7.4.html#content" },

                { text: `Này các Tỷ-kheo, hãy từ bỏ một pháp. Ta bảo đảm cho các Thầy không có tái sanh. Thế nào là một pháp? Tham, này các Tỷ-kheo, là một pháp, các Thầy hãy từ bỏ! Ta bảo đảm cho các Thầy không có tái sanh. Thế Tôn đã nói lên ý nghĩa này. Ở đây, điều này đã được nói đến.<br><br>Với tham bị tham đắm,<br>Chúng sanh đi ác thú,<br>Bậc thiền quán, chánh trí,<br>Từ bỏ tham ái ấy,<br>Từ bỏ, không bao giờ<br>Trở lại tại đời này.`, ref: "Itivuttaka 1", url: "https://loicuaducphat.org/iti/iti1.html#content" },


{ text: `Này các Tỷ-kheo, ai không thắng tri, không liễu tri tất cả, ở đây tâm không ly tham, từ bỏ, không thể diệt được khổ đau. Này các Tỷ-kheo, ai thắng tri, liễu tri tất cả, ở đây tâm ly tham, từ bỏ, có thể diệt được khổ đau. Thế Tôn đã nói lên ý nghĩa này. Ở đây, điều này được nói đến.<br><br>Ai hiểu, rõ biết được,<br>Tất cả là tất cả,<br>Ðối với tất cả chỗ,<br>Không có sự tham đắm,<br>Vị như vậy chắc chắn,<br>Liễu tri được tất cả,<br>Và có thể vượt qua,<br>Tất cả mọi đau khổ.`, ref: "Itivuttaka 7", url: "https://loicuaducphat.org/iti/iti7.html#content" },


{ text: `Này các Tỷ-kheo, Ta không thấy một triền cái nào khác, do bị bao trùm bởi triền cái ấy, chúng sanh trong một thời gian dài, lưu chuyển. Này các Tỷ-kheo, tức là Vô minh triền cái. Này các Tỷ-kheo, bị bao trùm bởi Vô minh triền cái, chúng sanh trong một thời gian dài chạy dài, lưu chuyển.<br><br>Không có một pháp khác,<br>Quần sanh bị bao phủ,<br>Ngày đêm chạy lưu chuyển,<br>Như bao phủ bởi si.<br><br>Và ai đoạn diệt si,<br>Ðâm thủng khối u ám,<br>Họ không lưu chuyển nữa,<br>Trong họ, nhân không còn.`, ref: "Itivuttaka 14", url: "https://loicuaducphat.org/iti/iti14.html#content" },


{ text: `Này các Tỷ-kheo, Ta không thấy một kiết sử nào khác, do bị cột bởi kiết sử ấy, chúng sanh trong một thời gian dài, chạy dài, lưu chuyển, này các Tỷ-kheo tức là Ái kiết sử. Này các Tỷ-kheo, bị cột với ái kiết sử, chúng sanh trong một thời gian dài, chạy dài lưu chuyển.<br><br>Người có ái làm bạn,<br>Thời gian dài, lưu chuyển,<br>Không vượt được lưu chuyển,<br>Sanh hữu vậy hay khác.<br><br>Ai biết nguy hiểm này,<br>Biết ái tác thành khổ,<br>Bỏ ái, không chấp trước,<br>Tỷ-kheo giữ chánh niệm,<br>Bỏ gia đình xuất gia,<br>Sống nếp sống như vậy.`, ref: "Itivuttaka 15", url: "https://loicuaducphat.org/iti/iti15.html#content" },


{ text: `Các xương của một người, này các Tỷ-kheo, chạy dài, lưu chuyển có thể lớn như một đồi xương, một chồng xương, một đống xương, như núi Vepulla này, nếu có người thâu người lượm xương lại, gìn giữ chúng không làm chúng hủy hoại.<br><br>Chồng chất như xương người,<br>Chỉ sống có một kiếp,<br>Chất đống bằng hòn núi,<br>Bậc Ðại sĩ nói vậy.<br><br>Ðống xương ấy được nói,<br>Lớn như Vepulla,<br>Phía Bắc núi Linh Thứu,<br>Thành núi Magadha.<br><br>Người thấy bốn sự thật,<br>Với chân chánh trí tuệ<br>Khổ và khổ tập khởi,<br>Sẽ vượt qua đau khổ,<br>Con đường Thánh tám ngành,<br>Dẫn đến khổ tịnh chỉ.<br><br>Người ấy phải luân chuyển,<br>Tối đa là bảy lần,<br>Là vị đoạn tận khổ,<br>Ðoạn diệt mọi kiết sử.`, ref: "Itivuttaka 24", url: "https://loicuaducphat.org/iti/iti24.html#content" },

{ text: `Có cái sanh, hiện hữu,<br>Cái khởi lên làm ra,<br>Hữu vi không thường hằng,<br>Tác thành ra già chết,<br>Một ổ của bệnh hoạn,<br>Mỏng manh, giòn, dễ vỡ,<br><br>Nhờ đồ ăn nuôi dưỡng,<br>Nên mới được hiện hữu,<br>Vật ấy thật không đủ<br>Ðể hoan hỷ ưa thích,<br>Thật có cái xuất ly,<br>Ra khỏi được cái ấy,<br>Thật có vượt lý luận,<br><br>Thường hằng, không sanh khởi,<br>Không có cái khởi lên,<br>Con đường không cấu uế,<br>Không đưa đến sầu muộn,<br>Ðoạn diệt các pháp khổ,<br>Sự tịnh chỉ mọi hành,<br>An lạc thật tịnh lạc.`, ref: "Itivuttaka 43", url: "https://loicuaducphat.org/iti/iti43.html#content" },


{ text: `Này các Tỷ-kheo, có ba khát ái này. Thế nào là ba? Dục ái, hữu ái, phi hữu ái. Này các Tỷ-kheo, có ba khát ái này.<br><br>Trói buộc bởi ái triền,<br>Tâm ưa hữu, phi hữu,<br>Bị ma triền trói buộc,<br>Chúng sanh ấy không được,<br>An ổn khỏi ách nạn.<br>Chúng sanh đi luân chuyển,<br>Ðến sanh rồi đến chết.<br><br>Những ai đoạn được ái,<br>Ly ái hữu, phi hữu,<br>Họ đến bờ bên kia,<br>Trong thế giới hiện tại,<br>Họ đã chứng đạt được,<br>Các lậu hoặc đoạn tận.`, ref: "Itivuttaka 58", url: "https://loicuaducphat.org/iti/iti58.html#content" },

{ text: `Này các Tỷ-kheo, với ai tham chưa đoạn tận, sân chưa đoạn tận, si chưa đoạn tận. Này các Tỷ-kheo, người ấy được gọi là người bị trói buộc với Ác ma, bị bẫy lưới của Ác ma bao trùm, bị làm theo ý Ác ma muốn.<br><br>Này các Tỷ-kheo, với ai tham đã đoạn tận, sân đã đoạn tận, si đã đoạn tận, này các Tỷ-kheo, người ấy được gọi là người không trói buộc với Ác ma, được thoát khỏi bẫy lưới của Ác ma, không bị làm theo Ác ma muốn.<br><br>Với ai đã từ bỏ<br>Tham, sân và vô minh,<br>Vị ấy được gọi là<br>Ðã tu tập tự ngã,<br><br>Ðã trở thành Phạm Thiên<br>Bậc Như Lai, Phật-đà,<br>Bậc đã vượt qua được,<br>Hận thù và sợ hãi,<br>Bậc đoạn tận tất cả,<br>Ðược gọi danh như vậy.`, ref: "Itivuttaka 68", url: "https://loicuaducphat.org/iti/iti68.html#content" },

{ text: `Với Tỷ-kheo hay Tỷ-kheo-ni nào, này các Tỷ-kheo, tham chưa đoạn tận, sân chưa đoạn tận, si chưa đoạn tận; này các Tỷ-kheo, vị ấy được gọi là vị chưa vượt qua đại dương, với sóng biển, với sóng ngầm, với nước xoáy, với cá mập, với các loài La-sát.<br><br>Này các Tỷ-kheo, với Tỷ-kheo hay Tỷ-kheo ni nào, tham đã đoạn tận, sân đã đoạn tận, si đã đoạn tận; này các Tỷ-kheo, vị ấy được gọi là: "Ðã vượt qua đại dương, với sóng biển, với sóng ngầm, với nước xoáy, với cá mập, với các loài la-sát, đã vượt qua bờ kia, là vị Bà-la-môn đã đứng trên đất liền.<br><br>Với ai đã từ bỏ<br>Tham, sanh và vô minh,<br>Vị ấy được gọi là<br>Ðã vượt qua biển này,<br>Với cá mập, Dạ-xoa,<br>Với sóng biển hãi hùng,<br>Rất khó được vượt qua,<br>Là vị vượt ác triền.<br><br>Ðã từ bỏ thần chết,<br>Không còn có sanh y,<br>Ðã từ bỏ đau khổ,<br>Không còn có tái sanh,<br>Ðã đi đến mục đích,<br>Không thể ước lượng được,<br>Ta nói rằng vị ấy<br>Làm ma vương si ám.`, ref: "Itivuttaka 69", url: "https://loicuaducphat.org/iti/iti69.html#content" },

{ text: `Này các Tỷ-kheo, có ba xuất ly giới này. Thế nào là ba? Sự xuất ly này khỏi các dục, tức là viễn ly. Sự xuất ly này khỏi các sắc, tức là vô sắc. Sự đoạn diệt cái gì được hiện hữu, được làm ra, được duyên khởi, là sự xuất ly cái ấy. Này các Tỷ-kheo, có ba xuất ly giới này.<br><br>Biết được xuất ly dục,<br>Vượt qua được các sắc,<br>Tịnh chỉ tất cả hành,<br>Luôn luôn cảm nhiệt tình.<br><br>Tỷ-kheo ấy thấy chánh,<br>Từ đấy, chính ở đây,<br>Vị ấy được giải thoát,<br>Thắng trí được viên thành,<br>Sống nếp sống an tịnh<br>Vị ấy sống như vậy,<br>Thật sự là ẩn sĩ,<br>Ðã vượt khỏi các ách.`, ref: "Itivuttaka 72", url: "https://loicuaducphat.org/iti/iti72.html#content" },

{ text: `Này các Tỷ-kheo, thân này bị hủy hoại, thức bị lụn tàn, tất cả sanh y là vô thường, khổ, chịu sự biến hoại.<br><br>Biết thân bị huỷ hoại,<br>Còn thức bị lụn tàn,<br>Thấy sợ trong sanh y,<br>Hiểu được sanh và chết.<br><br>Sau khi chứng đạt được,<br>Sự an tịnh tối thượng,<br>Tự ngã được tu tập,<br>Chỉ còn đợi thời gian.`, ref: "Itivuttaka 77", url: "https://loicuaducphat.org/iti/iti77.html#content" },


{ text: `Này các Tỷ-kheo, hãy sống tuỳ quán bất tịnh trên thân, hãy khéo an trú niệm hơi thở vô hơi thở ra, đặt niệm trước mặt, hướng về nội tâm; hãy sống tùy quán vô thường trong tất cả các hành. Này các Tỷ-kheo, khi sống tùy quán bất tịnh trên thân tham tùy miên đối với tịnh giới được đoạn trừ; khi khéo an trú niệm hơi thở vô hơi thở ra, đặt niệm trước mặt, hướng về nội tâm, thời các tâm hướng ngoại, dự phần vào tổn hại không có; khi sống tùy quán vô thường trong tất cả hành, thời vô minh trừ diệt, minh được khởi lên.<br><br>Quán bất tịnh trên thân,<br>Niệm thở vô thở ra,<br>Tịnh chỉ tất cả hành,<br>Thường nhiệt tâm, chánh kiến,<br><br>Vị Tỷ-kheo như vậy,<br>Ðã thấy rất chơn chánh,<br>Từ đấy ở nơi đây,<br>Vị ấy được giải thoát,<br>Thắng trí được thành tựu,<br>Lắng dịu thật an tịnh,<br>Vị ẩn sĩ như vậy,<br>Chắc vượt khỏi ách nạn.`, ref: "Itivuttaka 85", url: "https://loicuaducphat.org/iti/iti85.html#content" },

{ text: `Này các Tỷ-kheo, dục tầm tác thành mù, tác thành không mắt, tác thành không trí, đưa đến tuệ đoạn diệt, dự phần vào tổn hại, không đưa đến Niết-bàn. Này các Tỷ-kheo, sân tầm tác thành mù, tác thành không mắt, tác thành không trí, đưa đến tuệ đoạn diệt, dự phần vào tổn hại, không đưa đến Niết-bàn. Này các Tỷ-kheo, hại tầm tác thành mù, tác thành không mắt, tác thành không trí, đưa đến tuệ đoạn diệt, dự phần vào tổn hại, không đưa đến Niết-bàn.<br><br>Hãy suy tư, suy tầm,<br>Ba tầm thuộc chánh thiện,<br>Ðối ba tư duy ác,<br>Hãy từ bỏ, lánh xa,<br>Vị ấy chắc chế ngự,<br>Hành tướng các tư duy,<br><br>Như cơn mưa dẹp sạch,<br>Các bụi bặm chất chứa.<br>Vị ấy thật chắc chắn<br>An tịnh tầm với tâm.<br>Ở đây vị ấy đạt,<br>Con đường an tịnh đạo.`, ref: "Itivuttaka 87", url: "https://loicuaducphat.org/iti/iti87.html#content" },


{ text: `Tham sanh ra bất hạnh,<br>Tham làm tâm dao động,<br>Tham chính là sợ hãi,<br>Sanh ra từ bên trong,<br>Loài Người không rõ biết<br>Loại tham đặc biệt ấy.<br><br>Người tham không biết rõ<br>Ðâu chính là lợi ích,<br>Người tham không thấy được<br>Ðâu chính là Chánh pháp.<br>Mù lòa và tối tăm,<br>Sẽ xuất hiện, có mặt,<br>Ở nơi một người nào,<br>Có tham cùng chung sống.<br><br>Ai đoạn trừ được tham,<br>Không tham vật đáng tham,<br>Với ai tham đoạn trừ<br>Như giọt nước lá sen.<br><br>Sân sanh ra bất hạnh,<br>Sân làm tâm dao động.<br>Sân chính là sợ hãi,<br>Sanh ra từ bên trong<br>Loài Người không rõ biết,<br>Lòng sân đặc biệt ấy.<br><br>Người sân không biết rõ<br>Ðâu chính là lợi ích,<br>Người sân không thấy được<br>Ðâu chính là Chánh pháp,<br>Mù lòa và tối tăm,<br>Sẽ xuất hiện, có mặt,<br>Ở nơi sân người nào,<br>Có sân cùng chung sống.<br><br>Ai đoạn trừ được sân,<br>Không sân việc đáng sân,<br>Với ai, sân đoạn trừ,<br>Như quả cây ta-la<br>Ðược chặt đứt khỏi cành.<br><br>Si sanh ra bất hạnh,<br>Si làm tâm dao động,<br>Si chính là sợ hãi,<br>Sanh ra từ bên trong,<br>Loài Người không rõ biết<br>Lòng si đặc biệt ấy.<br><br>Người si không rõ biết<br>Ðâu chính là lợi ích,<br>Người si không thấy được<br>Ðâu chính là Chánh pháp,<br>Mù lòa và tối tăm<br>Sẽ xuất hiện, có mặt,<br>Ở nơi một người nào,<br>Có si cùng chung sống.<br><br>Ai đoạn trừ được si,<br>Không si việc đáng si,<br>Vị ấy quét sạch được<br>Tất cả mọi si ám,<br>Như mặt trời mọc lên,<br>Quét sạch mọi tăm tối.`, ref: "Itivuttaka 88", url: "https://loicuaducphat.org/iti/iti88.html#content" },


{ text: `Này các Tỷ-kheo, có ba nội uế, nội thù này, nội đối thủ, nội sát nhân, nội thù địch này. Thế nào là ba? Tham, này các Tỷ-kheo, là nội uế, nội thù, nội đối thủ, nội sát thủ, nội sát nhân, nội thù địch. Sân, này các Tỷ-kheo, là nội uế, nội thù, nội đối thủ, nội sát nhân, nội thù địch. Si, này các Tỷ-kheo, là nội uế, nội thù, nội đối thủ, nội sát nhân, nội thù địch. Này các Tỷ-kheo, có ba nội uế, nội thù, nội đối thủ, nội sát nhân, nội thù địch này.`, ref: "Itivuttaka 88", url: "https://loicuaducphat.org/iti/iti88.html#content" },


{ text: `Này các Tỷ-kheo, có ba loại lửa này. Thế nào là ba? Lửa tham, lửa sân, lửa si. Này các Tỷ-kheo, có ba loại lửa này.<br><br>Lửa tham đốt cháy người,<br>Say mê trong các dục,<br>Còn lửa sân đốt cháy,<br>Những người có sân hận,<br>Những người giết, sát hại,<br>Các loại có sanh mạng.<br><br>Còn lửa si đốt cháy,<br>Những kẻ bị mê muội,<br>Những kẻ không tinh luyện,<br>Trong giáo pháp bậc Thánh,<br>Do không được biết rõ<br>Các loại lửa như vậy,<br>Nên loài Người ưa thích,<br>Vui thích với có thân.<br><br>Họ làm cảnh dịa ngục,<br>Ðược lớn mạnh tăng trưởng,<br>Kể cả giới bàng sanh,<br>Chỗ sanh xứ súc vật,<br>Cùng với A-tu-la,<br>Với cảnh giới quỷ đói,<br>Họ không được thoát khỏi,<br>Trói buộc của Ác ma.`, ref: "Itivuttaka 93", url: "https://loicuaducphat.org/iti/iti93.html#content" },



{ text: `Những ai ngày và đêm,<br>Chú tâm vào, chuyên học,<br>Học những lời giảng dạy,<br>Bậc Chánh đẳng Chánh giác.<br>Họ làm cho lắng dịu<br>Ngọn lửa của lòng tham,<br>Luôn luôn ý thức được,<br>Tánh bất tịnh sự vật.<br><br>Với lòng thương, từ mẫn,<br>Những hạng người tối thượng,<br>Làm lắng dịu, chỉ tịnh,<br>Ngọn lửa của sân hận.<br>Còn ngọn lửa si mê,<br>Với trí tuệ dập tắt,<br>Trí tuệ này đưa đến<br>Thể nhập vào chân lý.<br><br>Bậc thận trọng sáng suốt,<br>Ngày đêm làm lắng dịu<br>Các loại lửa như vậy,<br>Không có biết mệt mỏi,<br>Họ làm cho lắng dịu,<br>Không một chút dư tàn.<br><br>Những bậc Thánh đã thấy,<br>Bậc trí tuệ hiểu biết,<br>Là những bậc Hiền trí,<br>Thấy được nhờ chánh trí<br>Do họ thắng tri được,<br>Sự diệt tận của sanh,<br>Nên họ không đi đến,<br>Sanh đi rồi sanh lại.`, ref: "Itivuttaka 93", url: "https://loicuaducphat.org/iti/iti93.html#content" },


{ text: `Này các Tỷ-kheo, có ba sanh khởi của dục. Thế nào là ba? Dục đối với sự vật hiện tại, sự thích thú đối với sự vật mình tạo ra, sự chấp nhận sự vật do người khác tạo ra. Này các Tỷ-kheo, có ba sanh khởi này của dục.<br><br>Chư Thiên hưởng dục lạc,<br>Chư Thiên uy lực lớn,<br>Hoá lạc thiên Chư Thiên,<br>Và các chư Thiên khác<br>Thọ hưởng các dục lạc,<br>Dầu cõi này cõi khác,<br>Không ra khỏi luân hồi.<br><br>Biết rõ hiểm nguy này,<br>Người trí đối các dục,<br>Trong đời này đời khác,<br>Từ bỏ tất cả dục,<br>Dầu thuộc về chư Thiên<br>Hay dục thuộc loài Người.<br><br>Những ai được chặt đứt<br>Dòng nước khó vượt qua,<br>Sự say đắm sự vật,<br>Thân ái và tốt đẹp,<br>Họ làm cho lắng dịu,<br>Không có vật dư thừa,<br>Họ vượt qua đau khổ,<br>Không còn chút dư tàn,<br><br>Những bậc Thánh đã thấy.<br>Bậc trí tuệ hiểu biết,<br>Là những bậc Hiền trí,<br>Thấy được nhờ chánh trí.<br>Do họ thắng tri được<br>Sự diệt tận của sanh,<br>Nên họ không đi đến,<br>Sanh đi rồi sanh lại.`, ref: "Itivuttaka 95", url: "https://loicuaducphat.org/iti/iti95.html#content" },

{ text: `Này các Tỷ-kheo, ví như có người bị dòng sông cuốn trôi, dòng sông đẹp đẽ, dễ thương. Có người có mắt, đứng trên bờ thấy người ấy, nói rằng: "Này người kia, tuy người bị cuốn trôi bởi dòng sông đẹp đẽ dễ thương nhưng ở dưới kia có một cái hồ, đầy sóng và nước xoáy, đầy cá sấu và quỷ Dạ-xoa; nếu Ông đến chỗ ấy, Ông sẽ bị chết, hay đau khổ gần như chết. Rồi người ấy, sau khi nghe tiếng của người kia, liền với tay và với chân, bơi ngược dòng". Này các Tỷ-kheo, Ta ví dụ này là để giải thích ý nghĩa. Ở đây, ý nghĩa là như sau: "Dòng sông, này các Tỷ-kheo, là đồng nghĩa với ái. Sắc khả ái dễ thương, này các Tỷ-kheo, là đồng nghĩa với sáu nội xứ. Cái hồ ở dưới, này các Tỷ-kheo, là đồng nghĩa với năm hạ phần kiết sử. Sóng, này các Tỷ-kheo, là đồng nghĩa với phẫn nộ, ưu não. Nước xoáy, này các Tỷ-kheo, là đồng nghĩa với năm dục tăng trưởng. Cá sấu, với quỷ Dạ-xoa, này các Tỷ-kheo, là đồng nghĩa với đàn bà; Ngược dòng, này các Tỷ-kheo, là đồng nghĩa xuất ly. Tinh tấn với tay với chân là đồng nghĩa với tinh cần tinh tấn. Người có mắt đứng trên bờ, này các Tỷ-kheo, là Như Lai, bậc A-la-hán, Chánh Ðẳng Giác".`, ref: "Itivuttaka 109", url: "https://loicuaducphat.org/iti/iti109.html#content" },


{ text: `Cùng với sự đau khổ,<br>Hãy từ bỏ các dục,<br>Mong cầu trong tương lai,<br>An ổn khỏi khổ ách,<br>Chơn chánh hiểu biết rõ,<br>Tâm khéo được giải thoát.<br><br>Tại đấy, ở tại đấy,<br>Cảm xúc được giải thoát,<br>Vị ấy đạt hiểu biết,<br>Phạm hạnh được thành tựu,<br>Ðến tận cùng thế giới,<br>Ðến được bờ bên kia.<br>Vị ấy được gọi vậy.`, ref: "Itivuttaka 109", url: "https://loicuaducphat.org/iti/iti109.html#content" },

{ text: `Ai cắt đứt tham ái,<br>Không còn chút dư tàn,<br>Làm cho nước cạn khô,<br>Dòng nước chảy nhanh mạnh<br>Tỷ-kheo ấy từ bỏ,<br>Bờ này và bờ kia,<br>Như loài rắn thoát bỏ<br>Da rắn cũ già xưa.<br><br>Ai phá hoại kiêu mạn<br>Không còn chút dư tàn,<br>Như nước mạnh tàn phá<br>Cây cỏ lau yếu hèn,<br>Tỷ-kheo ấy từ bỏ,<br>Bờ này và bờ kia,<br>Như loài rắn thoát bỏ<br>Da rắn cũ già xưa.`, ref: "Kinh Tập 1.1", url: "https://loicuaducphat.org/snp/snp1.1.html#content" },


{ text: `Ai trong các sanh hữu,<br>Không tìm thấy lõi cây,<br>Như kẻ đi hái hoa,<br>Trên cây sung không hoa.<br>Tỷ-kheo ấy từ bỏ,<br>Bờ này và bờ kia,<br>Như loài rắn thoát bỏ<br>Da rắn cũ già xưa.<br><br>Với ai trong nội tâm,<br>Không còn có phẫn hận,<br>Ðã vượt thoát ra khỏi,<br>Cả hữu và phi hữu.<br>Tỷ-kheo ấy từ bỏ,<br>Bờ này và bờ kia,<br>Như loài rắn thoát bỏ<br>Da rắn cũ già xưa.<br><br>Với ai những tầm tư,<br>Ðược làm cho tan biến<br>Nội tâm khéo sửa soạn,<br>Không còn chút dư tàn.<br>Tỷ-kheo ấy từ bỏ,<br>Bờ này và bờ kia,<br>Như loài rắn thoát bỏ<br>Da rắn cũ già xưa.`, ref: "Kinh Tập 1.1", url: "https://loicuaducphat.org/snp/snp1.1.html#content" },


{ text: `Ai không đi quá trớn,<br>Cũng không quá chậm trễ,<br>Từ bỏ, không tham dục,<br>Sự này toàn hư vọng.<br>Tỷ-kheo ấy từ bỏ,<br>Bờ này và bờ kia,<br>Như loài rắn thoát bỏ<br>Da rắn cũ già xưa.<br><br>Ai không đi quá trớn,<br>Cũng không quá chậm trễ,<br>Từ bỏ, ly sân hận,<br>Sự này toàn hư vọng.<br>Tỷ-kheo ấy từ bỏ,<br>Bờ này và bờ kia,<br>Như loài rắn thoát bỏ<br>Da rắn cũ già xưa.<br><br>Ai không đi quá trớn,<br>Cũng không quá chậm trễ,<br>Từ bỏ, ly si ám,<br>Sự này toàn hư vọng.<br>Tỷ-kheo ấy từ bỏ,<br>Bờ này và bờ kia,<br>Như loài rắn thoát bỏ<br>Da rắn cũ già xưa.`, ref: "Kinh Tập 1.1", url: "https://loicuaducphat.org/snp/snp1.1.html#content" },

{ text: `Với ai, các tùy miên,<br>Hoàn toàn không hiện hữu,<br>Các nguồn gốc bất thiện<br>Ðược nhổ lên trừ sạch.<br>Tỷ-kheo ấy từ bỏ,<br>Bờ này và bờ kia,<br>Như loài rắn thoát bỏ<br>Da rắn cũ già xưa.<br><br>Với ai, không có gì,<br>Do phiền não sanh khởi,<br>Làm duyên trở lui lại,<br>Về lại bờ bên này.<br>Tỷ-kheo ấy từ bỏ,<br>Bờ này và bờ kia,<br>Như loài rắn thoát bỏ<br>Da rắn cũ già xưa.<br><br>Với ai, không có gì,<br>Do rừng ái sanh khởi,<br>Tạo nhân khiến trói buộc<br>Con người vào tái sanh.<br>Tỷ-kheo ấy từ bỏ,<br>Bờ này và bờ kia,<br>Như loài rắn thoát bỏ<br>Da rắn cũ già xưa.<br><br>Ai đoạn năm triền cái,<br>Không sầu khổ bực phiền,<br>Vượt qua được nghi hoặc,<br>Thoát mũi tên phiền não.<br>Tỷ-kheo ấy từ bỏ,<br>Bờ này và bờ kia,<br>Như loài rắn thoát bỏ<br>Da rắn cũ già xưa.`, ref: "Kinh Tập 1.1", url: "https://loicuaducphat.org/snp/snp1.1.html#content" },


{ text: `Các dục thật mỹ miều,<br>Ngọt thơm và đẹp ý,<br>Dưới hình sắc, phi sắc,<br>Làm mê loạn tâm tư,<br>Thấy sự nguy hiểm này,<br>Trong các dục trưởng dưỡng,<br>Hãy sống riêng một mình<br>Như tê ngưu một sừng.<br><br>Ðây là một mụn nhọt,<br>Và cũng là tai họa,<br>Một tật bệnh, mũi tên,<br>Là sợ hãi cho ta,<br>Thấy sự nguy hiểm này,<br>Trong các dục trưởng dưỡng,<br>Hãy sống riêng một mình<br>Như tê ngưu một sừng.`, ref: "Kinh Tập 1.3", url: "https://loicuaducphat.org/snp/snp1.3.html#content" },


{ text: `Hemàvata:<br>Có phải đối các dục,<br>Vị ấy không tham ái?<br>Có phải tâm vị ấy<br>Không có bị dao động?<br>Có phải tâm vị ấy<br>Vượt khỏi sự si ám?<br>Có phải thật vị ấy,<br>Có mắt đối các pháp?<br><br>Sàtàgira:<br>Vị ấy không tham ái<br>Ðối với các dục vọng,<br>Tâm không có dao động,<br>Vượt khỏi mọi si ám,<br>Ðức Phật thật có mắt<br>Ðối với tất cả pháp.`, ref: "Kinh Tập 1.9", url: "https://loicuaducphat.org/snp/snp1.9.html#content" },


{ text: `Hemàvata:<br>Ðây, ai vượt bộc lưu?<br>Ðây, ai vượt biển lớn?<br>Không chân đứng bám víu,<br>Ai không chìm vực sâu?<br><br>Thế Tôn:<br>Ai luôn luôn đủ giới,<br>Có tuệ, khéo thiền định,<br>Tâm hướng nội, chánh niệm,<br>Vượt bộc lưu khó vượt.<br><br>Ai từ bỏ dục tưởng,<br>Vượt khỏi mọi kiết sử,<br>Ai, hỷ, hữu đoạn tận,<br>Không chìm vào vực sâu.`, ref: "Kinh Tập 1.9", url: "https://loicuaducphat.org/snp/snp1.9.html#content" },


{ text: `Ràng buộc với xương gân,<br>Trét thoa với da thịt,<br>Thân được da che đậy,<br>Như thật không thấy rõ.<br><br>Trong một bụng chứa đầy,<br>Cục gan, và bọng đái,<br>Quả tim và buồng phổi,<br>Cả thận, và tỳ tạng.<br><br>Nước mũi, và nước miếng,<br>Mồ hôi, và nước mỡ,<br>Máu, và nước khớp xương,<br>Mật, và bạch huyết cầu.<br><br>Từ chín nguồn nước này,<br>Bất tịnh luôn luôn chảy,<br>Từ mắt, đồ bẩn chảy,<br>Từ tai, đồ bẩn chảy.`, ref: "Kinh Tập 1.11", url: "https://loicuaducphat.org/snp/snp1.11.html#content" },

{ text: `Nước mũi từ lỗ mũi,<br>Từ miệng, có khi chảy,<br>Chảy mật, và niêm dịch,<br>Từ thân, mồ hôi bẩn.<br><br>Trong đầu thật trống rỗng,<br>Chứa đầy những óc, não.<br>Bị vô minh dắt dẫn,<br>Kẻ ngu nghĩ tịnh sạch.<br><br>Khi bị chết nằm xuống,<br>Phồng lên, và xanh bầm,<br>Quăng bỏ trong nghĩa địa,<br>Bà con không đoái hoài.<br><br>Chó, dã can đến ăn,<br>Chó sói, các côn trùng,<br>Quạ, diều hâu đến ăn,<br>Còn có hữu tình khác.`, ref: "Kinh Tập 1.11", url: "https://loicuaducphat.org/snp/snp1.11.html#content" },

{ text: `Ðược nghe lời Phật dạy,<br>Tỷ-kheo có trí tuệ,<br>Vị ấy liễu tri thân,<br>Thấy thân đúng như thật.<br><br>Ðây thế nào, kia vậy,<br>Kia thế nào, đây vậy,<br>Ðối với thân trong ngoài,<br>Từ bỏ mọi lòng dục.<br><br>Từ bỏ lòng tham dục,<br>Ðây Tỷ-kheo có tuệ,<br>Chứng bất tử, tịch tịnh,<br>Niết-bàn giới thường trú.<br><br>Thân này với hai chân,<br>Bất tịnh và hôi thúi,<br>Ðầy xác chết, chảy nước,<br>Lại được giữ, nâng niu.<br><br>Với thân thể như vậy,<br>Ai lại nghĩ đề cao,<br>Hay khinh miệt kẻ khác,<br>Trừ kẻ không thấy gì.`, ref: "Kinh Tập 1.11", url: "https://loicuaducphat.org/snp/snp1.11.html#content" },

{ text: `Như hố phân đầy tràn,<br>Sau nhiều năm chất chứa,<br>Cũng vậy, kẻ uế nhiễm,<br>Thật khó lòng gột sạch.<br><br>Hỡi này các Tỷ-kheo,<br>Hãy biết người như vậy,<br>Hệ lụy với gia đình,<br>Ác dục, ác tư duy,<br>Ác uy nghi cử chi,<br>Ác sở hành, hành xứ.<br><br>Tất cả đều đồng tình,<br>Tránh xa ngưòi như vậy,<br>Hãy thổi nó như bụi,<br>Hãy quăng nó như rác.<br><br>Hãy đuổi kẻ nói nhiều,<br>Kẻ Sa-môn giả hiệu,<br>Sau khi đuổi ác dục,<br>Ác uy nghi hành xứ.<br><br>Hãy giữ mình trong sạch,<br>Chung sống kẻ trong sạch,<br>Sống thích đáng, chánh niệm,<br>Rồi hòa hợp, sáng suốt,<br>Hãy chấm dứt khổ đau.`, ref: "Kinh Tập 2.6", url: "https://loicuaducphat.org/snp/snp2.6.html#content" },


{ text: `Thấy được sự đoạn tận,<br>Sanh diệt các kiết sử,<br>Trừ được đường tham dục,<br>Không còn lại dư tàn.<br>Thanh tịnh, không lỗi lầm,<br>Không cấu uế, không nhiễm.<br>Như Lai thật xứng đáng,<br>Ðồ cúng dường tế tự.<br><br>Ai không thấy tự ngã,<br>Với tự ngã của mình,<br>Ðịnh tâm và chánh trực,<br>Kiên trì không dao động,<br>Vị ấy không có dục,<br>Không cứng cỏi, phân vân.<br>Như Lai thật xứng đáng,<br>Ðồ cúng dường tế tự.<br><br>Với ai không còn nữa,<br>Nguyên nhân của si mê,<br>Biết rõ và thấy rõ,<br>Ðối với hết thảy pháp,<br>Và mang nặng thân này,<br>Thân này thân cuối cùng.<br>Chứng đạt Chánh Ðẳng Giác,<br>Vô thượng an ổn xứ,<br>Ðạt cho đến như vậy,<br>Như Lai thật xứng đáng,<br>Ðồ cúng dường tế tự.`, ref: "Kinh Tập 3.4", url: "https://loicuaducphat.org/snp/snp3.4.html#content" },


{ text: `Hãy bỏ dục, bỏ tham,<br>Ðây phàm phu bị nắm,<br>Bậc có mắt hành đạo,<br>Vượt địa ngục, loài Người.<br><br>Bụng đói, ăn chừng mực,<br>Ít dục, không tham lam.<br>Vị ấy không ham dục,<br>Không dục, thật tịch tịnh.<br><br>Sau khi đi khất thực,<br>Ẩn sĩ vào rừng sâu,<br>Ði đến dưới gốc cây,<br>Sửa soạn ngồi an tịnh.<br><br>Bậc Hiền trí hành thiền,<br>Hoan hỷ trong rừng sâu,<br>Hành thiền dưới gốc cây,<br>Thỏa mãn sở thích mình.`, ref: "Kinh Tập 3.11", url: "https://loicuaducphat.org/snp/snp3.11.html#content" },

{ text: `Chính do duyên sanh y,<br>Các khổ được sanh khởi,<br>Tất cả các khổ đau,<br>Sai biệt ở trên đời,<br>Ai chính do vô minh<br>Tạo lên sự sanh y,<br>Kẻ ngu ấy gặp khổ<br>Nối tiếp nhau sanh trưởng,<br>Do vậy vị hiểu biết,<br>Không tạo lên sanh y,<br>Tuỳ quán được hiện hữu<br>Của sanh và của khổ.<br><br>Những ai tiếp tục rơi,<br>Dòng luân chuyển sanh tử,<br>Ðến hữu này hữu khác,<br>Sanh thú do vô minh.<br><br>Vô minh này, đại si,<br>Ðưa đến luân chuyển dài,<br>Chúng sanh, minh đạt được,<br>Không còn phải tái sanh.`, ref: "Kinh Tập 3.12", url: "https://loicuaducphat.org/snp/snp3.12.html#content" },

{ text: `Sắc, tiếng, hương, vị, xúc,<br>Tất cả những pháp này,<br>Khả lạc, hỷ, khả ý,<br>Khi nào chúng hiện hữu.<br><br>Thế giới với chư Thiên<br>Xem chúng là khả lạc,<br>Khi chúng bị hoại diệt,<br>Mới thấy chúng là khổ.<br><br>Bậc Thánh thấy là lạc,<br>Khi có thân đoạn diệt,<br>Ðây hoàn toàn trái ngược,<br>Ðiều mọi giới được thấy.<br><br>Ðiều người khác gọi lạc,<br>Bậc Thánh gọi là khổ,<br>Ðiều người khác gọi khổ,<br>Bậc Thánh biết là lạc,<br><br>Bậc thiện, được rộng mở,<br>Bậc thấy, được ánh sáng,<br>Ai ngoài các bậc Thánh,<br>Xứng đáng đạo chánh giác.<br>Do chánh trí đạo ấy<br>Chứng vô lậu Niết-bàn.`, ref: "Kinh Tập 3.12", url: "https://loicuaducphat.org/snp/snp3.12.html#content" },

{ text: `Ai tránh né các dục<br>Như chân tránh đầu rắn,<br>Chánh niệm vượt thoát được,<br>Ái triền này ở đời.<br><br>Người nào tham đắm dục,<br>Ruộng đất, vàng, bò, ngựa,<br>Người nô tỳ, phục vụ,<br>Nữ nhân và bà con.<br><br>Như người không sức lực,<br>Bị các dục chinh phục,<br>Tai họa dẫm đạp nó,<br>Khổ đau bước theo nó,<br>Như nước ùa tràn vào,<br>Chiếc thuyền bị vỡ nát.<br><br>Do vậy người thường niệm,<br>Từ bỏ các loài dục,<br>Bỏ dục, vượt bộc lưu,<br>Tát thuyền đến bờ kia.`, ref: "Kinh Tập 4.1", url: "https://loicuaducphat.org/snp/snp4.1.html#content" },


{ text: `Sinh mạng này ngắn thay,<br>Trong trăm năm, rồi chết,<br>Nếu ai sống hơn nữa,<br>Rồi cũng chết vì già.<br><br>Loài Người sầu vì ngã,<br>Mọi chấp thủ vô thường,<br>Trống không là đời này,<br>Thấy vậy sống không nhà.<br><br>Vì loài Người nghĩ rằng<br>Cái này là của tôi,<br>Cái ấy bị sự chết,<br>Làm hoại diệt hư tàn.<br>Biết vậy, bậc Hiền trí,<br>Không gọi, không hướng đến,<br>Cái này ngã của ta,<br>Cái này là của ta.<br><br>Như những gì hiện lên,<br>Trong giấc ngủ mộng mị,<br>Con người khi tỉnh dậy,<br>Không còn thấy được gì.<br>Cũng vậy ở đời này,<br>Người được ưa, ái luyến,<br>Rồi sẽ chết mất đi,<br>Không ai còn thấy được.<br><br>Các loại hạng người ấy<br>Ðược thấy và được nghe,<br>Nên họ được gọi tên,<br>Tên này hay tên khác.<br>Với người đã chết đi,<br>Chỉ được gọi tên không,<br>Vì chỉ có tên suông,<br>Sẽ được còn tồn tại.<br><br>Tham đắm cái của ta,<br>Họ không có từ bỏ,<br>Sầu khổ và than van,<br>Cùng xan tham keo kiết.<br>Do vậy bậc ẩn sĩ,<br>Sau khi bỏ chấp thủ,<br>Ðã sống một đời sống,<br>Thấy được sự an ổn.`, ref: "Kinh Tập 4.6", url: "https://loicuaducphat.org/snp/snp4.6.html#content" },


{ text: `Ai đắm say dâm dục,<br>Quên mất lời giảng dạy,<br>Rơi vào đường tà vạy,<br>Nếp sống ấy không thánh.<br><br>Ai trước sống một mình,<br>Nay rơi vào dâm dục,<br>Như xe bị nghiêng ngã,<br>Người ấy ở trong đời,<br>Ðược gọi là phàm phu,<br>Ðược gọi là hạ liệt.<br><br>Tiếng tốt có từ trước,<br>Người ấy bị tổn giảm,<br>Thấy vậy hãy học tập,<br>Từ bỏ sự dâm dục.<br><br>Chi phối bởi suy tư,<br>Trầm ngâm như kẻ nghèo,<br>Nghe tiếng trách người khác,<br>Như kẻ bị thất vọng.<br><br>Bị người khác buộc tội,<br>Nó làm các đao kiếm,<br>Trở thành người tham lớn,<br>Chấp thủ điều vọng ngôn.<br><br>Ðược danh là Hiền trí,<br>An trú sống một mình,<br>Nếu rơi vào dâm dục,<br>Sầu não như kẻ ngu.<br><br>Thấy nguy hại như vậy,<br>Bậc ẩn sĩ trước sau,<br>Kiên trì sống cô độc,<br>Không thực hành dâm dục.<br><br>Hãy học tập viễn ly,<br>Ðây hạnh thánh tối thượng,<br>Không nghĩ mình tối thắng,<br>Dầu gần được Niết-bàn.<br><br>Sở hành bậc ẩn sĩ,<br>Trống không, không mong dục,<br>Bậc vượt khỏi bộc lưu,<br>Ðược các người ở đời,<br>Bị tham dục trói buộc,<br>Ganh tị và thèm muốn.`, ref: "Kinh Tập 4.7", url: "https://loicuaducphat.org/snp/snp4.7.html#content" },

{ text: `Thế Tôn:<br>Sau khi thấy khát ái,<br>Bất lạc và tham đắm,<br>Không thể có ưa muốn,<br>Ðối với sự dâm dục.<br>Sao, với bao đầy tràn,<br>Nước tiểu, phân uế này,<br>Ta không có ước muốn,<br>Với chân động chạm nó.`, ref: "Kinh Tập 4.9", url: "https://loicuaducphat.org/snp/snp4.9.html#content" },


{ text: `Ai ở đây vượt dục,<br>Ái khó vượt ở đời,<br>Không sầu, không tham muốn,<br>Cắt dòng không trói buộc.<br><br>Trước Ông làm khô cạn<br>Sau Ông không vật gì,<br>Ở giữa không nắm giữ,<br>Ông sẽ sống an tịnh.<br><br>Toàn diện đối danh sắc,<br>Không gì nghĩ "của ta"<br>Không có gì không sầu,<br>Không có già ở đời.<br><br>Không nghĩ "đây của tôi ",<br>Không nghĩ "đây của người ",<br>Người không có tự ngã,<br>Không sầu vì không ngã.<br><br>Không tàn bạo, không tham,<br>Không dục, thường đồng đẳng,<br>Ðược hỏi Ta nói lên,<br>Lợi ích bậc bất động.<br><br>Bậc ly dục rõ biết,<br>Vị ấy không sở hành,<br>Thoát ly, không tinh cần,<br>Thấy an ổn khắp nơi.<br><br>Bậc ẩn sĩ, không nói,<br>Bằng nhau, thua, hơn nhau,<br>An tịnh, ly xan tham,<br>Không nhận, không bác bỏ.<br>Thế Tôn giảng như vậy.`, ref: "Kinh Tập 4.15", url: "https://loicuaducphat.org/snp/snp4.15.html#content" },


{ text: `Lại nữa, năm loại vua,<br>Hiện có ở trên đời,<br>Hãy học nhiếp phục chúng.<br>Luôn luôn giữ chánh niệm.<br>Ðối với sắc và tiếng,<br>Ðối với vị và hương,<br>Cùng đối các cảm xúc,<br>Hãy chế ngự tham ái.<br><br>Hãy chế ngự ước muốn,<br>Ðối với những pháp ấy,<br>Vị Tỷ kheo chánh niệm,<br>Tâm tư khéo giải thoát,<br>Rồi đúng thời vị ấy,<br>Chơn chánh suy tư pháp,<br>Với chuyên tâm nhất trí,<br>Hãy đoạn tận hắc ám.<br>Thế Tôn nói như vậy.`, ref: "Kinh Tập 4.16", url: "https://loicuaducphat.org/snp/snp4.16.html#content" },


{ text: `Tôn Giả Ajita:<br>Do gì, đời bị che,<br>Do gì, không chói sáng,<br>Hãy nói lên cái gì,<br>Làm uế nhiễm cuộc đời,<br>Cái gì sợ hãi lớn?<br><br>Thế Tôn đáp Ajita:<br>Ðời bị vô minh che,<br>Do xan tham, phóng dật,<br>Ðời không được chói sáng,<br>Ta nói do mong cầu,<br>Nên đời bị uế nhiễm,<br>Chính là sự đau khổ,<br>Nên có sợ hãi lớn.`, ref: "Kinh Tập 5.2", url: "https://loicuaducphat.org/snp/snp5.2.html#content" },

{ text: `Thế Tôn đáp Upasiva:<br>Biết gìn giữ chánh niệm,<br>Không mong đợi vật gì,<br>Ông sẽ vượt bộc lưu,<br>Nương tựa: "không có gì ",<br>Ngày đêm ngươi nhận thấy,<br>Ðoạn dục, ly nghi ngờ,<br>Ái diệt là Niết-bàn.<br><br>Ai hoàn toàn ly tham,<br>Ðối với tất cả dục,<br>Y chỉ không có gì,<br>Từ bỏ mọi gì khác,<br>Ðược giải thoát hoàn toàn,<br>Tương giải thoát tối thượng,<br>Tại đấy, vị ấy trú,<br>Không tiếp tục đi tới.<br><br>Cũng giống như ngọn lửa,<br>Bị sức gió mạnh thổi,<br>Ði đến chỗ tận cùng,<br>Không có thể ước lượng,<br>Cũng vậy, vị ẩn sĩ,<br>Ðược giải thoát danh thân,<br>Ði đến chỗ tận cùng,<br>Không có thể ước lượng.<br><br>Người đi đến tận cùng,<br>Không thể còn ước lượng,<br>Với gì, nói đến nó,<br>Không còn có cái ấy,<br>Khi tất cả các pháp,<br>Ðã được nhổ hẳn lên,<br>Mọi con đường nói phô,<br>Ðược nhổ lên sạch hết.`, ref: "Kinh Tập 5.7", url: "https://loicuaducphat.org/snp/snp5.7.html#content" },


{ text: `Tôn Giả Todeyya:<br>Ai sống không dục vọng,<br>Ai sống không có ái,<br>Ai vượt khỏi nghi hoặc,<br>Giải thoát của vị ấy,<br>Giải thoát như thế nào?<br><br>Thế Tôn đáp Todeyya:<br>Ai sống không dục vọng,<br>Ai sống không có ái,<br>Ai vượt khỏi nghi hoặc<br>Giải thoát của vị ấy<br>Không có gì là khác.<br><br>Tôn Giả Todeyya:<br>Vị sống không ước vọng<br>Hay sống có ước vọng,<br>Vị ấy có trí tuệ,<br>Hay tác thành trí tuệ,<br>Ôi kính bậc Biến nhãn,<br>Hãy trả lời con rõ,<br>Ðể con có thể biết,<br>Thế nào là ẩn sĩ,<br>Ôi kính bậc Thích tử.<br><br>Thế Tôn:<br>Vị sống không ước vọng,<br>Không có ước vọng nào,<br>Vị ấy có trí tuệ,<br>Không tác thành trí tuệ,<br>Như vậy, Tô-đê-ya,<br>Hãy biết bậc ẩn sĩ,<br>Không có sở hữu gì,<br>Không tham dính dục hữu.`, ref: "Kinh Tập 5.10", url: "https://loicuaducphat.org/snp/snp5.10.html#content" },

{ text: `Tôn Giả Kappa:<br><br>Những ai đứng giữa nước,<br>Trong dòng nước mạnh chảy,<br>Giữa sợ hãi lớn lao,<br>Thưa Ngài hãy nói lên,<br>Hòn đảo cho những kẻ,<br>Bị già chết chinh phục,<br>Ngài nói con hòn đảo,<br>Ðể không có khổ khác,<br>Giống như đau khổ này.<br><br>Thế Tôn đáp Kappa:<br><br>Những ai đứng giữa nước,<br>Trong dòng nước mạnh chảy,<br>Giữa sợ hãi lớn lao,<br>Ta nói Ông hòn đảo,<br>Cho những ai đang bị,<br>Già và chết chinh phục.<br><br>Hòn đảo vô song này,<br>Không sở hữu, chấp trước,<br>Ta nói Ông Niết-bàn,<br>Già chết được đoạn diệt,<br><br>Biết vậy, giữ chánh niệm,<br>Hiện tại đạt mát lạnh,<br>Không rơi vào ma lực,<br>Không tùy tùng theo ma.`, ref: "Kinh Tập 5.11", url: "https://loicuaducphat.org/snp/snp5.11.html#content" },

{ text: `Tôn Giả Jatukanni:<br>Ðược nghe bậc anh hùng,<br>Không tham đắm dục vọng,<br>Nên con đã đến đây,<br>Ðể hỏi bậc vô dục,<br>Ðã thoát khỏi bộc lưu,<br>Bậc sanh với con mắt,<br>Hãy nói đường an tịnh,<br>Thế Tôn hãy như thật,<br>Nói cho con được biết.<br><br>Chinh phục dục vọng xong,<br>Thế Tôn sống ở đời,<br>Như mặt trời chiếu sáng,<br>Cõi đất với hào quang,<br>Bậc trí tuệ rộng lớn,<br>Hãy nói pháp cho con,<br>Kẻ trí tuệ bé nhỏ,<br>Do rõ biết pháp này,<br>Ở đây, con đoạn được,<br>Kể cả sanh và già.<br><br>Thế Tôn đáp Jatukanni:<br>Hãy nhiếp phục lòng tham,<br>Ðối với các dục vọng;<br>Hãy nhìn hạnh xuất ly,<br>Ðưa đến sự an ổn;<br>Chớ chấp chờ, từ bỏ,<br>Sự vật gì ở đời.<br><br>Những gì có trước Ông,<br>Hãy làm nó khô cạn,<br>Ðừng có sự vật gì,<br>Ở phía đàng sau Ông,<br>Ở giữa, Ông không chấp,<br>Ông sẽ sống an tịnh.<br><br>Hỡi này Bà-la-môn!<br>Ðối với danh và sắc,<br>Hoàn toàn không tham đắm,<br>Không có các lậu hoặc,<br>Chính do lậu hoặc này,<br>Bị thần chết chi phối.`, ref: "Kinh Tập 5.12", url: "https://loicuaducphat.org/snp/snp5.12.html#content" },

{ text: `Thế Tôn đáp Bhadràvudha:<br>Hãy nhiếp phục tất cả,<br>Mọi tham ái chấp thủ,<br>Trên, dưới cả bề ngang,<br>Và kể luôn chặng giữa,<br>Những ai có chấp thủ,<br>Sự gì ở trong đời,<br>Chính do sự việc ấy,<br>Ác ma theo người ấy.<br><br>Do vậy, bậc hiểu biết,<br>Không có chấp thủ gì,<br>Tỷ-kheo giữ chánh niệm,<br>Trong tất cả thế giới,<br>Phàm có sở hữu gì,<br>Vị ấy không mong ước,<br>Nhìn xem quần chúng này,<br>Là chúng sanh chấp thủ,<br>Trong lãnh vực của Ma,<br>Bị tham dính chấp trước.`, ref: "Kinh Tập 5.13", url: "https://loicuaducphat.org/snp/snp5.13.html#content" },


{ text: `Tôn Giả Udaya:<br>Con đến với câu hỏi,<br>Về tất cả mọi pháp,<br>Ðể hỏi bậc tu thiền,<br>Bậc an tọa không bụi;<br>Trách nhiệm đã làm xong,<br>Bậc không có lậu hoặc,<br>Ðã đạt bờ bên kia,<br>Hãy nói trí giải thoát<br>Ðể phá hoại vô minh.<br><br>Thế Tôn đáp Udaya:<br>Ðoạn ước muốn, dục vọng,<br>Và cả hai loại ưu,<br>Và trừ bỏ hôn trầm,<br>Ngăn chặn mọi hối hận.<br><br>Ta nói trí giải thoát,<br>Ðể phá hoại vô minh,<br>Thanh tịnh nhờ xả niệm,<br>Suy tư pháp đi trước.<br><br>Tôn Giả Udaya:<br>Ðời cái gì trói buộc,<br>Cái gì, đời vận hành?<br>Do đoạn được cái gì,<br>Ðược gọi là Niết-bàn?<br><br>Thế Tôn:<br>Ðời bị hỷ trói buộc,<br>Suy tầm là sở hành,<br>Do đoạn được khát ái,<br>Ðược gọi là Niết-bàn.`, ref: "Kinh Tập 5.14", url: "https://loicuaducphat.org/snp/snp5.14.html#content" },

{ text: `Thế Tôn đáp Pingiya:<br>Thấy được sự tác hại,<br>Trong các loại sắc pháp,<br>Chúng sanh sống phóng dật,<br>Bị phiền lụy trong sắc,<br>Do vậy, Pin-gi-ya,<br>Ông chớ có phóng dật,<br>Hãy từ bỏ sắc pháp<br>Chớ đi đến tái sanh.<br><br>Thấy chúng sanh loài Người,<br>Rơi vào trong khát ái,<br>Bị già nua đốt cháy,<br>Bị già nua chinh phục<br>Do vậy, Pin-gi-ya,<br>Ông chớ có phóng dật<br>Hãy từ bỏ khát ái,<br>Không còn bị tái sanh.`, ref: "Kinh Tập 5.17", url: "https://loicuaducphat.org/snp/snp5.17.html#content" },


{ text: `Trưởng Lão Bhalliya:<br><br>Ai đuổi đi thần chết,<br>Với đạo binh của nó,<br>Những dòng nước lớn mạnh,<br>Trói cây lau yếu ớt,<br>Thắng trận, không sợ hãi,<br>Nhiếp phục, trú tịch tịnh.`, ref: "Trưởng Lão Tăng Kệ 1.7", url: "https://loicuaducphat.org/thag/thag1.7.html#content" },

{ text: `Trưởng Lão Singala-Pitar:<br><br>Hãy nhìn trong khu rừng,<br>Rừng Bhesakala!<br>Một Tỷ-kheo đang sống,<br>Thừa tự lời Phật dạy,<br>Ngang thân địa đại này,<br>Tỏa khắp tưởng bộ xương.<br>Ta nghĩ Tỷ-kheo ấy,<br>Mau đoạn tận dục tham.`, ref: "Trưởng Lão Tăng Kệ 1.18", url: "https://loicuaducphat.org/thag/thag1.18.html#content" },

{ text: `Trưởng Lão Tissa:<br><br>Như bị kiếm chém xuống,<br>Như bị lửa cháy đầu,<br>Vị Tỷ-kheo xuất gia,<br>Chánh niệm, đoạn tham dục.`, ref: "Trưởng Lão Tăng Kệ 1.39", url: "https://loicuaducphat.org/thag/thag1.39.html#content" },

{ text: `Trưởng Lão Manava:<br><br>Ta thấy một người già,<br>Một người khổ bệnh hoạn,<br>Ta thấy một người chết,<br>Với tuổi thọ kiệt quệ,<br>Do vậy ta thoát ra,<br>Sống đời sống xuất gia,<br>Từ bỏ mọi dục vọng,<br>Hấp dẫn và thích ý.`, ref: "Trưởng Lão Tăng Kệ 1.73", url: "https://loicuaducphat.org/thag/thag1.73.html#content" },

{ text: `Trưởng Lão Hattharoha-Putta:<br><br>Trước tâm này lang thang,<br>Chạy chỗ này chỗ khác,<br>Chạy chỗ nó ưa thích,<br>Chạy chỗ nó vui sướng,<br>Nay ta chế ngự tâm,<br>Với như lý tư duy,<br>Như câu móc chế ngự,<br>Nhiếp phục con voi rừng.`, ref: "Trưởng Lão Tăng Kệ 1.77", url: "https://loicuaducphat.org/thag/thag1.77.html#content" },

{ text: `Trưởng Lão Sunaga:<br><br>Thiện xảo tướng của tâm,<br>Biết vị ngọt viễn ly,<br>Hành thiền, niệm, thận trọng,<br>Chứng lạc không thế tục.`, ref: "Trưởng Lão Tăng Kệ 1.85", url: "https://loicuaducphat.org/thag/thag1.85.html#content" },

{ text: `Trưởng Lão Samidatta:<br><br>Năm uẩn được rõ biết,<br>Tồn tại sẽ cắt đứt,<br>Vòng sanh tử đoạn tận,<br>Nay không còn tái sanh.`, ref: "Trưởng Lão Tăng Kệ 1.90", url: "https://loicuaducphat.org/thag/thag1.90.html#content" },

{ text: `Trưởng Lão Eraka:<br><br>Hỡi này Ê-ra-ka,<br>Khổ thay là các dục!<br>Hỡi này Ê-ra-ka,<br>Không lạc là các dục!<br>Ai tham dục các dục,<br>Là tham dục đau khổ,<br>Ai không tham các dục,<br>Là không tham dục khổ.<br>Hỡi này Ê-ra-ka!<br>Hãy biết là như vậy.`, ref: "Trưởng Lão Tăng Kệ 1.93", url: "https://loicuaducphat.org/thag/thag1.93.html#content" },

{ text: `Trưởng Lão Abhaya (2):<br><br>Thấy sắc, mất chánh niệm,<br>Tác ý tưởng luyến ái,<br>Tâm cảm thọ say mê,<br>Ðắm trước tưởng an trú,<br>Các lậu hoặc tăng trưởng,<br>Ðưa đến gốc sanh hữu.`, ref: "Trưởng Lão Tăng Kệ 1.98", url: "https://loicuaducphat.org/thag/thag1.98.html#content" },


{ text: `Trưởng Lão Uttiya:<br><br>Nghe tiếng, mất chánh niệm,<br>Tác ý tưởng luyến ái,<br>Tâm cảm thọ say mê,<br>Ðắm trước tưởng an trú,<br>Các lậu hoặc tăng trưởng,<br>Ðưa đến nhiễm luân hồi.`, ref: "Trưởng Lão Tăng Kệ 1.99", url: "https://loicuaducphat.org/thag/thag1.99.html#content" },

{ text: `Trưởng Lão Parapariya:<br><br>Từ bỏ sáu xúc xứ,<br>Căn môn khéo chế ngự,<br>Gốc tà ác, nhổ sạch,<br>Ta đạt lậu hoặc tận.`, ref: "Trưởng Lão Tăng Kệ 1.116", url: "https://loicuaducphat.org/thag/thag1.116.html#content" },

{ text: `Trưởng Lão Isidatta:<br><br>Năm uẩn được rõ biết,<br>Ðứng với rễ chặt đứt,<br>Khổ diệt đã đạt được,<br>Lậu hoặc diệt, ta chứng.`, ref: "Trưởng Lão Tăng Kệ 1.120", url: "https://loicuaducphat.org/thag/thag1.120.html#content" },


{ text: `Trưởng Lão Uttara:<br><br>Không có gì có mặt,<br>Lại thường còn mãi mãi,<br>Không có các hành gì,<br>Lại thường hằng thường trú.<br>Các uẩn được khởi lên,<br>Ðến đời khác diệt vong.<br><br>Biết được nguy hiểm này,<br>Ta không muốn sanh hữu,<br>Từ bỏ tất cả dục,<br>Ta chứng lậu hoặc tận.`, ref: "Trưởng Lão Tăng Kệ 2.1", url: "https://loicuaducphat.org/thag/thag2.1.html#content" },

{ text: `Trưởng Lão Radha:<br><br>Như mái nhà vụng lợp,<br>Mưa dễ thấm ướt vào,<br>Cũng vậy, tâm vụng tu<br>Tham ái được xâm nhập.<br><br>Như mái nhà khéo lợp<br>Mưa không thể thấm vào,<br>Cũng vậy, tâm khéo tu<br>Tham ái không xâm nhập.`, ref: "Trưởng Lão Tăng Kệ 2.7", url: "https://loicuaducphat.org/thag/thag2.7.html#content" },

{ text: `Trưởng Lão Mahakala:<br><br>Ai không rõ biết vậy,<br>Lại tác thành sanh y,<br>Kẻ ngu bước đi đến,<br>Chịu khổ đau liên tục,<br>Do vậy ai hiểu biết,<br>Không tạo nên sanh y,<br>Ta sẽ không nằm xuống,<br>Với đầu bị bẻ nát.`, ref: "Trưởng Lão Tăng Kệ 2.16", url: "https://loicuaducphat.org/thag/thag2.16.html#content" },

{ text: `Trưởng Lão Punnamasa:<br><br>Từ bỏ năm triền cái,<br>Ðạt an ổn khỏi ách,<br>Nắm giữ gương Chánh pháp,<br>Biết và thấy tự ngã.<br><br>Ta quán sát thân này,<br>Từ trong cho đến ngoài,<br>Thân được thấy trống không,<br>Trong thân cả ngoài thân.`, ref: "Trưởng Lão Tăng Kệ 2.26", url: "https://loicuaducphat.org/thag/thag2.26.html#content" },

{ text: `Trưởng Lão Sivaka:<br><br>Vô thường, những ngôi nhà,<br>Ðây đó lại dựng lên,<br>Tìm kiếm người làm nhà,<br>Tái sanh là đau khổ.<br><br>Hỡi kẻ làm nhà kia!<br>Ngươi đã bị thấy rồi,<br>Từ nay, ngươi không thể,<br>Lại dựng nhà lên nữa,<br>Mọi tường vách đổ vỡ,<br>Nóc nhà bị tan hoang,<br>Tâm bị đẩy khỏi dòng,<br>Ở đây, bị thổi nát.`, ref: "Trưởng Lão Tăng Kệ 2.32", url: "https://loicuaducphat.org/thag/thag2.32.html#content" },

{ text: `Trưởng Lão Nitaka:<br><br>Tâm ái như tảng đá<br>Ðứng vững, không dao động,<br>Hỡi những vật khả ái,<br>Tâm không có tham ái,<br>Ðối vật làm dao động,<br>Tâm không có dao động,<br>Tâm ai tu tập vậy,<br>Từ đâu, khổ sẽ đến.<br><br>Tâm ta như tảng đá<br>Ðứng vững, không dao động,<br>Ðối những vật khả ái,<br>Tâm không có tham ái,<br>Ðối vật làm dao động,<br>Tâm không có dao động,<br>Tâm ta tu tập vậy,<br>Từ đâu, khổ đến ta.`, ref: "Trưởng Lão Tăng Kệ 2.36", url: "https://loicuaducphat.org/thag/thag2.36.html#content" },


{ text: `Trưởng Lão Nisabha:<br><br>Sau khi đã từ bỏ<br>Năm loại dục trưởng dưỡng,<br>Những vật thật khả ái,<br>Khiến tâm ý thích thú,<br>Với lòng tin, xuất gia,<br>Chấm dứt sự khổ đau.<br><br>Ta không hoan hỷ chết,<br>Ta không hoan hỷ sống,<br>Ta chờ đợi thời đến,<br>Tỉnh giác và chánh niệm.`, ref: "Trưởng Lão Tăng Kệ 2.38", url: "https://loicuaducphat.org/thag/thag2.38.html#content" },

{ text: `Trưởng Lão Uttarapala:<br><br>Ta thật là hiền thiện,<br>Suy tư mục đích tốt,<br>Bỏ năm dục trưởng dưỡng,<br>Là thế giới si mê.<br><br>Sanh trong giới vức ma,<br>Bị tên mạnh xung kích,<br>Nhưng ta giải thoát được,<br>Cạm bẫy của Ma vương.<br><br>Mọi dục, ta đoạn tận,<br>Mọi sanh hữu, hủy hoại,<br>Ðường sanh tử chấm dứt,<br>Nay không còn tái sanh.`, ref: "Trưởng Lão Tăng Kệ 3.12", url: "https://loicuaducphat.org/thag/thag3.12.html#content" },

{ text: `Trưởng Lão Nagasamala:<br><br>Trang điểm, mặc áo đẹp,<br>Gieo bẫy mồi thần chết.<br><br>Rồi ta tự tác ý,<br>Như lý khởi tư duy,<br>Các hiểm nguy hiển lộ,<br>Nhàm chán, ta an trú.<br><br>Và tâm ta giải thoát,<br>Thấy pháp nhĩ là vậy,<br>Ba minh chứng đạt được,<br>Lời Phật dạy làm xong.`, ref: "Trưởng Lão Tăng Kệ 4.1", url: "https://loicuaducphat.org/thag/thag4.1.html#content" },

{ text: `Trưởng Lão Nandaka:<br><br>Gớm thay, vật hôi thối!<br>Ðầy sắc mùi hôi tanh,<br>Vật sở hữu của ma,<br>Ứ chảy nhiều dòng nước,<br>Thân này có chín dòng,<br>Luôn luôn được tuôn chảy.<br><br>Chớ khinh miệt cổ nhân!<br>Chớ xúc phạm Như Lai,<br>Họ không tham thiên giới,<br>Còn nói gì cõi người.<br><br>Kẻ ngu, thiếu trí tuệ,<br>Tà ý, si bao phủ,<br>Kẻ ấy đầy tham đắm,<br>Bị ma quăng dây trói.<br><br>Những ai đã thoát ly,<br>Tham, sân và vô minh,<br>Ðây họ không tham đắm,<br>Dây cắt, không trói buộc.`, ref: "Trưởng Lão Tăng Kệ 4.4", url: "https://loicuaducphat.org/thag/thag4.4.html#content" },

{ text: `Trưởng Lão Rahula:<br><br>Bị dục làm mù quáng,<br>Bị lưới tà bao trùm,<br>Khát ái làm màn che,<br>Bao trùm che phủ kín.<br>Do phóng dật trói buộc,<br>Như cá mắc mắt lưới.<br><br>Ta vượt qua dục ấy,<br>Cắt đứt ma trói buộc,<br>Nhổ lên gốc khát ái,<br>Ta mát lạnh tịch tịnh.`, ref: "Trưởng Lão Tăng Kệ 4.8", url: "https://loicuaducphat.org/thag/thag4.8.html#content" },

{ text: `Trưởng Lão Rajadatta:<br><br>Một Tỷ-kheo đi đến<br>Tại một bãi tha ma,<br>Thấy thân một đàn bà,<br>Bị quăng tại chỗ ấy,<br>Vất bỏ trong nghĩa địa,<br>Làm mồi cho sâu ăn.<br><br>Có kẻ sinh nhàm chán,<br>Thấy thân chết khốn nạn,<br>Trong ta, dục tham hiện,<br>Như mù, ta bị trói.<br><br>Mau hơn cơm sôi trào,<br>Chỗ ấy, ta đi thoát,<br>Chánh niệm, ta tỉnh giác,<br>Ta đến, ngồi một bên.<br><br>Rồi ta tự tác ý,<br>Như lý khởi tư duy,<br>Các hiểm nguy hiển lộ,<br>Nhàm chán ta an trú.<br><br>Và tâm ta giải thoát,<br>Thấy Pháp nhĩ là vậy,<br>Ba minh chứng đạt được,<br>Lời Phật dạy làm xong.`, ref: "Trưởng Lão Tăng Kệ 5.1", url: "https://loicuaducphat.org/thag/thag5.1.html#content" },

{ text: `Trưởng Lão Kulla:<br><br>Kulla đến nghĩa địa,<br>Thấy bỏ một đàn bà,<br>Vất ném trong nghĩa địa,<br>Làm mồi cho sâu ăn.<br><br>Kulla, hãy nhìn thân,<br>Bệnh hoạn nhớp hôi thối,<br>Nước ứ chảy, rỉ chảy,<br>Ðược kẻ ngu thích thú.<br><br>Sau khi nắm gương pháp,<br>Ðạt được chánh tri kiến,<br>Ta quán sát thân này,<br>Trống rỗng cả trong ngoài.<br><br>Ðây thế nào, kia vậy,<br>Kia thế nào, đây vậy,<br>Dưới thế nào, trên vậy,<br>Trên thế nào, dưới vậy.<br><br>Ngày thế nào, đêm vậy,<br>Ðêm thế nào, ngày vậy,<br>Trước thế nào, sau vậy,<br>Sau thế nào, trước vậy.<br><br>Người vậy không ưa thích,<br>Cả năm loại nhạc khí,<br>Khi đã được nhất tâm,<br>Chơn chánh thiền quán pháp.`, ref: "Trưởng Lão Tăng Kệ 6.4", url: "https://loicuaducphat.org/thag/thag6.4.html#content" },

{ text: `Trưởng Lão Malunkyaputta:<br><br>Có người sống phóng dật,<br>Ái lớn như cây leo,<br>Sống trôi nổi luân chuyển,<br>Ðời này qua đời khác,<br>Như con khỉ trong rừng,<br>Thèm muốn các trái cây.<br><br>Khát ái khốn nạn này<br>Thấm độc cả thế giới,<br>Khi đã chinh phục ai,<br>Khiến sầu muộn tăng trưởng,<br>Chẳng khác giống cỏ rừng,<br>Lan tràn và lớn mạnh.<br><br>Ai nhiếp phục được ái,<br>Khốn nạn, khó chinh phục,<br>Sầu rơi khỏi vị ấy,<br>Như giọt nước trên sen.<br><br>Các ông đã đến đây,<br>Ta thuyết điều lành ấy,<br>Hãy đào rễ khát ái,<br>Như tìm rễ ngon ngọt,<br>Loại cỏ u-sì-ra,<br>Chớ để Ma, dòng nước,<br>Tàn phá ông cây lau.<br>Liên tục vậy mãi mãi.<br><br>Hãy hành lời Phật dạy,<br>Chớ để Sát-na qua,<br>Sát-na qua, sầu khổ,<br>Thọ quả trong địa ngục,<br><br>Phóng dật như bụi bặm,<br>Bụi nhơ, do phóng dật,<br>Không phóng dật, minh trí,<br>Nhổ mũi tên khỏi ta.`, ref: "Trưởng Lão Tăng Kệ 6.5", url: "https://loicuaducphat.org/thag/thag6.5.html#content" },

{ text: `Trưởng Lão Sabbhakama:<br><br>Con vật hai chân này,<br>Bất tịnh và hôi thối,<br>Ðầy các loại tử thi,<br>Từ đấy, nước rỉ chảy.<br><br>Nai trốn, dùng bẫy sập,<br>Với cá dùng câu móc,<br>Với khỉ, dùng hầm hố,<br>Phàm phu bị bắt vậy.<br><br>Sắc, tiếng, vị, hương, xúc,<br>Khả ái và thích ý,<br>Năm dục trưởng dưỡng này,<br>Ðược tiếng trong nữ sắc.<br><br>Phàm phu tâm say đắm,<br>Chạy theo hưởng nữ sắc,<br>Tăng nghĩa địa hãi hùng,<br>Chất chứa sự tái sanh.<br><br>Ai tránh né nữ sắc,<br>Như chân tránh đầu rắn,<br>Chánh niệm, vượt qua được,<br>Kẻ đầu độc thế giới.<br><br>Thấy nguy hiểm trong dục,<br>An ổn trong viễn ly,<br>Thoát khỏi tất cả dục,<br>Ta đạt lậu hoặc tận.`, ref: "Trưởng Lão Tăng Kệ 6.14", url: "https://loicuaducphat.org/thag/thag6.14.html#content" },

{ text: `Trưởng Lão Lakuntaka-Bhaddiya:<br><br>Ra ngoài các khu vườn,<br>Tên Ambàtaka,<br>Trong rừng với lùm cây,<br>Ái, ái căn từ bỏ,<br>Bhaddiya ngồi thiền,<br>Bậc may mắn hạnh phúc.<br><br>Một số người ưa thích,<br>Trống, sáo và trống nhỏ,<br>Còn ta, dưới gốc cây,<br>Ta thích lời Phật dạy.<br><br>Nếu Phật ban ân huệ,<br>Ta được ân huệ ấy,<br>Ta trì thân hành niệm,<br>Thường hằng ở mọi giới.<br><br>Cười chê ta vì thân,<br>Ai theo ta vì tiếng,<br>Chúng không biết được ta,<br>Vì dục tham chi phối.<br><br>Không biết được phần trong,<br>Không thấy được phía ngoài,<br>Chặn bốn phía, người ngu,<br>Bị tiếng nói lôi cuốn.<br><br>Không biết được phần trong,<br>Quán thấy được phía ngoài,<br>Chỉ thấy quả phía ngoài,<br>Cũng bị tiếng lôi cuốn.<br><br>Quán trí được phần trong,<br>Quán thấy được phía ngoài,<br>Thấy không bị chướng ngại,<br>Không bị tiếng lôi cuốn.`, ref: "Trưởng Lão Tăng Kệ 7.2", url: "https://loicuaducphat.org/thag/thag7.2.html#content" },

{ text: `Trưởng Lão Kappa:<br><br>Ðầy nhiều loại uế vật,<br>Chỗ chưa còn phần uế,<br>Như vũng nước đọng lâu,<br>Ung nhọt vết thương lớn.<br><br>Ðầy những máu và mủ,<br>Chìm đắm, trong hố phân,<br>Thân ứ nước rỉ chảy,<br>Luôn chảy nước bất tịnh.<br><br>Trói bởi sáu mươi gân,<br>Trét dùng thịt làm hồ,<br>Mặc áo giáp bằng da,<br>Thân hôi thúi vô dụng.<br><br>Nối thành dây xúc xương,<br>Cột lại với dây gân,<br>Do chúng nhiều hợp sức,<br>Tác thành những uy nghi.<br><br>Thường tiến đến sự chết,<br>Ðến gần cảnh tử thần,<br>Ở đấy, bị quăng bỏ,<br>Con người đi theo dục.<br><br>Thân bị vô minh che,<br>Trói bởi bốn trói buộc,<br>Thân chìm trong bộc lưu,<br>Mắc vào lưới tùy miên,<br><br>Hệ lụy năm triền cái,<br>Ám ảnh bởi tâm tư,<br>Ði theo gốc khát ái,<br>Che trùm bởi màn si.<br><br>Thân này luân chuyển vậy,<br>Dẫn đi bởi xe nghiệp,<br>Khi thành công, khi bại,<br>Chịu đựng nhiều ái sanh.<br><br>Ai nghĩ 'thân của tôi',<br>Là phàm phu ngu muội,<br>Tăng mộ phần đáng sợ,<br>Chấp chặt sự tái sanh.<br><br>Ai tránh né thân này,<br>Như tránh rắn dính phân,<br>Họ bỏ gốc sanh hữu,<br>Chứng Niết-bàn, vô lậu.`, ref: "Trưởng Lão Tăng Kệ 10.5", url: "https://loicuaducphat.org/thag/thag10.5.html#content" },

{ text: `Trưởng Lão Anna-Kondanna:<br><br>Ta bội phần hân hoan,<br>Ðược nghe pháp vị lớn,<br>Pháp được giảng ly tham,<br>Hoàn toàn không chấp thủ.<br><br>Trên thế giới đất tròn,<br>Nhiều màu sắc hình tướng,<br>Làm say đắm tâm tư,<br>Ta nghĩ là như vậy,<br>Tướng tịnh rất hấp dẫn,<br>Liên hệ đến tham dục.<br><br>Như gió thổi tung bụi,<br>Ðược mây trấn áp xuống,<br>Các tư duy lắng dịu,<br>Khi thấy, với trí tuệ.<br><br>Mọi hành là vô thường<br>Khi thấy với trí tuệ,<br>Vị ấy nhàm chán khổ,<br>Ðây con đường đến tịnh.<br><br>Mọi hành là đau khổ,<br>Khi thấy với trí tuệ,<br>Vị ấy nhàm chán khổ,<br>Ðây con đường đến tịnh.<br><br>Mọi pháp là vô ngã,<br>Khi thấy với trí tuệ,<br>Vị ấy nhàm chán khổ,<br>Ðây con đường đến tịnh.`, ref: "Trưởng Lão Tăng Kệ 15.1", url: "https://loicuaducphat.org/thag/thag15.1.html#content" },


{ text: `Trưởng Lão Parapariya:<br><br>Con mắt đi đến sắc,<br>Không chế ngự ngăn chặn,<br>Không thấy các nguy hiểm,<br>Vị ấy không thoát khổ.<br><br>Lỗ tai đi đến tiếng,<br>Không chế ngự ngăn chặn,<br>Không thấy sự nguy hiểm,<br>Vị ấy không thoát khổ.<br><br>Không thấy sự xuất ly,<br>Thọ hưởng các mùi hương,<br>Vị ấy không thoát khổ,<br>Vì tham đắm các hương.<br><br>Nhớ chua ngọt tối thượng,<br>Nhớ vị đắng tối thượng,<br>Bị ái vị nô lệ,<br>Tâm không thể giác tỉnh.<br><br>Tưởng nhớ các cảm xúc,<br>Ðẹp đẽ và khoái cảm,<br>Ðam mê, duyên tham ái,<br>Gặp nhiều loại đau khổ.<br><br>Ý đối các pháp này<br>Tất cả là năm pháp,<br>Không có thể phòng hộ,<br>Khổ đi theo vị ấy.`, ref: "Trưởng Lão Tăng Kệ 16.2", url: "https://loicuaducphat.org/thag/thag16.2.html#content" },

{ text: `Trưởng Lão Parapariya:<br><br>Phần lớn các thân xác,<br>Ðầy tràn mủ và máu,<br>Do người thù thắng làm,<br>Thành hộp đẹp tô màu.<br><br>Cay đắng như vị ngọt,<br>Khổ do khả ái buộc,<br>Như dao bén dính mật,<br>Kẻ tham đâu có biết.<br><br>Ai tham đắm nữ sắc,<br>Nữ vị, nữ xúc chạm,<br>Ai mê say nữ hương,<br>Gặp nhiều loại đau khổ.<br><br>Mọi dòng từ nữ nhân,<br>Năm loại tràn năm xứ,<br>Người có tinh tấn lực,<br>Có thể ngăn chặn chúng.<br><br>Người có đích, trú pháp,<br>Người thiện xảo, sáng suốt,<br>Hoan hỷ làm nghĩa vụ,<br>Liên hệ đến pháp, nghĩa.<br><br>Chìm trong việc lợi tạm,<br>Hãy bỏ việc không lợi,<br>Nếu nó nghĩ việc ấy,<br>Không phải việc nên làm,<br>Vị ấy không phóng dật,<br>Sáng suốt thấy rõ vậy.<br><br>Nếu là việc làm tốt,<br>Hân hoan hành đúng pháp,<br>Hãy nắm việc làm ngay,<br>Ðấy thật lạc tối thượng.<br><br>Với phương tiện cao thấp,<br>Lừa dối các người khác,<br>Ðánh giết, làm sầu khổ,<br>Hung bạo, áp đảo người.<br><br>Như người mạnh đẽo gỗ,<br>Dùng nêm đánh bật nêm,<br>Cũng vậy là kẻ thiện,<br>Dùng căn đánh bật căn.<br><br>Tu tập tín, tấn, định,<br>Huấn luyện niệm, trí tuệ,<br>Dùng năm đánh đổ năm,<br>Không tỳ vết bước tới.<br><br>Là vị Bà-la-môn,<br>Người có đích, trú pháp,<br>Làm theo giáo huấn Phật,<br>Làm toàn diện, toàn lực,<br>Người ấy hưởng an lạc.`, ref: "Trưởng Lão Tăng Kệ 16.2", url: "https://loicuaducphat.org/thag/thag16.2.html#content" },

{ text: `Trưởng Lão Telakani:<br><br>Ta lặn sâu trong hồ,<br>Ðầy bụi bùn không thoát,<br>Ðầy man trá, tật đố,<br>Căng thẳng và hôn ám.<br><br>Sấm trạo cử nổ vang,<br>Mây kiết sử bao phủ,<br>Thác nước tà tư duy,<br>Liên hệ đến tham dục,<br>Chúng lôi cuốn trôi ta,<br>Vào đại dương tà kiến.<br><br>Khắp nơi, dòng suối chảy,<br>Cây leo đứng, đâm chồi,<br>Ai chặn đứng dòng ấy?<br>Ai chặt đứt cây leo?<br><br>Tôn giả hãy làm đê,<br>Ngăn chặn những dòng suối,<br>Chớ có để dòng nước,<br>Do ý sanh cuốn ngài,<br>Như dòng nước cuốn gấp,<br>Trôi cây chảy theo dòng.<br><br>Cũng vậy ta sợ hãi,<br>Bờ này tìm bờ kia,<br>Khi ấy bậc Ðạo Sư,<br>Có Thánh chúng hầu hạ,<br>Với binh khí trí tuệ,<br>Chờ y chỉ cho người.<br><br>Ðưa ta, đang chìm đắm,<br>Chiếc cầu thang, khéo làm,<br>Phật thanh tịnh, vững chắc,<br>Làm bằng lõi Chánh pháp,<br>Rồi ngài nói với ta,<br>Chớ có sợ hãi gì!.<br><br>Leo lên lầu niệm xứ,<br>Từ đấy ta quán sát,<br>Loài Người ưa thân kiến,<br>Trước đây, ta tự hào.<br><br>Khi ta thấy con đường,<br>Con thuyền cần leo lên,<br>Ta không trú tự ngã,<br>Vì thấy bến tối thượng.<br><br>Mũi tên khởi tự ngã,<br>Sanh do nhân sanh hữu<br>Ngài dạy đường tối thượng,<br>Chấm dứt các pháp ấy.<br><br>Cột gút đã lâu ngày,<br>Ẩn nằm, trú trong da,<br>Ðức Phật cởi, quăng đi,<br>Loại bỏ mọi độc hại.`, ref: "Trưởng Lão Tăng Kệ 16.3", url: "https://loicuaducphat.org/thag/thag16.3.html#content" },


{ text: `Trưởng Lão Ratthapala:<br><br>Hãy xem bóng trang sức,<br>Nhóm vết thương tích tụ,<br>Bệnh hoạn, nhiều tham tưởng,<br>Nhưng không gì trường cửu.<br><br>Hãy nhìn sắc trang sức,<br>Với châu báu, vòng tai,<br>Bộ xương, da bảo phủ,<br>Sáng chói nhờ y phục.<br><br>Chân sơn với son, sáp,<br>Mặt thoa với phấn bột,<br>Chỉ mê hoặc kẻ ngu,<br>Không mê bậc cầu giác.<br><br>Tóc được uốn tám vòng,<br>Mắt xoa với thuốc son,<br>Chỉ mê hoặc kẻ ngu,<br>Không mê bậc cầu giác.<br><br>Như hộp thuốc mới sơn,<br>Uế thân được trang điểm,<br>Chỉ mê hoặc kẻ ngu,<br>Không mê bậc cầu giác.<br><br>Thợ săn bày lưới sập,<br>Nai khôn không chạm lưới,<br>Ăn mồi xong, ta đi,<br>Mặc kẻ bắt nai khóc.<br><br>Bẫy thợ săn bị cắt,<br>Nai khôn không chạm lưới,<br>Ăn mồi xong, ta đi,<br>Mặc kẻ săn nai sầu.`, ref: "Trưởng Lão Tăng Kệ 16.4", url: "https://loicuaducphat.org/thag/thag16.4.html#content" },

{ text: `Trưởng Lão Malunkyaputta:<br><br>Thấy sắc, niệm say mê,<br>Nếu tác ý ái tưởng,<br>Tâm tham đắm cảm thọ,<br>Tâm nhập và an trú.<br><br>Thọ người ấy tăng trưởng,<br>Nhiều loại, do sắc sanh,<br>Tham, hại tâm lớn mạnh,<br>Chúng gia hại tâm nó,<br>Khổ chất chứa như vậy,<br>Rất xa vời Niết-bàn.<br><br>Nghe tiếng, niệm say mê,<br>Nếu tác ý ái tưởng,<br>Tâm tham đắm cảm thọ,<br>Xâm nhập và an trú.<br><br>Thọ người ấy tăng trưởng,<br>Nhiều loại, do tiếng sanh,<br>Tham, hại tâm lớn mạnh,<br>Chúng gia hại tâm nó,<br>Khổ chất chứa như vậy,<br>Rất xa vời Niết-bàn.<br><br>Ngửi hương, niệm say mê,<br>Nếu tác ý ái tưởng,<br>Tâm tham đắm cảm thọ,<br>Xâm nhập và an trú.<br><br>Thọ người ấy tăng trưởng,<br>Nhiều loại do hương sanh,<br>Tham, hại tâm lớn mạnh,<br>Chúng gia hại tâm nó.<br>Khổ chất chứa như vậy,<br>Rất xa vời Niết-bàn.<br><br>Nếm vị, niệm say mê,<br>Nếu tác ý ái tưởng,<br>Tâm tham đắm cảm thọ,<br>Xâm nhập và an trú.<br><br>Thọ người ấy tăng trưởng,<br>Nhiều loại do vị sanh,<br>Tham, hại tâm lớn mạnh,<br>Chúng gia hại tâm nó,<br>Khổ chất chứa như vậy,<br>Rất xa vời Niết-bàn.<br><br>Cảm xúc, niệm say mê,<br>Nếu tác ý ái tưởng,<br>Tâm tham đắm cảm thọ,<br>Xâm nhập và an trú.<br><br>Thọ người ấy tăng trưởng,<br>Nhiều loại, do xúc sanh,<br>Tham, hại tâm lớn mạnh,<br>Chúng gia hại tâm nó,<br>Khổ chất chứa như vậy,<br>Rất xa vời Niết-bàn.<br><br>Biết pháp, niệm say mê,<br>Nếu tác ý ái tưởng,<br>Tâm tham đắm cảm thọ,<br>Xâm nhập và an trú.<br><br>Thọ người ấy tăng trưởng,<br>Nhiều loại do ý sanh,<br>Tham, hại tâm lớn mạnh,<br>Chúng gia hại tâm nó,<br>Khổ chất chứa như vậy,<br>Rất xa vời Niết-bàn.`, ref: "Trưởng Lão Tăng Kệ 16.5", url: "https://loicuaducphat.org/thag/thag16.5.html#content" },


{ text: `Trưởng Lão Malunkyaputta:<br><br>Không tham nhiễm các sắc,<br>Thấy sắc, giữ chánh niệm,<br>Tâm không tham cảm thọ,<br>Không xâm nhập, an trú.<br><br>Thấy sắc như thế nào,<br>Như vậy có cảm thọ,<br>Từ bỏ không tích lũy,<br>Chánh niệm, hành trì vậy.<br><br>Như vậy, không chứa khổ,<br>Ðược gọi gần Niết-bàn,<br>Không tham nhiễm các tiếng,<br>Nghe tiếng, giữ chánh niệm,<br>Tâm không tham cảm thọ,<br>Không xâm nhập an trú.<br><br>Nghe tiếng như thế nào,<br>Như vậy có cảm thọ,<br>Từ bỏ không tích lũy,<br>Chánh niệm, hành trì vậy.<br>Như vậy không chứa khổ,<br>Ðược gọi gần Niết-bàn.<br><br>Không tham nhiễm các hương,<br>Ngửi hương, giữ chánh niệm,<br>Tâm không tham cảm thọ,<br>Không xâm nhập an trú.<br><br>Ngửi hương như thế nào,<br>Như vậy, có cảm thọ,<br>Từ bỏ, không tích lũy,<br>Chánh niệm, hành trì vậy,<br>Như vậy, không chứa khổ,<br>Ðược gọi, gần Niết-bàn.<br><br>Không tham nhiễm các vị,<br>Nếm vị, giữ chánh niệm,<br>Tâm không tham cảm thọ,<br>Không xâm nhập, an trú.<br><br>Nếm vị như thế nào,<br>Như vậy, có cảm thọ,<br>Từ bỏ, không tích lũy,<br>Chánh niệm, hành trì vậy.<br>Như vậy không chứa khổ,<br>Ðược gọi, gần Niết-bàn.<br><br>Không tham nhiễm các xúc,<br>Cảm xúc giữ chánh niệm,<br>Tâm không tham cảm thọ,<br>Không xâm nhập, an trú.<br><br>Cảm xúc như thế nào,<br>Như vậy, có cảm thọ,<br>Từ bỏ, không tích lũy,<br>Chánh niệm, hành trì vậy.<br>Như vậy không chứa khổ,<br>Ðược gọi, gần Niết-bàn.<br><br>Không tham nhiễm các pháp,<br>Biết pháp, giữ chánh niệm,<br>Tâm không tham cảm thọ,<br>Không xâm nhập, an trú.<br><br>Cảm xúc như thế nào,<br>Như vậy, có cảm thọ,<br>Từ bỏ, không tích lũy,<br>Chánh niệm, hành trì vậy.<br>Như vậy, không chứa khổ,<br>Ðược gọi, gần Niết-bàn.`, ref: "Trưởng Lão Tăng Kệ 16.5", url: "https://loicuaducphat.org/thag/thag16.5.html#content" },

{ text: `Trưởng Lão Talaputta:<br><br>Này tâm, khắp mọi nơi,<br>Ta làm theo lời ngươi,<br>Trải qua nhiều đời sống,<br>Ngươi không tức giận ta,<br>Và thân nội sanh này,<br>Là lòng ngươi biết ơn!<br>Trên đường luân hồi dài,<br>Khổ do chính ngươi tạo.<br><br>Này tâm, chính ngươi làm<br>Tác thành con người ta,<br>Chính ngươi làm, ta thành,<br>Thành một Bà-la-môn,<br>Thành vua chúa hoàng tộc,<br>Một ngày là người buôn,<br>Ngày kia thành nô tỳ,<br>Hoặc thành loại chư Thiên.<br>Tất cả đều do ngươi,<br>Chính do ngươi tác thành.<br><br>Chính do nhân nhà ngươi,<br>Chúng ta thành Tu-la,<br>Chính do ngươi tác thành,<br>Ta rơi đáy địa ngục;<br>Một thời thành súc sanh,<br>Một thời thành ngạ quỷ,<br>Tất cả đều do ngươi,<br>Chính do ngươi tác thành.<br><br>Ngươi sẽ không lừa ta,<br>Nhiều lần, nhiều thời nữa,<br>Như những người phù thủy,<br>Bày các trò ảo thuật,<br>Ngươi chơi lừa phỉnh ta,<br>Như chơi với người điên,<br>Này tâm, hãy nói ta,<br>Chỗ nào ta lỗi lầm.<br><br>Trước tâm này lang thang,<br>Chạy chỗ này chỗ khác,<br>Chạy chỗ nó ưa thích,<br>Chạy chỗ nó vui sướng,<br>Nay ta chế ngự tâm,<br>Với như lý tư duy,<br>Như câu móc chế ngự,<br>Nhiếp phục con voi rừng.<br><br>Với ta, bậc Ðạo Sư,<br>Xác định đời vô thường,<br>Ðời không có trường cửu,<br>Ðời không có kiên thực.<br>Này tâm, hãy đẩy ta,<br>Nhảy vào lời Phật dạy,<br>Khiến ta vượt bộc lưu,<br>Rất khó được vượt qua.<br><br>Ta nay đã xuất gia,<br>Trong pháp Ðại ẩn sĩ<br>Những người giống như ta,<br>Không chấp nhận tổn thất.<br><br>Rừng, biển, sông, đất liền,<br>Bốn phương, phụ trên dưới,<br>Tất cả là vô thường,<br>Ba hữu là hoạn nạn,<br>Này tâm, hãy đi đâu?<br>Ngươi sẽ hưởng an lạc.`, ref: "Trưởng Lão Tăng Kệ 19.1", url: "https://loicuaducphat.org/thag/thag19.1.html#content" },

{ text: `Trưởng Lão Maha-Moggallana:<br><br>Với am, sườn bằng xương,<br>May dính với gân thịt,<br>Gớm thay, đầy hơi thối!<br>Mang tay chân người khác,<br>Làm thân thể của mình!<br><br>Cái bị đựng đầy phân,<br>Ðược da bao bọc lại,<br>Ôi con Quỷ cái kia!<br>Với vú bị ung nhọt,<br>Thân Ngươi, chín dòng nước<br>Luôn luôn được tuôn chảy.<br><br>Thân Ngươi chín dòng nước<br>Hôi thối, tạo trói buộc,<br>Tỷ-kheo tránh thân ấy,<br>Như kẻ sạch tránh phân.<br><br>Nếu người khác biết Ngươi<br>Như ta biết được Ngươi,<br>Người ấy tránh xa Ngươi,<br>Như khi mưa tránh phân.<br><br>Thật là vậy, Ðại hùng,<br>Như Sa-môn, ngài nói:<br>Ở đây, có kẻ đắm,<br>Như bò già trong bùn.<br><br>Ai nghĩ có thể nhuộm,<br>Bầu trời với màu nghệ,<br>Hoặc với màu sắc khác<br>Kẻ ấy chỉ thất bại.<br><br>Tâm ta giống trời ấy,<br>Nội tâm khéo định tĩnh,<br>Chớ đem ác tâm đến<br>Như chim rơi đống lửa.`, ref: "Trưởng Lão Tăng Kệ 20.1", url: "https://loicuaducphat.org/thag/thag20.1.html#content" },


{ text: `Trưởng Lão Maha-Moggallana:<br><br>Các hành là vô thường<br>Có sanh phải có diệt,<br>Sau khi sanh, chúng diệt,<br>Nhiếp chúng là an lạc.<br><br>Những ai thấy năm uẩn,<br>Là khác, không phải ngã,<br>Quán thấu vật tế nhị,<br>Như tên đâm mũi tóc.<br><br>Những ai thấy các hành,<br>Là khác, không phải ngã,<br>Chúng thấu triệt tế nhị,<br>Như têm đâm mũi tóc.<br><br>Như bị kiếm chém xuống,<br>Như bị lửa cháy đầu,<br>Vị Tỷ-kheo xuất gia,<br>Chánh niệm, đoạn tham dục.<br><br>Như bị kiếm chém xuống,<br>Như bị lửa cháy đầu,<br>Vị Tỷ-kheo xuất gia,<br>Chánh niệm, đoạn tham hữu.<br><br>Không với nhu nhược này,<br>Không với ít lực này<br>Có thể chứng Niết-bàn,<br>Giải thoát mọi buộc ràng.<br><br>Vị Tỷ-kheo trẻ này,<br>Con người tối thượng này,<br>Chiến thắng ma, ma quân,<br>Mang thân này tối hậu.`, ref: "Trưởng Lão Tăng Kệ 20.1", url: "https://loicuaducphat.org/thag/thag20.1.html#content" },

{ text: `Trưởng Lão Vangisa:<br><br>Dục ái đốt cháy tôi!<br>Tâm tôi bị thiêu cháy,<br>Lành thay Gotama,<br>Vì lòng từ nói lên,<br>Pháp tiêu diệt lửa hừng.<br><br>Chính vì điên đảo tưởng,<br>Tâm ông bị thiêu đốt,<br>Hãy từ bỏ tịnh tướng,<br>Hệ lụy đến tham dục.<br><br>Nhìn các hành vô thường,<br>Khổ đau, không phải ngã,<br>Dập tắt đại tham dục,<br>Chớ để bị cháy dài,<br>Hãy tu tâm bất tịnh,<br>Nhất tâm, khéo định tĩnh,<br>Tu tập thân hành niệm,<br>Hành hạnh nhiều yếm ly.<br><br>Hãy tập hạnh vô tướng,<br>Ðoạn diệt mạn tùy miên,<br>Nhờ quán sân kiêu mạn,<br>Hạnh ông sẽ an tịnh.`, ref: "Trưởng Lão Tăng Kệ 21.1", url: "https://loicuaducphat.org/thag/thag21.1.html#content" },

{ text: `Một Trưởng Lão Ni Dhìra Khác<br><br>Dhìra, hãy kiên trì,<br>Nắm giữ các thiện pháp,<br>Hỡi này Tỷ-kheo-ni,<br>Các căn được tu tập,<br>Hãy mang cái thân này,<br>Là cái thân cuối cùng,<br>Sau khi đã chiến thắng,<br>Ác ma nữ quân lực,<br>Sau khi đã chiến thắng,<br>Ác ma với quân lực.`, ref: "Trưởng Lão Ni Kệ 1.7", url: "https://loicuaducphat.org/thig/thig1.7.html#content" },


{ text: `Trưởng Lão Ni Upasanà:<br><br>Hỡi Upasanà<br>Hãy vượt dòng nước mạnh,<br>Dòng nước khó vượt qua,<br>Bị thần chết chi phối,<br>Hãy mang cái thân này,<br>Là cái thân cuối cùng,<br>Sau khi đã chiến thắng,<br>Ác ma với quân lực.`, ref: "Trưởng Lão Ni Kệ 1.10", url: "https://loicuaducphat.org/thig/thig1.10.html#content" },

{ text: `Trưởng Lão Ni Abhirùpa Nandà:<br><br>Này Nandà, hãy nhìn,<br>Tấm thân chỗ quy tụ,<br>Nhiều bệnh hoạn, bất tịnh,<br>Ðầy hôi hám thối nát,<br>Tâm nàng hãy tu tập,<br>Quán tri tánh bất tịnh,<br>Ðạt cho được nhất tâm,<br>Tâm tư khéo thiền định.<br><br>Hãy tu tập vô tướng,<br>Hãy bỏ mạn tùy miên,<br>Do thắng tri được mạn,<br>Nàng sẽ sống an tịnh.`, ref: "Trưởng Lão Ni Kệ 2.1", url: "https://loicuaducphat.org/thig/thig2.1.html#content" },


{ text: `Trưởng Lão Ni Mẹ Của Abhayà:<br><br>Từ bàn chân trở lên,<br>Từ đầu tóc trở xuống,<br>Hãy quán sát thân này,<br>Thân này thật bất tịnh,<br>Thật hôi hám thối tha.<br><br>Ta an trú như vậy,<br>Mọi tham dục nhổ sạch,<br>Nhiệt não được đoạn trừ,<br>Ta mát lạnh, tịch tịnh.`, ref: "Trưởng Lão Ni Kệ 2.8", url: "https://loicuaducphat.org/thig/thig2.8.html#content" },

{ text: `Trưởng Lão Ni Abhaya:<br><br>Hỡi này vô úy Ni!<br>Thân này thật mỏng manh,<br>Chính ở đây phàm phu,<br>Ưa thích, thường tham đắm.<br>Ta sẽ bỏ thân này,<br>Tỉnh giác và chánh niệm<br><br>Chú tâm không phóng dật,<br>Ta gắng thoát pháp khổ,<br>Ái diệt, ta chứng đạt,<br>Thành tựu lời Phật dạy.`, ref: "Trưởng Lão Ni Kệ 2.9", url: "https://loicuaducphat.org/thig/thig2.9.html#content" },

{ text: `Trưởng Lão Ni Selà:<br><br>Nàng sẽ không thoát khỏi,<br>Thoát ly khỏi đời này,<br>Như vậy hạnh viễn ly,<br>Nàng dùng để làm gì?<br>Hãy thọ hưởng dục lạc,<br>Chớ bứt rứt về sau.<br><br>Các dục giống gươm giáo,<br>Chém nát các uẩn ta,<br>Những dục mà ngươi gọi,<br>Là lạc thú cuộc đời.<br><br>Ngày nay dục lạc ấy,<br>Với ta không hấp dẫn,<br>Ở tất cả mọi nơi,<br>Hỷ lạc được đoạn tận,<br>Khối tối tăm mù ám,<br>Ðã bị làm tan nát,<br>Hỡi này kẻ Ác ma,<br>Ngươi hãy biết như vậy,<br>Ngươi chính là Ác ma<br>Ngươi đã bị bại trận.`, ref: "Trưởng Lão Ni Kệ 3.7", url: "https://loicuaducphat.org/thig/thig3.7.html#content" },

{ text: `Ác ma:<br><br>Nàng sẽ không thoát khỏi,<br>Thoát ly khỏi đời này,<br>Như vậy hạnh viễn ly,<br>Nàng dùng để làm gì?<br>Hãy thọ hưởng dục lạc,<br>Chớ bứt rứt về sau.<br><br>Trưởng Lão Ni Selà:<br><br>Các dục giống gươm giáo,<br>Chém nát các uẩn ta,<br>Những dục mà ngươi gọi,<br>Là lạc thú cuộc đời.<br><br>Ngày nay dục lạc ấy,<br>Với ta không hấp dẫn,<br>Ở tất cả mọi nơi,<br>Hỷ lạc được đoạn tận,<br>Khối tối tăm mù ám,<br>Ðã bị làm tan nát,<br>Hỡi này kẻ Ác ma,<br>Ngươi hãy biết như vậy,<br>Ngươi chính là Ác ma<br>Ngươi đã bị bại trận.`, ref: "Trưởng Lão Ni Kệ 3.7", url: "https://loicuaducphat.org/thig/thig3.7.html#content" },


{ text: `Trưởng Lão Ni Sundarì Nandà:<br><br>Nandà, hãy nhìn thân,<br>Bệnh bất tịnh, hôi thúi,<br>Hãy tu tâm bất tịnh,<br>Nhất tâm khéo định tĩnh.<br><br>Như thân này thân ấy,<br>Như thân ấy thân này,<br>Hôi thối và rữa nát,<br>Chỉ kẻ ngu thích thú.<br><br>Như vậy quán thân này,<br>Ngày đêm không mệt mỏi,<br>Với trí tuệ của con,<br>Do vậy hãy thoát ly,<br>Với trí tuệ của con,<br>Thoát khỏi kiêu sắc đẹp,<br>Và người si nhìn thấy,<br>Với cái nhìn như thật.<br><br>Thành này làm bằng xương,<br>Quét tô bằng máu thịt,<br>Ở đây già và chết,<br>Mạn, lừa đảo chất chứa.<br><br>Với tâm không phóng dật,<br>Như lý, quán thân ấy,<br>Tánh như thật thân này,<br>Ðược thấy trong và ngoài.<br>Ta nhàm chán thân thể,<br>Nội tâm được ly tham,<br>Không phóng dật ly hệ,<br>Ta an bình tịch tịnh.`, ref: "Trưởng Lão Ni Kệ 5.4", url: "https://loicuaducphat.org/thig/thig5.4.html#content" },

{ text: `Ác ma:<br><br>Nàng vừa trẻ vừa đẹp,<br>Ta vừa trẻ vừa xuân,<br>Với cung đàn năm điệu,<br>Hãy vui hưởng, Khemà.<br><br>Trưởng Lão Ni Khemà:<br><br>Với thân hôi thối này,<br>Bệnh hoạn và mong manh,<br>Ta nhàm chán ghét bỏ,<br>Dục ái đã nhổ lên.<br><br>Dục ví như gươm giáo,<br>Các uẩn đoạn đầu đài,<br>Ðiều người nói dục lạc,<br>Nay ta đã xa lìa.<br><br>Mọi nơi, hỷ duyệt đoạn,<br>Khối si ám tan tành,<br>Hãy biết vậy, Ác ma!<br>Ngươi bị hại, Ma vương.<br><br>Ngươi đánh lễ vầng sao!<br>Ngươi thờ lửa rừng sâu,<br>Ngươi không biết như thật,<br>Kẻ ngu nghĩ rằng tịnh.<br><br>Còn ta, ta đảnh lễ,<br>Bậc Giác ngộ, Thượng nhân,<br>Giải thoát mọi khổ đau,<br>Hành lời Ðạo Sư dạy.`, ref: "Trưởng Lão Ni Kệ 6.3", url: "https://loicuaducphat.org/thig/thig6.3.html#content" },

{ text: `Trưởng Lão Ni Mẹ Của Vaddha:<br><br>Vaddha, chớ bao giờ,<br>Rơi vào cõi tham dục,<br>Này con, chớ chia phần,<br>Trong đau khổ liên tục.<br><br>Hạnh phúc là ẩn sĩ,<br>Không tham, nghi đoạn tận,<br>Sống mát lạnh, chế ngự,<br>Không còn các lậu hoặc.<br><br>Ẩn sĩ ấy hành trì,<br>Con đường đạt chánh kiến,<br>Chấm dứt sự khổ đau,<br>Vaddha! Hãy tiến tu.<br><br>Với tự tín mẹ nói,<br>Mục đích này cho con,<br>Mẹ thân! Con nghĩ rằng,<br>Mẹ không còn tham dục.<br><br>Vaddha! Phàm hành gì,<br>Thấp, cao hay bậc trung,<br>Một tí nhỏ tham dục,<br>Không có ở nơi ta.<br><br>Ta đoạn mọi lậu hoặc,<br>Không phóng dật, thiền tu,<br>Ba minh đã đạt được,<br>Làm xong lời dạy.<br><br>Vi diệu thay, mẹ ta,<br>Khích lệ, thúc đẩy ta,<br>Những kệ thuộc chân đế,<br>Với lòng từ thương tưởng.<br><br>Ta nghe lời mẹ dạy,<br>Lời giáo giới mẹ hiền,<br>Ta hành pháp cảm kích,<br>Ðạt an ổn khổ ách.<br><br>Ta tinh tấn tinh cần,<br>Ngày đêm không biếng nhác,<br>Ðược mẹ khéo khích lệ,<br>Ta chứng tịnh tối tượng.`, ref: "Trưởng Lão Ni Kệ 9.1", url: "https://loicuaducphat.org/thig/thig9.1.html#content" },

{ text: `Trưởng Lão Ni Uppalavanna:<br><br>Ðáng ngán thay các dục,<br>Bất tịnh, hôi, nhiều gai,<br>Thấy nguy hiểm trong dục,<br>Viễn ly an ổn vững<br>Nàng xuất gia Vương Xá,<br>Bỏ nhà, sống không nhà.<br><br>Ta biết các đời trước,<br>Thiên nhãn được thanh tịnh,<br>Trí biết được tâm người,<br>Nhĩ giới được trong sạch.<br><br>Ta chứng được thần thông,<br>Lậu tận ta đạt được,<br>Ta chứng sáu thắng trí,<br>Lời Phật dạy, làm xong.<br><br>Với tâm khéo nhiếp phục,<br>Thần túc khéo tu trì,<br>Sáu thắng trí, ta chứng,<br>Lời Phật dạy, làm xong.<br><br>Các dục giống gươm giáo,<br>Chém nát các uẩn ta,<br>Những dục mà ngươi gọi,<br>Là lạc thú cuộc đời.<br>Ngày nay, dục lạc ấy.<br>Với ta, không hấp dẫn.<br><br>Ở tất cả mọi nơi,<br>Hỷ lạc được đoạn tận,<br>Khối tối tăm mù ám,<br>Ðã bị làm tan nát,<br>Hỡi này kẻ Ác ma,<br>Ngươi hãy biết như vậy,<br>Ngươi chính là Ác ma,<br>Ngươi đã bị bại trận.`, ref: "Trưởng Lão Ni Kệ 11.1", url: "https://loicuaducphat.org/thig/thig11.1.html#content" },

{ text: `Trưởng Lão Ni Subhà:<br><br>Ðây, loài Người tham đắm,<br>Phóng dật, tâm uế nhiễm,<br>Chống đối thù địch nhau<br>Rộng đường đấu tranh nhau.<br><br>Giết hại, trói, tra tấn,<br>Hao tài sầu, ưu tư<br>Những ai chìm trong dục,<br>Gặp phải nhiều tai họa.<br><br>Vì sao bà con ta<br>Giống như kẻ thù ta,<br>Lại trói buộc ta vào,<br>Trong vòng các dục lạc,<br>Hãy biết ta xuất gia,<br>Vì thấy dục đáng sợ.<br><br>Bạc, vàng không có thể<br>Ðoạn được các lậu hoặc,<br>Các dục là thù địch,<br>Sát nhân, chuyên giết hại,<br>Chúng là kẻ oán thù,<br>Là mũi tên, dây trói.<br><br>Vì sao bà con ta<br>Giống như kẻ thù ta,<br>Lại trói buộc ta vào<br>Trong vòng các dục lạc,<br>Hãy biết ta xuất gia,<br>Cạo tóc đắp đại y.<br><br>Nuôi sống bằng đồ ăn,<br>Tích lũy nhờ khất thực,<br>Y áo được tác thành<br>Với miếng vải lượm lặt<br>Sống vậy, thích hợp ta,<br>Cơ bản, sống không nhà.<br><br>Dục đại sĩ từ bỏ<br>Dục loài Trời, loài Người,<br>Trú an ổn, giải thoát<br>Không dao động an lạc.<br><br>Chớ để ta đến dục,<br>Trong dục, không an toàn,<br>Dục, thù địch sát nhân<br>Gây khổ, dụ đống lửa.<br><br>Ðường hiểm, đầy sợ hãi,<br>Ðầy khổ hoạn, gai góc,<br>Tham ái đường gập ghềnh,<br>Hoang si mê rộng lớn.<br><br>Tai họa đầy hãi hùng,<br>Các dục dụ đầu rắn,<br>Kẻ ngu thích thú dục,<br>Kẻ mù lòa phàm phu.<br><br>Chúng sanh chìm bùn đục,<br>Những kẻ không thấy đời,<br>Họ không có rõ biết,<br>Sự chấm dứt sanh tử.<br><br>Loài Người vì nhân dục,<br>Con đường đến ác thú,<br>Phần nhiều đi đường ấy,<br>Khiến tự ngã bệnh hoạn.<br><br>Như vậy dục sanh thù,<br>Nung nấu, làm uế nhiễm,<br>Dục thuộc về thể vật,<br>Trói người vào tử vong.<br><br>Dục làm cho diên cuồng,<br>Loạn ngôn tâm thác loạn,<br>Làm uế nhiễm chúng sanh,<br>Sắp rơi bẫy Ác ma.<br><br>Dục nguy hiểm không cùng,<br>Nhiều khổ, thuốc độc lớn,<br>Ngọt ít, tạo đấu tranh,<br>Héo tàn ngày tươi sáng.<br><br>Ta quyết định như vậy,<br>Không trở lui dục nhân,<br>Tác thành điều bất hạnh,<br>Luôn vui hưởng Niết-bàn.<br><br>Quyết đấu tranh với dục,<br>Chờ đợi, mát, lắng dịu,<br>Sẽ sống không phóng dật,<br>Ðoạn diệt kiết sử dục.<br><br>Ta đi theo đường ấy<br>Ðường đại sĩ đi qua,<br>Không sầu, không cấu uế,<br>An ổn, thẳng, Tám ngành.<br><br>Hãy xem Subhà này,<br>An trú trên Chánh pháp,<br>Con gái một thợ vàng,<br>Ðạt được không tham dục,<br>Ngồi hành trì thiền định,<br>Ở dưới một gốc cây.`, ref: "Trưởng Lão Ni Kệ 13.5", url: "https://loicuaducphat.org/thig/thig13.5.html#content" },

{ text: `Trưởng Lão Ni Sumedhà:<br><br>Sá gì thân hôi nhớp,<br>Phát mùi, gây sợ hãi,<br>Bao da đựng xác chết,<br>Rỉ chảy đồ bất tịnh.<br><br>Sá gì thân ta biết,<br>Ghê tởm, lấm máu thịt,<br>Chỗ chứa đựng loài sâu,<br>Mồi ăn cho chim chóc,<br>Thân xác này là vậy,<br>Nay đem đến cho ai?<br><br>Thân thể bỏ nghĩa địa,<br>Không lâu, mất thức tri,<br>Như khúc gỗ quăng bỏ,<br>Bà con đều ghê tởm.<br><br>Thân ấy quăng nghĩa địa,<br>Làm mồi ăn kẻ khác,<br>Trước chúng tắm rửa sạch,<br>Nay chúng sinh ghê tởm,<br>Cha mẹ còn như vậy,<br>Nói gì chung quần chúng.<br><br>Họ mê thân không lõi,<br>Ràng buộc bởi gân xương,<br>Ðầy nước miếng, nước mắt,<br>Ðầy phân tiểu hôi hám.<br><br>Nếu thân được mổ xẻ,<br>Lội nội phần ra ngoài,<br>Chính mẹ phải ghê tởm,<br>Không chịu nổi mùi hôi.<br><br>Chính do uẩn, xứ, giới,<br>Tác thành các thân này,<br>Gốc tái sanh, đau khổ;<br>Họ như lý nói lên,<br>Hoàn toàn không vui thích.<br>Vậy ai, tôi muốn cưới?<br><br>Từng ngày trăm ngọn giáo,<br>Luôn luôn mới đâm thân,<br>Dầu bị hại trăm năm,<br>Như vậy còn tốt hơn,<br>Vì khổ ấy cuối cùng,<br>Rồi cũng được tiêu diệt.<br><br>Kẻ trí quyết bằng lòng<br>Sự giết hại như trên,<br>Bậc Ðạo Sư dạy rằng:<br>Họ luân hồi dài dà,<br>Với tâm tư giết hại,<br>Liên tục nối tiếp nhau.<br><br>Trong cảnh giới Trời, Người,<br>Bàng sanh, a-tu-la,<br>Ngạ quỷ và Ðịa ngục,<br>Chịu giết hại vô lượng.<br><br>Trong địa ngục, rất nhiều,<br>Kẻ tâm uế, đọa lạc,<br>Chỗ trú ẩn Thiên giới,<br>Không có lạc Niết-bàn.<br><br>Những ai đạt Niết-bàn,<br>Họ liên hệ mật thiết,<br>Với những lời thuyết dạy,<br>Của bậc đủ Mười lực,<br>Thong dong không rộn ràng,<br>Nỗ lực đoạn sanh tử.<br><br>Thưa cha ngày hôm nay<br>Con quyết tâm ra đi,<br>Những tài sản rỗng không,<br>Không có giá trị gì,<br>Con ghê tởm các dục,<br>Con chán ngấy các dục,<br>Họ đã được tách thành,<br>Như thân cây Ta-la.`, ref: "Trưởng Lão Ni Kệ 16.1", url: "https://loicuaducphat.org/thig/thig16.1.html#content" },

{ text: `Trưởng Lão Ni Sumedhà:<br><br>Dầu có mười bảy báu,<br>Khắp mười phương đầy tràn,<br>Không có dục thỏa mãn,<br>Người chết, chưa thỏa mãn.<br><br>Các dục ví gươm giáo,<br>Các dục ví đầu rắn,<br>Ví như bó đuốc cháy<br>Giống xương gậm trơn tru.<br><br>Các dục không thường còn,<br>Cũng không có thường hằng,<br>Khổ nhiều, thuốc độc lớn,<br>Như hòn đạn cháy đỏ,<br>Nguồn gốc của bất hạnh,<br>Kết quả là đau khổ.<br><br>Dục như trái của cây,<br>Như miếng thịt, khổ lụy,<br>Giống như mộng như huyễn,<br>Dục như của vay mượn.<br><br>Dục như gươm, như cọc,<br>Bệnh tật và cục bướu,<br>Bất hạnh và dao động,<br>Ví như hố than hừng,<br>Nguồn gốc của bất hạnh,<br>Sợ hãi và tàn sát.<br><br>Kẻ ngu, đã lâu rồi,<br>Khóc luân hồi nói tiếp,<br>Từ vô thỉ đến nay,<br>Khóc phải bị mệnh chung,<br>Khóc anh em bị giết,<br>Khóc tự mình bị giết.<br><br>Hãy nhớ từ vô thỉ,<br>Nước mắt, sữa và máu,<br>Tuôn chảy theo luân hồi,<br>Không bao giờ dừng nghỉ,<br>Hãy nhớ các chúng sanh,<br>Luân hồi xương chất đống.<br><br>Hãy nhớ tràn bốn biển,<br>Ðầy nước mắt, sữa, máu,<br>Hãy nhớ xương một kiếp,<br>Cao bằng Vi-pu-la.<br><br>Hãy nhớ từ vô thỉ,<br>Không đủ để làm thành,<br>Cả đất nước Diêm Phù,<br>Những nấm mồ hột táo,<br>Của mẹ cha luân hồi.<br><br>Hãy nhớ từ vô thỉ,<br>Những cỏ cây cành lá,<br>Không đủ để chứa đựng,<br>Những ghè bốn ngón tay,<br>Chứa người cha, luân hồi.<br><br>Hãy nhớ tới hình ảnh,<br>Con rùa mù biển đông,<br>Cho đầu nó lọt vào,<br>Lỗ hổng khúc cây trôi,<br>Ðể nói lên ví dụ,<br>Ðược làm người khó vậy.`, ref: "Trưởng Lão Ni Kệ 16.1", url: "https://loicuaducphat.org/thig/thig16.1.html#content" },



{ text: `Trưởng Lão Ni Sumedhà:<br><br>Hãy nhớ thân sắc người,<br>Ðược ví bong bóng nước,<br>Ðầy cả những bất hạnh,<br>Trống không không có lõi,<br>Hãy thấy uẩn vô thường!<br>Nhớ địa ngục nhiều họa.<br><br>Hãy nhớ nghĩa địa lớn,<br>Nhờ tái sanh tiếp tục,<br>Nhờ sợ hãi thuồng luồng,<br>Hãy nhớ Bốn sự thật.<br><br>Nước bất tử có đây,<br>Sao người uống trăm đắng,<br>Tất cả các dục lạc,<br>Thật trăm cay ngàn đắng.<br><br>Nước bất tử có đây!<br>Sao người ưa dục não!<br>Mọi dục lạc đốt cháy<br>Sôi sùng sục nung nấu.<br><br>Ðây không có kẻ thù!<br>Sao thích dục thù địch?<br>Vua lửa, trộm, nước, oán,<br>Thù chung thật là nhiều.<br><br>Ở đây có giải thoát!<br>Sao để dục giết trói,<br>Trong dục có giết trói!<br>Mê dục nhiều khổ đau.<br><br>Ðuốc cỏ đang cháy rực,<br>Nắm, không thả, bị đốt,<br>Dục ví như bó đuốc,<br>Ðốt cháy ai không thoát.<br><br>Chớ nhận dục lạc nhỏ,<br>Bỏ lạc lớn rộng rãi,<br>Chớ như cá nuốt câu,<br>Sau phải chịu hoạn nạn.<br><br>Hãy nhiếp dục trong dục,<br>Như chó bị dây cột,<br>Chớ để dục ăn ngươi,<br>Như dân đói ăn chó.<br><br>Khổ thật là vô lượng,<br>Khiến tâm nhiều ưu tư,<br>Ngươi hệ lụy với dục,<br>Hãy bỏ dục vô thường.<br><br>Ở đây, không có già!<br>Sao theo dục bị già?<br>Mọi sanh ở khắp nơi,<br>Bị bệnh chết chi phối,<br><br>Ðây không già, không chết.<br>Ðây con đường không già,<br>Không chết, không sầu não,<br>Không thù địch trói buộc,<br>Không vấp ngã sợ hãi,<br>Không nung nấu đọa đầy.<br><br>Ðích này, nhiều người đạt,<br>Ðích này là bất tử,<br>Nay cần phải chứng được,<br>Ai như lý chú tâm,<br>Nếu không có nỗ lực,<br>Không sao chứng đạt được.<br><br>Ðây là nhân, là nguồn<br>Ðây chính là căn gốc,<br>Kham nhẫn lời Ðạo Sư!<br>Ðây dây chuyền thứ nhất<br>Ðấy chính là Niết-bàn,<br>Nếu chúng ta mến pháp.<br><br>Như vậy với lòng tin,<br>Họ thuyết rõ nên lời<br>Lời nói đầy trí tuệ,<br>Thù thắng và tối thượng<br>Họ chán ghét tái sanh,<br>Do chán ghét, tham diệt.`, ref: "Trưởng Lão Ni Kệ 16.1", url: "https://loicuaducphat.org/thig/thig16.1.html#content" },

{ text: `Như vậy, này Ðại vương, Tỷ-kheo tự mình quán năm triền cái chưa xả ly, như món nợ, như bệnh hoạn, như ngục tù, như cảnh nô lệ, như con đường sa mạc. Này Ðại vương, cũng như không mắc nợ, như không bệnh tật, như được khỏi tù tội, như được tự do, như đất lành yên ổn, này Ðại vương, Tỷ-kheo quán năm triền cái khi diệt trừ chúng.`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `Này Poṭṭhapāda, Ta thuyết pháp để diệt thô phù ngã chấp. Nếu các người thực hành theo pháp này thời nhiễm pháp được diệt trừ, tịnh pháp được tăng trưởng, và ngay hiện tại, tự mình giác ngộ, với thắng trí, chứng đạt và an trú trí tuệ sung mãn, quảng đại. Này Poṭṭhapāda, rất có thể các người nghĩ: “Các nhiễm pháp sẽ diệt trừ, các tịnh pháp sẽ tăng trưởng, và ngay hiện tại tự mình giác ngộ, với thắng trí, chứng đạt và an trú trí tuệ sung mãn, quảng đại, tuy vậy đau khổ vẫn tồn tại”. Này Poṭṭhapāda, chớ có nghĩ như vậy. Khi nhiễm pháp được diệt trừ, tịnh pháp được tăng trưởng, ngay hiện tại tự mình giác ngộ, với thắng trí, chứng đạt và an trú trí tuệ sung mãn, quảng đại, thời hân hoan sanh, hoan hỷ, khinh an, chánh niệm, tỉnh giác và lạc trú sanh.`, ref: "Trường Bộ 9 – Kinh Poṭṭhapāda", url: "https://loicuaducphat.org/dn/dn9.html#content" },


{ text: `Này Vāseṭṭha, có năm pháp khiến dục lạc tăng thịnh. Thế nào là năm? Những sắc pháp do mắt cảm nhận khả ái, mỹ miều, thích thú, hấp dẫn, câu hữu với dục, ái lạc; những tiếng do tai cảm nhận...những hương do mũi cảm nhận...những vị do lưỡi cảm nhận... những xúc do thân cảm nhận khả ái, mỹ miều, thích thú, hấp dẫn, câu hữu với dục lạc. Này Vāseṭṭha, năm pháp khiến dục lạc tăng thịnh ấy, các Bà-la-môn tinh thông ba tập Vedā chấp trước, mê đắm, bị trói buộc, không thấy nguy hiểm của chúng, không nhận thức sự không thoát ly của chúng, đã tận hưởng năm pháp ấy. Này Vāseṭṭha, những Bà-la-môn tinh thông ba tập Vedā, loại bỏ những pháp tác thành người Bà-la-môn, tuân theo những pháp không tác thành người Bà-la-môn, chấp trước, mê đắm, bị trói buộc, không thấy nguy hiểm của chúng, không nhận thức sự không thoát ly của chúng, tận hưởng chúng, bị trói buộc bởi sự trói buộc của dục lạc, sau khi thân hoại mạng chung sẽ cộng trú với Phạm thiên, thật không có sự kiện ấy.`, ref: "Trường Bộ 13 – Kinh Tam Minh", url: "https://loicuaducphat.org/dn/dn13.html#content" },


{ text: `Này các Tỷ-kheo, hoàng tử Vipassì, khi đang đi đến vườn ngự uyển, thấy một người bệnh hoạn, khổ não, nguy kịch, bò lết trong tiểu tiện, đại tiện của mình, cần có người khác nâng đỡ, cần có người khác dìu dắt. Thấy vậy, hoàng tử hỏi người đánh xe. “Này khanh, người này đã làm gì, mà mắt của nó không giống mắt của những người khác, giọng nói của nó không giống giọng nói của những người khác?”: “Tâu Hoàng tử, đó là một người được gọi là một người bệnh vậy”. “Này khanh, sao người ấy được gọi là một người bệnh?”: “Tâu Hoàng tử, người ấy được gọi là một người bệnh vì người ấy chưa thoát khỏi căn bệnh của mình”: “Này khanh, vậy rồi ta có bị bệnh không, một người chưa bị bệnh?”: “Tâu Hoàng tử, Hoàng tử và cả con nữa, tất cả chúng ta sẽ bị bệnh tật, dầu chúng ta chưa bị bệnh tật”. “Này khanh, thôi nay thăm vườn ngự uyển như vậy vừa rồi. Hãy cho đánh xe trở về cung”. “Thưa vâng, Hoàng tử”. Này các Tỷ-kheo, người đánh xe vâng theo lời hoàng tử cho đánh xe trở về cung. Này các Tỷ-kheo, hoàng tử Vipassì về trong cung, đau khổ, sầu muộn và suy nghĩ: “Sỉ nhục thay, cái gọi là sanh! Và ai sanh ra, cũng phải già, cũng phải bệnh!”`, ref: "Trường Bộ 14 – Kinh Ðại bổn", url: "https://loicuaducphat.org/dn/dn14.html#content" },

{ text: `Này các Tỷ-kheo, người đánh xe vâng theo lời hoàng tử, cho đánh xe đến người vừa mới mệnh chung. Này các Tỷ-kheo, khi thấy thây người chết, hoàng tử Vipassì hỏi: “Này khanh, sao người ấy được gọi là người đã chết?”: “Tâu Hoàng tử, người ấy được gọi là người đã chết vì nay bà mẹ, ông cha, các người bà con ruột thịt khác không thấy người ấy nữa; và người ấy cũng không thấy bà mẹ, ông cha hay những người bà con ruột thịt khác!”: “Này khanh, vậy Ta chưa chết, rồi có bị chết không? Phụ vương, Mẫu hậu hay những người bà con ruột thịt khác sẽ không thấy Ta chăng, và Ta sẽ không thấy Phụ vương, Mẫu hậu hay những bà con ruột thịt chăng?”: “Tâu Hoàng tử, Hoàng tử và cả con nữa, chúng ta tuy nay chưa chết nhưng rồi sẽ cũng bị chết. Phụ vương, Mẫu hậu hay các người bà con ruột thịt khác sẽ không thấy Hoàng Tử, và Hoàng tử sẽ không thấy Phụ vương. Mẫu hậu hay các người bà con ruột thịt khác”. “Này khanh, thôi nay thăm vườn ngự uyển như vậy vừa rồi. Hãy cho đánh xe trở về cung”. “Thưa vâng, Hoàng tử”. Này các Tỷ-kheo, người đánh xe vâng lời hoàng tử, cho đánh xe trở về cung. Này các Tỷ-kheo, hoàng tử Vipassì về trong cung, đau khổ, sầu muộn và suy nghĩ: “Sỉ nhục thay cái gọi là sanh! Và ai sanh ra cũng phải già, cũng phải bệnh, cũng phải chết như vậy!”.`, ref: "Trường Bộ 14 – Kinh Ðại bổn", url: "https://loicuaducphat.org/dn/dn14.html#content" },


{ text: `Tất cả pháp hữu vi,<br>Thật sự là vô thường,<br>Khởi lên rồi diệt mất,<br>Thường tánh là như vậy.<br>Chúng được sanh khởi lên,<br>Rồi chúng lại hoại diệt.<br>Hạnh phúc thay khi chúng<br>Ðược tịnh chỉ an lạc.`, ref: "Trường Bộ 17 – Kinh Ðại Thiện Kiến Vương", url: "https://loicuaducphat.org/dn/dn17.html#content" },


{ text: `Và này các Tỷ-kheo, thế nào là sự nguy hiểm các sắc pháp? Này các Tỷ-kheo, ở đây người ta có thể thấy cô gái ấy trong một thời khác, khoảng tám mươi tuổi, chín mươi tuổi hay một trăm tuổi, già yếu, cong như nóc nhà, lưng còm, phải dựa gậy để chống đỡ, vừa đi vừa run rẩy, đau ốm, tuổi trẻ đã tận, râu rụng, tóc bạc, hư rụng, sói đầu, da nhăn, tay chân bị khô đét tái xám. Này các Tỷ-kheo, các Người nghĩ thế nào? Có phải sự mỹ diệu về sắc đẹp xưa kia của người đó nay đã biến mất và sự nguy hiểm đã hiện ra? - Bạch Thế Tôn, sự thật là vậy. - Này các Tỷ-kheo, như vậy là sự nguy hiểm các sắc pháp.`, ref: "Trung Bộ 13 – Ðại Kinh Khổ Uẩn", url: "https://loicuaducphat.org/mn/mn13.html#content" },

{ text: `Lại nữa này các Tỷ-kheo, người ta có thể thấy cô gái ấy bị bệnh hoạn đau khổ, trầm bệnh, nằm đắm mình trong phân tiểu của mình, phải có người nâng dậy, phải có người đỡ nằm. Này các Tỷ-kheo, các Người nghĩ thế nào? Có phải sự mỹ diệu về sắc đẹp xưa kia của người đó nay đã biến mất và sự nguy hiểm đã hiện ra? - Bạch Thế Tôn, sự thật là vậy. - Này các Tỷ-kheo, như vậy là sự nguy hiểm các sắc pháp.`, ref: "Trung Bộ 13 – Ðại Kinh Khổ Uẩn", url: "https://loicuaducphat.org/mn/mn13.html#content" },

{ text: `Lại nữa, này các Tỷ-kheo, người ta thấy cô gái ấy, thi thể bị quăng vào nghĩa địa, bị các loài quạ ăn, hay bị các loài diều hâu ăn, hay bị các chim kên ăn, hay bị các loài chó ăn, hay bị các loài giả can ăn, hay bị các loài côn trùng ăn. Này các Tỷ-kheo, các Người nghĩ thế nào? Có phải sự mỹ diệu về sắc đẹp xưa kia của cô gái nay đã biến mất và sự nguy hiểm đã hiện ra? - Bạch Thế Tôn, sự thật là vậy. - Này các Tỷ-kheo, như vậy là sự nguy hiểm các sắc pháp.`, ref: "Trung Bộ 13 – Ðại Kinh Khổ Uẩn", url: "https://loicuaducphat.org/mn/mn13.html#content" },

{ text: `Lại nữa, này các Tỷ-kheo, người ta thấy cô gái ấy, thi thể bị quăng trong nghĩa địa, với các bộ xương còn liên kết với nhau, còn dính thịt và máu, còn được các đường gân cột lại … với các bộ xương còn liên kết với nhau, không còn dính thịt nhưng còn dính máu, còn được các đường gân cột bộ xương, không còn thịt, không có máu, còn được gân cột lại, chỉ còn có xương không dính lại với nhau, rải rác chỗ này chỗ kia, ở đây là xương tay, ở đây là xương chân, ở đây là xương ống, ở đây là xương bắp vế, ở đây là xương mông, ở đây là xương sống, ở đây là xương đầu. Này các Tỷ-kheo, các Người nghĩ thế nào? Có phải sự mỹ diệu về sắc đẹp xưa kia của cô gái nay đã biến mất, và sự nguy hiểm đã hiện ra? - Bạch Thế Tôn, sự thật là vậy. - Này các Tỷ-kheo, như vậy là sự nguy hiểm các sắc pháp.`, ref: "Trung Bộ 13 – Ðại Kinh Khổ Uẩn", url: "https://loicuaducphat.org/mn/mn13.html#content" },

{ text: `Này các Tỷ-kheo, những Sa-môn, Bà-la-môn nào không như thật tuệ tri vị ngọt các sắc pháp là vị ngọt như vậy, sự nguy hiểm là sự nguy hiểm như vậy, sự xuất ly là sự xuất ly như vậy, những vị này nhất định sẽ không như thật tuệ tri các sắc pháp của họ, họ cũng không có thể đặt người khác trong một địa vị tương tự, nghĩa là như thật tuệ tri các sắc pháp, sự kiện như vậy không xảy ra. Này các Tỷ-kheo, những Sa-môn, Bà-la-môn nào như thật tuệ tri vị ngọt các sắc pháp là vị ngọt như vậy, sự nguy hiểm là sự nguy hiểm như vậy, sự xuất ly là sự xuất ly như vậy, những vị này nhất định như thật tuệ tri các sắc pháp của họ, họ cũng có thể đặt người khác trong một địa vị tương tự, nghĩa là như thật tuệ tri các sắc pháp, sự kiện như vậy có xảy ra.`, ref: "Trung Bộ 13 – Ðại Kinh Khổ Uẩn", url: "https://loicuaducphat.org/mn/mn13.html#content" },
				
        ];
		
		module.exports = { ASUBHA_DATA };